using GlBindFramebufferFn = void(APIENTRY*)(GLenum target, GLuint framebuffer);
using GlGenFramebuffersFn = void(APIENTRY*)(GLsizei count, GLuint* framebuffers);
using GlDeleteFramebuffersFn = void(APIENTRY*)(GLsizei count, const GLuint* framebuffers);
using GlFramebufferTexture2DFn = void(APIENTRY*)(GLenum target, GLenum attachment, GLenum textarget, GLuint texture,
                                                 GLint level);
using GlCheckFramebufferStatusFn = GLenum(APIENTRY*)(GLenum target);
using GlBindRenderbufferFn = void(APIENTRY*)(GLenum target, GLuint renderbuffer);
using GlGenRenderbuffersFn = void(APIENTRY*)(GLsizei count, GLuint* renderbuffers);
using GlDeleteRenderbuffersFn = void(APIENTRY*)(GLsizei count, const GLuint* renderbuffers);
using GlRenderbufferStorageFn = void(APIENTRY*)(GLenum target, GLenum internalformat, GLsizei width, GLsizei height);
using GlFramebufferRenderbufferFn = void(APIENTRY*)(GLenum target, GLenum attachment, GLenum renderbuffertarget,
                                                   GLuint renderbuffer);

struct FramebufferApi {
    bool loaded = false;
    GlBindFramebufferFn BindFramebuffer = nullptr;
    GlGenFramebuffersFn GenFramebuffers = nullptr;
    GlDeleteFramebuffersFn DeleteFramebuffers = nullptr;
    GlFramebufferTexture2DFn FramebufferTexture2D = nullptr;
    GlCheckFramebufferStatusFn CheckFramebufferStatus = nullptr;
    GlBindRenderbufferFn BindRenderbuffer = nullptr;
    GlGenRenderbuffersFn GenRenderbuffers = nullptr;
    GlDeleteRenderbuffersFn DeleteRenderbuffers = nullptr;
    GlRenderbufferStorageFn RenderbufferStorage = nullptr;
    GlFramebufferRenderbufferFn FramebufferRenderbuffer = nullptr;
};

FramebufferApi gFramebufferApi;

template <typename T>
bool LoadGlProc(T& proc, const char* name) {
    proc = reinterpret_cast<T>(glfwGetProcAddress(name));
    return proc != nullptr;
}

bool LoadFramebufferApi() {
    if (gFramebufferApi.loaded) {
        return true;
    }

    bool ok = true;
    ok = LoadGlProc(gFramebufferApi.BindFramebuffer, "glBindFramebuffer") && ok;
    ok = LoadGlProc(gFramebufferApi.GenFramebuffers, "glGenFramebuffers") && ok;
    ok = LoadGlProc(gFramebufferApi.DeleteFramebuffers, "glDeleteFramebuffers") && ok;
    ok = LoadGlProc(gFramebufferApi.FramebufferTexture2D, "glFramebufferTexture2D") && ok;
    ok = LoadGlProc(gFramebufferApi.CheckFramebufferStatus, "glCheckFramebufferStatus") && ok;
    ok = LoadGlProc(gFramebufferApi.BindRenderbuffer, "glBindRenderbuffer") && ok;
    ok = LoadGlProc(gFramebufferApi.GenRenderbuffers, "glGenRenderbuffers") && ok;
    ok = LoadGlProc(gFramebufferApi.DeleteRenderbuffers, "glDeleteRenderbuffers") && ok;
    ok = LoadGlProc(gFramebufferApi.RenderbufferStorage, "glRenderbufferStorage") && ok;
    ok = LoadGlProc(gFramebufferApi.FramebufferRenderbuffer, "glFramebufferRenderbuffer") && ok;
    gFramebufferApi.loaded = ok;
    return ok;
}

const EditorAppearanceSettings* gActiveAppearance = nullptr;

float Clamp01(float value) {
    return std::clamp(value, 0.0f, 1.0f);
}

ImVec4 ClampColor(ImVec4 color) {
    return ImVec4(Clamp01(color.x), Clamp01(color.y), Clamp01(color.z), Clamp01(color.w));
}

ImVec4 WithAlpha(ImVec4 color, float alpha);

const EditorAppearanceSettings& ActiveAppearance() {
    static const EditorAppearanceSettings fallback;
    return gActiveAppearance == nullptr ? fallback : *gActiveAppearance;
}

ImVec4 ScaleColor(ImVec4 color, float scale) {
    color.x = Clamp01(color.x * scale);
    color.y = Clamp01(color.y * scale);
    color.z = Clamp01(color.z * scale);
    return color;
}

ImVec4 OffsetColor(ImVec4 color, float offset) {
    color.x = Clamp01(color.x + offset);
    color.y = Clamp01(color.y + offset);
    color.z = Clamp01(color.z + offset);
    return color;
}

ImVec4 MixColor(ImVec4 left, ImVec4 right, float amount) {
    const float t = Clamp01(amount);
    return ImVec4(left.x + (right.x - left.x) * t, left.y + (right.y - left.y) * t,
                  left.z + (right.z - left.z) * t, left.w + (right.w - left.w) * t);
}

ImVec4 AdjustTextColor(ImVec4 color) {
    const EditorAppearanceSettings& appearance = ActiveAppearance();
    const float brightness = std::clamp(appearance.textBrightness, 0.72f, 1.30f);
    const float contrast = std::clamp(appearance.textContrast, 0.75f, 1.35f);
    color.x = Clamp01(((color.x - 0.5f) * contrast + 0.5f) * brightness);
    color.y = Clamp01(((color.y - 0.5f) * contrast + 0.5f) * brightness);
    color.z = Clamp01(((color.z - 0.5f) * contrast + 0.5f) * brightness);
    return color;
}

ImVec4 AccentColor();
ImVec4 MutedTextColor();
ImVec4 SelectionHighlightColor();
float UiScaleFromFont();
std::string ToLower(std::string value);
