std::string ActionStateLabel(const NormalizedProviderResult& action) {
    if (action.applied) {
        return "Applied";
    }
    if (action.rejected) {
        return "Rejected";
    }
    if (action.canApprove) {
        return "Pending";
    }
    return action.schemaValid ? "Ready" : "Invalid";
}

ImVec4 ActionStateColor(const NormalizedProviderResult& action) {
    if (action.applied) {
        return ImVec4(0.50f, 0.90f, 0.62f, 1.0f);
    }
    if (action.rejected || !action.schemaValid) {
        return ImVec4(0.92f, 0.52f, 0.52f, 1.0f);
    }
    if (action.canApprove) {
        return ImVec4(1.0f, 0.78f, 0.32f, 1.0f);
    }
    return AccentColor();
}

ImVec4 ActivityStatusColor(const std::string& status) {
    const std::string lower = [&status]() {
        std::string value = status;
        std::transform(value.begin(), value.end(), value.begin(), [](unsigned char ch) {
            return static_cast<char>(std::tolower(ch));
        });
        return value;
    }();

    if (lower.find("fail") != std::string::npos || lower.find("error") != std::string::npos ||
        lower.find("unavailable") != std::string::npos || lower.find("rejected") != std::string::npos ||
        lower.find("timed out") != std::string::npos) {
        return ImVec4(0.92f, 0.52f, 0.52f, 1.0f);
    }
    if (lower.find("pending") != std::string::npos || lower.find("placeholder") != std::string::npos ||
        lower.find("detected") != std::string::npos) {
        return ImVec4(1.0f, 0.78f, 0.32f, 1.0f);
    }
    if (lower.find("complete") != std::string::npos || lower.find("passed") != std::string::npos ||
        lower.find("ready") != std::string::npos || lower.find("active") != std::string::npos) {
        return ImVec4(0.50f, 0.90f, 0.62f, 1.0f);
    }
    return AccentColor();
}

