    const ImVec2 size(std::max(textSize.x + style.FramePadding.x * 1.75f, height * 1.15f), height);
    const ImVec2 pos = ImGui::GetCursorScreenPos();
    const float rounding = std::min(2.0f * UiScaleFromFont(), height * 0.22f);

    ImDrawList* drawList = ImGui::GetWindowDrawList();
    drawList->AddRectFilled(pos, ImVec2(pos.x + size.x, pos.y + size.y), ColorU32(BadgeBackground(color)), rounding);
    drawList->AddRect(pos, ImVec2(pos.x + size.x, pos.y + size.y),
                      ColorU32(WithAlpha(MixColor(color, PanelBackgroundColor(), 0.36f), 0.48f)), rounding);
    drawList->AddText(ImVec2(pos.x + (size.x - textSize.x) * 0.5f, pos.y + (height - textSize.y) * 0.5f),
                      ColorU32(BrightTextColor()), label);
    ImGui::Dummy(size);
