size_t CountDisplayLines(const std::string& text) {
    if (text.empty()) {
        return 1;
    }

    return static_cast<size_t>(std::count(text.begin(), text.end(), '\n')) + 1;
}

float EffectiveTextWrapWidth(float width) {
    const ImGuiStyle& style = ImGui::GetStyle();
    return std::max(40.0f, width - style.FramePadding.x * 2.0f - style.ScrollbarSize - style.ItemInnerSpacing.x);
}

float TextPixelWidth(const std::string& text) {
    if (text.empty()) {
        return 0.0f;
    }
    return ImGui::CalcTextSize(text.c_str(), text.c_str() + text.size(), false).x;
}

std::string TruncateToPixelWidth(const std::string& value, float maxWidth) {
    if (value.empty() || TextPixelWidth(value) <= maxWidth) {
        return value;
    }

    const std::string suffix = "...";
    if (TextPixelWidth(suffix) >= maxWidth) {
        return suffix;
    }

    std::string result = value;
    while (!result.empty() && TextPixelWidth(result + suffix) > maxWidth) {
        result.pop_back();
    }
    return result.empty() ? suffix : result + suffix;
}

size_t FindSoftWrapOffset(const std::string& line, float wrapWidth) {
    if (line.size() <= 1) {
        return std::string::npos;
    }

    for (size_t index = line.size() - 1; index > 0; --index) {
        const char character = line[index];
        if (character != ' ' && character != '\t') {
            continue;
        }
        if (TextPixelWidth(line.substr(0, index)) <= wrapWidth) {
            return index;
        }
    }

    return std::string::npos;
}

size_t FindHardWrapOffset(const std::string& line, float wrapWidth) {
    if (line.size() <= 1) {
        return line.size();
    }

    size_t best = 1;
    for (size_t index = 1; index <= line.size(); ++index) {
        if (TextPixelWidth(line.substr(0, index)) > wrapWidth) {
            break;
        }
        best = index;
    }
    return std::min(best, line.size() - 1);
}

void TrimAutoWrappedLeadingSpace(std::string& line) {
    while (!line.empty() && (line.front() == ' ' || line.front() == '\t')) {
        line.erase(line.begin());
    }
}

std::string WrapTextForDisplay(const std::string& text, float width) {
    if (text.empty()) {
        return text;
    }

    const float wrapWidth = EffectiveTextWrapWidth(width);
    std::string wrapped;
    wrapped.reserve(text.size() + 16);
    std::string line;

    auto wrapCurrentLine = [&]() {
        while (!line.empty() && TextPixelWidth(line) > wrapWidth) {
            size_t wrapOffset = FindSoftWrapOffset(line, wrapWidth);
            const bool softWrapped = wrapOffset != std::string::npos && wrapOffset > 0;
            if (!softWrapped) {
                wrapOffset = FindHardWrapOffset(line, wrapWidth);
            }

            wrapped.append(line.substr(0, wrapOffset));
            wrapped.push_back('\n');
            line.erase(0, softWrapped ? wrapOffset + 1 : wrapOffset);
            TrimAutoWrappedLeadingSpace(line);
        }
    };

    for (char character : text) {
        if (character == '\r') {
            continue;
        }
        if (character == '\n') {
            wrapCurrentLine();
            wrapped.append(line);
            wrapped.push_back('\n');
            line.clear();
            continue;
        }

        line.push_back(character);
        wrapCurrentLine();
    }

    wrapCurrentLine();
    wrapped.append(line);

    return wrapped;
}

template <size_t Size>
bool WrapInputBufferToWidth(std::array<char, Size>& buffer, float width) {
    const std::string current = buffer.data();
    if (current.empty()) {
        return false;
    }

    const std::string wrapped = WrapTextForDisplay(current, width);
    if (wrapped == current || wrapped.size() + 1 >= buffer.size()) {
        return false;
    }

    std::fill(buffer.begin(), buffer.end(), '\0');
    std::copy(wrapped.begin(), wrapped.end(), buffer.begin());
    return true;
}

size_t EstimateWrappedLineCount(const std::string& text, float width) {
    if (text.empty()) {
        return 1;
    }
    return CountDisplayLines(WrapTextForDisplay(text, width));
}

void DrawSelectableTextBlock(const std::string& text, float maxHeight) {
    const ImGuiStyle& style = ImGui::GetStyle();
    const float width = std::max(120.0f, ImGui::GetContentRegionAvail().x);
    const std::string displayText = WrapTextForDisplay(text, width);
    std::vector<char> buffer(displayText.begin(), displayText.end());
    buffer.push_back('\0');

    const size_t lineCount = CountDisplayLines(displayText);
    const float wantedHeight = ImGui::GetTextLineHeightWithSpacing() * static_cast<float>(lineCount) +
                               style.FramePadding.y * 2.0f;
    const float minHeight = ImGui::GetFrameHeightWithSpacing() * 1.45f;
    const float height = std::clamp(wantedHeight, minHeight, maxHeight);

    ImGui::PushStyleColor(ImGuiCol_FrameBg, OffsetColor(PanelBackgroundColor(), 0.018f));
    ImGui::PushStyleColor(ImGuiCol_FrameBgHovered, OffsetColor(PanelBackgroundColor(), 0.030f));
    ImGui::PushStyleColor(ImGuiCol_Text, TextColor());
    ImGui::InputTextMultiline("##selectable_text", buffer.data(), buffer.size(), ImVec2(-1.0f, height),
                              ImGuiInputTextFlags_ReadOnly | ImGuiInputTextFlags_NoHorizontalScroll);
    ImGui::PopStyleColor(3);
}

void DrawChatMessageCard(const ChatMessage& message, size_t index, float scale) {
    const ImGuiStyle& style = ImGui::GetStyle();
    const float availableWidth = std::max(180.0f, ImGui::GetContentRegionAvail().x);
    const float bodyWidth = std::max(120.0f, availableWidth - style.WindowPadding.x * 2.0f - 18.0f * scale);
    const size_t lineCount = EstimateWrappedLineCount(message.message, bodyWidth);
    const float textHeight = ImGui::GetTextLineHeightWithSpacing() * static_cast<float>(lineCount) +
                             style.FramePadding.y * 2.0f;
    const float maxBodyHeight = message.sender == ChatSender::Assistant ? 420.0f * scale : 240.0f * scale;
    const float bodyHeight = std::clamp(textHeight, ImGui::GetFrameHeightWithSpacing() * 1.55f, maxBodyHeight);
    const float cardHeight = bodyHeight + ImGui::GetFrameHeightWithSpacing() + style.ItemSpacing.y +
                             style.WindowPadding.y * 2.0f + 10.0f * scale;
    const bool textClamped = textHeight > bodyHeight + style.FramePadding.y;

    ImGui::PushID(static_cast<int>(index));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, 6.0f * scale);
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), 0.012f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(SenderColor(message.sender), 0.26f));
    ImGui::BeginChild("message_card", ImVec2(0.0f, cardHeight), true,
                      textClamped ? ImGuiWindowFlags_AlwaysVerticalScrollbar : ImGuiWindowFlags_NoScrollbar);

    DrawStatusBadge(SenderLabel(message.sender), SenderColor(message.sender));
    ImGui::SameLine();
    ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
    ImGui::TextUnformatted(message.sender == ChatSender::Assistant ? "Assistant" :
                           message.sender == ChatSender::User      ? "You"
                                                                    : "System");
    ImGui::PopStyleColor();

    const float copyWidth = ImGui::CalcTextSize("Copy").x + ImGui::GetStyle().FramePadding.x * 2.0f;
    const float copyX = ImGui::GetWindowContentRegionMax().x - copyWidth;
    if (copyX > ImGui::GetCursorPosX()) {
        ImGui::SameLine(copyX);
    } else {
        ImGui::SameLine();
    }
    if (ImGui::SmallButton("Copy")) {
        ImGui::SetClipboardText(message.message.c_str());
    }

    ImGui::Separator();
    ImGui::PushStyleColor(ImGuiCol_Text, TextColor());
    ImGui::PushTextWrapPos(0.0f);
    ImGui::TextUnformatted(message.message.c_str());
    ImGui::PopTextWrapPos();
    ImGui::PopStyleColor();
    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(2);
    ImGui::PopID();
}

void DrawAgentWorkingCard(AgentBackend backend, const std::string& prompt, double startedSeconds, float scale) {
    const double now = ImGui::GetTime();
    const float elapsed = static_cast<float>(std::max(0.0, now - startedSeconds));
    const int dotCount = static_cast<int>(std::fmod(now * 2.0, 4.0));
    std::string thinking = std::string("Thinking") + std::string(static_cast<size_t>(dotCount), '.');

    ImGui::BeginChild("agent_working_card", ImVec2(0.0f, 118.0f * scale), true, ImGuiWindowFlags_NoScrollbar);
    DrawStatusBadge(thinking.c_str(), ActivityStatusColor("Running"));
    ImGui::SameLine();
    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::Text("%s", AgentOrchestrator::BackendLabel(backend));
    ImGui::PopStyleColor();
    ImGui::SameLine();
    ImGui::TextDisabled("%s", FormatElapsedTime(elapsed).c_str());

    const float phase = static_cast<float>((std::sin(now * 2.8) + 1.0) * 0.5);
    ImGui::PushStyleColor(ImGuiCol_PlotHistogram, AccentColor());
    ImGui::ProgressBar(phase, ImVec2(-1.0f, 0.0f), "Waiting for provider response");
    ImGui::PopStyleColor();

    ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
    ImGui::TextWrapped("%s", TruncateForUi("Prompt: " + prompt, 150).c_str());
    ImGui::TextUnformatted("Stage: context captured -> provider running -> result normalization");
    ImGui::PopStyleColor();
    ImGui::EndChild();
}

