float ChipWidthForLabel(const std::string& label) {
    const ImGuiStyle& style = ImGui::GetStyle();
    return TextPixelWidth(label) + style.FramePadding.x * 2.3f;
}

std::string FitTextToPixelWidth(const std::string& label, float maxTextWidth) {
    if (label.empty() || TextPixelWidth(label) <= maxTextWidth) {
        return label;
    }

    constexpr const char* ellipsis = "...";
    const float ellipsisWidth = TextPixelWidth(ellipsis);
    if (maxTextWidth <= ellipsisWidth + ImGui::GetFontSize() * 0.5f) {
        return ellipsis;
    }

    size_t keep = label.size();
    while (keep > 0) {
        const std::string candidate = label.substr(0, keep) + ellipsis;
        if (TextPixelWidth(candidate) <= maxTextWidth) {
            return candidate;
        }
        --keep;
    }
    return ellipsis;
}

std::string FitChipLabelToWidth(const std::string& label, float maxChipWidth) {
    const ImGuiStyle& style = ImGui::GetStyle();
    const float maxTextWidth = std::max(ImGui::GetFontSize() * 3.0f, maxChipWidth - style.FramePadding.x * 2.3f);
    return FitTextToPixelWidth(label, maxTextWidth);
}

