bool DrawToolbarButton(const char* label, const char* tooltip, ImVec2 size, bool enabled = true,
                       bool selected = false) {
    const ImVec4 panel = PanelBackgroundColor();
    const ImVec4 base = selected ? MixColor(OffsetColor(panel, 0.030f), AccentColor(), 0.120f)
                                  : OffsetColor(panel, 0.010f);
    const ImVec4 hover = selected ? MixColor(base, AccentColor(), 0.080f)
                                   : MixColor(OffsetColor(panel, 0.034f), AccentColor(), 0.026f);
    const ImVec4 active = MixColor(base, AccentColor(), 0.150f);

    ImGui::PushStyleColor(ImGuiCol_Button, base);
    ImGui::PushStyleColor(ImGuiCol_ButtonHovered, hover);
    ImGui::PushStyleColor(ImGuiCol_ButtonActive, active);
    ImGui::PushStyleColor(ImGuiCol_Text, selected ? BrightTextColor() : TextColor());
    ImGui::PushStyleVar(ImGuiStyleVar_FrameBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameRounding, 2.0f * UiScaleFromFont());
    ImGui::PushStyleVar(ImGuiStyleVar_FramePadding,
                        ImVec2(ImGui::GetStyle().FramePadding.x * 0.88f,
                               ImGui::GetStyle().FramePadding.y * 0.70f));

    if (!enabled) {
        ImGui::BeginDisabled();
    }
    const bool pressed = ImGui::Button(label, size);
    if (!enabled) {
        ImGui::EndDisabled();
    }
    if (tooltip != nullptr && tooltip[0] != '\0' && ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", tooltip);
    }

    ImGui::PopStyleVar(3);
    ImGui::PopStyleColor(4);
    return enabled && pressed;
}

void DrawToolbarIconGlyph(ToolbarIcon icon, ImVec2 min, ImVec2 max, ImU32 color) {
    ImDrawList* drawList = ImGui::GetWindowDrawList();
    const ImVec2 center((min.x + max.x) * 0.5f, (min.y + max.y) * 0.5f);
    const float width = max.x - min.x;
    const float height = max.y - min.y;
    const float size = std::min(width, height) * 0.42f;
    const float barWidth = std::max(2.0f, size * 0.24f);
    const float rounding = std::max(1.0f, size * 0.12f);

    switch (icon) {
    case ToolbarIcon::Play:
        drawList->AddTriangleFilled(ImVec2(center.x - size * 0.42f, center.y - size * 0.58f),
                                    ImVec2(center.x - size * 0.42f, center.y + size * 0.58f),
                                    ImVec2(center.x + size * 0.58f, center.y), color);
        break;
    case ToolbarIcon::Pause:
        drawList->AddRectFilled(ImVec2(center.x - size * 0.44f, center.y - size * 0.56f),
                                ImVec2(center.x - size * 0.44f + barWidth, center.y + size * 0.56f), color,
                                rounding);
        drawList->AddRectFilled(ImVec2(center.x + size * 0.22f, center.y - size * 0.56f),
                                ImVec2(center.x + size * 0.22f + barWidth, center.y + size * 0.56f), color,
                                rounding);
        break;
    case ToolbarIcon::Stop:
        drawList->AddRectFilled(ImVec2(center.x - size * 0.50f, center.y - size * 0.50f),
                                ImVec2(center.x + size * 0.50f, center.y + size * 0.50f), color, rounding);
        break;
    case ToolbarIcon::Step:
        drawList->AddTriangleFilled(ImVec2(center.x - size * 0.58f, center.y - size * 0.56f),
                                    ImVec2(center.x - size * 0.58f, center.y + size * 0.56f),
                                    ImVec2(center.x + size * 0.28f, center.y), color);
        drawList->AddRectFilled(ImVec2(center.x + size * 0.45f, center.y - size * 0.56f),
                                ImVec2(center.x + size * 0.45f + barWidth, center.y + size * 0.56f), color,
                                rounding);
        break;
    }
}

bool DrawToolbarIconButton(const char* id, ToolbarIcon icon, const char* tooltip, ImVec2 size, bool enabled = true,
                           bool selected = false) {
    const ImVec4 panel = PanelBackgroundColor();
    const ImVec4 base = selected ? MixColor(OffsetColor(panel, 0.032f), AccentColor(), 0.130f)
                                  : OffsetColor(panel, 0.008f);
    const ImVec4 hover = selected ? MixColor(base, AccentColor(), 0.085f)
                                   : MixColor(OffsetColor(panel, 0.034f), AccentColor(), 0.028f);
    const ImVec4 active = MixColor(base, AccentColor(), 0.155f);

    ImGui::PushStyleColor(ImGuiCol_Button, base);
    ImGui::PushStyleColor(ImGuiCol_ButtonHovered, hover);
    ImGui::PushStyleColor(ImGuiCol_ButtonActive, active);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameRounding, 2.0f * UiScaleFromFont());

    if (!enabled) {
        ImGui::BeginDisabled();
    }
    const bool pressed = ImGui::Button(id, size);
    if (!enabled) {
        ImGui::EndDisabled();
    }

    const ImVec4 iconColor = enabled ? (selected ? BrightTextColor() : TextColor()) : WithAlpha(MutedTextColor(), 0.58f);
    DrawToolbarIconGlyph(icon, ImGui::GetItemRectMin(), ImGui::GetItemRectMax(), ColorU32(iconColor));
    if (tooltip != nullptr && tooltip[0] != '\0' && ImGui::IsItemHovered(ImGuiHoveredFlags_AllowWhenDisabled)) {
        ImGui::SetTooltip("%s", tooltip);
    }

    ImGui::PopStyleVar(2);
    ImGui::PopStyleColor(3);
    return enabled && pressed;
}

void DrawToolbarStatusDot(const char* label, ImVec4 color, const char* tooltip = nullptr) {
    const ImGuiStyle& style = ImGui::GetStyle();
    const float height = ImGui::GetFrameHeight();
    const ImVec2 textSize = ImGui::CalcTextSize(label);
    const float radius = std::max(3.0f * UiScaleFromFont(), ImGui::GetFontSize() * 0.23f);
    const float gap = style.ItemInnerSpacing.x * 0.72f;
    const ImVec2 pos = ImGui::GetCursorScreenPos();
    const ImVec2 size(radius * 2.0f + gap + textSize.x, height);
    const float centerY = pos.y + height * 0.5f;

    ImDrawList* drawList = ImGui::GetWindowDrawList();
    drawList->AddCircleFilled(ImVec2(pos.x + radius, centerY), radius, ColorU32(color), 18);
    drawList->AddText(ImVec2(pos.x + radius * 2.0f + gap, centerY - textSize.y * 0.5f),
                      ColorU32(TextColor()), label);
    ImGui::Dummy(size);
    if (tooltip != nullptr && tooltip[0] != '\0' && ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", tooltip);
    }
}

void DrawToolbarContextLabel(const std::string& label, float maxWidth) {
    const std::string fitted = FitTextToPixelWidth(label, maxWidth);
    DrawToolbarText(fitted.c_str(), MutedTextColor());
    if (fitted != label && ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", label.c_str());
    }
}

std::string ToLower(std::string value);

void SetComponentPropertyForUi(Component& component, const std::string& propertyName, std::string value) {
    for (ComponentProperty& property : component.properties) {
        if (property.name == propertyName) {
            property.value = std::move(value);
            return;
        }
    }
    component.properties.push_back({propertyName, std::move(value)});
}

float ComponentFloatForUi(const Component& component, const std::string& propertyName, float fallback) {
    std::istringstream stream(ComponentPropertyValue(component, propertyName));
    float value = fallback;
    if (stream >> value && std::isfinite(value)) {
        return value;
    }
    return fallback;
}

int ComponentIntForUi(const Component& component, const std::string& propertyName, int fallback) {
    std::istringstream stream(ComponentPropertyValue(component, propertyName));
    int value = fallback;
    return (stream >> value) ? value : fallback;
}

bool ComponentBoolForUi(const Component& component, const std::string& propertyName, bool fallback) {
    std::string value = ToLower(ComponentPropertyValue(component, propertyName));
    if (value == "true" || value == "1" || value == "yes") {
        return true;
    }
    if (value == "false" || value == "0" || value == "no") {
        return false;
    }
    return fallback;
}

std::vector<float> ParseUiFloatList(std::string value) {
    std::replace(value.begin(), value.end(), ',', ' ');
    std::istringstream stream(value);
    std::vector<float> values;
    float parsed = 0.0f;
    while (stream >> parsed) {
        if (std::isfinite(parsed)) {
            values.push_back(parsed);
        }
    }
    return values;
}

std::array<float, 2> ComponentVec2ForUi(const Component& component, const std::string& propertyName,
                                        std::array<float, 2> fallback) {
    const std::vector<float> values = ParseUiFloatList(ComponentPropertyValue(component, propertyName));
    if (values.size() < 2) {
        return fallback;
    }
    return {values[0], values[1]};
}

std::array<float, 3> ComponentVec3ForUi(const Component& component, const std::string& propertyName,
                                        std::array<float, 3> fallback) {
    const std::vector<float> values = ParseUiFloatList(ComponentPropertyValue(component, propertyName));
    if (values.size() < 3) {
        return fallback;
    }
    return {values[0], values[1], values[2]};
}

std::string Vec2ToUiString(const std::array<float, 2>& value) {
    std::ostringstream stream;
    stream << value[0] << ", " << value[1];
    return stream.str();
}

std::string Vec3ToUiString(const std::array<float, 3>& value) {
    std::ostringstream stream;
    stream << value[0] << ", " << value[1] << ", " << value[2];
    return stream.str();
}

ImVec4 ComponentColorForUi(const Component& component, const std::string& propertyName, ImVec4 fallback) {
    const std::vector<float> values = ParseUiFloatList(ComponentPropertyValue(component, propertyName));
    if (values.size() < 3) {
        return fallback;
    }
    return ClampColor(ImVec4(values[0], values[1], values[2], values.size() >= 4 ? values[3] : fallback.w));
}

bool IsRuntimeUiRenderableType(const std::string& type) {
    return type == "UICanvasRuntime" || type == "UIPanelRuntime" || type == "UITextRuntime" ||
           type == "UIButtonRuntime" || type == "UIBoxRuntime" || type == "UIImageRuntime";
}

const Component* FirstRuntimeUiLayoutComponent(const Entity& entity) {
    for (const char* type :
         {"UICanvasRuntime", "UIPanelRuntime", "UIImageRuntime", "UIBoxRuntime", "UIButtonRuntime", "UITextRuntime"}) {
        auto it = std::find_if(entity.components.begin(), entity.components.end(), [type](const Component& component) {
            return component.type == type;
        });
        if (it != entity.components.end()) {
            return &(*it);
        }
    }
    return nullptr;
}

bool RuntimeUiComponentVisible(const Component& component) {
    return ComponentEnabled(component) && ComponentBoolForUi(component, "visible", true);
}

ImVec2 RuntimeUiAnchoredPoint(ImVec2 parentMin, ImVec2 parentSize, const std::array<float, 2>& anchor,
                              const std::array<float, 2>& position) {
    return ImVec2(parentMin.x + parentSize.x * anchor[0] + position[0],
                  parentMin.y + parentSize.y * anchor[1] + position[1]);
}

float RuntimeUiReferenceScale(const EditorState& state, ImVec2 canvasSize) {
    for (const Entity& entity : state.Entities()) {
        const Component* canvas = FirstRuntimeUiLayoutComponent(entity);
        if (canvas == nullptr || canvas->type != "UICanvasRuntime") {
            continue;
        }
        const std::array<float, 2> referenceSize = ComponentVec2ForUi(*canvas, "size", {1280.0f, 720.0f});
        if (referenceSize[0] <= 1.0f || referenceSize[1] <= 1.0f) {
            continue;
        }
        return std::clamp(std::min(canvasSize.x / referenceSize[0], canvasSize.y / referenceSize[1]), 0.25f, 2.0f);
    }
    return 1.0f;
}

bool ResolveRuntimeUiRect(const EditorState& state, const Entity& entity, const Component& component,
                          ImVec2 canvasPos, ImVec2 canvasSize, float uiScale, ImVec2* outMin, ImVec2* outMax,
                          int depth = 0) {
    if (depth > 16 || outMin == nullptr || outMax == nullptr || !RuntimeUiComponentVisible(component)) {
        return false;
    }

    if (component.type == "UICanvasRuntime") {
        *outMin = canvasPos;
        *outMax = ImVec2(canvasPos.x + canvasSize.x, canvasPos.y + canvasSize.y);
        return canvasSize.x > 1.0f && canvasSize.y > 1.0f;
    }

    ImVec2 parentMin = canvasPos;
    ImVec2 parentMax(canvasPos.x + canvasSize.x, canvasPos.y + canvasSize.y);
    bool hasParentRect = false;
    if (entity.parentId != 0) {
        const Entity* parent = state.FindEntity(entity.parentId);
        const Component* parentUi = parent == nullptr ? nullptr : FirstRuntimeUiLayoutComponent(*parent);
        if (parent != nullptr && parentUi != nullptr && state.IsEntityActiveInHierarchy(parent->id)) {
            hasParentRect =
                ResolveRuntimeUiRect(state, *parent, *parentUi, canvasPos, canvasSize, uiScale, &parentMin, &parentMax,
                                     depth + 1);
        }
    }
    if (!hasParentRect) {
        const std::string canvasName = ComponentPropertyValue(component, "canvasName");
        const Entity* namedCanvas = canvasName.empty() ? nullptr : state.FindEntityByName(canvasName);
        const Component* canvas = namedCanvas == nullptr ? nullptr : FirstRuntimeUiLayoutComponent(*namedCanvas);
        hasParentRect = namedCanvas != nullptr && canvas != nullptr && canvas->type == "UICanvasRuntime" &&
                        state.IsEntityActiveInHierarchy(namedCanvas->id) &&
                        ResolveRuntimeUiRect(state, *namedCanvas, *canvas, canvasPos, canvasSize, uiScale, &parentMin,
                                             &parentMax, depth + 1);
    }
    if (!hasParentRect) {
        return false;
    }

    const ImVec2 parentSize(std::max(1.0f, parentMax.x - parentMin.x), std::max(1.0f, parentMax.y - parentMin.y));
    const std::array<float, 2> anchorMin = ComponentVec2ForUi(component, "anchorMin", {0.5f, 0.5f});
    const std::array<float, 2> anchorMax = ComponentVec2ForUi(component, "anchorMax", anchorMin);
    std::array<float, 2> position = ComponentVec2ForUi(component, "position", {0.0f, 0.0f});
    std::array<float, 2> size = ComponentVec2ForUi(component, "size", {120.0f, 48.0f});
    position[0] *= uiScale;
    position[1] *= uiScale;
    size[0] *= uiScale;
    size[1] *= uiScale;
    const ImVec2 anchorA = RuntimeUiAnchoredPoint(parentMin, parentSize, anchorMin, position);
    const ImVec2 anchorB = RuntimeUiAnchoredPoint(parentMin, parentSize, anchorMax, position);
    if (std::fabs(anchorA.x - anchorB.x) > 1.0f || std::fabs(anchorA.y - anchorB.y) > 1.0f) {
        *outMin = ImVec2(std::min(anchorA.x, anchorB.x), std::min(anchorA.y, anchorB.y));
        *outMax = ImVec2(std::max(anchorA.x, anchorB.x), std::max(anchorA.y, anchorB.y));
        return outMax->x > outMin->x && outMax->y > outMin->y;
    }

    *outMin = ImVec2(anchorA.x - size[0] * 0.5f, anchorA.y - size[1] * 0.5f);
    *outMax = ImVec2(anchorA.x + size[0] * 0.5f, anchorA.y + size[1] * 0.5f);
    return outMax->x > outMin->x && outMax->y > outMin->y;
}

bool PointInRect(ImVec2 point, ImVec2 rectMin, ImVec2 rectMax) {
    return point.x >= rectMin.x && point.x <= rectMax.x && point.y >= rectMin.y && point.y <= rectMax.y;
}

std::string ColorToUiString(ImVec4 value) {
    value = ClampColor(value);
    std::ostringstream stream;
    stream << value.x << ", " << value.y << ", " << value.z << ", " << value.w;
    return stream.str();
}

bool IsPhysicsComponentType(const std::string& type) {
    return type == "PhysicsSettings" || type == "Rigidbody2D" || type == "Rigidbody3D" ||
           type == "Collider2D" || type == "Collider3D";
}

void DrawCircleWireXY(float radius, ImVec4 color, float width, int segments = 48) {
    glLineWidth(width);
    SetGlColor(color);
    glBegin(GL_LINE_LOOP);
    for (int i = 0; i < segments; ++i) {
        const float angle = (static_cast<float>(i) / static_cast<float>(segments)) * 2.0f * 3.1415926535f;
        glVertex3f(std::cos(angle) * radius, std::sin(angle) * radius, 0.0f);
    }
    glEnd();
    glLineWidth(1.0f);
}

void DrawSphereWire(float radius, ImVec4 color, float width, int segments = 48) {
    glPushMatrix();
    DrawCircleWireXY(radius, color, width, segments);
    glRotatef(90.0f, 1.0f, 0.0f, 0.0f);
    DrawCircleWireXY(radius, color, width, segments);
    glRotatef(90.0f, 0.0f, 1.0f, 0.0f);
    DrawCircleWireXY(radius, color, width, segments);
    glPopMatrix();
}

void DrawPhysicsColliderGizmo(const Entity& entity, const Component& component, bool selected) {
    const bool trigger = ComponentBoolForUi(component, "trigger", false);
    ImVec4 color = trigger ? ImVec4(0.95f, 0.68f, 0.26f, 1.0f) : ImVec4(0.35f, 0.78f, 0.88f, 1.0f);
    if (selected) {
        color = MixColor(color, SelectionHighlightColor(), 0.24f);
    }
    const float width = selected ? 2.4f : 1.5f;

    if (component.type == "Collider2D") {
        const std::string shape = ToLower(ComponentPropertyValue(component, "shape"));
        const std::array<float, 2> offset = ComponentVec2ForUi(component, "offset", {0.0f, 0.0f});
        glPushMatrix();
        glTranslatef(entity.position[0], entity.position[1], entity.position[2]);
        glRotatef(entity.rotation[2], 0.0f, 0.0f, 1.0f);
        glTranslatef(offset[0] * entity.scale[0], offset[1] * entity.scale[1], 0.0f);
        if (shape == "circle") {
            const float radius = ComponentFloatForUi(component, "radius", 0.5f) *
                                 std::max(std::fabs(entity.scale[0]), std::fabs(entity.scale[1]));
            DrawCircleWireXY(std::max(0.001f, radius), color, width);
        } else {
            const std::array<float, 2> size = ComponentVec2ForUi(component, "size", {1.0f, 1.0f});
            glScalef(size[0] * entity.scale[0], size[1] * entity.scale[1], 0.025f);
            DrawUnitCubeWire(color, width);
        }
        glPopMatrix();
        return;
    }

    if (component.type == "Collider3D") {
        const std::string shape = ToLower(ComponentPropertyValue(component, "shape"));
        const std::array<float, 3> offset = ComponentVec3ForUi(component, "offset", {0.0f, 0.0f, 0.0f});
        glPushMatrix();
        ApplyEntityPose(entity);
        glTranslatef(offset[0] * entity.scale[0], offset[1] * entity.scale[1], offset[2] * entity.scale[2]);
        if (shape == "sphere") {
            const float radius = ComponentFloatForUi(component, "radius", 0.5f) *
                                 std::max({std::fabs(entity.scale[0]), std::fabs(entity.scale[1]),
                                           std::fabs(entity.scale[2])});
            DrawSphereWire(std::max(0.001f, radius), color, width);
        } else {
            const std::array<float, 3> size = ComponentVec3ForUi(component, "size", {1.0f, 1.0f, 1.0f});
            glScalef(size[0] * entity.scale[0], size[1] * entity.scale[1], size[2] * entity.scale[2]);
            DrawUnitCubeWire(color, width);
        }
        glPopMatrix();
    }
}

void DrawCameraBoundsWire(std::array<float, 3> minValue, std::array<float, 3> maxValue, ImVec4 color, float width) {
    glLineWidth(width);
    SetGlColor(color);
    glBegin(GL_LINES);
    const float x0 = std::min(minValue[0], maxValue[0]);
    const float y0 = std::min(minValue[1], maxValue[1]);
    const float z0 = std::min(minValue[2], maxValue[2]);
    const float x1 = std::max(minValue[0], maxValue[0]);
    const float y1 = std::max(minValue[1], maxValue[1]);
    const float z1 = std::max(minValue[2], maxValue[2]);
    const float points[8][3] = {{x0, y0, z0}, {x1, y0, z0}, {x1, y0, z1}, {x0, y0, z1},
                                {x0, y1, z0}, {x1, y1, z0}, {x1, y1, z1}, {x0, y1, z1}};
    const int edges[12][2] = {
        {0, 1}, {1, 2}, {2, 3}, {3, 0}, {4, 5}, {5, 6}, {6, 7}, {7, 4}, {0, 4}, {1, 5}, {2, 6}, {3, 7},
    };
    for (const auto& edge : edges) {
        glVertex3fv(points[edge[0]]);
        glVertex3fv(points[edge[1]]);
    }
    glEnd();
    glLineWidth(1.0f);
}

void DrawCircleWireXZ(std::array<float, 3> center, float radius, ImVec4 color, float width) {
    if (radius <= 0.0f) {
        return;
    }
    glPushMatrix();
    glTranslatef(center[0], center[1], center[2]);
    glRotatef(90.0f, 1.0f, 0.0f, 0.0f);
    DrawCircleWireXY(radius, color, width, 64);
    glPopMatrix();
}

void DrawCameraRuntimeGizmos(const EditorState& state, const Entity& camera, const Component& follow, bool selected) {
    if (!ComponentBoolForUi(follow, "debugGizmos", true)) {
        return;
    }
    const ImVec4 base = selected ? SelectionHighlightColor() : MixColor(CameraGizmoColor(), ImVec4(0.42f, 0.86f, 0.58f, 1.0f), 0.45f);
    const float width = selected ? 2.0f : 1.15f;
    const std::string targetName = ComponentPropertyValue(follow, "targetName");
    const Entity* target = targetName.empty() ? nullptr : state.FindEntityByName(targetName);
    if (target != nullptr && state.IsEntityActiveInHierarchy(target->id)) {
        glPushMatrix();
        glTranslatef(target->position[0], target->position[1], target->position[2]);
        DrawSphereWire(0.18f, base, width, 24);
        glPopMatrix();
        DrawCircleWireXZ(target->position, ComponentFloatForUi(follow, "deadZoneRadius", 0.0f),
                         ImVec4(base.x, base.y, base.z, 0.75f), 1.2f);
        DrawCircleWireXZ(target->position, ComponentFloatForUi(follow, "softZoneRadius", 0.0f),
                         ImVec4(base.x * 0.9f, base.y * 0.9f, base.z, 0.55f), 1.0f);
        glLineWidth(width);
        SetGlColor(base);
        glBegin(GL_LINES);
        glVertex3f(camera.position[0], camera.position[1], camera.position[2]);
        glVertex3f(target->position[0], target->position[1], target->position[2]);
        glEnd();
        glLineWidth(1.0f);
    }
    if (ComponentBoolForUi(follow, "boundsEnabled", false)) {
        DrawCameraBoundsWire(ComponentVec3ForUi(follow, "boundsMin", {-50.0f, -50.0f, -50.0f}),
                             ComponentVec3ForUi(follow, "boundsMax", {50.0f, 50.0f, 50.0f}),
                             ImVec4(base.x, base.y, base.z, 0.62f), width);
    }
}

void DrawPhysicsEventGizmo(const PhysicsEvent& event) {
    const ImVec4 color = event.trigger ? ImVec4(0.98f, 0.72f, 0.28f, 1.0f) : ImVec4(0.40f, 0.84f, 0.95f, 1.0f);
    const PhysicsVec3 point = event.point;
    const PhysicsVec3 normal = Normalize(event.normal, {0.0f, 1.0f, 0.0f});
    glDisable(GL_DEPTH_TEST);
    glLineWidth(event.trigger ? 2.8f : 2.0f);
    SetGlColor(color);
    glBegin(GL_LINES);
    glVertex3f(point.x, point.y, point.z);
    glVertex3f(point.x + normal.x * 0.45f, point.y + normal.y * 0.45f, point.z + normal.z * 0.45f);
    glEnd();
    glPushMatrix();
    glTranslatef(point.x, point.y, point.z);
    DrawSphereWire(0.055f, color, 1.4f, 18);
    glPopMatrix();
    glLineWidth(1.0f);
    glEnable(GL_DEPTH_TEST);
}

void DrawPhysicsRaycastProbe(const PhysicsWorld& physics, const std::vector<Entity>& entities, const Entity& entity,
                             const Component& component) {
    const float maxDistance = std::max(0.01f, ComponentFloatForUi(component, "maxDistance", 10.0f));
    const ImVec4 rayColor = ImVec4(0.78f, 0.86f, 0.38f, 1.0f);
    const ImVec4 missColor = ImVec4(0.56f, 0.60f, 0.38f, 1.0f);

    if (component.type == "PhysicsRaycastProbe2D") {
        const std::array<float, 2> originValue =
            ComponentVec2ForUi(component, "origin", {entity.position[0], entity.position[1]});
        const std::array<float, 2> directionValue = ComponentVec2ForUi(component, "direction", {0.0f, -1.0f});
        const PhysicsVec2 direction =
            aine::Normalize(PhysicsVec2{directionValue[0], directionValue[1]}, PhysicsVec2{0.0f, -1.0f});
        PhysicsRayHit2D hit;
        const bool hasHit = physics.Raycast2D(entities, {originValue[0], originValue[1]}, direction, maxDistance, &hit);
        const float distance = hasHit ? hit.distance : maxDistance;
        const PhysicsVec2 end{originValue[0] + direction.x * distance, originValue[1] + direction.y * distance};
        glLineWidth(2.0f);
        SetGlColor(hasHit ? rayColor : missColor);
        glBegin(GL_LINES);
        glVertex3f(originValue[0], originValue[1], entity.position[2]);
        glVertex3f(end.x, end.y, entity.position[2]);
        glEnd();
        if (hasHit) {
            glPushMatrix();
            glTranslatef(hit.point.x, hit.point.y, entity.position[2]);
            DrawSphereWire(0.07f, rayColor, 1.5f, 18);
            glPopMatrix();
        }
        glLineWidth(1.0f);
        return;
    }

    if (component.type == "PhysicsRaycastProbe3D") {
        const std::array<float, 3> originValue =
            ComponentVec3ForUi(component, "origin", {entity.position[0], entity.position[1], entity.position[2]});
        const std::array<float, 3> directionValue = ComponentVec3ForUi(component, "direction", {0.0f, -1.0f, 0.0f});
        const PhysicsVec3 direction = aine::Normalize(
            PhysicsVec3{directionValue[0], directionValue[1], directionValue[2]}, PhysicsVec3{0.0f, -1.0f, 0.0f});
        PhysicsRayHit3D hit;
        const bool hasHit =
            physics.Raycast3D(entities, {originValue[0], originValue[1], originValue[2]}, direction, maxDistance, &hit);
        const float distance = hasHit ? hit.distance : maxDistance;
        const PhysicsVec3 end{originValue[0] + direction.x * distance, originValue[1] + direction.y * distance,
                              originValue[2] + direction.z * distance};
        glLineWidth(2.0f);
        SetGlColor(hasHit ? rayColor : missColor);
        glBegin(GL_LINES);
        glVertex3f(originValue[0], originValue[1], originValue[2]);
        glVertex3f(end.x, end.y, end.z);
        glEnd();
        if (hasHit) {
            glPushMatrix();
            glTranslatef(hit.point.x, hit.point.y, hit.point.z);
            DrawSphereWire(0.07f, rayColor, 1.5f, 18);
            glPopMatrix();
        }
        glLineWidth(1.0f);
    }
}

std::string ToLower(std::string value) {
    std::transform(value.begin(), value.end(), value.begin(), [](unsigned char c) {
        return static_cast<char>(std::tolower(c));
    });
    return value;
}

std::string TrimWhitespace(std::string value) {
    value.erase(value.begin(), std::find_if(value.begin(), value.end(), [](unsigned char ch) {
                    return !std::isspace(ch);
                }));
    value.erase(std::find_if(value.rbegin(), value.rend(), [](unsigned char ch) {
                    return !std::isspace(ch);
                }).base(),
                value.end());
    return value;
}

std::string NormalizeBuildTargetPlatformName(std::string value) {
    const std::string lower = ToLower(TrimWhitespace(std::move(value)));
    if (lower == "linux") {
        return "Linux";
    }
    if (lower == "macos" || lower == "mac" || lower == "osx" || lower == "darwin") {
        return "macOS";
    }
    return "Windows";
}

std::string DefaultBuildOutputDirectoryForTarget(const std::string& targetPlatform) {
    const std::string normalized = NormalizeBuildTargetPlatformName(targetPlatform);
    if (normalized == "Linux") {
        return "Builds/Linux";
    }
    if (normalized == "macOS") {
        return "Builds/macOS";
    }
    return "Builds/Windows";
}

bool IsKnownDefaultBuildOutputDirectory(const std::string& value) {
    const std::string normalized = ToLower(TrimWhitespace(value));
    return normalized == "builds/windows" || normalized == "builds\\windows" ||
           normalized == "builds/linux" || normalized == "builds\\linux" ||
           normalized == "builds/macos" || normalized == "builds\\macos";
}

std::string JoinStrings(const std::vector<std::string>& values, const std::string& separator) {
    std::ostringstream stream;
    for (size_t index = 0; index < values.size(); ++index) {
        if (index > 0) {
            stream << separator;
        }
        stream << values[index];
    }
    return stream.str();
}

std::string RenderProfileFeatureSummary(const RenderProfileSettings& profile) {
    std::vector<std::string> features;
    if (profile.mesh3d) {
        features.push_back("3D meshes");
    }
    if (profile.sprites) {
        features.push_back("sprites");
    }
    if (profile.runtimeUi) {
        features.push_back("runtime UI");
    }
    if (profile.editorGizmos) {
        features.push_back("editor gizmos");
    }
    if (profile.postProcessingEnabled && !profile.postProcessingEffects.empty()) {
        features.push_back("post: " + JoinStrings(profile.postProcessingEffects, ", "));
    }
    if (!profile.requirements.empty()) {
        features.push_back("requires: " + JoinStrings(profile.requirements, ", "));
    }
    return features.empty() ? "none" : JoinStrings(features, " | ");
}

struct ConsoleLogDisplayEntry {
    const LogEntry* entry = nullptr;
    int count = 1;
    std::uint64_t lastSequence = 0;
};

std::string FormatConsoleTimestamp(std::chrono::system_clock::time_point timestamp) {
    if (timestamp.time_since_epoch().count() == 0) {
        return "--:--:--";
    }

    const std::time_t time = std::chrono::system_clock::to_time_t(timestamp);
    std::tm local{};
#if defined(_WIN32)
    localtime_s(&local, &time);
#else
    localtime_r(&time, &local);
#endif
    std::ostringstream stream;
    stream << std::put_time(&local, "%H:%M:%S");
    return stream.str();
}

std::uint64_t MaxLogSequence(const std::vector<LogEntry>& logs) {
    std::uint64_t sequence = 0;
    for (const LogEntry& entry : logs) {
        sequence = std::max(sequence, entry.sequence);
    }
    return sequence;
}

bool ConsoleEntryLevelEnabled(const LogEntry& entry, bool showInfo, bool showWarnings, bool showErrors) {
    switch (entry.level) {
    case LogLevel::Warning:
        return showWarnings;
    case LogLevel::Error:
        return showErrors;
    case LogLevel::Info:
    default:
        return showInfo;
    }
}

bool ConsoleEntryMatchesQuery(const LogEntry& entry, const std::string& normalizedQuery) {
    if (normalizedQuery.empty()) {
        return true;
    }
    std::string searchable = LogLevelLabel(entry.level);
    searchable.push_back(' ');
    searchable += entry.message;
    searchable.push_back(' ');
    searchable += FormatConsoleTimestamp(entry.timestamp);
    return ToLower(std::move(searchable)).find(normalizedQuery) != std::string::npos;
}

std::vector<ConsoleLogDisplayEntry> BuildConsoleDisplayEntries(const std::vector<LogEntry>& logs,
                                                               bool showInfo,
                                                               bool showWarnings,
                                                               bool showErrors,
                                                               const std::string& search,
                                                               bool collapse) {
    const std::string normalizedQuery = ToLower(TrimWhitespace(search));
    std::vector<ConsoleLogDisplayEntry> entries;
    std::unordered_map<std::string, size_t> collapsedIndexByKey;

    for (const LogEntry& log : logs) {
        if (!ConsoleEntryLevelEnabled(log, showInfo, showWarnings, showErrors) ||
            !ConsoleEntryMatchesQuery(log, normalizedQuery)) {
            continue;
        }

        if (collapse) {
            std::string key = std::to_string(static_cast<int>(log.level));
            key.push_back('\n');
            key += log.message;
            const auto existing = collapsedIndexByKey.find(key);
            if (existing != collapsedIndexByKey.end()) {
                ConsoleLogDisplayEntry& display = entries[existing->second];
                ++display.count;
                display.lastSequence = log.sequence;
                continue;
            }
            collapsedIndexByKey.emplace(std::move(key), entries.size());
        }

        entries.push_back(ConsoleLogDisplayEntry{&log, 1, log.sequence});
    }

    return entries;
}

std::string ConsoleEntryClipboardLine(const ConsoleLogDisplayEntry& display) {
    if (display.entry == nullptr) {
        return {};
    }

    std::ostringstream stream;
    stream << '[' << FormatConsoleTimestamp(display.entry->timestamp) << "] " << LogLevelLabel(display.entry->level);
    if (display.count > 1) {
        stream << " x" << display.count;
    }
    stream << ": " << display.entry->message;
    return stream.str();
}

std::string BuildConsoleClipboardText(const std::vector<ConsoleLogDisplayEntry>& entries) {
    std::ostringstream stream;
    for (size_t index = 0; index < entries.size(); ++index) {
        if (index > 0) {
            stream << '\n';
        }
        stream << ConsoleEntryClipboardLine(entries[index]);
    }
    return stream.str();
}

bool DrawConsoleFilterToggle(const std::string& label, bool active, ImVec4 color) {
    const ImVec4 button = active ? MixColor(OffsetColor(PanelBackgroundColor(), 0.018f), color, 0.075f)
                                  : OffsetColor(PanelBackgroundColor(), 0.018f);
    const ImVec4 hover = active ? MixColor(button, color, 0.105f) : OffsetColor(button, 0.030f);
    const ImVec4 text = active ? BrightTextColor() : MutedTextColor();
    ImGui::PushStyleColor(ImGuiCol_Button, button);
    ImGui::PushStyleColor(ImGuiCol_ButtonHovered, hover);
    ImGui::PushStyleColor(ImGuiCol_ButtonActive, MixColor(button, color, 0.34f));
    ImGui::PushStyleColor(ImGuiCol_Text, text);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameRounding, 2.0f * UiScaleFromFont());
    const bool clicked = ImGui::SmallButton(label.c_str());
    ImGui::PopStyleVar(2);
    ImGui::PopStyleColor(4);
    return clicked;
}

std::string CollapseWhitespaceForComparison(std::string value) {
    value = TrimWhitespace(std::move(value));
    std::string collapsed;
    collapsed.reserve(value.size());
    bool lastWasWhitespace = false;
    for (unsigned char character : value) {
        if (std::isspace(character)) {
            if (!collapsed.empty() && !lastWasWhitespace) {
                collapsed.push_back(' ');
            }
            lastWasWhitespace = true;
            continue;
        }
        collapsed.push_back(static_cast<char>(character));
        lastWasWhitespace = false;
    }
    return collapsed;
}

bool PromptTextMatchesUserRequest(const std::string& prompt, const std::string& request) {
    return CollapseWhitespaceForComparison(prompt) == CollapseWhitespaceForComparison(request);
}

bool ContainsAnyToken(const std::string& haystack, const std::vector<std::string>& needles) {
    for (const std::string& needle : needles) {
        if (haystack.find(needle) != std::string::npos) {
            return true;
        }
    }
    return false;
}

std::string SanitizePathSegment(std::string value, const std::string& fallback) {
    value = TrimWhitespace(std::move(value));
    std::string sanitized;
    sanitized.reserve(value.size());
    for (unsigned char character : value) {
        if (std::isalnum(character) || character == '-' || character == '_') {
            sanitized.push_back(static_cast<char>(character));
        } else if (std::isspace(character) || character == '.') {
            sanitized.push_back('_');
        }
    }

    while (!sanitized.empty() && sanitized.front() == '_') {
        sanitized.erase(sanitized.begin());
    }
    while (!sanitized.empty() && sanitized.back() == '_') {
        sanitized.pop_back();
    }
    return sanitized.empty() ? fallback : sanitized;
}

bool IsAssetImportCandidate(const std::filesystem::path& path) {
    const std::string extension = ToLower(path.extension().string());
    return extension == ".fbx" || extension == ".obj" || extension == ".gltf" || extension == ".glb" ||
           extension == ".anim" || extension == ".controller" || extension == ".png" || extension == ".jpg" ||
           extension == ".jpeg" || extension == ".tga" || extension == ".exr" || extension == ".hdr" ||
           extension == ".wav" || extension == ".ogg" || extension == ".mat" || extension == ".prefab";
}

bool IsModelImportCandidate(const std::filesystem::path& path) {
    const std::string extension = ToLower(path.extension().string());
    return extension == ".fbx" || extension == ".obj" || extension == ".gltf" || extension == ".glb" ||
           extension == ".prefab";
}

bool IsAnimationImportCandidate(const std::filesystem::path& path) {
    const std::string extension = ToLower(path.extension().string());
    return extension == ".anim" || extension == ".controller";
}

json ComponentForPreviewToJson(const Component& component) {
    json properties = json::object();
    for (const ComponentProperty& property : component.properties) {
        properties[property.name] = property.value;
    }
    return json{{"type", component.type}, {"properties", properties}};
}

json ComponentsForPreviewToJson(const std::vector<Component>& components) {
    json serialized = json::array();
    for (const Component& component : components) {
        serialized.push_back(ComponentForPreviewToJson(component));
    }
    return serialized;
}

bool ContainsDelimitedToken(const std::string& haystack, const std::string& needle) {
    size_t position = haystack.find(needle);
    while (position != std::string::npos) {
        const bool leftDelimited =
            position == 0 ||
            (!std::isalnum(static_cast<unsigned char>(haystack[position - 1])) && haystack[position - 1] != '_');
        const size_t end = position + needle.size();
        const bool rightDelimited =
            end >= haystack.size() ||
            (!std::isalnum(static_cast<unsigned char>(haystack[end])) && haystack[end] != '_');
        if (leftDelimited && rightDelimited) {
            return true;
        }
        position = haystack.find(needle, position + needle.size());
    }
    return false;
}

bool ContainsAnyDelimitedToken(const std::string& haystack, const std::vector<std::string>& needles) {
    for (const std::string& needle : needles) {
        if (ContainsDelimitedToken(haystack, needle)) {
            return true;
        }
    }
    return false;
}

bool StartsWithAnyToken(const std::string& haystack, const std::vector<std::string>& needles) {
    for (const std::string& needle : needles) {
        if (haystack.rfind(needle, 0) == 0) {
            return true;
        }
    }
    return false;
}

bool IsUsableWindowPlacement(int x, int y, int width, int height) {
    if (width < 640 || height < 420) {
        return false;
    }
    // Windows reports minimized/offscreen placeholder windows around -32000.
    return x > -10000 && y > -10000;
}

bool PromptLooksLikeDeterministicSceneEdit(const std::string& prompt) {
    const std::string normalized = ToLower(TrimWhitespace(prompt));
    if (normalized.empty()) {
        return false;
    }

    const std::vector<std::string> sourceCodeWords{
        "source", "repo", "repository", "code", "c++", "cmake", "compile", "test", "smoke", "script",
        "ui", "window", "layout",
    };
    const std::vector<std::string> sourceCodePhrases{
        "editor ui", "agent ui", "prompt area", "codex cli",
        "build client", "build editor", "build engine", "build project", "build repo", "build repository",
        "build executable", "build exe", "build binary", "build app", "build the app", "build system",
        "build pipeline",
    };
    if (ContainsAnyDelimitedToken(normalized, sourceCodeWords) || ContainsAnyToken(normalized, sourceCodePhrases)) {
        return false;
    }

    const bool asksForCreation = ContainsAnyToken(normalized, {"add ", "create", "make", "spawn", "place", "put ",
                                                               "set up", "setup", "look at", "prototype", "build"});
    const bool asksForSave = ContainsAnyToken(normalized, {"save project", "save scene", "save current project",
                                                           "save current scene", "save folder", "save location",
                                                           "save data"});
    if (asksForSave) {
        return true;
    }

    if (ContainsAnyToken(normalized, {"validate scene", "check scene", "inspect project", "project state"})) {
        return true;
    }

    if (ContainsAnyToken(normalized, {"rename selected", "rename entity"})) {
        return true;
    }

    const bool explicitStarterScene = ContainsAnyToken(normalized, {"starter scene", "start scene", "default scene",
                                                                    "prototype scene", "basic scene", "simple scene"});
    const bool starterTemplate = normalized.find("starter") != std::string::npos &&
                                 ContainsAnyToken(normalized, {"camera", "light", "ground", "spawn"});
    if (asksForCreation && (explicitStarterScene || starterTemplate)) {
        return true;
    }

    const bool explicitRunningTemplate =
        ContainsAnyToken(normalized, {"running simulator scene template", "runner scene template",
                                      "create running simulator scene template",
                                      "create the running simulator scene"});
    const bool runningSimulator = explicitRunningTemplate &&
                                  ContainsAnyToken(normalized, {"running", "runner", "run ", "run-"}) &&
                                  ContainsAnyToken(normalized, {"simulator", "simulation", "symulator"}) &&
                                  ContainsAnyToken(normalized, {"player", "character", "controller"}) &&
                                  ContainsAnyToken(normalized, {"build", "create", "make", "look at", "prototype"});
    if (runningSimulator) {
        return true;
    }

    if (!asksForCreation) {
        return false;
    }

    const bool mentionsPrimitive = ContainsAnyToken(normalized, {"cube", "cubes", "box", "boxes", "block", "blocks"});
    const bool mentionsLight = ContainsAnyDelimitedToken(normalized, {"light", "lights"});
    const bool mentionsCamera = ContainsAnyDelimitedToken(normalized, {"camera", "cameras"});
    return mentionsPrimitive || mentionsLight || mentionsCamera;
}

bool PromptLooksLikeEditorImprovementReview(const std::string& prompt) {
    const std::string normalized = ToLower(TrimWhitespace(prompt));
    if (normalized.empty()) {
        return false;
    }

    const bool asksForReview =
        normalized.find("suggest") != std::string::npos ||
        normalized.find("recommend") != std::string::npos ||
        normalized.find("improvement") != std::string::npos ||
        normalized.find("improvements") != std::string::npos ||
        normalized.find("review") != std::string::npos ||
        normalized.find("audit") != std::string::npos ||
        normalized.find("look at") != std::string::npos ||
        normalized.find("take a look") != std::string::npos;
    const bool targetsEditor =
        normalized.find("editor") != std::string::npos ||
        normalized.find("ui") != std::string::npos ||
        normalized.find("ux") != std::string::npos ||
        normalized.find("interface") != std::string::npos ||
        normalized.find("workflow") != std::string::npos ||
        normalized.find("viewport") != std::string::npos ||
        normalized.find("inspector") != std::string::npos ||
        normalized.find("hierarchy") != std::string::npos ||
        normalized.find("agent") != std::string::npos ||
        normalized.find("composer") != std::string::npos;
    const bool explicitlyImplementation =
        normalized.find("implement") != std::string::npos ||
        normalized.find("build") != std::string::npos ||
        normalized.find("fix") != std::string::npos ||
        normalized.find("change") != std::string::npos ||
        normalized.find("update") != std::string::npos;
    return asksForReview && targetsEditor && !explicitlyImplementation;
}

bool PromptLooksLikeConversationTask(const std::string& prompt) {
    const std::string normalized = ToLower(TrimWhitespace(prompt));
    if (normalized.empty()) {
        return false;
    }

    const bool asksWhyOrWhat =
        normalized.find(" why") != std::string::npos ||
        normalized.rfind("why ", 0) == 0 ||
        normalized.find("what happened") != std::string::npos ||
        normalized.find("what is wrong") != std::string::npos ||
        normalized.find("what's wrong") != std::string::npos ||
        normalized.find("how do i") != std::string::npos ||
        normalized.find("how to") != std::string::npos ||
        normalized.rfind("please diagnose", 0) == 0 ||
        normalized.rfind("diagnose ", 0) == 0;
    const bool describesFailure =
        normalized.find("not working") != std::string::npos ||
        normalized.find("isn't working") != std::string::npos ||
        normalized.find("isnt working") != std::string::npos ||
        normalized.find("doesn't work") != std::string::npos ||
        normalized.find("does not work") != std::string::npos ||
        normalized.find("broken") != std::string::npos ||
        normalized.find("failing") != std::string::npos ||
        normalized.find("failed") != std::string::npos ||
        normalized.find("error") != std::string::npos ||
        normalized.find("issue") != std::string::npos;
    const bool explicitlyRequestsImplementation =
        normalized.rfind("fix ", 0) == 0 ||
        normalized.rfind("repair ", 0) == 0 ||
        normalized.rfind("implement ", 0) == 0 ||
        normalized.rfind("change ", 0) == 0 ||
        normalized.rfind("update ", 0) == 0;
    if (asksWhyOrWhat && describesFailure && !explicitlyRequestsImplementation) {
        return true;
    }

    const std::vector<std::string> conversationStarts{
        "hello", "hi", "hey", "thanks", "thank you", "what ", "why ", "how ", "when ", "where ",
        "can you explain", "explain ", "tell me ", "i don't understand", "i do not understand",
        "what is going", "what happened", "why did", "are you ", "are we ", "do you ",
    };
    if (normalized.size() < 180 && StartsWithAnyToken(normalized, conversationStarts)) {
        return true;
    }
    return normalized.find('?') != std::string::npos &&
           !ContainsAnyToken(normalized, {"implement", "fix", "build", "create", "add ", "change", "update"});
}

bool PromptLooksLikeBuildLaunchIntent(const std::string& prompt) {
    const std::string normalized = ToLower(TrimWhitespace(prompt));
    if (normalized.empty()) {
        return false;
    }

    if (StartsWithAnyToken(normalized, {"are you ", "are we ", "do you ", "can you "})) {
        return false;
    }

    if (normalized == "let's build" || normalized == "lets build" ||
        normalized == "start building now" || normalized == "start implementing now") {
        return true;
    }

    return normalized.size() < 96 &&
           (normalized.find("start building now") != std::string::npos ||
            normalized.find("start implementing now") != std::string::npos ||
            normalized.find("let's start building") != std::string::npos ||
            normalized.find("lets start building") != std::string::npos);
}

bool PromptLooksTooBroadForAutoImplementation(const std::string& prompt) {
    const std::string normalized = ToLower(TrimWhitespace(prompt));
    if (normalized.empty()) {
        return false;
    }

    const bool broadAction =
        normalized.find("start implementing") != std::string::npos ||
        normalized.find("start building") != std::string::npos ||
        normalized.find("implement features") != std::string::npos ||
        normalized.find("implement all") != std::string::npos ||
        normalized.find("all missing") != std::string::npos ||
        normalized.find("everything") != std::string::npos;
    const bool broadTarget =
        normalized.find("game engine") != std::string::npos ||
        normalized.find("engine") != std::string::npos ||
        normalized.find("features") != std::string::npos ||
        normalized.find("current gaps") != std::string::npos ||
        normalized.find("missing gaps") != std::string::npos;
    if (!(broadAction && broadTarget)) {
        return false;
    }

    const std::vector<std::string> concreteTargets{
        "agent", "chat", "prompt", "enter", "resize", "conversation", "codex", "login",
        "viewport", "inspector", "hierarchy", "collider", "blocks", "cube", "scene",
        "physics", "camera", "ui", "button", "layout",
    };
    return !ContainsAnyToken(normalized, concreteTargets);
}

bool PromptLooksLikeImplementationTask(const std::string& prompt) {
    const std::string normalized = ToLower(TrimWhitespace(prompt));
    if (normalized.empty()) {
        return false;
    }

    if (normalized.rfind("# codex implementation brief", 0) == 0) {
        return true;
    }
    if (PromptLooksLikeConversationTask(normalized)) {
        return false;
    }
    if (PromptLooksLikeBuildLaunchIntent(normalized)) {
        return true;
    }
    if (PromptLooksTooBroadForAutoImplementation(normalized)) {
        return false;
    }
    if (PromptLooksLikeDeterministicSceneEdit(normalized)) {
        return false;
    }

    const std::vector<std::string> actionTokens{
        "implement", "add ", "build", "create", "fix", "repair", "update", "change", "integrate",
        "refactor", "redesign", "modernize", "improve", "test", "verify", "smoke", "wire",
        "make ", "need to", "we need", "i need", "remove", "delete", "rename", "clean up", "cleanup",
        "polish",
    };
    const std::vector<std::string> targetTokens{
        "ui", "editor", "scene", "viewport", "game view", "play mode", "character controller",
        "component", "script", "tool", "menu", "renderer", "inspector", "hierarchy", "project",
        "codex", "agent", "chat", "save", "load", "color", "theme", "layout", "button", "issue",
        "bug", "problem", "crash", "this", "gap", "gaps", "missing", "feature", "features",
    };
    const bool hasAction = ContainsAnyToken(normalized, actionTokens);
    const bool hasTarget = ContainsAnyToken(normalized, targetTokens);
    if (hasAction && (hasTarget || normalized.size() >= 72)) {
        return true;
    }

    const std::vector<std::string> questionStarts{
        "hello", "hi", "hey", "thanks", "thank you", "what ", "why ", "how ", "when ", "where ",
        "can you explain", "explain ", "tell me ",
    };
    if (normalized.size() < 64 && StartsWithAnyToken(normalized, questionStarts)) {
        return false;
    }

    return normalized.size() >= 140 && hasAction;
}

bool ShouldAutoGenerateImplementationBrief(AgentBackend backend, const std::string& prompt) {
    if (!BackendRunsOnWorker(backend)) {
        return false;
    }
    const std::string trimmed = TrimWhitespace(prompt);
    if (trimmed.empty()) {
        return false;
    }
    if (PromptLooksLikeEditorImprovementReview(trimmed)) {
        return true;
    }
    if (PromptLooksLikeConversationTask(trimmed)) {
        return false;
    }
    if (PromptLooksLikeBuildLaunchIntent(trimmed)) {
        return true;
    }
    if (PromptLooksTooBroadForAutoImplementation(trimmed)) {
        return false;
    }
    return PromptLooksLikeImplementationTask(trimmed);
}

std::string StderrSummaryForUi(const AgentOrchestratorResult& result, size_t limit = 280) {
    std::string stderrText = TrimWhitespace(result.stderrText);
    if (stderrText.empty() && !result.diagnostics.empty()) {
        stderrText = result.diagnostics.front();
    }
    return TruncateForUi(stderrText, limit);
}

std::string BackendDisplayLabel(AgentBackend requestedBackend, const AgentOrchestratorResult& result) {
    if (result.usedFallback && requestedBackend != AgentBackend::LocalToolGateway) {
        return std::string(AgentOrchestrator::BackendLabel(requestedBackend)) + " -> Local Tool Gateway fallback";
    }
    return AgentOrchestrator::BackendLabel(result.backend);
}

std::string BuildAgentResultSummaryText(AgentBackend requestedBackend, const AgentOrchestratorResult& result) {
    std::ostringstream summary;
    if (result.usedFallback) {
        summary << "Local Tool Gateway fallback "
                << (result.ok ? "completed" : "failed")
                << " after " << AgentOrchestrator::BackendLabel(requestedBackend) << " could not finish";
    } else if (result.hasGatewayResult && result.backend == AgentBackend::CodexCli) {
        summary << "Codex command batch "
                << (result.gatewayResult.batch.ok ? "applied" : "applied with diagnostics");
    } else {
        summary << AgentOrchestrator::BackendLabel(result.backend) << (result.ok ? " finished" : " failed");
    }

    if (result.exitCode != 0) {
        summary << "; exit code " << result.exitCode;
    }
    if (result.hasGatewayResult && !result.gatewayResult.batch.transactionId.empty()) {
        summary << "; transaction " << result.gatewayResult.batch.transactionId;
    }
    if (result.hasNormalizedResult) {
        summary << "; " << ProviderResultNormalizer::TypeId(result.normalizedResult.type);
    }
    const std::string stderrSummary = StderrSummaryForUi(result, 160);
    if (!stderrSummary.empty() && (!result.ok || result.usedFallback)) {
        summary << "; " << stderrSummary;
    }
    return summary.str();
}

std::string BuildAgentResultDisplayText(const AgentOrchestratorResult& result) {
    if (!result.ok) {
        if (result.hasGatewayResult && result.backend == AgentBackend::CodexCli) {
            std::ostringstream message;
            message << "Codex CLI returned a ToolGateway command batch, but the editor could not complete it cleanly.";
            message << "\n\nExit code: " << result.exitCode;
            const std::string stderrSummary = StderrSummaryForUi(result);
            if (!stderrSummary.empty()) {
                message << "\nStderr summary: " << stderrSummary;
            }
            message << "\n\nWhat happened: Codex produced usable structured commands, but Local Tool Gateway validation or scene validation reported diagnostics.";
            message << "\nNext action: review the diagnostics below; the backend connection itself does not need to be fixed.";
            if (!TrimWhitespace(result.assistantMessage).empty()) {
                message << "\n\nProvider message:\n" << result.assistantMessage;
            }
            return message.str();
        }

        std::ostringstream message;
        const std::string stderrSummary = StderrSummaryForUi(result);
        const std::string lowerSummary = ToLower(stderrSummary);
        message << AgentOrchestrator::BackendLabel(result.backend) << " failed.";
        message << "\n\nExit code: " << result.exitCode;
        if (!stderrSummary.empty()) {
            message << "\nStderr summary: " << stderrSummary;
        } else {
            message << "\nStderr summary: none captured.";
        }
        if (lowerSummary.find("timed out") != std::string::npos) {
            message << "\n\nWhat happened: the backend connection was available, but this individual run did not return before the timeout. Nothing was applied.";
            message << "\nNext action: retry a smaller backend request, or use Local Tool Gateway for deterministic scene edits.";
        } else {
            message << "\nNext action: open Advanced > Provider Health and Raw Logs, fix the backend issue, then resend.";
        }
        if (!TrimWhitespace(result.assistantMessage).empty()) {
            message << "\n\nProvider message:\n" << result.assistantMessage;
        }
        return message.str();
    }

    if (result.backend == AgentBackend::CodexCli && result.exitCode == 0 &&
        TrimWhitespace(result.stdoutText).empty() && !result.usedFallback) {
        return "Codex CLI exited successfully but returned no response text, so the editor had nothing to apply.\n\n"
               "Connected only means the CLI is installed and authenticated; it does not guarantee a run produced a usable result.\n"
               "For direct scene edits, use Local Tool Gateway or a supported scene command such as adding cubes, blocks, lights, or cameras.";
    }

    if (result.usedFallback) {
        std::ostringstream message;
        message << "Local Tool Gateway fallback completed.";
        if (!result.diagnostics.empty()) {
            message << "\n\nBackend issue: " << result.diagnostics.front();
        }
        if (!TrimWhitespace(result.assistantMessage).empty()) {
            message << "\n\n" << result.assistantMessage;
        }
        return message.str();
    }

    if (result.hasNormalizedResult && result.normalizedResult.type == ProviderResultType::ChatResponse) {
        const std::string message = TrimWhitespace(result.normalizedResult.message);
        return message.empty() ? "Provider returned an empty chat response." : message;
    }

    const std::string assistantMessage = TrimWhitespace(result.assistantMessage);
    if (assistantMessage.empty()) {
        return "No response received yet.";
    }
    return result.assistantMessage;
}

std::string JoinInline(const std::vector<std::string>& values, size_t limit = 6) {
    if (values.empty()) {
        return {};
    }
    std::ostringstream stream;
    const size_t count = std::min(values.size(), limit);
    for (size_t index = 0; index < count; ++index) {
        if (index > 0) {
            stream << ", ";
        }
        stream << values[index];
    }
    if (values.size() > count) {
        stream << ", +" << (values.size() - count) << " more";
    }
    return stream.str();
}

std::string BuildAgentOutputSummaryText(const AgentOrchestratorResult& result) {
    std::ostringstream stream;
    stream << "Exit " << result.exitCode;
    if (result.hasNormalizedResult) {
        stream << " | " << ProviderResultNormalizer::TypeId(result.normalizedResult.type);
    }
    stream << " | stdout " << result.stdoutText.size() << " chars";
    stream << " | stderr " << result.stderrText.size() << " chars";
    if (result.hasGatewayResult && !result.gatewayResult.batch.transactionId.empty()) {
        stream << " | " << result.gatewayResult.batch.transactionId;
    }
    if (result.usedFallback) {
        stream << " | fallback";
    }
    return stream.str();
}

std::string BuildAgentCommandSummaryText(const AgentOrchestratorResult& result) {
    const ToolCommandBatch* batch = nullptr;
    if (result.hasGatewayResult) {
        batch = &result.gatewayResult.batch;
    } else if (result.hasNormalizedResult && result.normalizedResult.hasCommandBatch) {
        batch = &result.normalizedResult.commandBatch;
    }
    if (batch == nullptr) {
        if (result.hasNormalizedResult && result.normalizedResult.hasFileChange) {
            return "File proposal: " + result.normalizedResult.fileChange.path;
        }
        return {};
    }

    std::ostringstream stream;
    stream << "Batch: " << (batch->name.empty() ? "Unnamed command batch" : batch->name)
           << " | " << batch->commands.size() << " command(s)";
    if (batch->applied) {
        stream << " | applied";
    } else if (batch->approval == "provider_requires_approval") {
        stream << " | awaiting approval";
    }
    const size_t previewCount = std::min<size_t>(batch->commands.size(), 4);
    for (size_t index = 0; index < previewCount; ++index) {
        stream << "\n- " << batch->commands[index].type;
        if (!batch->commands[index].summary.empty()) {
            stream << ": " << batch->commands[index].summary;
        }
    }
    if (batch->commands.size() > previewCount) {
        stream << "\n- +" << (batch->commands.size() - previewCount) << " more command(s)";
    }
    return stream.str();
}

std::string BuildAgentChangedSummaryText(const AgentOrchestratorResult& result) {
    std::vector<std::string> entities;
    std::vector<std::string> files;
    if (result.hasGatewayResult) {
        entities = result.gatewayResult.batch.changedEntities;
        files = result.gatewayResult.batch.changedFiles;
    } else if (result.hasNormalizedResult && result.normalizedResult.hasCommandBatch) {
        entities = result.normalizedResult.commandBatch.changedEntities;
        files = result.normalizedResult.commandBatch.changedFiles;
    } else if (result.hasNormalizedResult && result.normalizedResult.hasFileChange) {
        files.push_back(result.normalizedResult.fileChange.path);
    }

    std::ostringstream stream;
    if (!entities.empty()) {
        stream << "Entities: " << JoinInline(entities);
    }
    if (!files.empty()) {
        if (stream.tellp() > 0) {
            stream << "\n";
        }
        stream << "Files: " << JoinInline(files, 4);
    }
    return stream.str();
}

std::string BuildAgentFailureReasonText(const AgentOrchestratorResult& result) {
    if (result.ok) {
        return {};
    }
    if (!result.diagnostics.empty()) {
        return result.diagnostics.front();
    }
    if (result.hasGatewayResult && !result.gatewayResult.batch.diagnostics.empty()) {
        return result.gatewayResult.batch.diagnostics.front();
    }
    const std::string stderrSummary = StderrSummaryForUi(result, 360);
    return stderrSummary.empty() ? "No failure diagnostic was captured." : stderrSummary;
}

std::string BuildRecentActivityTimelineText(const EditorState& state, size_t maxEntries = 5) {
    const std::vector<AgentActivity>& activities = state.AgentActivities();
    if (activities.empty()) {
        return "- Waiting for activity.\n";
    }
    const size_t start = activities.size() > maxEntries ? activities.size() - maxEntries : 0;
    std::ostringstream stream;
    for (size_t index = start; index < activities.size(); ++index) {
        const AgentActivity& activity = activities[index];
        stream << "- " << activity.label << " [" << activity.status << "]";
        if (!activity.detail.empty()) {
            stream << ": " << TruncateForUi(activity.detail, 160);
        }
        stream << "\n";
    }
    return stream.str();
}

std::string JoinLines(const std::vector<std::string>& values, const std::string& prefix = "- ") {
    std::ostringstream stream;
    if (values.empty()) {
        stream << prefix << "none\n";
        return stream.str();
    }
    for (const std::string& value : values) {
        stream << prefix << value << "\n";
    }
    return stream.str();
}

std::string ReadTextFilePreview(const std::filesystem::path& path, size_t limit) {
    std::ifstream input(path, std::ios::binary);
    if (!input) {
        return {};
    }

    std::string text;
    text.resize(limit + 1);
    input.read(text.data(), static_cast<std::streamsize>(text.size()));
    text.resize(static_cast<size_t>(input.gcount()));
    if (text.size() > limit) {
        text.resize(limit);
        text += "\n...[truncated]";
    }
    return text;
}

std::string ReadRunLogSummaryPreview(const std::filesystem::path& path, size_t maxEntries = 6) {
    std::ifstream input(path, std::ios::binary);
    if (!input) {
        return "- none\n";
    }

    std::vector<std::string> recentLines;
    std::string line;
    while (std::getline(input, line)) {
        if (TrimWhitespace(line).empty()) {
            continue;
        }
        recentLines.push_back(line);
        if (recentLines.size() > maxEntries) {
            recentLines.erase(recentLines.begin());
        }
    }

    if (recentLines.empty()) {
        return "- none\n";
    }

    std::ostringstream stream;
    for (const std::string& jsonLine : recentLines) {
        try {
            const json entry = json::parse(jsonLine);
            stream << "- " << entry.value("timestamp_utc", "unknown-time")
                   << " " << entry.value("event", "event")
                   << " run_id=" << entry.value("run_id", "none")
                   << " request=" << TruncateForUi(entry.value("user_request", ""), 90)
                   << " prompt_chars=" << entry.value("prompt_char_count", 0)
                   << " summary=" << TruncateForUi(entry.value("summary", ""), 160)
                   << "\n";
        } catch (...) {
            stream << "- unreadable run-log entry\n";
        }
    }
    return stream.str();
}

std::vector<AgentRunHistoryItem> ReadAgentRunHistory(const std::filesystem::path& path, size_t maxEntries = 24) {
    std::ifstream input(path, std::ios::binary);
    if (!input) {
        return {};
    }

    std::vector<AgentRunHistoryItem> items;
    std::string line;
    while (std::getline(input, line)) {
        if (TrimWhitespace(line).empty()) {
            continue;
        }
        try {
            const json entry = json::parse(line);
            AgentRunHistoryItem item;
            item.timestamp = entry.value("timestamp_utc", "unknown-time");
            item.event = entry.value("event", "event");
            item.runId = entry.value("run_id", "none");
            item.userRequest = entry.value("user_request", "");
            item.prompt = entry.value("prompt", entry.value("prompt_preview", ""));
            item.summary = entry.value("summary", "");
            item.backend = "Not run";
            item.status = item.event == "run_started" ? "Running" : "Saved";
            item.resultSummary = item.summary;
            constexpr const char* startedBackendPrefix = "Started backend: ";
            if (item.summary.rfind(startedBackendPrefix, 0) == 0) {
                item.backend = item.summary.substr(std::strlen(startedBackendPrefix));
            }
            if (entry.contains("result") && entry.at("result").is_object()) {
                const json& result = entry.at("result");
                item.backend = result.value("backend_label", result.value("backend", "Unknown backend"));
                item.exitCode = result.value("exit_code", 0);
                item.usedFallback = result.value("used_fallback", false);
                const bool ok = result.value("ok", false);
                item.status = ok ? "Complete" : "Failed";
                if (item.usedFallback) {
                    item.backend += " fallback";
                }
                if (item.resultSummary.empty()) {
                    item.resultSummary = ok ? "Completed." : "Failed.";
                }
                if (item.exitCode != 0) {
                    item.resultSummary += " Exit code " + std::to_string(item.exitCode) + ".";
                }
            } else if (item.event == "run_completed") {
                item.status = "Complete";
            }
            if (item.prompt.empty() && item.userRequest.empty()) {
                continue;
            }
            items.push_back(std::move(item));
            if (items.size() > maxEntries) {
                items.erase(items.begin());
            }
        } catch (...) {
        }
    }
    std::reverse(items.begin(), items.end());
    return items;
}

std::string CurrentTimestampUtc() {
    const auto now = std::chrono::system_clock::now();
    const std::time_t time = std::chrono::system_clock::to_time_t(now);
    std::tm utc{};
#if defined(_WIN32)
    gmtime_s(&utc, &time);
#else
    gmtime_r(&time, &utc);
#endif
    std::ostringstream stream;
    stream << std::put_time(&utc, "%Y-%m-%dT%H:%M:%SZ");
    return stream.str();
}

std::string HashTextForLog(const std::string& text) {
    std::uint64_t hash = 1469598103934665603ull;
    for (unsigned char value : text) {
        hash ^= static_cast<std::uint64_t>(value);
        hash *= 1099511628211ull;
    }
    std::ostringstream stream;
    stream << std::hex << std::setw(16) << std::setfill('0') << hash;
    return stream.str();
}

void AddUniqueLine(std::vector<std::string>& values, const std::string& value) {
    if (value.empty()) {
        return;
    }
    if (std::find(values.begin(), values.end(), value) == values.end()) {
        values.push_back(value);
    }
}

std::string QuoteWindowsCommandArgument(const std::string& argument);

bool OpenExternalUrl(const std::string& url) {
#if defined(_WIN32)
    const HINSTANCE result = ShellExecuteA(nullptr, "open", url.c_str(), nullptr, nullptr, SW_SHOWNORMAL);
    return reinterpret_cast<intptr_t>(result) > 32;
#else
    (void)url;
    return false;
#endif
}

std::filesystem::path CurrentExecutablePath() {
#if defined(_WIN32)
    std::vector<char> buffer(MAX_PATH);
    DWORD length = GetModuleFileNameA(nullptr, buffer.data(), static_cast<DWORD>(buffer.size()));
    while (length == buffer.size()) {
        buffer.resize(buffer.size() * 2);
        length = GetModuleFileNameA(nullptr, buffer.data(), static_cast<DWORD>(buffer.size()));
    }
    if (length > 0) {
        return std::filesystem::path(std::string(buffer.data(), length));
    }
#endif
    return std::filesystem::current_path() / "ai_native_editor.exe";
}

bool ShowPathInExplorer(const std::filesystem::path& path, std::string* error) {
#if defined(_WIN32)
    std::error_code filesystemError;
    const std::filesystem::path absolutePath = std::filesystem::absolute(path, filesystemError);
    if (filesystemError) {
        if (error != nullptr) {
            *error = filesystemError.message();
        }
        return false;
    }

    const bool isDirectory = std::filesystem::is_directory(absolutePath, filesystemError);
    const std::string parameters = isDirectory ? QuoteWindowsCommandArgument(absolutePath.string())
                                               : "/select," + QuoteWindowsCommandArgument(absolutePath.string());
    const HINSTANCE result = ShellExecuteA(nullptr, "open", "explorer.exe", parameters.c_str(), nullptr, SW_SHOWNORMAL);
    const bool opened = reinterpret_cast<intptr_t>(result) > 32;
    if (!opened && error != nullptr) {
        *error = "ShellExecute failed while opening Explorer.";
    }
    return opened;
#else
    (void)path;
    if (error != nullptr) {
        *error = "Show In Explorer is currently implemented for Windows.";
    }
    return false;
#endif
}

bool IsPathInsideOrSame(const std::filesystem::path& root, const std::filesystem::path& path, bool* samePath = nullptr) {
    std::error_code error;
    const std::filesystem::path normalizedRoot = std::filesystem::weakly_canonical(root, error);
    if (error) {
        return false;
    }
    const std::filesystem::path normalizedPath = std::filesystem::weakly_canonical(path, error);
    if (error) {
        return false;
    }
    const std::filesystem::path relative = std::filesystem::relative(normalizedPath, normalizedRoot, error);
    if (error) {
        return false;
    }
    const bool same = relative.empty() || relative == ".";
    if (samePath != nullptr) {
        *samePath = same;
    }
    if (same) {
        return true;
    }
    for (const std::filesystem::path& part : relative) {
        if (part == "..") {
            return false;
        }
        break;
    }
    return !relative.is_absolute();
}

std::string QuoteWindowsCommandArgument(const std::string& argument) {
    if (argument.empty()) {
        return "\"\"";
    }

    const bool needsQuotes = argument.find_first_of(" \t\n\v\"") != std::string::npos;
    if (!needsQuotes) {
        return argument;
    }

    std::string result = "\"";
    size_t backslashes = 0;
    for (const char ch : argument) {
        if (ch == '\\') {
            ++backslashes;
            continue;
        }
        if (ch == '"') {
            result.append(backslashes * 2 + 1, '\\');
            result.push_back(ch);
            backslashes = 0;
            continue;
        }
        result.append(backslashes, '\\');
        backslashes = 0;
        result.push_back(ch);
    }
    result.append(backslashes * 2, '\\');
    result.push_back('"');
    return result;
}

std::string QuotePowerShellLiteral(const std::string& value) {
    std::string result = "'";
    for (const char ch : value) {
        if (ch == '\'') {
            result += "''";
        } else {
            result.push_back(ch);
        }
    }
    result.push_back('\'');
    return result;
}

bool CanLaunchCodexLogin(const ProviderHealth* codexHealth) {
    if (codexHealth == nullptr) {
        return false;
    }

    const std::string status = ToLower(codexHealth->status);
    if (status.find("not found") != std::string::npos ||
        status.find("windowsapps") != std::string::npos) {
        return false;
    }
    if (codexHealth->source == "cmd shim" || codexHealth->source == "PowerShell shim") {
        return true;
    }
    return !codexHealth->executablePath.empty();
}

bool OpenInteractiveCodexLoginTerminal(const ProviderHealth* codexHealth,
                                       const std::filesystem::path& workingDirectory,
                                       std::string* detail) {
#if defined(_WIN32)
    std::string codexCommand = "codex login";
    if (codexHealth != nullptr && !codexHealth->executablePath.empty() &&
        codexHealth->source != "cmd shim" && codexHealth->source != "PowerShell shim") {
        codexCommand = "& " + QuotePowerShellLiteral(codexHealth->executablePath) + " login";
    }

    const std::string psCommand =
        "$Host.UI.RawUI.WindowTitle = 'AI Native Editor - Codex Login'; "
        "Write-Host 'Launching Codex login for AI Native Editor...'; " +
        codexCommand +
        "; Write-Host ''; "
        "Write-Host 'After login completes, return to AI Native Editor and click Refresh Codex.'";
    const std::string parameters =
        "-NoExit -ExecutionPolicy Bypass -Command " + QuoteWindowsCommandArgument(psCommand);
    const std::string directory = workingDirectory.empty() ? std::filesystem::current_path().string()
                                                           : workingDirectory.string();
    const HINSTANCE result = ShellExecuteA(nullptr, "open", "powershell.exe", parameters.c_str(),
                                           directory.c_str(), SW_SHOWNORMAL);
    const bool opened = reinterpret_cast<intptr_t>(result) > 32;
    if (detail != nullptr) {
        *detail = opened ? "Opened an interactive PowerShell window running " + codexCommand
                         : "ShellExecute failed while opening PowerShell for Codex login.";
    }
    return opened;
#else
    (void)codexHealth;
    (void)workingDirectory;
    if (detail != nullptr) {
        *detail = "Interactive Codex login launch is currently implemented for Windows.";
    }
    return false;
#endif
}

#if defined(_WIN32)
std::wstring Utf8ToWide(const std::string& value) {
    if (value.empty()) {
        return {};
    }

    const int required = MultiByteToWideChar(CP_UTF8, 0, value.c_str(), -1, nullptr, 0);
    if (required <= 0) {
        return std::wstring(value.begin(), value.end());
    }

    std::wstring result(static_cast<size_t>(required - 1), L'\0');
    MultiByteToWideChar(CP_UTF8, 0, value.c_str(), -1, result.data(), required);
    return result;
}

std::string WideToUtf8(const wchar_t* value) {
    if (value == nullptr || value[0] == L'\0') {
        return {};
    }

    const int required = WideCharToMultiByte(CP_UTF8, 0, value, -1, nullptr, 0, nullptr, nullptr);
    if (required <= 0) {
        std::wstring wide(value);
        return std::string(wide.begin(), wide.end());
    }

    std::string result(static_cast<size_t>(required - 1), '\0');
    WideCharToMultiByte(CP_UTF8, 0, value, -1, result.data(), required, nullptr, nullptr);
    return result;
}

struct ComApartment {
    HRESULT result = E_FAIL;
    bool shouldUninitialize = false;

    ComApartment() {
        result = CoInitializeEx(nullptr, COINIT_APARTMENTTHREADED | COINIT_DISABLE_OLE1DDE);
        shouldUninitialize = SUCCEEDED(result);
    }

    ~ComApartment() {
        if (shouldUninitialize) {
            CoUninitialize();
        }
    }
};

std::filesystem::path ExistingFolderForDialog(std::filesystem::path path) {
    std::error_code filesystemError;
    if (path.empty()) {
        path = std::filesystem::current_path(filesystemError);
    }
    if (!filesystemError && std::filesystem::is_regular_file(path, filesystemError)) {
        path = path.parent_path();
    }
    while (!path.empty() && !std::filesystem::exists(path, filesystemError)) {
        path = path.parent_path();
    }
    if (path.empty() || filesystemError) {
        path = std::filesystem::current_path(filesystemError);
    }
    return path;
}

void SetDialogInitialFolder(IFileDialog* dialog, const std::filesystem::path& initialPath) {
    if (dialog == nullptr) {
        return;
    }

    const std::filesystem::path folder = ExistingFolderForDialog(initialPath);
    const std::wstring wideFolder = Utf8ToWide(folder.string());
    if (wideFolder.empty()) {
        return;
    }

    IShellItem* item = nullptr;
    if (SUCCEEDED(SHCreateItemFromParsingName(wideFolder.c_str(), nullptr, IID_PPV_ARGS(&item))) && item != nullptr) {
        dialog->SetFolder(item);
        item->Release();
    }
}

bool ExtractDialogResultPath(IFileDialog* dialog, std::filesystem::path* selectedPath, std::string* error) {
    IShellItem* item = nullptr;
    HRESULT result = dialog->GetResult(&item);
    if (FAILED(result) || item == nullptr) {
        if (error != nullptr) {
            *error = "The selected shell item could not be read.";
        }
        return false;
    }

    PWSTR path = nullptr;
    result = item->GetDisplayName(SIGDN_FILESYSPATH, &path);
    item->Release();
    if (FAILED(result) || path == nullptr || path[0] == L'\0') {
        if (path != nullptr) {
            CoTaskMemFree(path);
        }
        if (error != nullptr) {
            *error = "The selected shell item did not resolve to a filesystem path.";
        }
        return false;
    }

    *selectedPath = WideToUtf8(path);
    CoTaskMemFree(path);
    return true;
}
#endif

bool PickFolderWithDialog(const char* title, const std::filesystem::path& initialPath,
                          std::filesystem::path* selectedPath, std::string* error) {
    if (selectedPath == nullptr) {
        if (error != nullptr) {
            *error = "No selected-path output was provided.";
        }
        return false;
    }

#if defined(_WIN32)
    ComApartment apartment;
    if (FAILED(apartment.result) && apartment.result != RPC_E_CHANGED_MODE) {
        if (error != nullptr) {
            *error = "COM initialization failed before opening the folder picker.";
        }
        return false;
    }

    IFileOpenDialog* dialog = nullptr;
    HRESULT result = CoCreateInstance(CLSID_FileOpenDialog, nullptr, CLSCTX_INPROC_SERVER, IID_PPV_ARGS(&dialog));
    if (FAILED(result) || dialog == nullptr) {
        if (error != nullptr) {
            *error = "Could not create the Windows folder picker.";
        }
        return false;
    }

    DWORD options = 0;
    if (SUCCEEDED(dialog->GetOptions(&options))) {
        dialog->SetOptions(options | FOS_PICKFOLDERS | FOS_FORCEFILESYSTEM | FOS_PATHMUSTEXIST);
    }
    dialog->SetTitle(Utf8ToWide(title == nullptr ? "Select folder" : title).c_str());
    SetDialogInitialFolder(dialog, initialPath);

    result = dialog->Show(nullptr);
    if (result == HRESULT_FROM_WIN32(ERROR_CANCELLED)) {
        dialog->Release();
        return false;
    }
    if (FAILED(result)) {
        dialog->Release();
        if (error != nullptr) {
            *error = "The Windows folder picker failed before a folder was selected.";
        }
        return false;
    }

    const bool ok = ExtractDialogResultPath(dialog, selectedPath, error);
    dialog->Release();
    return ok;
#else
    (void)title;
    (void)initialPath;
    if (error != nullptr) {
        *error = "Folder picking is not implemented on this platform; type the folder path manually.";
    }
    return false;
#endif
}

bool PickSaveFileWithDialog(const char* title, const std::filesystem::path& initialPath,
                            const char* defaultFileName, std::filesystem::path* selectedPath,
                            std::string* error) {
    if (selectedPath == nullptr) {
        if (error != nullptr) {
            *error = "No selected-path output was provided.";
        }
        return false;
    }

#if defined(_WIN32)
    ComApartment apartment;
    if (FAILED(apartment.result) && apartment.result != RPC_E_CHANGED_MODE) {
        if (error != nullptr) {
            *error = "COM initialization failed before opening the Save As dialog.";
        }
        return false;
    }

    IFileSaveDialog* dialog = nullptr;
    HRESULT result = CoCreateInstance(CLSID_FileSaveDialog, nullptr, CLSCTX_INPROC_SERVER, IID_PPV_ARGS(&dialog));
    if (FAILED(result) || dialog == nullptr) {
        if (error != nullptr) {
            *error = "Could not create the Windows Save As dialog.";
        }
        return false;
    }

    DWORD options = 0;
    if (SUCCEEDED(dialog->GetOptions(&options))) {
        dialog->SetOptions(options | FOS_FORCEFILESYSTEM | FOS_OVERWRITEPROMPT | FOS_PATHMUSTEXIST);
    }
    const COMDLG_FILTERSPEC filters[] = {
        {L"AI Native Scene (*.scene.json)", L"*.scene.json"},
        {L"JSON files (*.json)", L"*.json"},
        {L"All files (*.*)", L"*.*"},
    };
    dialog->SetFileTypes(static_cast<UINT>(sizeof(filters) / sizeof(filters[0])), filters);
    dialog->SetFileTypeIndex(1);
    dialog->SetDefaultExtension(L"json");
    dialog->SetTitle(Utf8ToWide(title == nullptr ? "Save As" : title).c_str());
    SetDialogInitialFolder(dialog, initialPath);
    if (defaultFileName != nullptr && defaultFileName[0] != '\0') {
        dialog->SetFileName(Utf8ToWide(defaultFileName).c_str());
    }

    result = dialog->Show(nullptr);
    if (result == HRESULT_FROM_WIN32(ERROR_CANCELLED)) {
        dialog->Release();
        return false;
    }
    if (FAILED(result)) {
        dialog->Release();
        if (error != nullptr) {
            *error = "The Windows Save As dialog failed before a file was selected.";
        }
        return false;
    }

    const bool ok = ExtractDialogResultPath(dialog, selectedPath, error);
    dialog->Release();
    return ok;
#else
    (void)title;
    (void)initialPath;
    (void)defaultFileName;
    if (error != nullptr) {
        *error = "Save As picking is not implemented on this platform; type the file path manually.";
    }
    return false;
#endif
}

std::filesystem::path NormalizeSceneSavePath(std::filesystem::path scenePath) {
    const std::string filename = ToLower(scenePath.filename().string());
    constexpr const char* sceneExtension = ".scene.json";
    if (filename.size() >= std::strlen(sceneExtension) &&
        filename.compare(filename.size() - std::strlen(sceneExtension), std::strlen(sceneExtension), sceneExtension) == 0) {
        return scenePath;
    }

    if (ToLower(scenePath.extension().string()) == ".json") {
        scenePath.replace_extension();
    }
    scenePath += sceneExtension;
    return scenePath;
}

bool SetProcessEnvironmentValue(const char* name, const std::string& value) {
#if defined(_WIN32)
    return _putenv_s(name, value.c_str()) == 0;
#else
    return setenv(name, value.c_str(), 1) == 0;
#endif
}

std::string EnvironmentStatusText(const char* name) {
    const char* value = std::getenv(name);
    return value != nullptr && value[0] != '\0' ? std::string(name) + " is set"
                                                : std::string(name) + " is not set";
}

template <size_t Size>
void CopyStringToBuffer(std::array<char, Size>& buffer, const std::string& value) {
    std::fill(buffer.begin(), buffer.end(), '\0');
    std::strncpy(buffer.data(), value.c_str(), buffer.size() - 1);
}

float UiScaleFromFont() {
    return std::max(0.75f, ImGui::GetFontSize() / kBaseFontSize);
}

std::string HumanizeIdentifier(std::string value) {
    if (value.empty()) {
        return value;
    }

    for (char& character : value) {
        if (character == '_' || character == '-') {
            character = ' ';
        }
    }

    std::string result;
    result.reserve(value.size() + 8);
    for (size_t i = 0; i < value.size(); ++i) {
        const char c = value[i];
        const char previous = i == 0 ? '\0' : value[i - 1];
        const char next = i + 1 < value.size() ? value[i + 1] : '\0';
        const bool splitBeforeUpper = i > 0 && std::isupper(static_cast<unsigned char>(c)) &&
                                      (std::islower(static_cast<unsigned char>(previous)) ||
                                       std::isdigit(static_cast<unsigned char>(previous)) ||
                                       (std::isupper(static_cast<unsigned char>(previous)) &&
                                        std::islower(static_cast<unsigned char>(next))));
        const bool splitBeforeDigit = i > 0 && std::isdigit(static_cast<unsigned char>(c)) &&
                                      std::isalpha(static_cast<unsigned char>(previous));
        if ((splitBeforeUpper || splitBeforeDigit) && !result.empty() && result.back() != ' ') {
            result.push_back(' ');
        }
        result.push_back(c);
    }

    if (!result.empty()) {
        result[0] = static_cast<char>(std::toupper(static_cast<unsigned char>(result[0])));
    }
    return result;
}

std::string ComponentInspectorTitle(const Component& component) {
    const ComponentSchema* schema = FindRuntimeSchema(component.type);
    const bool scriptLike = !ComponentPropertyValue(component, "scriptPath").empty() ||
                            (schema != nullptr && schema->category == "Runtime");
    std::string title = component.type == "CameraFollowRuntime" ? "Camera Controller" : HumanizeIdentifier(component.type);
    if (scriptLike && title.find("(Script)") == std::string::npos) {
        title += " (Script)";
    }
    return title;
}

ImVec4 ComponentAccentColor(const Component& component) {
    const ComponentSchema* schema = FindRuntimeSchema(component.type);
    const std::string category = schema == nullptr ? "Scripts" : schema->category;
    if (component.type == "Transform" || category == "Core") {
        return MixColor(AccentColor(), ImVec4(0.42f, 0.86f, 0.58f, 1.0f), 0.68f);
    }
    if (category == "Rendering") {
        return MixColor(AccentColor(), ImVec4(0.32f, 0.66f, 1.0f, 1.0f), 0.64f);
    }
    if (category == "Physics") {
        return MixColor(AccentColor(), ImVec4(0.30f, 0.88f, 0.92f, 1.0f), 0.66f);
    }
    if (category == "Terrain") {
        return MixColor(AccentColor(), ImVec4(0.58f, 0.62f, 0.62f, 1.0f), 0.58f);
    }
    if (category == "Runtime") {
        return MixColor(AccentColor(), ImVec4(0.80f, 0.55f, 1.0f, 1.0f), 0.62f);
    }
    if (category == "UI") {
        return MixColor(AccentColor(), ImVec4(0.38f, 0.82f, 0.72f, 1.0f), 0.64f);
    }
    return MixColor(AccentColor(), ImVec4(1.0f, 0.74f, 0.28f, 1.0f), 0.66f);
}

bool DrawStringCombo(const char* id, std::string& value, const std::vector<const char*>& options,
                     const char* fallback) {
    if (value.empty()) {
        value = fallback == nullptr ? "" : fallback;
    }

    bool changed = false;
    ImGui::SetNextItemWidth(-1.0f);
    if (ImGui::BeginCombo(id, value.c_str())) {
        for (const char* option : options) {
            const bool selected = value == option;
            if (ImGui::Selectable(option, selected)) {
                value = option;
                changed = true;
            }
            if (selected) {
                ImGui::SetItemDefaultFocus();
            }
        }
        ImGui::EndCombo();
    }
    return changed;
}

bool DrawStringCombo(const char* id, std::string& value, std::vector<std::string> options,
                     const char* fallback) {
    if (value.empty()) {
        value = fallback == nullptr ? "" : fallback;
    }
    if (!value.empty() && std::find(options.begin(), options.end(), value) == options.end()) {
        options.push_back(value);
    }

    bool changed = false;
    ImGui::SetNextItemWidth(-1.0f);
    if (ImGui::BeginCombo(id, value.c_str())) {
        for (const std::string& option : options) {
            const bool selected = value == option;
            if (ImGui::Selectable(option.c_str(), selected)) {
                value = option;
                changed = true;
            }
            if (selected) {
                ImGui::SetItemDefaultFocus();
            }
        }
        ImGui::EndCombo();
    }
    return changed;
}

