void DrawInspectorObjectIcon(ImVec4 accent, ImVec2 size) {
    const ImVec2 pos = ImGui::GetCursorScreenPos();
    ImGui::InvisibleButton("##entity_icon", size);
    ImDrawList* drawList = ImGui::GetWindowDrawList();
    const ImU32 outline = ColorU32(WithAlpha(accent, 0.90f));
    const ImU32 fill = ColorU32(WithAlpha(MixColor(PanelBackgroundColor(), accent, 0.22f), 0.95f));
    const float pad = size.x * 0.18f;
    const ImVec2 a(pos.x + size.x * 0.50f, pos.y + pad);
    const ImVec2 b(pos.x + size.x - pad, pos.y + size.y * 0.33f);
    const ImVec2 c(pos.x + size.x - pad, pos.y + size.y * 0.70f);
    const ImVec2 d(pos.x + size.x * 0.50f, pos.y + size.y - pad);
    const ImVec2 e(pos.x + pad, pos.y + size.y * 0.70f);
    const ImVec2 f(pos.x + pad, pos.y + size.y * 0.33f);
    drawList->AddQuadFilled(a, b, d, f, fill);
    drawList->AddQuad(a, b, d, f, outline, std::max(1.0f, UiScaleFromFont()));
    drawList->AddLine(f, e, outline, std::max(1.0f, UiScaleFromFont()));
    drawList->AddLine(e, d, outline, std::max(1.0f, UiScaleFromFont()));
    drawList->AddLine(b, c, outline, std::max(1.0f, UiScaleFromFont()));
    drawList->AddLine(c, d, outline, std::max(1.0f, UiScaleFromFont()));
}

