bool DrawInspectorVec3Row(const char* label, std::array<float, 3>& value, float speed = 0.1f) {
    bool changed = false;
    ImGui::TableNextRow();
    ImGui::TableSetColumnIndex(0);
    DrawInspectorFieldLabel(label);
    ImGui::TableSetColumnIndex(1);

    ImGui::PushID(label);
    const float spacing = ImGui::GetStyle().ItemSpacing.x;
    const float axisLabelWidth = ImGui::CalcTextSize("X").x + spacing * 0.55f;
    const float fieldWidth = std::max(ImGui::GetFontSize() * 3.4f,
                                      (ImGui::GetContentRegionAvail().x - axisLabelWidth * 3.0f - spacing * 2.0f) /
                                          3.0f);
    const char* labels[3] = {"X", "Y", "Z"};
    for (int axis = 0; axis < 3; ++axis) {
        if (axis > 0) {
            ImGui::SameLine();
        }
        ImGui::TextDisabled("%s", labels[axis]);
        ImGui::SameLine();
        ImGui::SetNextItemWidth(fieldWidth);
        changed = ImGui::DragFloat((std::string("##") + labels[axis]).c_str(), &value[static_cast<size_t>(axis)],
                                   speed, -1000.0f, 1000.0f, "%.2f") ||
                  changed;
    }
    ImGui::PopID();
    return changed;
}

