    RemoveClosedPanelTabs();
    state_.LoadChatConversations({}, {});
    const std::string smokeChatId = state_.CreateChatConversation("Smoke pinned Codex chat");
    state_.SetChatConversationPinned(smokeChatId, true);
    state_.SwitchChatConversation(smokeChatId);
    state_.AddChat(ChatSender::User, "verify pinned chat persistence");
    state_.AddChat(ChatSender::Assistant, "pinned chat persistence response");
    ApplyEditorTheme();

    std::string error;
    if (!SaveEditorProfile(&error)) {
        state_.AddLog(LogLevel::Error, "Editor profile smoke failed: save failed: " + error);
        return false;
    }

    appearance_ = EditorAppearanceSettings{};
    selectedBackend_ = AgentBackend::LocalToolGateway;
    showAppearancePreferences_ = false;
    showProjectSettings_ = false;
    showAgentHistory_ = false;
    agentAutoApplyCodexCommandBatches_ = true;
