void EditorApp::CreateSpriteTemplate(const char* source) {
    if (!EnsureEditModeForAction("Create sprite")) {
        return;
    }

    std::string textureReference;
    for (const AssetRecord& asset : state_.Assets()) {
        if (asset.type == "Texture" && !asset.importedPath.empty()) {
            textureReference = asset.id;
            break;
        }
    }

    if (textureReference.empty()) {
        const std::filesystem::path projectRoot = state_.ProjectRootPathString();
        if (projectRoot.empty()) {
            state_.AddLog(LogLevel::Warning, "Create Sprite requires an open project.");
            return;
        }

        const std::filesystem::path generatedPath = projectRoot / "Assets" / "Sprites" / "DefaultSprite.png";
        std::vector<unsigned char> pixels(static_cast<size_t>(64 * 64 * 4), 255u);
        for (int y = 0; y < 64; ++y) {
            for (int x = 0; x < 64; ++x) {
                const bool checker = ((x / 8) + (y / 8)) % 2 == 0;
                const size_t offset = static_cast<size_t>(y * 64 + x) * 4u;
                pixels[offset + 0] = checker ? 230u : 74u;
                pixels[offset + 1] = checker ? 235u : 133u;
                pixels[offset + 2] = checker ? 244u : 212u;
                pixels[offset + 3] = 255u;
            }
        }

        std::string encodeError;
        if (!EncodeImagePngBgra(generatedPath, 64, 64, pixels, &encodeError)) {
            state_.AddLog(LogLevel::Warning, "Could not generate default sprite texture: " + encodeError);
            return;
        }

        AssetRecord importedTexture;
        std::string importError;
        if (state_.ImportAsset(generatedPath, "generated-sprite", "project-generated", &importedTexture, &importError)) {
            textureReference = importedTexture.id;
        } else {
            state_.AddLog(LogLevel::Warning, "Could not import generated sprite texture; using direct path: " + importError);
            std::error_code relativeError;
            const std::filesystem::path relative = std::filesystem::relative(generatedPath, projectRoot, relativeError);
            textureReference = (relativeError ? generatedPath : relative).generic_string();
        }
    }

    bool hasCamera = false;
    for (const Entity& entity : state_.Entities()) {
        hasCamera = hasCamera || HasComponentType(entity, "Camera");
    }
    if (!hasCamera) {
        Component camera = MakeCameraComponent();
        SetComponentPropertyForUi(camera, "projection", "Orthographic");
        SetComponentPropertyForUi(camera, "orthographicSize", "4.5");
        Entity& cameraEntity = state_.CreateEntity("2D Camera", {MakeTransformComponent(), camera});
        const std::array<float, 3> cameraPosition{0.0f, 0.0f, 10.0f};
        const std::array<float, 3> cameraRotation{0.0f, 0.0f, 0.0f};
        state_.SetEntityTransform(cameraEntity.id, &cameraPosition, &cameraRotation, nullptr);
    }

    Component sprite = MakeSpriteRendererComponent(textureReference);
    SetComponentPropertyForUi(sprite, "sortingLayer", "Default");
    SetComponentPropertyForUi(sprite, "orderInLayer", "0");
    Component body = MakeRigidbody2DComponent("Static");
    Component collider = MakeCollider2DComponent("Box");

    SpriteRectPixels rect = FullTextureSpriteRect(100, 100);
    if (TerrainGlTexture* texture = GetTerrainGlTexture(textureReference, state_.ProjectRootPathString());
        texture != nullptr && texture->loaded && texture->width > 0 && texture->height > 0) {
        rect = FullTextureSpriteRect(texture->width, texture->height);
    }
    const SpriteWorldBounds2D bounds =
        SpriteWorldBoundsFromPixels(rect, ComponentFloatValue(sprite, "pixelsPerUnit", 100.0f),
                                    ComponentVec2Value(sprite, "pivot", {0.5f, 0.5f}));
    SetComponentPropertyForUi(collider, "size", Vec2ToUiString(bounds.size));
    SetComponentPropertyForUi(collider, "offset", Vec2ToUiString(bounds.offset));

    const std::string spriteName = UniqueEntityName(state_, "Sprite");
    Entity& entity = state_.CreateEntity(spriteName, {MakeTransformComponent(), sprite, body, collider});
    const std::array<float, 3> position{0.0f, 0.0f, 0.0f};
    state_.SetEntityTransform(entity.id, &position, nullptr, nullptr);
    state_.SelectEntity(entity.id);
    state_.MarkSceneDirty("Created sprite.");
    state_.AddLog(LogLevel::Info, std::string(source) + " created Sprite with SpriteRenderer and Collider2D.");
}

