RuntimeInputState EditorApp::BuildRuntimeInputState() const {
    RuntimeInputState input;
    input.captured = state_.IsPlaying() && gameViewportInputActive_;
    input.captureSurface = input.captured ? "Game" : "";
    input.actions = {
        {"Move X", "KeyboardMove", 0.0f, false},
        {"Move Z", "KeyboardMove", 0.0f, false},
        {"Sprint", "KeyboardSprint", 0.0f, false},
        {"Interact", "KeyboardInteract", 0.0f, false},
        {"Jump", "KeyboardJump", 0.0f, false},
    };
    if (!input.captured) {
        return input;
    }

    ImGuiIO& io = ImGui::GetIO();
    if (io.WantTextInput) {
        return input;
    }

    if (ImGui::IsKeyDown(ImGuiKey_D) || ImGui::IsKeyDown(ImGuiKey_RightArrow)) {
        input.character.moveX += 1.0f;
    }
    if (ImGui::IsKeyDown(ImGuiKey_A) || ImGui::IsKeyDown(ImGuiKey_LeftArrow)) {
        input.character.moveX -= 1.0f;
    }
    if (ImGui::IsKeyDown(ImGuiKey_W) || ImGui::IsKeyDown(ImGuiKey_UpArrow)) {
        input.character.moveZ -= 1.0f;
    }
    if (ImGui::IsKeyDown(ImGuiKey_S) || ImGui::IsKeyDown(ImGuiKey_DownArrow)) {
        input.character.moveZ += 1.0f;
    }
    input.character.sprint = io.KeyShift;
    input.actions[0].value = input.character.moveX;
    input.actions[0].active = std::fabs(input.character.moveX) > 0.0001f;
    input.actions[1].value = input.character.moveZ;
    input.actions[1].active = std::fabs(input.character.moveZ) > 0.0001f;
    input.actions[2].value = input.character.sprint ? 1.0f : 0.0f;
    input.actions[2].active = input.character.sprint;
    input.actions[3].value = ImGui::IsKeyDown(ImGuiKey_E) ? 1.0f : 0.0f;
    input.actions[3].active = input.actions[3].value > 0.0f;
    input.actions[4].value = ImGui::IsKeyDown(ImGuiKey_Space) ? 1.0f : 0.0f;
    input.actions[4].active = input.actions[4].value > 0.0f;
    return input;
}

void EditorApp::DeleteSelectedEntity(const char* source) {
    if (!EnsureEditModeForAction("Delete GameObject")) {
        return;
    }

    const int selectedId = state_.SelectedEntityId();
    if (selectedId == 0) {
        return;
    }

    const Entity* selected = state_.FindEntity(selectedId);
    const std::string name = selected == nullptr ? "selected entity" : selected->name;
    if (state_.DeleteEntity(selectedId)) {
        state_.AddLog(LogLevel::Info, std::string(source) + " deleted GameObject: " + name + ".");
        state_.AddActivity("delete.gameObject", "Complete", name);
    }
}

int EditorApp::PickViewportEntity(ImVec2 localMouse, ImVec2 viewportSize) const {
    if (viewportSize.x <= 1.0f || viewportSize.y <= 1.0f) {
        return 0;
    }

    const CameraBasis camera =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    Vec3 rayOrigin;
    Vec3 rayDirection;
    if (!MouseRayFromViewport(localMouse, viewportSize, camera, &rayOrigin, &rayDirection)) {
        return 0;
    }

    int pickedEntityId = 0;
    float closestDistance = std::numeric_limits<float>::max();
    for (const Entity& entity : state_.Entities()) {
        if (!HasRenderableMesh(state_, entity)) {
            continue;
        }

        const Vec3 localOrigin = InverseTransformPoint(entity, rayOrigin);
        const Vec3 localDirection = InverseTransformDirection(entity, rayDirection);
        float hitDistance = 0.0f;
        if (RayIntersectsUnitCube(localOrigin, localDirection, &hitDistance) && hitDistance < closestDistance) {
            closestDistance = hitDistance;
            pickedEntityId = entity.id;
        }
    }
    if (pickedEntityId == 0) {
        TerrainRayHit terrainHit;
        pickedEntityId = PickViewportTerrain(localMouse, viewportSize, &terrainHit);
    }
    if (pickedEntityId == 0) {
        CaveRayHit caveHit;
        pickedEntityId = PickViewportCave(localMouse, viewportSize, &caveHit);
    }
    return pickedEntityId;
}

int EditorApp::PickViewportTerrain(ImVec2 localMouse, ImVec2 viewportSize, TerrainRayHit* outHit,
                                   bool includeHoles) const {
    if (viewportSize.x <= 1.0f || viewportSize.y <= 1.0f) {
        return 0;
    }

    const CameraBasis camera =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    Vec3 rayOrigin;
    Vec3 rayDirection;
    if (!MouseRayFromViewport(localMouse, viewportSize, camera, &rayOrigin, &rayDirection)) {
        return 0;
    }

    int pickedEntityId = 0;
    TerrainRayHit closest;
    closest.distance = std::numeric_limits<float>::max();
    for (const Entity& entity : state_.Entities()) {
        const Component* component = FindTerrainComponent(entity);
        if (component == nullptr || !state_.IsEntityActiveInHierarchy(entity.id)) {
            continue;
        }
        TerrainData terrain;
        if (!LoadTerrainDataFromComponentCached(entity.id, *component, &terrain)) {
            continue;
        }
        TerrainRayHit hit;
        if (TerrainUsesHeightfield(terrain) &&
            TerrainRaycastWorld(terrain, entity, {rayOrigin.x, rayOrigin.y, rayOrigin.z},
                                {rayDirection.x, rayDirection.y, rayDirection.z}, kViewportFarPlane, &hit,
                                includeHoles) &&
            hit.distance < closest.distance) {
            hit.surfaceType = "Heightfield";
            closest = hit;
            pickedEntityId = entity.id;
        }
        CaveRayHit volumeHit;
        if (TerrainUsesVolumetric(terrain) &&
            TerrainVolumeRaycastWorld(terrain, entity, {rayOrigin.x, rayOrigin.y, rayOrigin.z},
                                      {rayDirection.x, rayDirection.y, rayDirection.z}, kViewportFarPlane,
                                      &volumeHit) &&
            volumeHit.distance < closest.distance) {
            closest.hit = true;
            closest.distance = volumeHit.distance;
            closest.point = volumeHit.point;
            closest.normal = volumeHit.normal;
            closest.entityId = entity.id;
            closest.entityName = entity.name;
            closest.surfaceType = "Volume";
            pickedEntityId = entity.id;
        }
    }
    if (pickedEntityId != 0 && outHit != nullptr) {
        *outHit = closest;
    }
    return pickedEntityId;
}

int EditorApp::PickViewportCave(ImVec2 localMouse, ImVec2 viewportSize, CaveRayHit* outHit) const {
    if (viewportSize.x <= 1.0f || viewportSize.y <= 1.0f) {
        return 0;
    }

    const CameraBasis camera =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    Vec3 rayOrigin;
    Vec3 rayDirection;
    if (!MouseRayFromViewport(localMouse, viewportSize, camera, &rayOrigin, &rayDirection)) {
        return 0;
    }

    int pickedEntityId = 0;
    CaveRayHit closest;
    closest.distance = std::numeric_limits<float>::max();
    for (const Entity& entity : state_.Entities()) {
        const Component* component = FindCaveVolumeComponent(entity);
        if (component == nullptr || !state_.IsEntityActiveInHierarchy(entity.id)) {
            continue;
        }
        CaveVolumeData cave;
        if (!LoadCaveVolumeDataFromComponentCached(entity.id, *component, &cave)) {
            continue;
        }
        CaveRayHit hit;
        if (CaveRaycastWorld(cave, entity, {rayOrigin.x, rayOrigin.y, rayOrigin.z},
                             {rayDirection.x, rayDirection.y, rayDirection.z}, kViewportFarPlane, &hit) &&
            hit.distance < closest.distance) {
            closest = hit;
            pickedEntityId = entity.id;
        }
    }
    if (pickedEntityId != 0 && outHit != nullptr) {
        *outHit = closest;
    }
    return pickedEntityId;
}

int EditorApp::PickMoveGizmoAxis(ImVec2 localMouse, ImVec2 viewportSize) const {
    const Entity* selected = state_.FindEntity(state_.SelectedEntityId());
    if (selected == nullptr || viewportSize.x <= 1.0f || viewportSize.y <= 1.0f) {
        return 0;
    }

    const CameraBasis camera =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    const Vec3 origin = MakeVec3(selected->position);
    const float length = MaxAbsScale(*selected) * 1.35f;
    ImVec2 originScreen;
    if (ProjectWorldToViewport(origin, camera, viewportSize, &originScreen)) {
        const float dx = localMouse.x - originScreen.x;
        const float dy = localMouse.y - originScreen.y;
        if (std::sqrt(dx * dx + dy * dy) <= Scaled(15.0f)) {
            return kViewportMoveCenterHandle;
        }
    }

    int bestAxis = 0;
    float bestDistance = std::numeric_limits<float>::max();
    for (int axis = 1; axis <= 3; ++axis) {
        const Vec3 axisDirection = AxisVectorForEntity(*selected, axis, viewportTransformLocal_);
        ImVec2 start;
        ImVec2 end;
        if (!ProjectWorldToViewport(origin, camera, viewportSize, &start) ||
            !ProjectWorldToViewport(origin + axisDirection * length, camera, viewportSize, &end)) {
            continue;
        }

        const float distance = DistancePointToSegment(localMouse, start, end);
        if (distance < bestDistance) {
            bestDistance = distance;
            bestAxis = axis;
        }
    }

    return bestDistance <= Scaled(13.0f) ? bestAxis : 0;
}

float EditorApp::ProjectMouseToMoveAxis(int axis, ImVec2 localMouse, ImVec2 viewportSize) const {
    if (axis == kViewportMoveCenterHandle) {
        const CameraBasis camera =
            BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
        Vec3 world;
        if (!ProjectMouseToViewPlane(localMouse, viewportSize, camera, MakeVec3(viewportMoveDragStartPosition_), &world)) {
            return viewportMoveDragStartAxisT_;
        }
        const Vec3 delta = world - MakeVec3(viewportMoveDragStartPosition_);
        return Dot(delta, camera.right) + Dot(delta, camera.up);
    }

    const Entity* selectedForAxis = state_.FindEntity(state_.SelectedEntityId());
    const Vec3 axisDirection =
        selectedForAxis == nullptr ? AxisVector(axis) : AxisVectorForEntity(*selectedForAxis, axis, viewportTransformLocal_);
    if (Length(axisDirection) <= 0.0001f || viewportSize.x <= 1.0f || viewportSize.y <= 1.0f) {
        return viewportMoveDragStartAxisT_;
    }

    const CameraBasis camera =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    Vec3 rayOrigin;
    Vec3 rayDirection;
    if (!MouseRayFromViewport(localMouse, viewportSize, camera, &rayOrigin, &rayDirection)) {
        return viewportMoveDragStartAxisT_;
    }

    Vec3 axisOrigin = MakeVec3(viewportMoveDragStartPosition_);
    if (viewportActiveMoveAxis_ == 0) {
        const Entity* selected = state_.FindEntity(state_.SelectedEntityId());
        if (selected == nullptr) {
            return viewportMoveDragStartAxisT_;
        }
        axisOrigin = MakeVec3(selected->position);
    }
    const Vec3 w0 = axisOrigin - rayOrigin;
    const float a = Dot(axisDirection, axisDirection);
    const float b = Dot(axisDirection, rayDirection);
    const float c = Dot(rayDirection, rayDirection);
    const float d = Dot(axisDirection, w0);
    const float e = Dot(rayDirection, w0);
    const float denominator = a * c - b * b;
    if (std::fabs(denominator) <= 0.00001f || !std::isfinite(denominator)) {
        return viewportMoveDragStartAxisT_;
    }

    const float axisT = (b * e - c * d) / denominator;
    return std::isfinite(axisT) ? axisT : viewportMoveDragStartAxisT_;
}

void EditorApp::BeginMoveGizmoDrag(int axis, ImVec2 localMouse, ImVec2 viewportSize) {
    Entity* selected = state_.FindEntity(state_.SelectedEntityId());
    if (selected == nullptr || !state_.IsEditMode()) {
        return;
    }

    viewportActiveMoveAxis_ = axis;
    viewportHotMoveAxis_ = axis;
    viewportMoveDragEntityId_ = selected->id;
    viewportMoveDragStartPosition_ = selected->position;
    viewportMoveDragStartPlanePoint_ = selected->position;
    if (axis == kViewportMoveCenterHandle) {
        const CameraBasis camera =
            BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
        Vec3 planePoint;
        if (ProjectMouseToViewPlane(localMouse, viewportSize, camera, MakeVec3(selected->position), &planePoint)) {
            viewportMoveDragStartPlanePoint_ = {planePoint.x, planePoint.y, planePoint.z};
        }
    }
    viewportMoveDragStartAxisT_ = ProjectMouseToMoveAxis(axis, localMouse, viewportSize);
    viewportMoveDragMoved_ = false;
}

void EditorApp::UpdateMoveGizmoDrag(ImVec2 localMouse, ImVec2 viewportSize) {
    Entity* selected = state_.FindEntity(viewportMoveDragEntityId_);
    if (selected == nullptr || viewportActiveMoveAxis_ == 0 || !state_.IsEditMode()) {
        EndMoveGizmoDrag();
        return;
    }

    std::array<float, 3> position = viewportMoveDragStartPosition_;
    if (viewportActiveMoveAxis_ == kViewportMoveCenterHandle) {
        const CameraBasis camera =
            BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
        Vec3 currentPlanePoint;
        if (!ProjectMouseToViewPlane(localMouse, viewportSize, camera, MakeVec3(viewportMoveDragStartPosition_),
                                     &currentPlanePoint)) {
            return;
        }
        const Vec3 delta = currentPlanePoint - MakeVec3(viewportMoveDragStartPlanePoint_);
        position = {
            viewportMoveDragStartPosition_[0] + delta.x,
            viewportMoveDragStartPosition_[1] + delta.y,
            viewportMoveDragStartPosition_[2] + delta.z,
        };
    } else {
        const float currentAxisT = ProjectMouseToMoveAxis(viewportActiveMoveAxis_, localMouse, viewportSize);
        const float delta = currentAxisT - viewportMoveDragStartAxisT_;
        const Vec3 axisDirection = AxisVectorForEntity(*selected, viewportActiveMoveAxis_, viewportTransformLocal_);
        position = {
            viewportMoveDragStartPosition_[0] + axisDirection.x * delta,
            viewportMoveDragStartPosition_[1] + axisDirection.y * delta,
            viewportMoveDragStartPosition_[2] + axisDirection.z * delta,
        };
    }

    if (viewportSnapEnabled_ || ImGui::GetIO().KeyCtrl) {
        const float kSnapStep = std::clamp(viewportSnapStep_, 0.01f, 100.0f);
        for (float& value : position) {
            value = std::round(value / kSnapStep) * kSnapStep;
        }
    }

    if (!NearlyEqual(position[0], selected->position[0]) || !NearlyEqual(position[1], selected->position[1]) ||
        !NearlyEqual(position[2], selected->position[2])) {
        state_.SetEntityTransform(selected->id, &position, nullptr, nullptr);
        viewportMoveDragMoved_ = true;
    }
}

void EditorApp::EndMoveGizmoDrag() {
    if (viewportActiveMoveAxis_ != 0 && viewportMoveDragMoved_) {
        const Entity* selected = state_.FindEntity(viewportMoveDragEntityId_);
        if (selected != nullptr) {
            state_.AddActivity("scene.move", "Complete",
                               selected->name + " moved on " + AxisLabel(viewportActiveMoveAxis_) + " axis.");
        }
    }

    viewportActiveMoveAxis_ = 0;
    viewportHotMoveAxis_ = 0;
    viewportMoveDragEntityId_ = 0;
    viewportMoveDragStartAxisT_ = 0.0f;
    viewportMoveDragMoved_ = false;
    viewportMoveDragStartPlanePoint_ = {0.0f, 0.0f, 0.0f};
}

void EditorApp::DrawWorkspacePanel(EditorPanelInstance& panel) {
    if (!panel.open) {
        return;
    }

    switch (panel.kind) {
    case EditorPanelKind::Scene:
        DrawViewportPanel(panel);
        break;
    case EditorPanelKind::Game:
        DrawGameViewportPanel(panel);
        break;
    case EditorPanelKind::Hierarchy:
        DrawHierarchyPanel(panel);
        break;
    case EditorPanelKind::Inspector:
        DrawInspectorPanel(panel);
        break;
    case EditorPanelKind::Console:
        DrawConsolePanel(panel);
        break;
    case EditorPanelKind::Agent:
        DrawAIChatPanel(panel);
        break;
    case EditorPanelKind::Terrain:
        DrawTerrainPanel(panel);
        break;
    case EditorPanelKind::Lighting:
        DrawLightingPanel(panel);
        break;
    case EditorPanelKind::ProjectSource:
        DrawProjectTreePanel(panel);
        break;
    case EditorPanelKind::Profiler:
        DrawProfilerPanel(panel);
        break;
    }
}

void EditorApp::DrawViewportPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.SceneView");
    if (!BeginPanel(panel, ImVec2(560.0f, 360.0f))) {
        ImGui::End();
        return;
    }

    DrawViewportToolbar();

    ImVec2 canvasSize = ImGui::GetContentRegionAvail();
    canvasSize.x = std::max(canvasSize.x, 1.0f);
    canvasSize.y = std::max(canvasSize.y, 1.0f);
    const int renderWidth = std::max(1, static_cast<int>(std::round(canvasSize.x)));
    const int renderHeight = std::max(1, static_cast<int>(std::round(canvasSize.y)));
    RenderViewportScene(renderWidth, renderHeight);

    const ImVec2 canvasPos = ImGui::GetCursorScreenPos();
    const ImVec2 canvasMax(canvasPos.x + canvasSize.x, canvasPos.y + canvasSize.y);
    ImDrawList* drawList = ImGui::GetWindowDrawList();
    if (viewportFramebufferComplete_ && viewportColorTexture_ != 0) {
        drawList->AddImage((ImTextureID)(intptr_t)viewportColorTexture_, canvasPos, canvasMax, ImVec2(0.0f, 1.0f),
                           ImVec2(1.0f, 0.0f));
    } else {
        drawList->AddRectFilled(canvasPos, canvasMax, ColorU32(WindowBackgroundColor()));
        drawList->AddText(ImVec2(canvasPos.x + Scaled(16.0f), canvasPos.y + Scaled(14.0f)),
                          ColorU32(BrightTextColor()), "Scene framebuffer unavailable");
    }

    ImGui::InvisibleButton("viewport_canvas", canvasSize,
                           ImGuiButtonFlags_MouseButtonLeft | ImGuiButtonFlags_MouseButtonRight |
                               ImGuiButtonFlags_MouseButtonMiddle);
    {
        PerformanceScope tickScope(&profiler_, PerformanceDomain::Editor, "EditorSceneView.Tick");
        HandleViewportInput(canvasPos, canvasSize);
    }

    drawList->AddRect(canvasPos, canvasMax, ColorU32(OffsetColor(PanelBackgroundColor(), 0.16f)), Scaled(3.0f));
    const Entity* selected = state_.FindEntity(state_.SelectedEntityId());
    const char* selectedName = selected == nullptr ? "None" : selected->name.c_str();
    const char* cameraModeLabel = viewportCameraMode_ == 1 ? "Fly" : "Orbit";
    const ImVec2 overlayPos(canvasPos.x + Scaled(14.0f), canvasPos.y + Scaled(12.0f));
    drawList->AddText(overlayPos, ColorU32(BrightTextColor()), selectedName);
    drawList->AddText(ImVec2(overlayPos.x, overlayPos.y + Scaled(22.0f)), ColorU32(MutedTextColor()),
                      cameraModeLabel);

    ImGui::End();
}

void EditorApp::DrawGameViewportPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.GameView");
    if (focusGameViewportNextFrame_) {
        ImGui::SetNextWindowFocus();
        focusGameViewportNextFrame_ = false;
    }

    if (!BeginPanel(panel, ImVec2(520.0f, 300.0f))) {
        ImGui::End();
        return;
    }
    const bool gameWindowFocused = ImGui::IsWindowFocused(ImGuiFocusedFlags_RootAndChildWindows);
    if (!state_.IsPlaying()) {
        gameViewportInputActive_ = false;
    } else if (gameWindowFocused) {
        gameViewportInputActive_ = true;
    }

    const Entity* cameraEntity = nullptr;
    for (const Entity& entity : state_.Entities()) {
        if (HasEnabledComponentType(state_, entity, "Camera")) {
            cameraEntity = &entity;
            break;
        }
    }

    const float headerHeight = Scaled(30.0f);
    ImGui::PushStyleColor(ImGuiCol_ChildBg, ScaleColor(PanelBackgroundColor(), 0.88f));
    ImGui::PushStyleVar(ImGuiStyleVar_WindowPadding, ImVec2(Scaled(6.0f), Scaled(3.0f)));
    ImGui::PushStyleVar(ImGuiStyleVar_ItemSpacing, ImVec2(Scaled(5.0f), 0.0f));
    ImGui::BeginChild("##game_view_header", ImVec2(0.0f, headerHeight), true,
                      ImGuiWindowFlags_NoScrollbar | ImGuiWindowFlags_NoScrollWithMouse);
    DrawToolbarText("Game", BrightTextColor());
    ImGui::SameLine();
    const std::string cameraLabel = cameraEntity != nullptr ? TruncateForUi(cameraEntity->name, 18) : "No Camera";
    DrawToolbarStatusDot(cameraLabel.c_str(),
                         cameraEntity != nullptr ? AccentColor() : ImVec4(0.82f, 0.42f, 0.42f, 1.0f));
    ImGui::SameLine();
    DrawToolbarStatusDot(state_.PlayStateLabel(), PlayStateColor(state_.PlayState()));
    if (ImGui::GetWindowWidth() > Scaled(580.0f)) {
        ImGui::SameLine();
        DrawToolbarStatusDot(gameViewportInputActive_ ? "Input Active" : "Input Idle",
                             gameViewportInputActive_ ? ImVec4(0.34f, 0.66f, 0.40f, 1.0f)
                                                      : ImVec4(0.52f, 0.54f, 0.57f, 1.0f));
    }
    if (ImGui::GetWindowWidth() > Scaled(720.0f)) {
        const float playControlsX =
            std::max(ImGui::GetCursorPosX() + Scaled(12.0f), ImGui::GetWindowWidth() - Scaled(132.0f));
        ImGui::SameLine(playControlsX);
        DrawToolbarPlayModeControls("game_view_header");
    }
    ImGui::EndChild();
    ImGui::PopStyleVar(2);
    ImGui::PopStyleColor();

    ImVec2 canvasSize = ImGui::GetContentRegionAvail();
    canvasSize.x = std::max(canvasSize.x, 1.0f);
    canvasSize.y = std::max(canvasSize.y, 1.0f);
    const int renderWidth = std::max(1, static_cast<int>(std::round(canvasSize.x)));
    const int renderHeight = std::max(1, static_cast<int>(std::round(canvasSize.y)));
    RenderGameViewportScene(renderWidth, renderHeight);

    const ImVec2 canvasPos = ImGui::GetCursorScreenPos();
    const ImVec2 canvasMax(canvasPos.x + canvasSize.x, canvasPos.y + canvasSize.y);
    ImDrawList* drawList = ImGui::GetWindowDrawList();
    if (gameFramebufferComplete_ && gameColorTexture_ != 0) {
        drawList->AddImage((ImTextureID)(intptr_t)gameColorTexture_, canvasPos, canvasMax, ImVec2(0.0f, 1.0f),
                           ImVec2(1.0f, 0.0f));
    } else {
        drawList->AddRectFilled(canvasPos, canvasMax, ColorU32(WindowBackgroundColor()));
        drawList->AddText(ImVec2(canvasPos.x + Scaled(16.0f), canvasPos.y + Scaled(14.0f)),
                          ColorU32(BrightTextColor()), "Game framebuffer unavailable");
    }
    drawList->AddRect(canvasPos, canvasMax, ColorU32(OffsetColor(PanelBackgroundColor(), 0.14f)), Scaled(3.0f));

    if (cameraEntity == nullptr) {
        std::string playOverlay = std::string(state_.PlayStateLabel()) +
                                  " | t=" + FormatElapsedTime(state_.PlayElapsedSeconds()) +
                                  " | score=" + std::to_string(state_.PlayScore());
        if (state_.PlayGoalReached()) {
            playOverlay += " | goal";
        } else if (state_.PlayFailed()) {
            playOverlay += " | failed";
        }
        drawList->AddText(ImVec2(canvasPos.x + Scaled(14.0f), canvasPos.y + Scaled(12.0f)),
                          ColorU32(BrightTextColor()), playOverlay.c_str());
        drawList->AddText(ImVec2(canvasPos.x + Scaled(16.0f), canvasPos.y + Scaled(42.0f)),
                          IM_COL32(232, 180, 180, 255), "Add a Camera component to preview gameplay.");
    } else {
        const std::string overlay = "Camera: " + cameraEntity->name +
                                    " | Renderables: " +
                                    std::to_string(gameLastRenderedCubeCount_ + gameLastRenderedSpriteCount_);
        drawList->AddText(ImVec2(canvasPos.x + Scaled(14.0f), canvasPos.y + Scaled(12.0f)),
                          ColorU32(BrightTextColor()), overlay.c_str());
        std::string playOverlay = std::string(state_.PlayStateLabel()) +
                                  " | t=" + FormatElapsedTime(state_.PlayElapsedSeconds()) +
                                  " | score=" + std::to_string(state_.PlayScore());
        if (state_.PlayGoalReached()) {
            playOverlay += " | goal";
        } else if (state_.PlayFailed()) {
            playOverlay += " | failed";
        }
        drawList->AddText(ImVec2(canvasPos.x + Scaled(14.0f), canvasPos.y + Scaled(34.0f)),
                          ColorU32(MutedTextColor()), playOverlay.c_str());
    }

    const RuntimeInputState& runtimeInput = state_.RuntimeInput();
    std::ostringstream inputOverlay;
    inputOverlay << "Controlled: ";
    const std::string controlledName = state_.ControlledRuntimeEntityName();
    inputOverlay << (controlledName.empty() ? "None" : controlledName);
    inputOverlay << " | Move " << runtimeInput.character.moveX << ", " << runtimeInput.character.moveZ;
    inputOverlay << " | Sprint " << (runtimeInput.character.sprint ? "On" : "Off");
    drawList->AddText(ImVec2(canvasPos.x + Scaled(14.0f), canvasPos.y + Scaled(58.0f)),
                      ColorU32(MutedTextColor()), inputOverlay.str().c_str());
    const std::string runtimeOverlay = "Runtime: " + state_.RuntimeStatus() +
                                       (state_.LastRuntimeSystemSummary().empty()
                                            ? ""
                                            : " | " + state_.LastRuntimeSystemSummary());
    drawList->AddText(ImVec2(canvasPos.x + Scaled(14.0f), canvasPos.y + Scaled(80.0f)),
                      ColorU32(MutedTextColor()), runtimeOverlay.c_str());

    const std::vector<RuntimeLogEntry>& runtimeLogs = state_.RuntimeLogs();
    if (!runtimeLogs.empty() && !state_.IsEditMode()) {
        const size_t maxOverlayEntries = std::min<size_t>(runtimeLogs.size(), 4);
        const size_t firstEntry = runtimeLogs.size() - maxOverlayEntries;
        float lineY = canvasPos.y + Scaled(104.0f);
        const float lineHeight = ImGui::GetTextLineHeight() + Scaled(2.0f);
        for (size_t index = firstEntry; index < runtimeLogs.size(); ++index) {
            if (lineY + lineHeight > canvasMax.y - Scaled(8.0f)) {
                break;
            }
            const RuntimeLogEntry& entry = runtimeLogs[index];
            std::ostringstream line;
            line << FormatElapsedTime(entry.elapsedSeconds) << " " << entry.event << " " << entry.status;
            if (!entry.detail.empty()) {
                line << ": " << entry.detail;
            }
            drawList->AddText(ImVec2(canvasPos.x + Scaled(14.0f), lineY), ColorU32(LogColor(entry.level)),
                              line.str().c_str());
            lineY += lineHeight;
        }
    }

    const bool uiClickHandled = DrawGameRuntimeUiOverlay(drawList, canvasPos, canvasSize, true);

    ImGui::InvisibleButton("game_view_canvas", canvasSize,
                           ImGuiButtonFlags_MouseButtonLeft | ImGuiButtonFlags_MouseButtonRight |
                               ImGuiButtonFlags_MouseButtonMiddle);
    if (state_.IsPlaying() && !uiClickHandled &&
        (ImGui::IsItemClicked(ImGuiMouseButton_Left) || ImGui::IsItemClicked(ImGuiMouseButton_Right) ||
         ImGui::IsItemClicked(ImGuiMouseButton_Middle))) {
        gameViewportInputActive_ = true;
        ImGui::SetWindowFocus();
    }
    ImGui::End();
}

bool EditorApp::DrawGameRuntimeUiOverlay(ImDrawList* drawList, ImVec2 canvasPos, ImVec2 canvasSize,
                                         bool handleClicks) {
    struct RuntimeUiDrawItem {
        int entityId = 0;
        int order = 0;
        const Entity* entity = nullptr;
        const Component* component = nullptr;
    };

    std::vector<RuntimeUiDrawItem> items;
    for (const Entity& entity : state_.Entities()) {
        if (!state_.IsEntityActiveInHierarchy(entity.id)) {
            continue;
        }
        for (const Component& component : entity.components) {
            if (!IsRuntimeUiRenderableType(component.type) || !RuntimeUiComponentVisible(component)) {
                continue;
            }
            items.push_back({entity.id, ComponentIntForUi(component, "order", 0), &entity, &component});
        }
    }

    std::sort(items.begin(), items.end(), [](const RuntimeUiDrawItem& left, const RuntimeUiDrawItem& right) {
        return left.order == right.order ? left.entityId < right.entityId : left.order < right.order;
    });

    gameLastRenderedUiElementCount_ = 0;
    const float uiScale = RuntimeUiReferenceScale(state_, canvasSize);
    const ImVec2 mouse = ImGui::GetMousePos();
    const bool leftClicked = handleClicks && state_.IsPlaying() && ImGui::IsMouseClicked(ImGuiMouseButton_Left);
    std::string clickedAction;

    for (const RuntimeUiDrawItem& item : items) {
        ImVec2 rectMin;
        ImVec2 rectMax;
        if (item.entity == nullptr || item.component == nullptr ||
            !ResolveRuntimeUiRect(state_, *item.entity, *item.component, canvasPos, canvasSize, uiScale, &rectMin,
                                  &rectMax)) {
            continue;
        }

        const bool isCanvas = item.component->type == "UICanvasRuntime";
        const bool isButton = item.component->type == "UIButtonRuntime";
        const bool hovered = isButton && handleClicks && state_.IsPlaying() && PointInRect(mouse, rectMin, rectMax);
        ImVec4 color = ComponentColorForUi(*item.component, "color", ImVec4(0.10f, 0.12f, 0.14f, 0.82f));
        if (hovered) {
            color = MixColor(color, BrightTextColor(), 0.08f);
        }

        if (drawList != nullptr) {
            if (!isCanvas || color.w > 0.001f) {
                if (item.component->type == "UIPanelRuntime" || item.component->type == "UIButtonRuntime" ||
                    item.component->type == "UIBoxRuntime" || item.component->type == "UIImageRuntime" ||
                    color.w > 0.001f) {
                    drawList->AddRectFilled(rectMin, rectMax, ColorU32(color), Scaled(isButton ? 4.0f : 3.0f));
                    drawList->AddRect(rectMin, rectMax,
                                      ColorU32(WithAlpha(OffsetColor(color, 0.18f), isButton ? 0.95f : 0.52f)),
                                      Scaled(isButton ? 4.0f : 3.0f));
                }
            }

            if (item.component->type == "UITextRuntime" || item.component->type == "UIButtonRuntime") {
                const std::string text = ComponentPropertyValue(*item.component, "text");
                if (!text.empty()) {
                    const ImVec4 textColor =
                        item.component->type == "UIButtonRuntime"
                            ? ComponentColorForUi(*item.component, "textColor", BrightTextColor())
                            : ComponentColorForUi(*item.component, "color", BrightTextColor());
                    const float fontSize =
                        std::max(10.0f, ComponentFloatForUi(*item.component, "fontSize", 20.0f) * uiScale);
                    const std::string align = ToLower(ComponentPropertyValue(*item.component, "align"));
                    const ImVec2 textSize = ImGui::GetFont()->CalcTextSizeA(fontSize, FLT_MAX, 0.0f, text.c_str());
                    float textX = rectMin.x + Scaled(8.0f);
                    if (align.empty() || align == "center" || item.component->type == "UIButtonRuntime") {
                        textX = rectMin.x + std::max(0.0f, (rectMax.x - rectMin.x - textSize.x) * 0.5f);
                    } else if (align == "right") {
                        textX = rectMax.x - textSize.x - Scaled(8.0f);
                    }
                    const float textY = rectMin.y + std::max(0.0f, (rectMax.y - rectMin.y - textSize.y) * 0.5f);
                    drawList->AddText(ImGui::GetFont(), fontSize, ImVec2(textX, textY), ColorU32(textColor),
                                      text.c_str());
                }
            }
        }

        if (!isCanvas || color.w > 0.001f) {
            ++gameLastRenderedUiElementCount_;
        }
        if (hovered && leftClicked) {
            clickedAction = ComponentPropertyValue(*item.component, "action");
        }
    }

    if (options_.smokeTestRuntimeUi && gameLastRenderedUiElementCount_ >= 3) {
        runtimeUiSmokeVerifiedOverlay_ = true;
    }
    return !clickedAction.empty() && ExecuteRuntimeUIButtonAction(clickedAction);
}

bool EditorApp::ExecuteRuntimeUIButtonAction(const std::string& action) {
    const std::string normalized = ToLower(action);
    if (normalized.empty() || normalized == "none") {
        return false;
    }

    if (normalized == "restart" || normalized == "reset" || normalized == "resetgame" ||
        normalized == "restartgame" || normalized == "restartrun") {
        StopPlayMode();
        StartOrResumePlayMode();
        gameViewportInputActive_ = false;
        state_.AddActivity("ui.button", "Restart", action);
        state_.AddLog(LogLevel::Info, "Runtime UI button executed action: " + action + ".");
        return true;
    }

    if (normalized.rfind("script:", 0) == 0) {
        const std::string method = action.substr(std::string("script:").size());
        state_.AddActivity("ui.scriptCallback", "Invoked", method.empty() ? action : method);
        state_.AddLog(LogLevel::Info, "Runtime UI script callback invoked: " + action + ".");
        return true;
    }

    state_.AddActivity("ui.button", "Unhandled", action);
    state_.AddLog(LogLevel::Warning, "Runtime UI button action is not implemented: " + action + ".");
    return true;
}

void EditorApp::DrawHierarchyPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.Hierarchy");
    if (!BeginPanel(panel, ImVec2(240.0f, 280.0f))) {
        ImGui::End();
        return;
    }

    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::TextUnformatted(TruncateForUi(state_.SceneName(), 36).c_str());
    ImGui::PopStyleColor();
    ImGui::SameLine();
    ImGui::TextDisabled("%d entities", static_cast<int>(state_.Entities().size()));
    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Edit actions are disabled until Play Mode stops.");
    }

    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::BeginTable("hierarchy_actions", 3, ImGuiTableFlags_SizingStretchSame)) {
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        if (ImGui::SmallButton("Create Empty")) {
            Entity& entity = state_.CreateEntity("Empty Entity", {MakeTransformComponent()});
            state_.SelectEntity(entity.id);
            state_.AddLog(LogLevel::Info, "Created Empty Entity.");
        }
        ImGui::TableSetColumnIndex(1);
        if (ImGui::SmallButton("Camera")) {
            CreateCameraObject("Hierarchy");
        }
        ImGui::TableSetColumnIndex(2);
        if (ImGui::SmallButton("Starter")) {
            state_.SeedStarterScene();
        }
        ImGui::EndTable();
    }
    ImGui::EndDisabled();

    ImGui::Separator();
    ImGui::BeginChild("hierarchy_entities", ImVec2(0.0f, 0.0f), false);
    int pendingDeleteId = 0;
    int pendingCreateChildParentId = 0;
    bool pendingCreateCamera = false;
    int pendingUnparentId = 0;
    if (state_.Entities().empty()) {
        DrawEmptyState("Scene is empty.", "Create an entity or generate a starter scene.");
    } else {
        std::vector<int> drawStack;
        std::function<void(int)> drawEntityNode = [&](int entityId) {
            if (std::find(drawStack.begin(), drawStack.end(), entityId) != drawStack.end()) {
                return;
            }
            const Entity* entity = state_.FindEntity(entityId);
            if (entity == nullptr) {
                return;
            }

            drawStack.push_back(entityId);
            const std::vector<int> childIds = HierarchyChildIds(state_, entityId);
            const bool hasChildren = !childIds.empty();
            const bool activeInHierarchy = state_.IsEntityActiveInHierarchy(entityId);

            ImGui::PushID(entityId);
            bool active = entity->activeSelf;
            ImGui::PushStyleVar(ImGuiStyleVar_FramePadding, ImVec2(Scaled(2.0f), Scaled(2.0f)));
            ImGui::BeginDisabled(!state_.IsEditMode());
            if (ImGui::Checkbox("##hierarchy_active", &active)) {
                if (Entity* editable = state_.FindEntity(entityId)) {
                    editable->activeSelf = active;
                    state_.AddLog(LogLevel::Info, editable->name + (active ? " enabled from Hierarchy." : " disabled from Hierarchy."));
                }
            }
            ImGui::EndDisabled();
            ImGui::PopStyleVar();
            ImGui::SameLine();

            const bool cameraObject = HasComponentType(*entity, "Camera");
            if (cameraObject) {
                if (DrawCameraIconButton("##hierarchy_camera_icon",
                                         activeInHierarchy ? CameraGizmoColor() : MutedTextColor(),
                                         ImVec2(Scaled(17.0f), Scaled(17.0f)), "Camera")) {
                    state_.SelectEntity(entityId);
                }
                ImGui::SameLine(0.0f, Scaled(3.0f));
            }

            ImGuiTreeNodeFlags flags =
                ImGuiTreeNodeFlags_OpenOnArrow | ImGuiTreeNodeFlags_OpenOnDoubleClick |
                ImGuiTreeNodeFlags_SpanAvailWidth;
            if (!hasChildren) {
                flags |= ImGuiTreeNodeFlags_Leaf | ImGuiTreeNodeFlags_NoTreePushOnOpen;
            } else {
                flags |= ImGuiTreeNodeFlags_DefaultOpen;
            }
            if (entityId == state_.SelectedEntityId()) {
                flags |= ImGuiTreeNodeFlags_Selected;
            }
            if (!activeInHierarchy) {
                ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
            }
            const bool open = ImGui::TreeNodeEx("##entity_node", flags, "%s", entity->name.c_str());
            if (!activeInHierarchy) {
                ImGui::PopStyleColor();
            }
            if (ImGui::IsItemClicked()) {
                state_.SelectEntity(entityId);
            }
            if (state_.IsEditMode() && ImGui::BeginDragDropSource()) {
                ImGui::SetDragDropPayload(kHierarchyEntityDragPayload, &entityId, sizeof(entityId));
                ImGui::TextUnformatted(entity->name.c_str());
                ImGui::EndDragDropSource();
            }
            if (state_.IsEditMode() && ImGui::BeginDragDropTarget()) {
                if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload(kHierarchyEntityDragPayload)) {
                    if (payload->DataSize == sizeof(int)) {
                        const int draggedId = *static_cast<const int*>(payload->Data);
                        const Entity* dragged = state_.FindEntity(draggedId);
                        const Entity* parent = state_.FindEntity(entityId);
                        if (dragged != nullptr && parent != nullptr && state_.SetEntityParent(draggedId, entityId)) {
                            state_.AddLog(LogLevel::Info, "Parented " + dragged->name + " to " + parent->name + ".");
                        }
                    }
                }
                ImGui::EndDragDropTarget();
            }
            if (ImGui::BeginPopupContextItem()) {
                state_.SelectEntity(entityId);
                ImGui::TextUnformatted(entity->name.c_str());
                ImGui::Separator();
                if (ImGui::MenuItem("Focus in Scene", "F")) {
                    FocusSelectedEntity();
                }
                ImGui::BeginDisabled(!state_.IsEditMode());
                if (ImGui::MenuItem("Create Child")) {
                    pendingCreateChildParentId = entityId;
                }
                if (ImGui::MenuItem("Create Camera")) {
                    pendingCreateCamera = true;
                }
                ImGui::BeginDisabled(entity->parentId == 0);
                if (ImGui::MenuItem("Move To Root")) {
                    pendingUnparentId = entityId;
                }
                ImGui::EndDisabled();
                ImGui::Separator();
                if (ImGui::MenuItem("Add Mesh Placeholder")) {
                    state_.AddComponentToEntity(entityId, MakeMeshPlaceholderComponent("UnitCube"));
                    state_.AddLog(LogLevel::Info, "Added MeshRenderer placeholder to " + entity->name + ".");
                }
                if (ImGui::MenuItem("Add SpinRuntime")) {
                    AddSpinRuntimeToSelected("Hierarchy context menu");
                }
                ImGui::Separator();
                if (ImGui::MenuItem("Delete GameObject", "Del")) {
                    pendingDeleteId = entityId;
                }
                ImGui::EndDisabled();
                ImGui::EndPopup();
            }
            if (open && hasChildren) {
                for (int childId : childIds) {
                    drawEntityNode(childId);
                }
                ImGui::TreePop();
            }
            ImGui::PopID();
            drawStack.pop_back();
        };

        for (int rootId : HierarchyRootIds(state_)) {
            drawEntityNode(rootId);
        }

        ImGui::Dummy(ImVec2(ImGui::GetContentRegionAvail().x, Scaled(18.0f)));
        if (state_.IsEditMode() && ImGui::BeginDragDropTarget()) {
            if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload(kHierarchyEntityDragPayload)) {
                if (payload->DataSize == sizeof(int)) {
                    const int draggedId = *static_cast<const int*>(payload->Data);
                    const Entity* dragged = state_.FindEntity(draggedId);
                    if (dragged != nullptr && state_.SetEntityParent(draggedId, 0)) {
                        state_.AddLog(LogLevel::Info, "Moved " + dragged->name + " to the scene root.");
                    }
                }
            }
            ImGui::EndDragDropTarget();
        }
    }
    if (pendingCreateChildParentId != 0) {
        const Entity* parent = state_.FindEntity(pendingCreateChildParentId);
        const std::string parentName = parent == nullptr ? std::string{} : parent->name;
        Entity& child = state_.CreateEntity("Child Entity", {MakeTransformComponent()});
        state_.SetEntityParent(child.id, pendingCreateChildParentId);
        state_.SelectEntity(child.id);
        state_.AddLog(LogLevel::Info, parentName.empty() ? "Created child entity."
                                                         : "Created child entity under " + parentName + ".");
    }
    if (pendingCreateCamera) {
        CreateCameraObject("Hierarchy context menu");
    }
    if (pendingUnparentId != 0) {
        const Entity* entity = state_.FindEntity(pendingUnparentId);
        const std::string entityName = entity == nullptr ? std::string{"Entity"} : entity->name;
        if (state_.SetEntityParent(pendingUnparentId, 0)) {
            state_.AddLog(LogLevel::Info, "Moved " + entityName + " to the scene root.");
        }
    }
    if (pendingDeleteId != 0) {
        state_.SelectEntity(pendingDeleteId);
        DeleteSelectedEntity("Hierarchy context menu");
    }
    ImGui::EndChild();

    ImGui::End();
}

void EditorApp::DrawInspectorPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.Inspector");
    if (!BeginPanel(panel, ImVec2(360.0f, 300.0f))) {
        ImGui::End();
        return;
    }

    Entity* selected = state_.FindEntity(state_.SelectedEntityId());
    if (selected == nullptr) {
        DrawEmptyState("No entity selected.", "Select an entity in the scene hierarchy or viewport to inspect its transform and components.");
        ImGui::End();
        return;
    }

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Inspector edits are disabled during Play Mode; runtime changes will be restored on Stop.");
    }
    if (inspectorNameEntityId_ != selected->id || inspectorNameCommittedValue_ != selected->name) {
        inspectorNameEntityId_ = selected->id;
        inspectorNameCommittedValue_ = selected->name;
        inspectorNameStatus_.clear();
        CopyStringToBuffer(inspectorNameInput_, selected->name);
    }

    ImGui::Dummy(ImVec2(0.0f, ImGui::GetStyle().ItemSpacing.y * 0.35f));
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (HasComponentType(*selected, "Camera")) {
        DrawInspectorCameraIcon(CameraGizmoColor(), ImVec2(Scaled(24.0f), Scaled(21.0f)));
    } else {
        DrawInspectorObjectIcon(AccentColor(), ImVec2(Scaled(21.0f), Scaled(21.0f)));
    }
    ImGui::SameLine();
    bool activeSelf = selected->activeSelf;
    if (ImGui::Checkbox("##entity_active", &activeSelf)) {
        selected->activeSelf = activeSelf;
        state_.AddLog(LogLevel::Info, selected->name + (activeSelf ? " enabled." : " disabled."));
    }
    ImGui::SameLine();
    const float staticWidth = Scaled(96.0f);
    const float nameWidth = std::max(Scaled(120.0f), ImGui::GetContentRegionAvail().x - staticWidth - ImGui::GetStyle().ItemSpacing.x);
    ImGui::SetNextItemWidth(nameWidth);
    const bool enterCommitted = ImGui::InputText("##inspector_name", inspectorNameInput_.data(),
                                                 inspectorNameInput_.size(), ImGuiInputTextFlags_EnterReturnsTrue);
    const bool nameEditFinished = enterCommitted || ImGui::IsItemDeactivatedAfterEdit();
    if (nameEditFinished) {
        RenameSelectedEntityFromInspector(inspectorNameInput_.data());
    }
    ImGui::SameLine();
    bool isStatic = selected->isStatic;
    if (ImGui::Checkbox("Static", &isStatic)) {
        selected->isStatic = isStatic;
    }
    ImGui::EndDisabled();
    if (!inspectorNameStatus_.empty()) {
        DrawMutedWrapped(inspectorNameStatus_);
    }

    ImGui::PushStyleColor(ImGuiCol_TableRowBg, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.012f), 0.46f));
    ImGui::PushStyleColor(ImGuiCol_TableRowBgAlt, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.024f), 0.54f));
    if (ImGui::BeginTable("entity_tag_layer", 4,
                          ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp | ImGuiTableFlags_PadOuterX)) {
        ImGui::TableSetupColumn("TagLabel", ImGuiTableColumnFlags_WidthFixed, Scaled(42.0f));
        ImGui::TableSetupColumn("TagValue", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableSetupColumn("LayerLabel", ImGuiTableColumnFlags_WidthFixed, Scaled(48.0f));
        ImGui::TableSetupColumn("LayerValue", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        DrawInspectorFieldLabel("Tag");
        ImGui::TableSetColumnIndex(1);
        ImGui::BeginDisabled(!state_.IsEditMode());
        if (DrawStringCombo("##entity_tag", selected->tag, state_.ProjectTags(), "Untagged")) {
            state_.MarkSceneDirty("Entity tag changed");
        }
        ImGui::EndDisabled();

        ImGui::TableSetColumnIndex(2);
        DrawInspectorFieldLabel("Layer");
        ImGui::TableSetColumnIndex(3);
        ImGui::BeginDisabled(!state_.IsEditMode());
        if (DrawStringCombo("##entity_layer", selected->layer, state_.ProjectLayers(), "Default")) {
            state_.MarkSceneDirty("Entity layer changed");
        }
        ImGui::EndDisabled();
        ImGui::EndTable();
    }
    ImGui::PopStyleColor(2);

    ImGui::Spacing();
    std::string pendingRemoveComponentType;
    for (size_t componentIndex = 0; componentIndex < selected->components.size(); ++componentIndex) {
        Component& component = selected->components[componentIndex];
        if (DrawComponentHeader(component, componentIndex, state_.IsEditMode())) {
            const ComponentSchema* schema = FindRuntimeSchema(component.type);
            const bool componentEnabled = component.type == "Transform" || ComponentBoolForUi(component, "enabled", true);
            ImGui::BeginDisabled(!state_.IsEditMode() || !componentEnabled);
            if (component.type == "Transform") {
                std::array<float, 3> position = selected->position;
                std::array<float, 3> rotation = selected->rotation;
                std::array<float, 3> scale = selected->scale;
                bool transformChanged = false;
                if (BeginInspectorPropertyTable("transform_properties")) {
                    transformChanged = DrawInspectorVec3Row("Position", position) || transformChanged;
                    transformChanged = DrawInspectorVec3Row("Rotation", rotation) || transformChanged;
                    transformChanged = DrawInspectorVec3Row("Scale", scale) || transformChanged;
                    EndInspectorPropertyTable();
                }
                if (transformChanged) {
                    state_.SetEntityTransform(selected->id, &position, &rotation, &scale);
                }
            } else {
                if (component.type == "Terrain") {
                    DrawTerrainInspectorBody(&component);
                } else if (component.type == "CaveVolume") {
                    DrawCaveVolumeInspectorBody(&component);
                } else {
                    DrawComponentPropertyBody(component, schema);
                }
                if (IsPhysicsComponentType(component.type) && component.type != "PhysicsSettings") {
                    if (ImGui::SmallButton(("Remove " + HumanizeIdentifier(component.type)).c_str())) {
                        pendingRemoveComponentType = component.type;
                    }
                }
            }
            ImGui::EndDisabled();
            ImGui::TreePop();
        }
    }
    if (!pendingRemoveComponentType.empty() &&
        state_.RemoveComponentFromEntity(selected->id, pendingRemoveComponentType)) {
        state_.AddLog(LogLevel::Info, "Removed " + pendingRemoveComponentType + " from " + selected->name + ".");
    }

    ImGui::Spacing();
    ImGui::BeginDisabled(!state_.IsEditMode());
    const float addComponentButtonWidth = Scaled(228.0f);
    const float addComponentButtonX =
        ImGui::GetCursorPosX() + std::max(0.0f, (ImGui::GetContentRegionAvail().x - addComponentButtonWidth) * 0.5f);
    ImGui::SetCursorPosX(addComponentButtonX);
    if (ImGui::Button("Add Component", ImVec2(addComponentButtonWidth, 0.0f))) {
        std::fill(addComponentSearchInput_.begin(), addComponentSearchInput_.end(), '\0');
        ImGui::OpenPopup("add_component_popup");
    }
    DrawAddComponentPopup(state_, *selected, addComponentSearchInput_);
    ImGui::EndDisabled();

    ImGui::End();
}

void EditorApp::DrawTerrainPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.TerrainPanel");
    if (!BeginPanel(panel, ImVec2(360.0f, 300.0f))) {
        ImGui::End();
        return;
    }

    ImGui::PushStyleColor(ImGuiCol_Text, AccentColor());
    ImGui::TextUnformatted("Terrain / Caves Browser");
    ImGui::PopStyleColor();
    ImGui::Separator();

    DrawTerrainCreateSection();

    Entity* selected = state_.FindEntity(state_.SelectedEntityId());
    Component* terrainComponent = selected == nullptr ? nullptr : FindTerrainComponent(*selected);
    Component* caveComponent = selected == nullptr ? nullptr : FindCaveVolumeComponent(*selected);
    if (terrainComponent != nullptr) {
        ImGui::Spacing();
        DrawStatusBadge("Selected Terrain", ImVec4(0.54f, 0.66f, 0.86f, 1.0f));
        ImGui::SameLine();
        DrawMutedWrapped(selected->name);
        if (ImGui::Button("Edit In Inspector", ImVec2(-1.0f, 0.0f))) {
            ImGui::SetWindowFocus("Inspector");
        }
    }
    if (caveComponent != nullptr) {
        ImGui::Spacing();
        DrawStatusBadge("Selected Cave", ImVec4(0.54f, 0.66f, 0.86f, 1.0f));
        ImGui::SameLine();
        DrawMutedWrapped(selected->name);
        if (ImGui::Button("Edit Cave In Inspector", ImVec2(-1.0f, 0.0f))) {
            ImGui::SetWindowFocus("Inspector");
        }
    }

    ImGui::Spacing();
    if (ImGui::BeginChild("terrain_entity_list", ImVec2(0.0f, Scaled(170.0f)), true)) {
        bool any = false;
        for (const Entity& entity : state_.Entities()) {
            const bool hasTerrain = HasTerrain(state_, entity);
            const bool hasCave = HasCaveVolume(state_, entity);
            if (!hasTerrain && !hasCave) {
                continue;
            }
            any = true;
            const std::string label = std::string(hasCave ? "[Legacy Cave] " : "[Terrain] ") + entity.name;
            if (ImGui::Selectable(label.c_str(), entity.id == state_.SelectedEntityId())) {
                state_.SelectEntity(entity.id);
                sceneToolMode_ = hasCave ? 4 : 2;
                terrainToolActive_ = hasTerrain && !hasCave;
                caveToolActive_ = hasCave;
                ImGui::SetWindowFocus("Inspector");
            }
        }
        if (!any) {
            ImGui::TextDisabled("No Terrain or terrain volume in the current scene.");
        }
    }
    ImGui::EndChild();

    ImGui::End();
}

void EditorApp::DrawTerrainCreateSection() {
    if (!ImGui::CollapsingHeader("Create Terrain / Volume", ImGuiTreeNodeFlags_DefaultOpen)) {
        return;
    }
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::Button("Create Terrain", ImVec2(Scaled(140.0f), 0.0f))) {
        CreateTerrainTemplate("Terrain panel");
    }
    AttachTooltip("Creates a heightfield Terrain GameObject for outdoor ground.");
    ImGui::SameLine();
    if (ImGui::Button("Create Volume", ImVec2(Scaled(120.0f), 0.0f))) {
        CreateCaveVolumeTemplate("Terrain panel");
    }
    AttachTooltip("Creates a Terrain GameObject with embedded density data for tunnels, ceilings, and overhangs.");
    ImGui::SameLine();
    if (ImGui::Button("Inspector", ImVec2(Scaled(96.0f), 0.0f))) {
        ImGui::SetWindowFocus("Inspector");
    }
    ImGui::EndDisabled();
}

void EditorApp::DrawTerrainInspectorBody(Component* terrainComponent) {
    if (terrainComponent == nullptr) {
        return;
    }
    TerrainData data;
    if (!LoadTerrainDataFromComponentCached(state_.SelectedEntityId(), *terrainComponent, &data)) {
        ImGui::TextDisabled("Terrain data could not be loaded.");
        DrawComponentPropertyBody(*terrainComponent, FindRuntimeSchema(terrainComponent->type));
        return;
    }

    ImGui::Spacing();
    DrawStatusBadge(TerrainBackendLabel(data.backend),
                    TerrainUsesVolumetric(data) ? ImVec4(0.54f, 0.66f, 0.86f, 1.0f)
                                                : ComponentAccentColor(*terrainComponent));
    ImGui::SameLine();
    DrawStatusBadge(("Resolution " + std::to_string(data.resolution)).c_str(), ComponentAccentColor(*terrainComponent));
    ImGui::SameLine();
    DrawStatusBadge(("Chunks " + std::to_string(TerrainChunkCountX(data) * TerrainChunkCountZ(data))).c_str(),
                    ImVec4(0.60f, 0.64f, 0.64f, 1.0f));
    ImGui::SameLine();
    DrawStatusBadge((std::to_string(data.layers.size()) + " Layers").c_str(), ImVec4(0.54f, 0.66f, 0.86f, 1.0f));
    if (state_.IsSceneDirty()) {
        ImGui::SameLine();
        DrawStatusBadge("Unsaved", ImVec4(1.0f, 0.74f, 0.30f, 1.0f));
    }

    ImGui::Spacing();
    const float buttonWidth = std::max(Scaled(66.0f),
                                       (ImGui::GetContentRegionAvail().x - ImGui::GetStyle().ItemSpacing.x * 2.0f) /
                                           3.0f);
    if (DrawToolbarButton("Select##terrain_inspector_tool_select", "Use normal GameObject selection",
                          ImVec2(buttonWidth, ImGui::GetFrameHeight()), true, sceneToolMode_ == 0)) {
        sceneToolMode_ = 0;
        terrainToolActive_ = false;
        caveToolActive_ = false;
    }
    ImGui::SameLine();
    if (DrawToolbarButton("Sculpt##terrain_inspector_tool_sculpt", "Sculpt this Terrain in the Scene view",
                          ImVec2(buttonWidth, ImGui::GetFrameHeight()), true, sceneToolMode_ == 2)) {
        sceneToolMode_ = 2;
        terrainToolActive_ = true;
        caveToolActive_ = false;
        if (terrainBrushMode_ == static_cast<int>(TerrainBrushMode::Paint)) {
            terrainBrushMode_ = static_cast<int>(TerrainBrushMode::RaiseLower);
        }
    }
    ImGui::SameLine();
    if (DrawToolbarButton("Paint##terrain_inspector_tool_paint", "Paint this Terrain's layer weights",
                          ImVec2(buttonWidth, ImGui::GetFrameHeight()), true, sceneToolMode_ == 3)) {
        sceneToolMode_ = 3;
        terrainToolActive_ = true;
        caveToolActive_ = false;
        terrainBrushMode_ = static_cast<int>(TerrainBrushMode::Paint);
    }

    ImGui::Checkbox("Brush Preview", &terrainBrushPreviewVisible_);
    AttachTooltip("Shows the brush radius at the terrain hit point in the Scene view.");
    ImGui::SameLine();
    DrawStatusBadge(terrainToolActive_ && (sceneToolMode_ == 2 || sceneToolMode_ == 3) ? "Scene Tool Active" : "Scene Tool Idle",
                    terrainToolActive_ && (sceneToolMode_ == 2 || sceneToolMode_ == 3)
                        ? ImVec4(0.54f, 0.66f, 0.86f, 1.0f)
                        : ImVec4(0.58f, 0.60f, 0.63f, 1.0f));

    if (TerrainUsesHeightfield(data)) {
        DrawTerrainSculptSection(terrainComponent);
        DrawTerrainPaintSection(terrainComponent);
        DrawTerrainVolumeSection(terrainComponent);
    } else {
        DrawTerrainVolumeSection(terrainComponent);
    }
    DrawTerrainSettingsSection(terrainComponent);
}

void EditorApp::DrawTerrainSculptSection(Component* terrainComponent) {
    (void)terrainComponent;
    if (!ImGui::CollapsingHeader("Sculpt##terrain_sculpt_section", ImGuiTreeNodeFlags_DefaultOpen)) {
        return;
    }
    const char* modes[] = {"Raise/Lower", "Flatten", "Smooth", "Set Height", "Noise", "Hole Cut/Fill"};
    int sculptMode = terrainBrushMode_ == static_cast<int>(TerrainBrushMode::Hole)
                         ? 5
                         : std::clamp(terrainBrushMode_, 0, 4);
    SetNextInlineLabeledItemWidth("Brush");
    if (ImGui::Combo("Brush", &sculptMode, modes, IM_ARRAYSIZE(modes))) {
        terrainBrushMode_ = sculptMode == 5 ? static_cast<int>(TerrainBrushMode::Hole) : sculptMode;
        terrainToolActive_ = true;
        sceneToolMode_ = 2;
    }
    AttachTooltip("Raise/Lower sculpts height, Flatten averages toward the clicked area, Smooth softens height changes, Set Height moves toward Target Height, Noise roughens the surface, and Hole Cut/Fill opens clean terrain holes.");
    const char* falloffs[] = {"Smooth", "Linear", "Constant", "Bell"};
    SetNextInlineLabeledItemWidth("Falloff");
    ImGui::Combo("Falloff", &terrainFalloff_, falloffs, IM_ARRAYSIZE(falloffs));
    AttachTooltip("Controls how strongly the brush fades from the center to the outer radius.");
    SetNextInlineLabeledItemWidth("Radius");
    ImGui::SliderFloat("Radius", &terrainBrushRadius_, 0.25f, 16.0f, "%.2f");
    AttachTooltip("World-space brush radius.");
    SetNextInlineLabeledItemWidth("Strength");
    ImGui::SliderFloat("Strength", &terrainBrushStrength_, 0.01f, 4.0f, "%.2f");
    AttachTooltip("Height, paint, or hole-mask force applied by each brush stamp. Hole Cut/Fill is binary once the stamp influence is high enough.");
    SetNextInlineLabeledItemWidth("Opacity");
    ImGui::SliderFloat("Opacity", &terrainBrushOpacity_, 0.01f, 1.0f, "%.2f");
    AttachTooltip("Blends each stamp with the existing terrain data.");
    SetNextInlineLabeledItemWidth("Target Height");
    ImGui::SliderFloat("Target Height", &terrainBrushTargetHeight_, 0.0f, 12.0f, "%.2f");
    AttachTooltip("Height used by Flatten and Set Height.");
    SetNextInlineLabeledItemWidth("Spacing");
    ImGui::SliderFloat("Spacing", &terrainBrushSpacing_, 0.02f, 1.0f, "%.2f");
    AttachTooltip("Distance between brush stamps as a fraction of the radius.");
    ImGui::Checkbox("Invert Brush", &terrainBrushInvert_);
    AttachTooltip("Reverses the current brush direction. For Hole Cut/Fill, inverted strokes fill holes. Hold Shift in the Scene view to temporarily invert it.");
}

void EditorApp::DrawTerrainVolumeSection(Component* terrainComponent) {
    if (!ImGui::CollapsingHeader("Volumetric Terrain", ImGuiTreeNodeFlags_DefaultOpen) || terrainComponent == nullptr) {
        return;
    }

    TerrainData data;
    if (!LoadTerrainDataFromComponentCached(state_.SelectedEntityId(), *terrainComponent, &data)) {
        ImGui::TextDisabled("Terrain volume data could not be loaded.");
        return;
    }

    if (!TerrainUsesVolumetric(data)) {
        if (ImGui::Button("Convert To Volumetric Terrain")) {
            state_.PushUndoSnapshot("Convert To Volumetric Terrain");
            EnsureTerrainVolume(&data);
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Converted terrain to terrain-owned volumetric sculpting.");
        }
        AttachTooltip("Opts this Terrain into a density backend for tunnels, caves, arches, ceilings, and overhangs. Heightfield sculpting stays separate.");
        return;
    }

    caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data.volume) - 1));

    DrawStatusBadge(("Volume Chunks " + std::to_string(CaveChunkCountX(data.volume) * CaveChunkCountY(data.volume) *
                                                       CaveChunkCountZ(data.volume)))
                        .c_str(),
                    ImVec4(0.54f, 0.66f, 0.86f, 1.0f));
    ImGui::SameLine();
    DrawStatusBadge(("Samples " + std::to_string(CaveSampleCount(data.volume))).c_str(),
                    ImVec4(0.60f, 0.64f, 0.64f, 1.0f));

    const char* modes[] = {"Tunnel / Dig", "Dig", "Fill", "Smooth Volume", "Flatten Density", "Paint Cave/Rock"};
    int volumeMode = TerrainVolumeModeIndex(terrainBrushMode_);
    SetNextInlineLabeledItemWidth("Brush");
    if (ImGui::Combo("Volume Brush", &volumeMode, modes, IM_ARRAYSIZE(modes))) {
        terrainBrushMode_ = static_cast<int>(TerrainBrushModeFromVolumeIndex(volumeMode));
        terrainToolActive_ = true;
        caveToolActive_ = false;
        sceneToolMode_ = 2;
    }
    AttachTooltip("Terrain-owned volume brushes carve tunnels, add/fill rock, smooth density, flatten toward a target density, or paint cave/rock layers.");

    if (ImGui::Button("Volume Mode")) {
        if (!IsTerrainVolumeBrushMode(terrainBrushMode_)) {
            terrainBrushMode_ = static_cast<int>(TerrainBrushMode::VolumeTunnel);
        }
        terrainToolActive_ = true;
        caveToolActive_ = false;
        sceneToolMode_ = 2;
    }
    AttachTooltip("Uses the Scene view brush on this Terrain's embedded volume.");
    ImGui::SameLine();
    if (ImGui::Button("Paint Volume")) {
        terrainBrushMode_ = static_cast<int>(TerrainBrushMode::VolumePaint);
        terrainToolActive_ = true;
        caveToolActive_ = false;
        sceneToolMode_ = 2;
    }
    AttachTooltip("Paints the selected embedded cave/rock layer on terrain-owned volumetric surfaces.");

    const char* falloffs[] = {"Smooth", "Linear", "Constant", "Bell"};
    SetNextInlineLabeledItemWidth("Falloff");
    ImGui::Combo("Volume Falloff", &terrainFalloff_, falloffs, IM_ARRAYSIZE(falloffs));
    SetNextInlineLabeledItemWidth("Radius");
    ImGui::SliderFloat("Volume Radius", &terrainBrushRadius_, 0.25f, 12.0f, "%.2f");
    SetNextInlineLabeledItemWidth("Strength");
    ImGui::SliderFloat("Volume Strength", &terrainBrushStrength_, 0.01f, 4.0f, "%.2f");
    SetNextInlineLabeledItemWidth("Opacity");
    ImGui::SliderFloat("Volume Opacity", &terrainBrushOpacity_, 0.01f, 1.0f, "%.2f");
    SetNextInlineLabeledItemWidth("Target Density");
    ImGui::SliderFloat("Target Density", &caveBrushTargetDensity_, -1.0f, 1.0f, "%.2f");
    SetNextInlineLabeledItemWidth("Spacing");
    ImGui::SliderFloat("Volume Spacing", &terrainBrushSpacing_, 0.02f, 1.0f, "%.2f");
    ImGui::Checkbox("Invert Volume Brush", &terrainBrushInvert_);
    AttachTooltip("Reverses tunnel/dig/fill behavior. Hold Shift in the Scene view to temporarily invert it.");

    if (ImGui::Button("Add Volume Layer")) {
        state_.PushUndoSnapshot("Add Terrain Volume Layer");
        CaveLayer layer;
        layer.name = "Volume Layer " + std::to_string(CaveLayerCount(data.volume) + 1);
        layer.displayColor = {0.44f, 0.43f, 0.41f, 1.0f};
        AppendCaveLayer(data.volume, layer);
        caveSelectedLayer_ = CaveLayerCount(data.volume) - 1;
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Added terrain volume layer.");
    }
    ImGui::SameLine();
    ImGui::BeginDisabled(CaveLayerCount(data.volume) <= 1);
    if (ImGui::Button("Remove Volume Layer")) {
        state_.PushUndoSnapshot("Remove Terrain Volume Layer");
        if (RemoveCaveLayer(data.volume, caveSelectedLayer_)) {
            caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data.volume) - 1));
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Removed terrain volume layer.");
        }
    }
    ImGui::EndDisabled();

    if (ImGui::Button("Starter Volume Layers")) {
        state_.PushUndoSnapshot("Terrain Volume Starter Layers");
        ApplyCaveStarterLayerSet(data.volume);
        caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data.volume) - 1));
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Applied terrain volume starter layers.");
    }
    ImGui::SameLine();
    if (ImGui::Button("Auto Paint Volume")) {
        state_.PushUndoSnapshot("Auto Paint Terrain Volume");
        ApplyCaveStarterLayerSet(data.volume);
        if (AutoPaintCaveLayers(data.volume)) {
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Auto-painted terrain volume layers.");
        }
    }

    if (ImGui::BeginChild("terrain_volume_layers_list", ImVec2(0.0f, Scaled(104.0f)), true)) {
        for (int layerIndex = 0; layerIndex < CaveLayerCount(data.volume); ++layerIndex) {
            ImGui::PushID(layerIndex);
            const CaveLayer& layer = data.volume.layers[static_cast<size_t>(layerIndex)];
            ImGui::ColorButton("##volume_swatch", CaveColorToImVec4(layer.displayColor),
                               ImGuiColorEditFlags_NoTooltip, ImVec2(Scaled(20.0f), Scaled(20.0f)));
            ImGui::SameLine();
            if (ImGui::Selectable(layer.name.c_str(), caveSelectedLayer_ == layerIndex)) {
                caveSelectedLayer_ = layerIndex;
                terrainBrushMode_ = static_cast<int>(TerrainBrushMode::VolumePaint);
                terrainToolActive_ = true;
                caveToolActive_ = false;
                sceneToolMode_ = 2;
            }
            ImGui::PopID();
        }
    }
    ImGui::EndChild();

    bool settingsChanged = false;
    std::array<int, 3> resolution = data.volume.resolution;
    int chunkSize = data.volume.chunkSize;
    float volumeHeight = data.volume.size[1];
    bool collisionEnabled = data.volume.collisionEnabled;
    std::array<const char*, 4> collisionModes{"ImmediateForSmallEdits", "Deferred", "Async",
                                              "DisabledInEditorPreview"};
    int collisionModeIndex = 1;
    for (size_t index = 0; index < collisionModes.size(); ++index) {
        if (data.volume.collisionUpdateMode == collisionModes[index]) {
            collisionModeIndex = static_cast<int>(index);
            break;
        }
    }
    ImGui::BeginDisabled(terrainBrushDragging_);
    SetNextInlineLabeledItemWidth("Resolution");
    settingsChanged = ImGui::DragInt3("Volume Resolution", resolution.data(), 1.0f, 3, 97) || settingsChanged;
    SetNextInlineLabeledItemWidth("Chunk Size");
    settingsChanged = ImGui::DragInt("Volume Chunk Size", &chunkSize, 1.0f, 2, 32) || settingsChanged;
    SetNextInlineLabeledItemWidth("Volume Height");
    settingsChanged = ImGui::DragFloat("Volume Height", &volumeHeight, 0.2f, 1.0f, 64.0f, "%.2f") || settingsChanged;
    settingsChanged = ImGui::Checkbox("Volume Collision", &collisionEnabled) || settingsChanged;
    SetNextInlineLabeledItemWidth("Collision Update");
    settingsChanged = ImGui::Combo("Collision Update", &collisionModeIndex, collisionModes.data(),
                                   static_cast<int>(collisionModes.size())) ||
                      settingsChanged;
    AttachTooltip("Deferred avoids blocking scene camera movement while edited terrain chunks settle.");
    ImGui::EndDisabled();

    if (settingsChanged) {
        state_.PushUndoSnapshot("Terrain Volume Settings");
        data.volume.resolution = resolution;
        data.volume.chunkSize = chunkSize;
        data.volume.size = {data.size[0], std::max(volumeHeight, data.size[1]), data.size[2]};
        data.volume.collisionEnabled = collisionEnabled;
        data.volume.collisionUpdateMode = collisionModes[static_cast<size_t>(
            std::clamp(collisionModeIndex, 0, static_cast<int>(collisionModes.size()) - 1))];
        ++data.volume.editRevision;
        NormalizeCaveVolumeData(&data.volume);
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Edited terrain volume settings.");
    }
}

void EditorApp::DrawTerrainPaintSection(Component* terrainComponent) {
    if (!ImGui::CollapsingHeader("Paint / Terrain Layers", ImGuiTreeNodeFlags_DefaultOpen)) {
        return;
    }
    if (terrainComponent == nullptr) {
        return;
    }
    TerrainData data;
    if (!LoadTerrainDataFromComponentCached(state_.SelectedEntityId(), *terrainComponent, &data)) {
        ImGui::TextDisabled("Terrain data could not be loaded.");
        return;
    }
    terrainSelectedLayer_ = std::clamp(terrainSelectedLayer_, 0, std::max(0, TerrainLayerCount(data) - 1));

    if (ImGui::Button("Paint Mode")) {
        terrainBrushMode_ = static_cast<int>(TerrainBrushMode::Paint);
        terrainToolActive_ = true;
        caveToolActive_ = false;
        sceneToolMode_ = 3;
    }
    AttachTooltip("Switches the Scene view brush to paint the selected terrain layer.");
    ImGui::SameLine();
    if (ImGui::Button("Add Layer")) {
        state_.PushUndoSnapshot("Add Terrain Layer");
        TerrainLayer layer;
        layer.name = "Layer " + std::to_string(TerrainLayerCount(data) + 1);
        layer.displayColor = {0.46f, 0.47f, 0.46f, 1.0f};
        AppendTerrainLayer(data, layer);
        terrainSelectedLayer_ = TerrainLayerCount(data) - 1;
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Added terrain layer.");
    }
    AttachTooltip("Adds a neutral paint layer. Use presets below to turn it into rock, soil, grass, sand, or snow.");
    ImGui::SameLine();
    ImGui::BeginDisabled(TerrainLayerCount(data) <= 1);
    if (ImGui::Button("Remove")) {
        state_.PushUndoSnapshot("Remove Terrain Layer");
        if (RemoveTerrainLayer(data, terrainSelectedLayer_)) {
            terrainSelectedLayer_ = std::clamp(terrainSelectedLayer_, 0, std::max(0, TerrainLayerCount(data) - 1));
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Removed terrain layer.");
        }
    }
    ImGui::EndDisabled();
    AttachTooltip("Removes the selected layer and renormalizes the remaining layer weights.");

    SetNextInlineLabeledItemWidth("Paint Strength");
    ImGui::SliderFloat("Paint Strength", &terrainBrushStrength_, 0.01f, 4.0f, "%.2f");
    AttachTooltip("How strongly each paint stamp pushes the selected layer into the terrain blend.");
    SetNextInlineLabeledItemWidth("Paint Opacity");
    ImGui::SliderFloat("Paint Opacity", &terrainBrushOpacity_, 0.01f, 1.0f, "%.2f");
    AttachTooltip("Blends each paint stamp with the existing normalized layer weights.");

    if (ImGui::Button("Starter Textures")) {
        state_.PushUndoSnapshot("Terrain Starter Textures");
        ApplyRealisticTerrainLayerSet(data);
        terrainSelectedLayer_ = std::clamp(terrainSelectedLayer_, 0, std::max(0, TerrainLayerCount(data) - 1));
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Applied terrain starter texture layers.");
    }
    AttachTooltip("Sets the first terrain layers to Ground, Rock, Soil, and Grass presets with procedural detail.");
    ImGui::SameLine();
    if (ImGui::Button("Auto Texture")) {
        state_.PushUndoSnapshot("Auto Texture Terrain");
        ApplyRealisticTerrainLayerSet(data);
        if (AutoTextureTerrainLayers(data)) {
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Auto-textured terrain layers.");
        }
    }
    AttachTooltip("Paints layer weights from terrain slope and height so cliffs become rock and flatter areas blend ground, soil, and grass.");
    ImGui::SameLine();
    if (ImGui::Button("Load Test Textures")) {
        state_.PushUndoSnapshot("Load Terrain Test Textures");
        ApplyRealisticTerrainLayerSet(data);
        std::string copyError;
        if (CopyTerrainTestTexturesToProject(state_.ProjectRootPathString(), &data, &copyError)) {
            terrainSelectedLayer_ = std::clamp(terrainSelectedLayer_, 0, std::max(0, TerrainLayerCount(data) - 1));
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Loaded temporary terrain test textures.");
            state_.RefreshProjectTree();
            state_.AddActivity("terrain.textures", "Copied",
                               std::string(kTerrainTempTextureFolder) + " from local paid test pack.");
        } else {
            state_.AddLog(LogLevel::Error, "Terrain test texture import failed: " + copyError);
        }
    }
    AttachTooltip("Copies a few local paid-pack albedo textures into this project as temporary test assets and assigns them to the first terrain layers. Do not ship these copies.");

    if (ImGui::BeginChild("terrain_layers_list", ImVec2(0.0f, Scaled(128.0f)), true)) {
        for (int layerIndex = 0; layerIndex < TerrainLayerCount(data); ++layerIndex) {
            ImGui::PushID(layerIndex);
            const TerrainLayer& listLayer = data.layers[static_cast<size_t>(layerIndex)];
            TerrainGlTexture* listTexture = listLayer.albedoTexture.empty()
                                                ? nullptr
                                                : GetTerrainGlTexture(listLayer.albedoTexture,
                                                                      state_.ProjectRootPathString());
            if (listTexture != nullptr && listTexture->loaded) {
                ImGui::Image(static_cast<ImTextureID>(listTexture->id),
                             ImVec2(Scaled(20.0f), Scaled(20.0f)));
                AttachTooltip("Layer albedo texture preview.");
            } else {
                ImVec4 color = TerrainColorToImVec4(listLayer.displayColor);
                ImGui::ColorButton("##swatch", color, ImGuiColorEditFlags_NoTooltip,
                                   ImVec2(Scaled(20.0f), Scaled(20.0f)));
                AttachTooltip("Layer preview color used when no albedo texture is assigned or loaded.");
            }
            ImGui::SameLine();
            if (ImGui::Selectable(listLayer.name.c_str(), terrainSelectedLayer_ == layerIndex)) {
                terrainSelectedLayer_ = layerIndex;
                terrainBrushMode_ = static_cast<int>(TerrainBrushMode::Paint);
                terrainToolActive_ = true;
                caveToolActive_ = false;
                sceneToolMode_ = 3;
            }
            AttachTooltip("Selects the layer used by Paint Mode.");
            ImGui::PopID();
        }
    }
    ImGui::EndChild();

    ImGui::BeginDisabled(TerrainLayerCount(data) <= 1);
    if (ImGui::Button("Move Up") && terrainSelectedLayer_ > 0) {
        state_.PushUndoSnapshot("Reorder Terrain Layer");
        if (MoveTerrainLayer(data, terrainSelectedLayer_, terrainSelectedLayer_ - 1)) {
            --terrainSelectedLayer_;
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Reordered terrain layer.");
        }
    }
    AttachTooltip("Moves the selected layer up in saved terrain layer order.");
    ImGui::SameLine();
    if (ImGui::Button("Move Down") && terrainSelectedLayer_ < TerrainLayerCount(data) - 1) {
        state_.PushUndoSnapshot("Reorder Terrain Layer");
        if (MoveTerrainLayer(data, terrainSelectedLayer_, terrainSelectedLayer_ + 1)) {
            ++terrainSelectedLayer_;
            SaveTerrainDataToComponent(data, terrainComponent);
            state_.MarkSceneDirty("Reordered terrain layer.");
        }
    }
    AttachTooltip("Moves the selected layer down in saved terrain layer order.");
    ImGui::EndDisabled();

    if (TerrainLayerCount(data) <= 0) {
        return;
    }

    TerrainLayer& layer = data.layers[static_cast<size_t>(terrainSelectedLayer_)];
    static int sLayerEditEntity = 0;
    static int sLayerEditIndex = -1;
    static std::array<char, 128> sLayerName{};
    static std::array<char, 128> sLayerMaterial{};
    static std::array<char, 512> sLayerAlbedoTexture{};
    static std::array<char, 512> sLayerNormalTexture{};
    static std::array<char, 512> sLayerMaskTexture{};
    const int selectedId = state_.SelectedEntityId();
    if (sLayerEditEntity != selectedId || sLayerEditIndex != terrainSelectedLayer_ ||
        std::string(sLayerAlbedoTexture.data()) != layer.albedoTexture ||
        std::string(sLayerNormalTexture.data()) != layer.normalTexture ||
        std::string(sLayerMaskTexture.data()) != layer.maskTexture) {
        sLayerEditEntity = selectedId;
        sLayerEditIndex = terrainSelectedLayer_;
        CopyStringToBuffer(sLayerName, layer.name);
        CopyStringToBuffer(sLayerMaterial, layer.material);
        CopyStringToBuffer(sLayerAlbedoTexture, layer.albedoTexture);
        CopyStringToBuffer(sLayerNormalTexture, layer.normalTexture);
        CopyStringToBuffer(sLayerMaskTexture, layer.maskTexture);
    }

    bool changed = false;
    SetNextInlineLabeledItemWidth("Name");
    if (ImGui::InputText("Name", sLayerName.data(), sLayerName.size()) && sLayerName[0] != '\0') {
        layer.name = sLayerName.data();
        changed = true;
    }
    AttachTooltip("Display name shown in the Terrain Layers list.");
    SetNextInlineLabeledItemWidth("Material");
    if (ImGui::InputText("Material", sLayerMaterial.data(), sLayerMaterial.size())) {
        layer.material = sLayerMaterial.data();
        changed = true;
    }
    AttachTooltip("Optional material label saved with this terrain layer.");

    SetNextInlineLabeledItemWidth("Albedo Texture");
    if (ImGui::InputText("Albedo Texture", sLayerAlbedoTexture.data(), sLayerAlbedoTexture.size())) {
        layer.albedoTexture = sLayerAlbedoTexture.data();
        changed = true;
    }
    AttachTooltip("Project-relative or absolute image path for this layer's base color texture. Project paths like Assets/TempTerrainTextures/file.png resolve from the active project root.");
    TerrainGlTexture* selectedTexture = layer.albedoTexture.empty()
                                            ? nullptr
                                            : GetTerrainGlTexture(layer.albedoTexture,
                                                                  state_.ProjectRootPathString());
    if (selectedTexture != nullptr && selectedTexture->loaded) {
        ImGui::Image(static_cast<ImTextureID>(selectedTexture->id), ImVec2(Scaled(72.0f), Scaled(72.0f)));
        ImGui::SameLine();
        ImGui::TextDisabled("%dx%d", selectedTexture->width, selectedTexture->height);
    } else if (!layer.albedoTexture.empty()) {
        ImGui::TextDisabled("Texture not loaded");
        AttachTooltip(selectedTexture == nullptr || selectedTexture->error.empty()
                          ? "The texture path could not be resolved."
                          : selectedTexture->error.c_str());
    }
    if (!layer.albedoTexture.empty()) {
        if (ImGui::Button("Clear Albedo Texture")) {
            layer.albedoTexture.clear();
            CopyStringToBuffer(sLayerAlbedoTexture, layer.albedoTexture);
            changed = true;
        }
        AttachTooltip("Removes the albedo texture reference from this terrain layer. Painted weights stay intact.");
    }

    SetNextInlineLabeledItemWidth("Normal Texture");
    if (ImGui::InputText("Normal Texture", sLayerNormalTexture.data(), sLayerNormalTexture.size())) {
        layer.normalTexture = sLayerNormalTexture.data();
        changed = true;
    }
    AttachTooltip("Optional normal map reference saved with the layer for future material rendering.");
    SetNextInlineLabeledItemWidth("Mask Texture");
    if (ImGui::InputText("Mask Texture", sLayerMaskTexture.data(), sLayerMaskTexture.size())) {
        layer.maskTexture = sLayerMaskTexture.data();
        changed = true;
    }
    AttachTooltip("Optional mask/AO/packed texture reference saved with the layer for future material rendering.");

    ImGui::TextUnformatted("Presets");
    DrawHelpMarker("Applies common terrain layer values to the selected layer without changing the painted weights.");
    for (int presetIndex = 0; presetIndex < IM_ARRAYSIZE(kTerrainLayerPresets); ++presetIndex) {
        if (presetIndex > 0) {
            ImGui::SameLine();
        }
        ImGui::PushID(presetIndex);
        if (ImGui::Button(kTerrainLayerPresets[presetIndex].name)) {
            ApplyTerrainLayerPreset(layer, kTerrainLayerPresets[presetIndex]);
            CopyStringToBuffer(sLayerName, layer.name);
            CopyStringToBuffer(sLayerMaterial, layer.material);
            changed = true;
        }
        AttachTooltip("Applies color, material name, tiling, roughness, and procedural detail values.");
        ImGui::PopID();
    }

    SetNextInlineLabeledItemWidth("Display Color");
    changed = ImGui::ColorEdit4("Display Color", layer.displayColor.data(), ImGuiColorEditFlags_AlphaBar) || changed;
    AttachTooltip("Base color used for this layer in the viewport and layer list.");
    SetNextInlineLabeledItemWidth("Tiling");
    changed = ImGui::DragFloat("Tiling", &layer.tiling, 0.1f, 0.1f, 128.0f, "%.2f") || changed;
    AttachTooltip("Texture scale/reference tiling. Higher values repeat the layer detail more often.");
    SetNextInlineLabeledItemWidth("Roughness");
    changed = ImGui::SliderFloat("Roughness", &layer.roughness, 0.0f, 1.0f, "%.2f") || changed;
    AttachTooltip("Material roughness value saved with the terrain layer.");
    SetNextInlineLabeledItemWidth("Metalness");
    changed = ImGui::SliderFloat("Metalness", &layer.metalness, 0.0f, 1.0f, "%.2f") || changed;
    AttachTooltip("Material metalness value saved with the terrain layer.");
    SetNextInlineLabeledItemWidth("Detail Scale");
    changed = ImGui::DragFloat("Detail Scale", &layer.detailScale, 0.5f, 0.1f, 256.0f, "%.1f") || changed;
    AttachTooltip("Procedural surface grain scale used by the viewport mesh color.");
    SetNextInlineLabeledItemWidth("Detail Strength");
    changed = ImGui::SliderFloat("Detail Strength", &layer.detailStrength, 0.0f, 0.75f, "%.2f") || changed;
    AttachTooltip("How strongly procedural detail modulates this layer color.");
    if (changed) {
        NormalizeTerrainData(&data);
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Edited terrain layer.");
    }
}

void EditorApp::DrawTerrainSettingsSection(Component* terrainComponent) {
    if (!ImGui::CollapsingHeader("Settings", ImGuiTreeNodeFlags_DefaultOpen) || terrainComponent == nullptr) {
        return;
    }
    TerrainData data;
    if (!LoadTerrainDataFromComponentCached(state_.SelectedEntityId(), *terrainComponent, &data)) {
        return;
    }
    bool changed = false;
    int resolution = data.resolution;
    int chunkSize = data.chunkSize;
    std::array<float, 3> size = data.size;
    bool collisionEnabled = data.collisionEnabled;

    ImGui::BeginDisabled(terrainBrushDragging_);
    SetNextInlineLabeledItemWidth("Resolution");
    changed = ImGui::DragInt("Resolution", &resolution, 1.0f, 2, 129) || changed;
    AttachTooltip("Number of height samples per side. Higher values support finer sculpting and heavier meshes.");
    SetNextInlineLabeledItemWidth("Chunk Size");
    changed = ImGui::DragInt("Chunk Size", &chunkSize, 1.0f, 1, 64) || changed;
    AttachTooltip("Number of terrain cells per mesh chunk. Smaller chunks make brush rebuilds more localized.");
    changed = DrawInspectorVec3Value("Size", size, 0.2f) || changed;
    AttachTooltip("World size of the terrain volume: X and Z footprint, Y maximum height.");
    changed = ImGui::Checkbox("Collision Enabled", &collisionEnabled) || changed;
    AttachTooltip("Enables terrain collision for play mode, physics queries, and terrain raycasts.");
    ImGui::EndDisabled();

    if (changed) {
        state_.PushUndoSnapshot("Terrain Settings");
        data.resolution = resolution;
        data.chunkSize = chunkSize;
        data.size = size;
        data.collisionEnabled = collisionEnabled;
        ++data.editRevision;
        NormalizeTerrainData(&data);
        SaveTerrainDataToComponent(data, terrainComponent);
        state_.MarkSceneDirty("Edited terrain settings.");
    }
}

void EditorApp::DrawCaveVolumeInspectorBody(Component* caveComponent) {
    if (caveComponent == nullptr) {
        return;
    }
    CaveVolumeData data;
    if (!LoadCaveVolumeDataFromComponentCached(state_.SelectedEntityId(), *caveComponent, &data)) {
        ImGui::TextDisabled("Cave volume data could not be loaded.");
        DrawComponentPropertyBody(*caveComponent, FindRuntimeSchema(caveComponent->type));
        return;
    }

    ImGui::Spacing();
    DrawStatusBadge(("Resolution " + std::to_string(data.resolution[0]) + "x" +
                     std::to_string(data.resolution[1]) + "x" + std::to_string(data.resolution[2]))
                        .c_str(),
                    ComponentAccentColor(*caveComponent));
    ImGui::SameLine();
    DrawStatusBadge(("Chunks " + std::to_string(CaveChunkCountX(data) * CaveChunkCountY(data) *
                                                 CaveChunkCountZ(data)))
                        .c_str(),
                    ImVec4(0.60f, 0.64f, 0.64f, 1.0f));
    ImGui::SameLine();
    DrawStatusBadge((std::to_string(data.layers.size()) + " Layers").c_str(),
                    ImVec4(0.54f, 0.66f, 0.86f, 1.0f));
    if (state_.IsSceneDirty()) {
        ImGui::SameLine();
        DrawStatusBadge("Unsaved", ImVec4(1.0f, 0.74f, 0.30f, 1.0f));
    }

    ImGui::Spacing();
    const float buttonWidth = std::max(Scaled(66.0f),
                                       (ImGui::GetContentRegionAvail().x - ImGui::GetStyle().ItemSpacing.x * 2.0f) /
                                           3.0f);
    if (DrawToolbarButton("Select", "Use normal GameObject selection", ImVec2(buttonWidth, ImGui::GetFrameHeight()),
                          true, sceneToolMode_ == 0)) {
        sceneToolMode_ = 0;
        caveToolActive_ = false;
    }
    ImGui::SameLine();
    if (DrawToolbarButton("Dig", "Edit this Cave Volume in the Scene view", ImVec2(buttonWidth, ImGui::GetFrameHeight()),
                          true, sceneToolMode_ == 4 && caveBrushMode_ != static_cast<int>(CaveBrushMode::Paint))) {
        sceneToolMode_ = 4;
        caveToolActive_ = true;
        terrainToolActive_ = false;
        if (caveBrushMode_ == static_cast<int>(CaveBrushMode::Paint)) {
            caveBrushMode_ = static_cast<int>(CaveBrushMode::Tunnel);
        }
    }
    ImGui::SameLine();
    if (DrawToolbarButton("Paint", "Paint this Cave Volume's layer weights",
                          ImVec2(buttonWidth, ImGui::GetFrameHeight()), true,
                          sceneToolMode_ == 4 && caveBrushMode_ == static_cast<int>(CaveBrushMode::Paint))) {
        sceneToolMode_ = 4;
        caveToolActive_ = true;
        terrainToolActive_ = false;
        caveBrushMode_ = static_cast<int>(CaveBrushMode::Paint);
    }

    ImGui::Checkbox("Brush Preview", &caveBrushPreviewVisible_);
    AttachTooltip("Shows a 3D brush sphere at the cave surface hit point in the Scene view.");
    ImGui::SameLine();
    DrawStatusBadge(caveToolActive_ && sceneToolMode_ == 4 ? "Scene Tool Active" : "Scene Tool Idle",
                    caveToolActive_ && sceneToolMode_ == 4 ? ImVec4(0.54f, 0.66f, 0.86f, 1.0f)
                                                           : ImVec4(0.58f, 0.60f, 0.63f, 1.0f));

    DrawCaveBrushSection(caveComponent);
    DrawCaveLayerSection(caveComponent);
    DrawCaveSettingsSection(caveComponent);
}

void EditorApp::DrawCaveBrushSection(Component* caveComponent) {
    (void)caveComponent;
    if (!ImGui::CollapsingHeader("Brush", ImGuiTreeNodeFlags_DefaultOpen)) {
        return;
    }
    const char* modes[] = {"Dig", "Fill", "Smooth", "Flatten", "Tunnel", "Paint"};
    caveBrushMode_ = std::clamp(caveBrushMode_, 0, 5);
    SetNextInlineLabeledItemWidth("Brush");
    if (ImGui::Combo("Brush", &caveBrushMode_, modes, IM_ARRAYSIZE(modes))) {
        caveToolActive_ = true;
        terrainToolActive_ = false;
        sceneToolMode_ = 4;
    }
    AttachTooltip("Dig subtracts solid volume, Fill adds solid volume, Smooth softens density, Flatten moves density toward Target Density, Tunnel carves a capsule between brush stamps, and Paint edits cave layer weights.");
    const char* falloffs[] = {"Smooth", "Linear", "Constant", "Bell"};
    SetNextInlineLabeledItemWidth("Falloff");
    ImGui::Combo("Falloff", &caveFalloff_, falloffs, IM_ARRAYSIZE(falloffs));
    AttachTooltip("Controls how strongly the brush fades from the center to the outer radius.");
    SetNextInlineLabeledItemWidth("Radius");
    ImGui::SliderFloat("Radius", &caveBrushRadius_, 0.25f, 8.0f, "%.2f");
    AttachTooltip("World-space brush radius for digging, filling, smoothing, tunneling, and painting.");
    SetNextInlineLabeledItemWidth("Strength");
    ImGui::SliderFloat("Strength", &caveBrushStrength_, 0.01f, 4.0f, "%.2f");
    AttachTooltip("Force applied by each brush stamp. Higher values dig/fill faster and paint the selected layer more strongly.");
    SetNextInlineLabeledItemWidth("Opacity");
    ImGui::SliderFloat("Opacity", &caveBrushOpacity_, 0.01f, 1.0f, "%.2f");
    AttachTooltip("Blends each brush stamp with existing cave density or layer weights.");
    SetNextInlineLabeledItemWidth("Target Density");
    ImGui::SliderFloat("Target Density", &caveBrushTargetDensity_, -1.0f, 1.0f, "%.2f");
    AttachTooltip("Density used by Flatten. Positive is solid terrain, zero is the visible surface, negative is empty air.");
    SetNextInlineLabeledItemWidth("Spacing");
    ImGui::SliderFloat("Spacing", &caveBrushSpacing_, 0.02f, 1.0f, "%.2f");
    AttachTooltip("Distance between brush stamps as a fraction of radius. Lower values produce smoother tunnels.");
    ImGui::Checkbox("Invert Brush", &caveBrushInvert_);
    AttachTooltip("Reverses the current brush direction. Hold Shift in the Scene view to temporarily invert it.");
}

void EditorApp::DrawCaveLayerSection(Component* caveComponent) {
    if (!ImGui::CollapsingHeader("Cave Layers", ImGuiTreeNodeFlags_DefaultOpen) || caveComponent == nullptr) {
        return;
    }
    CaveVolumeData data;
    if (!LoadCaveVolumeDataFromComponentCached(state_.SelectedEntityId(), *caveComponent, &data)) {
        ImGui::TextDisabled("Cave volume data could not be loaded.");
        return;
    }
    caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data) - 1));

    if (ImGui::Button("Paint Mode")) {
        caveBrushMode_ = static_cast<int>(CaveBrushMode::Paint);
        caveToolActive_ = true;
        terrainToolActive_ = false;
        sceneToolMode_ = 4;
    }
    AttachTooltip("Switches the Scene view brush to paint the selected cave layer.");
    ImGui::SameLine();
    if (ImGui::Button("Add Layer")) {
        state_.PushUndoSnapshot("Add Cave Layer");
        CaveLayer layer;
        layer.name = "Cave Layer " + std::to_string(CaveLayerCount(data) + 1);
        layer.displayColor = {0.44f, 0.43f, 0.41f, 1.0f};
        AppendCaveLayer(data, layer);
        caveSelectedLayer_ = CaveLayerCount(data) - 1;
        SaveCaveVolumeDataToComponent(data, caveComponent);
        state_.MarkSceneDirty("Added cave layer.");
    }
    AttachTooltip("Adds a neutral cave paint layer and expands the normalized layer weight data.");
    ImGui::SameLine();
    ImGui::BeginDisabled(CaveLayerCount(data) <= 1);
    if (ImGui::Button("Remove")) {
        state_.PushUndoSnapshot("Remove Cave Layer");
        if (RemoveCaveLayer(data, caveSelectedLayer_)) {
            caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data) - 1));
            SaveCaveVolumeDataToComponent(data, caveComponent);
            state_.MarkSceneDirty("Removed cave layer.");
        }
    }
    ImGui::EndDisabled();
    AttachTooltip("Removes the selected layer and renormalizes the remaining cave paint weights.");

    SetNextInlineLabeledItemWidth("Paint Strength");
    ImGui::SliderFloat("Paint Strength", &caveBrushStrength_, 0.01f, 4.0f, "%.2f");
    AttachTooltip("How strongly each paint stamp pushes the selected cave layer into the blend.");
    SetNextInlineLabeledItemWidth("Paint Opacity");
    ImGui::SliderFloat("Paint Opacity", &caveBrushOpacity_, 0.01f, 1.0f, "%.2f");
    AttachTooltip("Blends each paint stamp with existing normalized cave layer weights.");

    if (ImGui::Button("Starter Layers")) {
        state_.PushUndoSnapshot("Cave Starter Layers");
        ApplyCaveStarterLayerSet(data);
        caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data) - 1));
        SaveCaveVolumeDataToComponent(data, caveComponent);
        state_.MarkSceneDirty("Applied cave starter layers.");
    }
    AttachTooltip("Sets the first cave layers to Rock, Dirt, Damp Stone, and Moss with neutral grey/earth colors.");
    ImGui::SameLine();
    if (ImGui::Button("Auto Paint")) {
        state_.PushUndoSnapshot("Auto Paint Cave");
        ApplyCaveStarterLayerSet(data);
        if (AutoPaintCaveLayers(data)) {
            SaveCaveVolumeDataToComponent(data, caveComponent);
            state_.MarkSceneDirty("Auto-painted cave layers.");
        }
    }
    AttachTooltip("Paints cave layers from local height and surface orientation so floors, walls, and damp areas vary.");
    ImGui::SameLine();
    if (ImGui::Button("Load Test Textures")) {
        state_.PushUndoSnapshot("Load Cave Test Textures");
        std::string copyError;
        if (CopyCaveTestTexturesToProject(state_.ProjectRootPathString(), &data, &copyError)) {
            caveSelectedLayer_ = std::clamp(caveSelectedLayer_, 0, std::max(0, CaveLayerCount(data) - 1));
            SaveCaveVolumeDataToComponent(data, caveComponent);
            state_.MarkSceneDirty("Loaded temporary cave test textures.");
            state_.RefreshProjectTree();
            state_.AddActivity("cave.textures", "Copied",
                               std::string(kTerrainTempTextureFolder) + " from local paid test pack.");
        } else {
            state_.AddLog(LogLevel::Error, "Cave test texture import failed: " + copyError);
        }
    }
    AttachTooltip("Copies a few local paid-pack albedo textures into this project as temporary test assets and assigns them to cave layers. Do not ship these copies.");

    if (ImGui::BeginChild("cave_layers_list", ImVec2(0.0f, Scaled(128.0f)), true)) {
        for (int layerIndex = 0; layerIndex < CaveLayerCount(data); ++layerIndex) {
            ImGui::PushID(layerIndex);
            const CaveLayer& listLayer = data.layers[static_cast<size_t>(layerIndex)];
            TerrainGlTexture* listTexture =
                listLayer.albedoTexture.empty() ? nullptr
                                                : GetTerrainGlTexture(listLayer.albedoTexture,
                                                                      state_.ProjectRootPathString());
            if (listTexture != nullptr && listTexture->loaded) {
                ImGui::Image(static_cast<ImTextureID>(listTexture->id), ImVec2(Scaled(20.0f), Scaled(20.0f)));
                AttachTooltip("Layer albedo texture preview.");
            } else {
                ImGui::ColorButton("##swatch", CaveColorToImVec4(listLayer.displayColor),
                                   ImGuiColorEditFlags_NoTooltip, ImVec2(Scaled(20.0f), Scaled(20.0f)));
                AttachTooltip("Layer preview color used when no albedo texture is assigned or loaded.");
            }
            ImGui::SameLine();
            if (ImGui::Selectable(listLayer.name.c_str(), caveSelectedLayer_ == layerIndex)) {
                caveSelectedLayer_ = layerIndex;
                caveBrushMode_ = static_cast<int>(CaveBrushMode::Paint);
                caveToolActive_ = true;
                terrainToolActive_ = false;
                sceneToolMode_ = 4;
            }
            AttachTooltip("Selects the cave layer used by Paint Mode.");
            ImGui::PopID();
        }
    }
    ImGui::EndChild();

    ImGui::BeginDisabled(CaveLayerCount(data) <= 1);
    if (ImGui::Button("Move Up") && caveSelectedLayer_ > 0) {
        state_.PushUndoSnapshot("Reorder Cave Layer");
        if (MoveCaveLayer(data, caveSelectedLayer_, caveSelectedLayer_ - 1)) {
            --caveSelectedLayer_;
            SaveCaveVolumeDataToComponent(data, caveComponent);
            state_.MarkSceneDirty("Reordered cave layer.");
        }
    }
    AttachTooltip("Moves the selected layer up in saved cave layer order.");
    ImGui::SameLine();
    if (ImGui::Button("Move Down") && caveSelectedLayer_ < CaveLayerCount(data) - 1) {
        state_.PushUndoSnapshot("Reorder Cave Layer");
        if (MoveCaveLayer(data, caveSelectedLayer_, caveSelectedLayer_ + 1)) {
            ++caveSelectedLayer_;
            SaveCaveVolumeDataToComponent(data, caveComponent);
            state_.MarkSceneDirty("Reordered cave layer.");
        }
    }
    AttachTooltip("Moves the selected layer down in saved cave layer order.");
    ImGui::EndDisabled();

    if (CaveLayerCount(data) <= 0) {
        return;
    }

    CaveLayer& layer = data.layers[static_cast<size_t>(caveSelectedLayer_)];
    static int sCaveLayerEditEntity = 0;
    static int sCaveLayerEditIndex = -1;
    static std::array<char, 128> sCaveLayerName{};
    static std::array<char, 128> sCaveLayerMaterial{};
    static std::array<char, 512> sCaveLayerAlbedoTexture{};
    const int selectedId = state_.SelectedEntityId();
    if (sCaveLayerEditEntity != selectedId || sCaveLayerEditIndex != caveSelectedLayer_ ||
        std::string(sCaveLayerAlbedoTexture.data()) != layer.albedoTexture) {
        sCaveLayerEditEntity = selectedId;
        sCaveLayerEditIndex = caveSelectedLayer_;
        CopyStringToBuffer(sCaveLayerName, layer.name);
        CopyStringToBuffer(sCaveLayerMaterial, layer.material);
        CopyStringToBuffer(sCaveLayerAlbedoTexture, layer.albedoTexture);
    }

    bool changed = false;
    SetNextInlineLabeledItemWidth("Name");
    if (ImGui::InputText("Name", sCaveLayerName.data(), sCaveLayerName.size()) && sCaveLayerName[0] != '\0') {
        layer.name = sCaveLayerName.data();
        changed = true;
    }
    AttachTooltip("Display name shown in the Cave Layers list.");
    SetNextInlineLabeledItemWidth("Material");
    if (ImGui::InputText("Material", sCaveLayerMaterial.data(), sCaveLayerMaterial.size())) {
        layer.material = sCaveLayerMaterial.data();
        changed = true;
    }
    AttachTooltip("Optional material label saved with this cave layer.");
    SetNextInlineLabeledItemWidth("Albedo Texture");
    if (ImGui::InputText("Albedo Texture", sCaveLayerAlbedoTexture.data(), sCaveLayerAlbedoTexture.size())) {
        layer.albedoTexture = sCaveLayerAlbedoTexture.data();
        changed = true;
    }
    AttachTooltip("Project-relative or absolute image path for this layer's base color texture.");
    TerrainGlTexture* selectedTexture =
        layer.albedoTexture.empty() ? nullptr : GetTerrainGlTexture(layer.albedoTexture, state_.ProjectRootPathString());
    if (selectedTexture != nullptr && selectedTexture->loaded) {
        ImGui::Image(static_cast<ImTextureID>(selectedTexture->id), ImVec2(Scaled(72.0f), Scaled(72.0f)));
        ImGui::SameLine();
        ImGui::TextDisabled("%dx%d", selectedTexture->width, selectedTexture->height);
    } else if (!layer.albedoTexture.empty()) {
        ImGui::TextDisabled("Texture not loaded");
        AttachTooltip(selectedTexture == nullptr || selectedTexture->error.empty()
                          ? "The texture path could not be resolved."
                          : selectedTexture->error.c_str());
    }
    if (!layer.albedoTexture.empty()) {
        if (ImGui::Button("Clear Albedo Texture")) {
            layer.albedoTexture.clear();
            CopyStringToBuffer(sCaveLayerAlbedoTexture, layer.albedoTexture);
            changed = true;
        }
        AttachTooltip("Removes the albedo texture reference from this cave layer. Painted weights stay intact.");
    }

    ImGui::TextUnformatted("Presets");
    DrawHelpMarker("Applies common cave layer values to the selected layer without changing painted weights.");
    for (int presetIndex = 0; presetIndex < IM_ARRAYSIZE(kCaveLayerPresets); ++presetIndex) {
        if (presetIndex > 0) {
            ImGui::SameLine();
        }
        ImGui::PushID(presetIndex);
        if (ImGui::Button(kCaveLayerPresets[presetIndex].name)) {
            ApplyCaveLayerPreset(layer, kCaveLayerPresets[presetIndex]);
            CopyStringToBuffer(sCaveLayerName, layer.name);
            CopyStringToBuffer(sCaveLayerMaterial, layer.material);
            changed = true;
        }
        AttachTooltip("Applies color, material name, tiling, roughness, and metalness values.");
        ImGui::PopID();
    }

    SetNextInlineLabeledItemWidth("Display Color");
    changed = ImGui::ColorEdit4("Display Color", layer.displayColor.data(), ImGuiColorEditFlags_AlphaBar) || changed;
    AttachTooltip("Base color used for this cave layer in the viewport and layer list.");
    SetNextInlineLabeledItemWidth("Tiling");
    changed = ImGui::DragFloat("Tiling", &layer.tiling, 0.1f, 0.1f, 128.0f, "%.2f") || changed;
    AttachTooltip("Texture scale/reference tiling. Higher values repeat cave detail more often.");
    SetNextInlineLabeledItemWidth("Roughness");
    changed = ImGui::SliderFloat("Roughness", &layer.roughness, 0.0f, 1.0f, "%.2f") || changed;
    AttachTooltip("Material roughness value saved with the cave layer.");
    SetNextInlineLabeledItemWidth("Metalness");
    changed = ImGui::SliderFloat("Metalness", &layer.metalness, 0.0f, 1.0f, "%.2f") || changed;
    AttachTooltip("Material metalness value saved with the cave layer.");
    if (changed) {
        NormalizeCaveVolumeData(&data);
        SaveCaveVolumeDataToComponent(data, caveComponent);
        state_.MarkSceneDirty("Edited cave layer.");
    }
}

void EditorApp::DrawCaveSettingsSection(Component* caveComponent) {
    if (!ImGui::CollapsingHeader("Settings", ImGuiTreeNodeFlags_DefaultOpen) || caveComponent == nullptr) {
        return;
    }
    CaveVolumeData data;
    if (!LoadCaveVolumeDataFromComponentCached(state_.SelectedEntityId(), *caveComponent, &data)) {
        return;
    }
    bool changed = false;
    std::array<int, 3> resolution = data.resolution;
    int chunkSize = data.chunkSize;
    std::array<float, 3> size = data.size;
    bool collisionEnabled = data.collisionEnabled;

    ImGui::BeginDisabled(caveBrushDragging_);
    SetNextInlineLabeledItemWidth("Resolution");
    changed = ImGui::DragInt3("Resolution", resolution.data(), 1.0f, 3, 97) || changed;
    AttachTooltip("Density samples on X, Y, and Z. Higher values support finer tunnels and heavier meshes.");
    SetNextInlineLabeledItemWidth("Chunk Size");
    changed = ImGui::DragInt("Chunk Size", &chunkSize, 1.0f, 2, 32) || changed;
    AttachTooltip("Number of voxel cells per mesh chunk. Smaller chunks make brush rebuilds more localized.");
    changed = DrawInspectorVec3Value("Size", size, 0.2f) || changed;
    AttachTooltip("World size of the editable cave volume bounds.");
    changed = ImGui::Checkbox("Collision Enabled", &collisionEnabled) || changed;
    AttachTooltip("Enables CaveVolume collision for play mode, physics queries, and cave raycasts.");
    ImGui::EndDisabled();

    if (changed) {
        state_.PushUndoSnapshot("Cave Settings");
        data.resolution = resolution;
        data.chunkSize = chunkSize;
        data.size = size;
        data.collisionEnabled = collisionEnabled;
        ++data.editRevision;
        NormalizeCaveVolumeData(&data);
        SaveCaveVolumeDataToComponent(data, caveComponent);
        state_.MarkSceneDirty("Edited cave settings.");
    }
}

void EditorApp::DrawConsolePanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.Console");
    if (!BeginPanel(panel, ImVec2(380.0f, 180.0f))) {
        ImGui::End();
        return;
    }

    const std::vector<LogEntry>& liveLogs = state_.Logs();
    if (consolePaused_) {
        if (!consolePausedSnapshotValid_) {
            consolePausedLogs_ = liveLogs;
            consolePausedSnapshotValid_ = true;
        }
    } else {
        consolePausedSnapshotValid_ = false;
        consolePausedLogs_.clear();
    }

    const std::vector<LogEntry>& logs = consolePaused_ ? consolePausedLogs_ : liveLogs;
    const int errorCount = static_cast<int>(std::count_if(liveLogs.begin(), liveLogs.end(), [](const LogEntry& entry) {
        return entry.level == LogLevel::Error;
    }));
    const int warningCount = static_cast<int>(std::count_if(liveLogs.begin(), liveLogs.end(), [](const LogEntry& entry) {
        return entry.level == LogLevel::Warning;
    }));
    const int infoCount = static_cast<int>(liveLogs.size()) - errorCount - warningCount;

    const std::string search = consoleSearchInput_.data();
    const std::vector<ConsoleLogDisplayEntry> displayEntries =
        BuildConsoleDisplayEntries(logs, consoleShowInfo_, consoleShowWarnings_, consoleShowErrors_, search,
                                   consoleCollapse_);

    if (DrawConsoleFilterToggle("Errors " + std::to_string(errorCount), consoleShowErrors_,
                                ImVec4(0.92f, 0.52f, 0.52f, 1.0f))) {
        consoleShowErrors_ = !consoleShowErrors_;
    }
    ImGui::SameLine();
    if (DrawConsoleFilterToggle("Warnings " + std::to_string(warningCount), consoleShowWarnings_,
                                ImVec4(1.0f, 0.78f, 0.32f, 1.0f))) {
        consoleShowWarnings_ = !consoleShowWarnings_;
    }
    ImGui::SameLine();
    if (DrawConsoleFilterToggle("Logs " + std::to_string(infoCount), consoleShowInfo_, AccentColor())) {
        consoleShowInfo_ = !consoleShowInfo_;
    }
    ImGui::SameLine();
    if (DrawConsoleFilterToggle("Collapse", consoleCollapse_, AccentColor())) {
        consoleCollapse_ = !consoleCollapse_;
    }
    ImGui::SameLine();
    if (DrawConsoleFilterToggle("Pause", consolePaused_, AccentColor())) {
        consolePaused_ = !consolePaused_;
        if (!consolePaused_) {
            consolePausedSnapshotValid_ = false;
            consolePausedLogs_.clear();
        }
    }
    ImGui::SameLine();
    if (DrawConsoleFilterToggle("Error Pause", consoleErrorPause_, ImVec4(0.92f, 0.52f, 0.52f, 1.0f))) {
        consoleErrorPause_ = !consoleErrorPause_;
        consoleLastObservedLogSequence_ = MaxLogSequence(liveLogs);
    }
    ImGui::SameLine();
    if (DrawConsoleFilterToggle("Clear On Play", consoleClearOnPlay_, AccentColor())) {
        consoleClearOnPlay_ = !consoleClearOnPlay_;
        consoleWasPlaying_ = state_.IsPlaying();
    }
    ImGui::SameLine();
    if (ImGui::SmallButton("Clear")) {
        state_.ClearConsole();
        consolePausedLogs_.clear();
        consolePausedSnapshotValid_ = false;
        consoleLastObservedLogSequence_ = 0;
    }
    ImGui::SameLine();
    ImGui::BeginDisabled(displayEntries.empty());
    if (ImGui::SmallButton("Copy Visible")) {
        const std::string clipboard = BuildConsoleClipboardText(displayEntries);
        ImGui::SetClipboardText(clipboard.c_str());
        state_.AddActivity("console.copy", "Copied", std::to_string(displayEntries.size()) + " visible log entries.");
    }
    ImGui::EndDisabled();
    ImGui::SameLine();
    if (ImGui::SmallButton("Validate Scene")) {
        const SceneValidationResult validation = state_.ValidateScene();
        for (const std::string& diagnostic : validation.diagnostics) {
            state_.AddLog(validation.ok ? LogLevel::Info : LogLevel::Warning, diagnostic);
        }
        state_.AddActivity("validate.scene", validation.ok ? "Passed" : "Failed", "Manual validation command");
    }
    ImGui::SameLine();
    if (ImGui::SmallButton("Compile Scripts")) {
        CompileScriptsFromUi();
    }

    const float searchWidth = std::clamp(ImGui::GetWindowWidth() * 0.24f, Scaled(150.0f), Scaled(300.0f));
    const float availableWidth = ImGui::GetContentRegionAvail().x;
    if (availableWidth > searchWidth + Scaled(18.0f)) {
        ImGui::SameLine(ImGui::GetCursorPosX() + availableWidth - searchWidth);
    }
    ImGui::SetNextItemWidth(searchWidth);
    ImGui::InputTextWithHint("##console_search", "Search logs", consoleSearchInput_.data(), consoleSearchInput_.size());

    if (consolePaused_ && liveLogs.size() > consolePausedLogs_.size()) {
        DrawMutedWrapped(std::to_string(liveLogs.size() - consolePausedLogs_.size()) +
                         " new entries are hidden while the console view is paused.");
    }

    ImGui::Separator();
    ImGui::BeginChild("console_scroll", ImVec2(0.0f, 0.0f), false, ImGuiWindowFlags_AlwaysVerticalScrollbar);
    if (liveLogs.empty()) {
        DrawEmptyState("Console is clear.", "Validation, save, and gateway diagnostics will appear here.");
    } else if (displayEntries.empty()) {
        DrawEmptyState("No visible console entries.", "Enable a log type or clear the search filter.");
    } else if (ImGui::BeginTable("console_log_table", 3,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp |
                                     ImGuiTableFlags_BordersInnerV)) {
        ImGui::TableSetupColumn("Time", ImGuiTableColumnFlags_WidthFixed, Scaled(68.0f));
        ImGui::TableSetupColumn("Level", ImGuiTableColumnFlags_WidthFixed, Scaled(82.0f));
        ImGui::TableSetupColumn("Message", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableHeadersRow();
        for (size_t index = 0; index < displayEntries.size(); ++index) {
            const ConsoleLogDisplayEntry& display = displayEntries[index];
            if (display.entry == nullptr) {
                continue;
            }
            const LogEntry& entry = *display.entry;
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            ImGui::TextDisabled("%s", FormatConsoleTimestamp(entry.timestamp).c_str());
            ImGui::TableSetColumnIndex(1);
            const std::string levelLabel = display.count > 1
                                               ? std::string(LogLevelLabel(entry.level)) + " x" +
                                                     std::to_string(display.count)
                                               : std::string(LogLevelLabel(entry.level));
            DrawStatusBadge(levelLabel.c_str(), LogColor(entry.level));
            ImGui::TableSetColumnIndex(2);
            ImGui::PushStyleColor(ImGuiCol_Text, entry.level == LogLevel::Info ? ImVec4(0.80f, 0.86f, 0.92f, 1.0f)
                                                                               : LogColor(entry.level));
            ImGui::PushID(static_cast<int>(entry.sequence));
            DrawSelectableTextBlock(entry.message, Scaled(130.0f));
            ImGui::PopStyleColor();
            if (ImGui::BeginPopupContextItem("console_log_context")) {
                if (ImGui::MenuItem("Copy Message")) {
                    ImGui::SetClipboardText(entry.message.c_str());
                    state_.AddActivity("console.copy", "Copied", "Copied one console message.");
                }
                if (ImGui::MenuItem("Copy Entry")) {
                    const std::string clipboard = ConsoleEntryClipboardLine(display);
                    ImGui::SetClipboardText(clipboard.c_str());
                    state_.AddActivity("console.copy", "Copied", "Copied one formatted console entry.");
                }
                if (ImGui::MenuItem("Copy Visible")) {
                    const std::string clipboard = BuildConsoleClipboardText(displayEntries);
                    ImGui::SetClipboardText(clipboard.c_str());
                    state_.AddActivity("console.copy", "Copied",
                                       std::to_string(displayEntries.size()) + " visible log entries.");
                }
                ImGui::Separator();
                if (ImGui::MenuItem("Clear")) {
                    state_.ClearConsole();
                    consolePausedLogs_.clear();
                    consolePausedSnapshotValid_ = false;
                    consoleLastObservedLogSequence_ = 0;
                }
                ImGui::EndPopup();
            }
            ImGui::PopID();
        }
        ImGui::EndTable();
    }
    if (!consolePaused_ && ImGui::GetScrollY() >= ImGui::GetScrollMaxY()) {
        ImGui::SetScrollHereY(1.0f);
    }
    ImGui::EndChild();
    ImGui::End();
}

void EditorApp::DrawCodexSetupSection() {
    const ProviderHealth* codexHealth = orchestrator_.FindProvider(AgentBackend::CodexCli);
    if (codexHealth == nullptr || codexHealth->available) {
        return;
    }

    std::string setupReason = ProviderStateLabel(codexHealth);
    if (setupReason == "Not found") {
        setupReason = "Codex CLI missing";
    } else if (setupReason == "WindowsApps alias inaccessible") {
        setupReason = "WindowsApps alias blocked";
    } else if (setupReason == "Not authenticated") {
        setupReason = "Codex login required";
    } else if (setupReason == "Launch failed") {
        setupReason = "Codex launch failed";
    }

    const float setupHeight = showCodexPathInput_ ? Scaled(318.0f) : Scaled(224.0f);
    ImGui::BeginChild("codex_setup_card", ImVec2(0.0f, setupHeight), true,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::TextUnformatted("Codex CLI setup");
    ImGui::PopStyleColor();
    ImGui::SameLine(0.0f, Scaled(8.0f));
    DrawStatusBadge(setupReason.c_str(), ProviderStatusColor(codexHealth));
    DrawMutedWrapped("Codex is installed separately from this editor. Log in once, then refresh backend health.");
    DrawMutedWrapped(TruncateForUi(codexHealth->detail.empty() ? "Reason: " + setupReason
                                                               : "Reason: " + setupReason + ". " + codexHealth->detail,
                                   260));
    if (!codexHealth->detail.empty() && ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", codexHealth->detail.c_str());
    }

    if (ImGui::BeginTable("codex_setup_actions", 2, ImGuiTableFlags_SizingStretchSame)) {
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        ImGui::BeginDisabled(!CanLaunchCodexLogin(codexHealth));
        if (ImGui::Button("Log In To Codex", ImVec2(-FLT_MIN, 0.0f))) {
            OpenCodexLoginFromUi();
        }
        ImGui::EndDisabled();
        ImGui::TableSetColumnIndex(1);
        if (ImGui::Button("Refresh Codex", ImVec2(-FLT_MIN, 0.0f))) {
            RequestProviderHealthRefresh("Codex setup panel refresh");
        }

        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        if (ImGui::Button("Set Codex Path", ImVec2(-FLT_MIN, 0.0f))) {
            showCodexPathInput_ = !showCodexPathInput_;
        }
        ImGui::TableSetColumnIndex(1);
        if (ImGui::Button("Install / Docs", ImVec2(-FLT_MIN, 0.0f))) {
            if (OpenExternalUrl("https://developers.openai.com/codex/cli")) {
                state_.AddActivity("Codex setup", "Opened", "Opened Codex CLI installation documentation.");
            } else {
                state_.AddLog(LogLevel::Warning, "Could not open Codex CLI installation documentation.");
            }
        }
        ImGui::EndTable();
    }

    if (showCodexPathInput_) {
        ImGui::TextUnformatted("AI_NATIVE_CODEX_PATH");
        ImGui::SetNextItemWidth(-1.0f);
        ImGui::InputTextWithHint("##codex_path_input", "C:\\path\\to\\codex.exe", codexPathInput_.data(),
                                 codexPathInput_.size());
        if (ImGui::BeginTable("codex_path_actions", 3, ImGuiTableFlags_SizingStretchSame)) {
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            if (ImGui::Button("Apply Path", ImVec2(-FLT_MIN, 0.0f))) {
                ApplyCodexPathFromUi();
            }
            ImGui::TableSetColumnIndex(1);
            if (ImGui::Button("Clear Path", ImVec2(-FLT_MIN, 0.0f))) {
                std::fill(codexPathInput_.begin(), codexPathInput_.end(), '\0');
                ApplyCodexPathFromUi();
            }
            ImGui::TableSetColumnIndex(2);
            if (ImGui::Button("Cancel", ImVec2(-FLT_MIN, 0.0f))) {
                showCodexPathInput_ = false;
            }
            ImGui::EndTable();
        }
    }
    ImGui::EndChild();
}

void EditorApp::DrawAIChatPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.AgentPanel");
    if (!BeginPanel(panel, ImVec2(640.0f, 420.0f))) {
        ImGui::End();
        return;
    }

    const float availableWidth = ImGui::GetContentRegionAvail().x;
    if (availableWidth >= Scaled(660.0f)) {
        if (ImGui::BeginTable("agent_workspace_table", 2, ImGuiTableFlags_SizingStretchProp)) {
            ImGui::TableSetupColumn("Chats", ImGuiTableColumnFlags_WidthFixed, Scaled(256.0f));
            ImGui::TableSetupColumn("Workspace", ImGuiTableColumnFlags_WidthStretch);
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            DrawAgentConversationSidebar(false);
            ImGui::TableSetColumnIndex(1);
            DrawAgentWorkflow();
            ImGui::EndTable();
        }
    } else {
        DrawAgentConversationSidebar(true);
        ImGui::Separator();
        DrawAgentWorkflow();
    }
    DrawAgentHistoryPanel();

    ImGui::End();
}

std::filesystem::path EditorApp::ProfilerDefaultExportPath() const {
    if (options_.smokeTestProfiler) {
        return std::filesystem::current_path() / "build" / "profiler-smoke" / "profiler-report.json";
    }

    const std::string stamp = SanitizePathSegment(CurrentTimestampUtc(), "capture");
    return AgentMemoryDirectoryPath() / "perf" / ("perf-profile-" + stamp + ".json");
}

bool EditorApp::ExportProfilerReport(const std::filesystem::path& outputPath, std::string* error) {
    if (!profiler_.ExportReport(outputPath, error)) {
        profilerStatus_ = error == nullptr || error->empty() ? "Profiler export failed." : "Profiler export failed: " + *error;
        return false;
    }

    profilerLastExportPath_ = outputPath.string();
    profilerStatus_ = "Profiler report exported.";
    state_.AddActivity("profiler.export", "Exported", profilerLastExportPath_);
    return true;
}

void EditorApp::DrawProfilerPanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.ProfilerPanel");
    if (!BeginPanel(panel, ImVec2(420.0f, 300.0f))) {
        ImGui::End();
        return;
    }

    bool enabled = profiler_.Enabled();
    if (ImGui::Checkbox("Capture", &enabled)) {
        profiler_.SetEnabled(enabled);
        profilerStatus_ = enabled ? "Profiler capture enabled." : "Profiler capture disabled.";
    }
    ImGui::SameLine();
    bool paused = profiler_.Paused();
    ImGui::BeginDisabled(!profiler_.Enabled());
    if (ImGui::Checkbox("Pause", &paused)) {
        profiler_.SetPaused(paused);
        profilerStatus_ = paused ? "Profiler capture paused." : "Profiler capture resumed.";
    }
    ImGui::EndDisabled();
    ImGui::SameLine();
    if (ImGui::Button("Clear")) {
        profiler_.Clear();
        profilerStatus_ = "Profiler capture cleared.";
    }
    ImGui::SameLine();
    if (ImGui::Button("Export")) {
        std::string error;
        ExportProfilerReport(ProfilerDefaultExportPath(), &error);
    }

    const char* filters[] = {"Editor", "Runtime", "Combined"};
    profilerDomainFilter_ = std::clamp(profilerDomainFilter_, 0, 2);
    ImGui::SetNextItemWidth(Scaled(160.0f));
    ImGui::Combo("View", &profilerDomainFilter_, filters, IM_ARRAYSIZE(filters));
    if (!profilerStatus_.empty()) {
        DrawMutedWrapped(profilerStatus_);
    }

    const PerformanceProfilerSnapshot snapshot = profiler_.Snapshot();
    DrawSectionTitle("Frame Summary");
    if (snapshot.frameCount == 0) {
        DrawEmptyState("No profiler samples yet.", "Enable capture and run the editor or Play Mode to collect frame data.");
    } else {
        auto msText = [](double value) {
            std::ostringstream stream;
            stream << std::fixed << std::setprecision(2) << value << " ms";
            return stream.str();
        };
        DrawKeyValue("Frames", std::to_string(snapshot.frameCount), Scaled(118.0f));
        DrawKeyValue("Last editor", msText(snapshot.lastEditorFrameMs), Scaled(118.0f));
        DrawKeyValue("Last runtime", msText(snapshot.lastRuntimeFrameMs), Scaled(118.0f));
        DrawKeyValue("Last export", profilerLastExportPath_.empty() ? "-" : TruncateForUi(profilerLastExportPath_, 160),
                     Scaled(118.0f));
    }

    auto showDomain = [this](PerformanceDomain domain) {
        return profilerDomainFilter_ == 2 ||
               (profilerDomainFilter_ == 0 && domain == PerformanceDomain::Editor) ||
               (profilerDomainFilter_ == 1 && domain == PerformanceDomain::Runtime);
    };

    DrawSectionTitle("Slowest Zones");
    if (snapshot.zones.empty()) {
        DrawMutedWrapped("No timed zones have been captured.");
    } else if (ImGui::BeginTable("profiler_zones", 6,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_BordersInnerV |
                                     ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("Domain", ImGuiTableColumnFlags_WidthFixed, Scaled(74.0f));
        ImGui::TableSetupColumn("Zone", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableSetupColumn("Avg", ImGuiTableColumnFlags_WidthFixed, Scaled(62.0f));
        ImGui::TableSetupColumn("P95", ImGuiTableColumnFlags_WidthFixed, Scaled(62.0f));
        ImGui::TableSetupColumn("Max", ImGuiTableColumnFlags_WidthFixed, Scaled(62.0f));
        ImGui::TableSetupColumn("Samples", ImGuiTableColumnFlags_WidthFixed, Scaled(66.0f));
        ImGui::TableHeadersRow();
        int displayed = 0;
        for (const PerformanceZoneSummary& zone : snapshot.zones) {
            if (!showDomain(zone.domain)) {
                continue;
            }
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            ImGui::TextUnformatted(PerformanceDomainLabel(zone.domain));
            ImGui::TableSetColumnIndex(1);
            ImGui::TextWrapped("%s", zone.name.c_str());
            ImGui::TableSetColumnIndex(2);
            ImGui::Text("%.2f", zone.avgMs);
            ImGui::TableSetColumnIndex(3);
            ImGui::Text("%.2f", zone.p95Ms);
            ImGui::TableSetColumnIndex(4);
            ImGui::Text("%.2f", zone.maxMs);
            ImGui::TableSetColumnIndex(5);
            ImGui::Text("%d", zone.sampleCount);
            if (++displayed >= 12) {
                break;
            }
        }
        ImGui::EndTable();
    }

    DrawSectionTitle("Recent Spikes");
    if (snapshot.spikes.empty()) {
        DrawMutedWrapped("No frame or zone spikes over the current thresholds.");
    } else if (ImGui::BeginTable("profiler_spikes", 4,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_BordersInnerV |
                                     ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("Frame", ImGuiTableColumnFlags_WidthFixed, Scaled(58.0f));
        ImGui::TableSetupColumn("Domain", ImGuiTableColumnFlags_WidthFixed, Scaled(74.0f));
        ImGui::TableSetupColumn("Zone", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableSetupColumn("Ms", ImGuiTableColumnFlags_WidthFixed, Scaled(64.0f));
        ImGui::TableHeadersRow();
        for (const PerformanceSpike& spike : snapshot.spikes) {
            if (!showDomain(spike.domain)) {
                continue;
            }
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            ImGui::Text("%d", spike.frameIndex);
            ImGui::TableSetColumnIndex(1);
            ImGui::TextUnformatted(PerformanceDomainLabel(spike.domain));
            ImGui::TableSetColumnIndex(2);
            ImGui::TextWrapped("%s", spike.zoneName.c_str());
            ImGui::TableSetColumnIndex(3);
            ImGui::Text("%.2f", spike.ms);
        }
        ImGui::EndTable();
    }

    DrawSectionTitle("Counters");
    if (snapshot.counters.empty()) {
        DrawMutedWrapped("No counters captured yet.");
    } else if (ImGui::BeginTable("profiler_counters", 3,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_BordersInnerV |
                                     ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("Domain", ImGuiTableColumnFlags_WidthFixed, Scaled(74.0f));
        ImGui::TableSetupColumn("Counter", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableSetupColumn("Value", ImGuiTableColumnFlags_WidthFixed, Scaled(82.0f));
        ImGui::TableHeadersRow();
        for (const PerformanceCounterSummary& counter : snapshot.counters) {
            if (!showDomain(counter.domain)) {
                continue;
            }
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            ImGui::TextUnformatted(PerformanceDomainLabel(counter.domain));
            ImGui::TableSetColumnIndex(1);
            ImGui::TextWrapped("%s", counter.name.c_str());
            ImGui::TableSetColumnIndex(2);
            ImGui::Text("%.0f", counter.value);
        }
        ImGui::EndTable();
    }

    DrawSectionTitle("Measured Guidance");
    for (const std::string& line : snapshot.guidance) {
        ImGui::Bullet();
        ImGui::SameLine();
        DrawMutedWrapped(line);
    }

    ImGui::End();
}

void EditorApp::SelectAgentConversation(const std::string& id) {
    if (!state_.SwitchChatConversation(id)) {
        return;
    }
    std::fill(chatInput_.begin(), chatInput_.end(), '\0');
    std::fill(composerPromptInput_.begin(), composerPromptInput_.end(), '\0');
    std::fill(composerRequestInput_.begin(), composerRequestInput_.end(), '\0');
    composerRunId_.clear();
    composerStatus_.clear();
    agentSurfaceStatus_ = "Switched chat.";
}

void EditorApp::StartNewAgentConversation() {
    const std::string id = state_.CreateChatConversation("New chat");
    SelectAgentConversation(id);
    agentSurfaceStatus_ = "Started a new Codex chat.";
}

void EditorApp::DrawAgentConversationSidebar(bool compact) {
    const float height = compact ? Scaled(166.0f) : 0.0f;
    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, Scaled(8.0f));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_WindowPadding, Scaled(ImVec2(10.0f, 10.0f)));
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), compact ? 0.010f : 0.018f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.090f), 0.76f));
    ImGui::BeginChild(compact ? "agent_chat_rail_compact" : "agent_chat_rail", ImVec2(0.0f, height), true,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);

    if (ImGui::Button("+ New chat", ImVec2(-FLT_MIN, 0.0f))) {
        StartNewAgentConversation();
    }

    const ChatConversation* activeConversation = state_.ActiveChatConversation();
    if (activeConversation != nullptr) {
        const char* pinLabel = activeConversation->pinned ? "Unpin chat" : "Pin chat";
        if (DrawChip(pinLabel)) {
            const bool pin = !activeConversation->pinned;
            state_.SetChatConversationPinned(activeConversation->id, pin);
            agentSurfaceStatus_ = pin ? "Chat pinned." : "Chat unpinned.";
        }
        ImGui::SameLine();
        if (DrawChip("History")) {
            showAgentHistory_ = true;
        }
    }

    ImGui::SetNextItemWidth(-FLT_MIN);
    ImGui::InputTextWithHint("##agent_chat_search", "Search chats", chatSearchInput_.data(), chatSearchInput_.size());
    const std::string search = ToLower(TrimWhitespace(chatSearchInput_.data()));
    const std::vector<ChatConversation>& conversations = state_.ChatConversations();
    const std::string activeId = state_.ActiveChatConversationId();
    std::string pendingDeleteId;
    bool drewPinned = false;
    bool drewDevelopment = false;

    auto matchesSearch = [&](const ChatConversation& conversation) {
        if (search.empty()) {
            return true;
        }
        std::string haystack = ToLower(conversation.title + " " + conversation.projectName);
        for (const ChatMessage& message : conversation.messages) {
            haystack += " " + ToLower(message.message);
        }
        return haystack.find(search) != std::string::npos;
    };

    auto visibleMessageCount = [](const ChatConversation& conversation) {
        return static_cast<int>(std::count_if(conversation.messages.begin(), conversation.messages.end(),
                                              [](const ChatMessage& message) {
                                                  return message.sender != ChatSender::System;
                                              }));
    };

    auto drawGroupLabel = [](const char* label) {
        ImGui::Spacing();
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted(label);
        ImGui::PopStyleColor();
    };

    auto drawConversationRow = [&](const ChatConversation& conversation) {
        if (!matchesSearch(conversation)) {
            return false;
        }
        const bool active = conversation.id == activeId;
        const std::string count = std::to_string(visibleMessageCount(conversation));
        std::string title = conversation.title.empty() ? "New chat" : conversation.title;
        if (conversation.pinned) {
            title = "[pinned] " + title;
        }
        const int titleLimit = compact ? 38 : 30;
        const std::string rowLabel = TruncateForUi(title, titleLimit) + "  " + count + "##" + conversation.id;
        if (ImGui::Selectable(rowLabel.c_str(), active, 0, ImVec2(0.0f, Scaled(28.0f)))) {
            SelectAgentConversation(conversation.id);
        }
        if (ImGui::IsItemHovered()) {
            std::string tooltip = conversation.title + "\nProject: " + conversation.projectName +
                                  "\nMessages: " + std::to_string(visibleMessageCount(conversation));
            ImGui::SetTooltip("%s", tooltip.c_str());
        }
        if (ImGui::BeginPopupContextItem(("chat_context_" + conversation.id).c_str())) {
            if (ImGui::MenuItem(conversation.pinned ? "Unpin chat" : "Pin chat")) {
                state_.SetChatConversationPinned(conversation.id, !conversation.pinned);
            }
            const bool canDelete = conversations.size() > 1 && !(agentJob_ != nullptr && active);
            ImGui::BeginDisabled(!canDelete);
            if (ImGui::MenuItem("Close chat")) {
                pendingDeleteId = conversation.id;
            }
            ImGui::EndDisabled();
            ImGui::EndPopup();
        }
        return true;
    };

    drawGroupLabel("Pinned");
    for (const ChatConversation& conversation : conversations) {
        if (conversation.pinned && drawConversationRow(conversation)) {
            drewPinned = true;
        }
    }
    if (!drewPinned) {
        DrawMutedWrapped("No pinned chats.");
    }

    drawGroupLabel("Development Chats");
    for (const ChatConversation& conversation : conversations) {
        if (!conversation.pinned && drawConversationRow(conversation)) {
            drewDevelopment = true;
        }
    }
    if (!drewDevelopment) {
        DrawMutedWrapped(search.empty() ? "No chats yet." : "No matching chats.");
    }

    if (!pendingDeleteId.empty()) {
        const bool deletingActive = pendingDeleteId == activeId;
        if (state_.DeleteChatConversation(pendingDeleteId) && deletingActive) {
            std::fill(chatInput_.begin(), chatInput_.end(), '\0');
            std::fill(composerPromptInput_.begin(), composerPromptInput_.end(), '\0');
            std::fill(composerRequestInput_.begin(), composerRequestInput_.end(), '\0');
        }
    }

    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(3);
}

void EditorApp::DrawAgentWorkflow() {
    selectedBackend_ = AgentBackend::CodexCli;
    const ProviderHealth* selectedHealth = orchestrator_.FindProvider(AgentBackend::CodexCli);
    const ImGuiStyle& style = ImGui::GetStyle();

    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, Scaled(8.0f));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_WindowPadding, Scaled(ImVec2(11.0f, 9.0f)));
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), 0.010f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.085f), 0.72f));
    ImGui::BeginChild("agent_compact_header", ImVec2(0.0f, Scaled(58.0f)), true, ImGuiWindowFlags_NoScrollbar);

    if (ImGui::BeginTable("agent_header_table", 2, ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("State", ImGuiTableColumnFlags_WidthStretch, 1.0f);
        ImGui::TableSetupColumn("Actions", ImGuiTableColumnFlags_WidthFixed, Scaled(194.0f));
        ImGui::TableNextRow();

        ImGui::TableSetColumnIndex(0);
        const std::string agentState = agentJob_ != nullptr ? "Running" : state_.AgentStatus();
        DrawStatusBadge(TruncateForUi(ProviderStateLabel(selectedHealth), 18).c_str(), ProviderStatusColor(selectedHealth));
        ImGui::SameLine(0.0f, Scaled(8.0f));
        ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
        ImGui::TextUnformatted("Codex");
        ImGui::PopStyleColor();
        ImGui::SameLine(0.0f, Scaled(6.0f));
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted(TruncateForUi(agentState + " | in-editor chat", 30).c_str());
        ImGui::PopStyleColor();

        ImGui::TableSetColumnIndex(1);
        if (ImGui::Button("History", ImVec2(-FLT_MIN, 0.0f))) {
            showAgentHistory_ = true;
        }
        ImGui::EndTable();
    }

    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(3);

    DrawAgentControlStrip();
    DrawAgentVisualControls();

    if (selectedBackend_ == AgentBackend::CodexCli) {
        DrawCodexSetupSection();
    }

    const std::string requestPrompt = TrimWhitespace(chatInput_.data());
    const std::string generatedBrief = TrimWhitespace(composerPromptInput_.data());
    const std::string briefRequest = TrimWhitespace(composerRequestInput_.data());
    const bool hasGeneratedBrief =
        !generatedBrief.empty() && !briefRequest.empty() && PromptTextMatchesUserRequest(requestPrompt, briefRequest);

    const float availableHeight = ImGui::GetContentRegionAvail().y;
    const float minTopHeight = Scaled(180.0f);
    const float minPromptHeight = hasGeneratedBrief ? Scaled(250.0f) : Scaled(142.0f);
    const bool canAnchorPrompt =
        availableHeight > minTopHeight + minPromptHeight + style.ItemSpacing.y && availableHeight > Scaled(300.0f);

    if (canAnchorPrompt) {
        const float preferredPromptHeight = hasGeneratedBrief ? Scaled(314.0f) : Scaled(178.0f);
        const float maxPromptHeight = availableHeight - minTopHeight - style.ItemSpacing.y;
        agentPromptPanelHeight_ = std::clamp(preferredPromptHeight, minPromptHeight, maxPromptHeight);
        const float promptHeight = agentPromptPanelHeight_;
        const float topHeight = availableHeight - promptHeight - style.ItemSpacing.y;

        ImGui::BeginChild("agent_content_top", ImVec2(0.0f, topHeight), false,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar);
        DrawAgentConversationAndRuns();
        ImGui::EndChild();

        ImGui::Spacing();
        ImGui::BeginChild("agent_prompt_bottom", ImVec2(0.0f, 0.0f), false, ImGuiWindowFlags_NoScrollbar);
        DrawAgentPromptComposer();
        ImGui::EndChild();
    } else {
        agentPromptPanelHeight_ = 0.0f;
        ImGui::BeginChild("agent_content_stacked", ImVec2(0.0f, 0.0f), false,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar);
        DrawAgentConversationAndRuns();
        ImGui::Separator();
        DrawAgentPromptComposer();
        ImGui::EndChild();
    }
}

void EditorApp::DrawAgentControlStrip() {
    const float availableWidth = ImGui::GetContentRegionAvail().x;
    const bool compact = availableWidth < Scaled(390.0f);
    const float childHeight = compact ? Scaled(108.0f) : Scaled(82.0f);

    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, Scaled(8.0f));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_WindowPadding, Scaled(ImVec2(11.0f, 8.0f)));
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), 0.014f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.080f), 0.72f));
    ImGui::BeginChild("agent_control_strip", ImVec2(0.0f, childHeight), true, ImGuiWindowFlags_NoScrollbar);

    if (ImGui::BeginTable("agent_control_actions", 2, ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("Label", ImGuiTableColumnFlags_WidthStretch, 1.0f);
        ImGui::TableSetupColumn("Actions", ImGuiTableColumnFlags_WidthFixed, compact ? Scaled(192.0f) : Scaled(232.0f));
        ImGui::TableNextRow();

        ImGui::TableSetColumnIndex(0);
        ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
        ImGui::TextUnformatted("Chat mode");
        ImGui::PopStyleColor();
        ImGui::SameLine(0.0f, Scaled(8.0f));
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted(compact ? "Codex first" : "Codex responses with local AI disabled");
        ImGui::PopStyleColor();

        ImGui::TableSetColumnIndex(1);
        if (DrawChip("Refresh")) {
            RequestProviderHealthRefresh("Agent control strip refresh");
            agentSurfaceStatus_ = "Provider health refresh queued.";
        }
        ImGui::SameLine(0.0f, Scaled(6.0f));
        if (DrawChip("Login")) {
            OpenCodexLoginFromUi();
        }
        ImGui::SameLine(0.0f, Scaled(6.0f));
        if (DrawChip("History")) {
            showAgentHistory_ = true;
        }
        ImGui::EndTable();
    }

    agentRouteSceneEditsLocally_ = false;
    const int modeColumns = compact ? 1 : 3;
    if (ImGui::BeginTable("agent_control_modes", modeColumns, ImGuiTableFlags_SizingStretchSame)) {
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        DrawStatusBadge("Codex primary", AccentColor());
        if (!compact) {
            ImGui::TableSetColumnIndex(1);
            DrawStatusBadge("Local AI off", ImVec4(1.0f, 0.78f, 0.32f, 1.0f));
            ImGui::TableSetColumnIndex(2);
        } else {
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            DrawStatusBadge("Local AI off", ImVec4(1.0f, 0.78f, 0.32f, 1.0f));
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
        }
        if (ImGui::Checkbox("Auto briefs", &agentAutoGenerateImplementationBriefs_)) {
            agentSurfaceStatus_ = agentAutoGenerateImplementationBriefs_ ? "Auto briefs enabled." : "Auto briefs disabled.";
            state_.AddActivity("Agent control", agentAutoGenerateImplementationBriefs_ ? "Enabled" : "Disabled",
                               "Auto briefs");
        }
        if (ImGui::IsItemHovered()) {
            ImGui::SetTooltip("Expand short implementation requests into editable Codex briefs before launch.");
        }
        ImGui::EndTable();
    }

    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(3);
}

void EditorApp::DrawAgentVisualControls() {
    const float availableWidth = ImGui::GetContentRegionAvail().x;
    const bool compact = availableWidth < Scaled(460.0f);
    const float childHeight = compact ? Scaled(112.0f) : Scaled(76.0f);

    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, Scaled(8.0f));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_WindowPadding, Scaled(ImVec2(11.0f, 8.0f)));
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), 0.012f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.080f), 0.72f));
    ImGui::BeginChild("agent_visual_controls", ImVec2(0.0f, childHeight), true, ImGuiWindowFlags_NoScrollbar);

    if (ImGui::BeginTable("agent_visual_actions", compact ? 1 : 2, ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        DrawStatusBadge(agentVisualRecording_ ? "Recording frames" : "Visual context", AccentColor());
        ImGui::SameLine(0.0f, Scaled(8.0f));
        if (ImGui::Checkbox("Auto capture", &agentAutoCaptureVisuals_)) {
            state_.AddActivity("Agent visual context", agentAutoCaptureVisuals_ ? "Enabled" : "Disabled",
                               "Auto capture before agent runs.");
        }
        if (ImGui::IsItemHovered()) {
            ImGui::SetTooltip("Capture Scene and Game screenshots before launching an agent run.");
        }
        if (!agentVisualCaptures_.empty()) {
            const AgentVisualCapture& latest = agentVisualCaptures_.back();
            DrawMutedWrapped(TruncateForUi(latest.view + ": " + latest.path, compact ? 110 : 180));
        } else if (!agentVisualRecordingFolder_.empty()) {
            DrawMutedWrapped(TruncateForUi(agentVisualRecordingFolder_, compact ? 110 : 180));
        }

        if (!compact) {
            ImGui::TableSetColumnIndex(1);
        } else {
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
        }

        if (DrawChip("Capture")) {
            std::vector<AgentVisualCapture> captures;
            const std::string runId = activeAgentRunId_.empty() ? GenerateAgentRunId() : activeAgentRunId_;
            if (CaptureAgentVisualSnapshot("manual agent visual capture", runId, &captures)) {
                agentSurfaceStatus_ = "Captured Scene and Game screenshots.";
            } else {
                agentSurfaceStatus_ = "Visual capture failed; see Agent Activity.";
            }
        }
        ImGui::SameLine(0.0f, Scaled(6.0f));
        if (DrawChip(agentVisualRecording_ ? "Stop Frames" : "Record Frames")) {
            if (agentVisualRecording_) {
                StopAgentVisualRecording();
                agentSurfaceStatus_ = "Stopped visual frame recording.";
            } else {
                StartAgentVisualRecording();
                agentSurfaceStatus_ = "Started visual frame recording.";
            }
        }
        ImGui::SameLine(0.0f, Scaled(6.0f));
        ImGui::BeginDisabled(agentVisualCaptures_.empty() && agentVisualRecordingFolder_.empty());
        if (DrawChip("Copy Path")) {
            const std::string path = !agentVisualCaptures_.empty() ? agentVisualCaptures_.back().path
                                                                   : agentVisualRecordingFolder_;
            ImGui::SetClipboardText(path.c_str());
            state_.AddActivity("Agent visual context", "Copied", path);
        }
        ImGui::EndDisabled();
        if (agentVisualRecording_) {
            ImGui::SameLine(0.0f, Scaled(8.0f));
            ImGui::TextDisabled("%d", agentVisualRecordingFrameCount_);
        }
        ImGui::EndTable();
    }

    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(3);
}

bool EditorApp::DrawAgentCurrentRunCard() {
    const std::string activeConversationId = state_.ActiveChatConversationId();
    AgentRunUiItem* activeCard = nullptr;
    for (auto it = agentRunCards_.rbegin(); it != agentRunCards_.rend(); ++it) {
        if (it->conversationId.empty() || it->conversationId == activeConversationId) {
            activeCard = &(*it);
            break;
        }
    }
    if (activeCard == nullptr) {
        return false;
    }

    AgentRunUiItem& card = *activeCard;
    const bool finished = card.finishedSeconds > 0.0;
    const double now = ImGui::GetTime();
    const float elapsed = static_cast<float>(std::max(0.0, (finished ? card.finishedSeconds : now) - card.startedSeconds));
    const bool running = card.status == "Pending" || card.status == "Running";
    const float cardHeight = running ? Scaled(244.0f) : Scaled(292.0f);

    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, Scaled(8.0f));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), 0.014f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(ActivityStatusColor(card.status), 0.24f));
    ImGui::BeginChild("agent_current_run_card", ImVec2(0.0f, cardHeight), true,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    DrawStatusBadge(card.status.c_str(), ActivityStatusColor(card.status));
    ImGui::SameLine(0.0f, Scaled(8.0f));
    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::TextUnformatted("Current run");
    ImGui::PopStyleColor();
    ImGui::SameLine(0.0f, Scaled(6.0f));
    ImGui::TextDisabled("%s | %s", card.backendLabel.empty() ? AgentOrchestrator::BackendLabel(card.backend)
                                                              : card.backendLabel.c_str(),
                        FormatElapsedTime(elapsed).c_str());

    if (running) {
        const int dotCount = static_cast<int>(std::fmod(now * 2.0, 4.0));
        const std::string label = std::string("Working") + std::string(static_cast<size_t>(dotCount), '.');
        const float phase = static_cast<float>((std::sin(now * 2.8) + 1.0) * 0.5);
        ImGui::PushStyleColor(ImGuiCol_PlotHistogram, AccentColor());
        ImGui::ProgressBar(phase, ImVec2(-1.0f, 0.0f), label.c_str());
        ImGui::PopStyleColor();
    }

    DrawKeyValue("Run", TruncateForUi(card.runId, 76), Scaled(64.0f));
    DrawKeyValue("Stage", card.stage, Scaled(64.0f));
    DrawKeyValue("Output", TruncateForUi(card.outputSummary, 180), Scaled(64.0f));
    DrawMutedWrapped(TruncateForUi(card.summary.empty() ? "No response received yet." : card.summary, 220));

    DrawMutedWrapped("Recent events");
    DrawSelectableTextBlock(BuildRecentActivityTimelineText(state_), running ? Scaled(72.0f) : Scaled(64.0f));

    if (!card.commandSummary.empty()) {
        DrawMutedWrapped("Commands");
        DrawSelectableTextBlock(card.commandSummary, Scaled(58.0f));
    }
    if (!card.changedSummary.empty()) {
        DrawMutedWrapped("Changed");
        DrawSelectableTextBlock(card.changedSummary, Scaled(42.0f));
    }
    if (!card.failureReason.empty()) {
        DrawMutedWrapped("Failure reason");
        DrawSelectableTextBlock(card.failureReason, Scaled(42.0f));
    }
    if (!running && card.resultText != "No response received yet.") {
        DrawMutedWrapped("Result");
        DrawSelectableTextBlock(card.resultText, Scaled(78.0f));
    }

    if (ImGui::SmallButton("Copy Prompt")) {
        ImGui::SetClipboardText(card.prompt.c_str());
        agentSurfaceStatus_ = "Copied run prompt.";
    }
    ImGui::SameLine();
    ImGui::BeginDisabled(card.resultText.empty() || card.resultText == "No response received yet.");
    if (ImGui::SmallButton("Copy Result")) {
        ImGui::SetClipboardText(card.resultText.c_str());
        agentSurfaceStatus_ = "Copied run result.";
    }
    ImGui::EndDisabled();
    if (!card.logPath.empty()) {
        ImGui::SameLine();
        if (ImGui::SmallButton("Copy Log Path")) {
            ImGui::SetClipboardText(card.logPath.c_str());
            agentSurfaceStatus_ = "Copied run log path.";
        }
    }

    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(2);

    if (ImGui::TreeNodeEx("Run details", ImGuiTreeNodeFlags_SpanAvailWidth)) {
        DrawKeyValue("Run", card.runId, Scaled(56.0f));
        DrawKeyValue("Stage", card.stage, Scaled(56.0f));
        if (!card.logPath.empty()) {
            DrawKeyValue("Log", card.logPath, Scaled(56.0f));
        }

        DrawMutedWrapped("Prompt");
        DrawSelectableTextBlock(card.prompt, Scaled(92.0f));
        if (!running) {
            DrawMutedWrapped("Result");
            DrawSelectableTextBlock(card.resultText.empty() ? "No response received yet." : card.resultText,
                                    Scaled(120.0f));
        }
        ImGui::TreePop();
    }

    return true;
}

void EditorApp::DrawAgentConversationAndRuns() {
    if (DrawAgentCurrentRunCard()) {
        ImGui::Spacing();
    }

    if (!proposedActions_.empty()) {
        DrawProposedActionsSection(true);
        ImGui::Separator();
    }

    const std::vector<ChatMessage>& chatHistory = state_.ChatHistory();
    const auto isStartupSystemNote = [](const ChatMessage& message) {
        return message.sender == ChatSender::System &&
               (message.message.rfind("AI surface ready.", 0) == 0 ||
                message.message.rfind("Codex chat ready.", 0) == 0);
    };
    const bool hasVisibleChat = std::any_of(chatHistory.begin(), chatHistory.end(), [&](const ChatMessage& message) {
        return !isStartupSystemNote(message);
    });
    if (hasVisibleChat) {
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted("Conversation");
        ImGui::PopStyleColor();
    }

    const float remainingHeight = std::max(Scaled(160.0f), ImGui::GetContentRegionAvail().y);
    const float advancedReserve = Scaled(34.0f);
    const float conversationHeight = std::max(Scaled(156.0f), remainingHeight - advancedReserve);
    ImGui::BeginChild("agent_conversation_history", ImVec2(0.0f, conversationHeight), false,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    if (!hasVisibleChat) {
        const float emptyHeight = ImGui::GetContentRegionAvail().y;
        ImGui::Dummy(ImVec2(1.0f, std::max(0.0f, emptyHeight * 0.35f - ImGui::GetTextLineHeightWithSpacing())));
        const auto drawCenteredLine = [](const char* text, ImVec4 color) {
            const float startX = ImGui::GetCursorPosX();
            const float width = ImGui::GetContentRegionAvail().x;
            const float textWidth = ImGui::CalcTextSize(text).x;
            ImGui::SetCursorPosX(startX + std::max(0.0f, (width - textWidth) * 0.5f));
            ImGui::PushStyleColor(ImGuiCol_Text, color);
            ImGui::TextUnformatted(text);
            ImGui::PopStyleColor();
        };
        drawCenteredLine("What should we work on?", BrightTextColor());
        drawCenteredLine("Describe an editor, engine, scene, or build task below.", MutedTextColor());
    } else {
        for (size_t index = 0; index < chatHistory.size(); ++index) {
            if (isStartupSystemNote(chatHistory[index])) {
                continue;
            }
            DrawChatMessageCard(chatHistory[index], index, uiScale_);
            if (index + 1 < chatHistory.size()) {
                ImGui::Spacing();
            }
        }
    }
    if (ImGui::GetScrollY() >= ImGui::GetScrollMaxY()) {
        ImGui::SetScrollHereY(1.0f);
    }
    ImGui::EndChild();

    DrawAgentAdvancedDetails();
}

void EditorApp::DrawAgentPromptComposer() {
    const bool agentBusy = agentJob_ != nullptr;

    const ImGuiStyle& style = ImGui::GetStyle();
    const std::string initialRequestPrompt = TrimWhitespace(chatInput_.data());
    const std::string initialGeneratedBrief = TrimWhitespace(composerPromptInput_.data());
    const std::string initialBriefRequest = TrimWhitespace(composerRequestInput_.data());
    const bool initiallyHasGeneratedBrief = !initialGeneratedBrief.empty() && !initialBriefRequest.empty() &&
                                            PromptTextMatchesUserRequest(initialRequestPrompt, initialBriefRequest);
    const float surfaceHeight = std::max(initiallyHasGeneratedBrief ? Scaled(244.0f) : Scaled(136.0f),
                                         ImGui::GetContentRegionAvail().y);

    ImGui::PushStyleVar(ImGuiStyleVar_ChildRounding, Scaled(8.0f));
    ImGui::PushStyleVar(ImGuiStyleVar_ChildBorderSize, 1.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_WindowPadding, Scaled(ImVec2(12.0f, 10.0f)));
    ImGui::PushStyleColor(ImGuiCol_ChildBg, OffsetColor(PanelBackgroundColor(), 0.020f));
    ImGui::PushStyleColor(ImGuiCol_Border, WithAlpha(OffsetColor(PanelBackgroundColor(), 0.110f), 0.78f));
    ImGui::BeginChild("agent_prompt_surface", ImVec2(0.0f, surfaceHeight), true,
                      initiallyHasGeneratedBrief ? ImGuiWindowFlags_AlwaysVerticalScrollbar
                                                 : ImGuiWindowFlags_NoScrollbar);

    const float inputWidth = std::max(Scaled(180.0f), ImGui::GetContentRegionAvail().x);
    WrapInputBufferToWidth(chatInput_, inputWidth);
    const std::string inputPreview = WrapTextForDisplay(chatInput_.data(), inputWidth);
    const size_t inputLineCount = CountDisplayLines(inputPreview);
    const float inputMinHeight = ImGui::GetFrameHeightWithSpacing() * 1.85f;
    const float inputMaxHeight = std::max(inputMinHeight, initiallyHasGeneratedBrief ? Scaled(80.0f) : Scaled(108.0f));
    const float inputHeight = std::clamp(ImGui::GetTextLineHeightWithSpacing() * static_cast<float>(inputLineCount) +
                                             style.FramePadding.y * 2.0f,
                                         inputMinHeight, inputMaxHeight);
    const ImVec2 inputPos = ImGui::GetCursorScreenPos();
    bool sendRequested = false;
    const std::string previousInput = chatInput_.data();
    ImGui::BeginDisabled(agentBusy);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameBorderSize, 0.0f);
    ImGui::PushStyleVar(ImGuiStyleVar_FrameRounding, Scaled(6.0f));
    ImGui::PushStyleColor(ImGuiCol_FrameBg, OffsetColor(PanelBackgroundColor(), 0.006f));
    ImGui::PushStyleColor(ImGuiCol_FrameBgHovered, OffsetColor(PanelBackgroundColor(), 0.014f));
    ImGui::PushStyleColor(ImGuiCol_FrameBgActive, OffsetColor(PanelBackgroundColor(), 0.020f));
    const bool inputSubmitted = ImGui::InputTextMultiline(
        "##agent_prompt", chatInput_.data(), chatInput_.size(), ImVec2(-1.0f, inputHeight),
        ImGuiInputTextFlags_NoHorizontalScroll | ImGuiInputTextFlags_EnterReturnsTrue |
            ImGuiInputTextFlags_CtrlEnterForNewLine);
    ImGui::PopStyleColor(3);
    ImGui::PopStyleVar(2);
    const bool inputActive = ImGui::IsItemActive();
    if (inputSubmitted && !ImGui::GetIO().KeyCtrl) {
        sendRequested = true;
    }
    ImGui::EndDisabled();
    const bool inputEdited = previousInput != chatInput_.data();
    if (inputEdited) {
        WrapInputBufferToWidth(chatInput_, inputWidth);
        const std::string currentPrompt = TrimWhitespace(chatInput_.data());
        const std::string briefRequest = TrimWhitespace(composerRequestInput_.data());
        if (!briefRequest.empty() && !PromptTextMatchesUserRequest(currentPrompt, briefRequest)) {
            std::fill(composerPromptInput_.begin(), composerPromptInput_.end(), '\0');
            std::fill(composerRequestInput_.begin(), composerRequestInput_.end(), '\0');
            composerRunId_.clear();
            composerStatus_.clear();
        }
    }
    if (chatInput_[0] == '\0' && !inputActive) {
        const char* placeholder = "Ask Codex to build, debug, polish, or change the current project...";
        const float placeholderWrapWidth = std::max(Scaled(80.0f), inputWidth - style.FramePadding.x * 2.0f);
        const ImVec4 clipRect(inputPos.x, inputPos.y, inputPos.x + inputWidth, inputPos.y + inputHeight);
        ImGui::GetWindowDrawList()->AddText(
            nullptr, 0.0f, ImVec2(inputPos.x + style.FramePadding.x, inputPos.y + style.FramePadding.y),
            ColorU32(MutedTextColor()), placeholder, nullptr, placeholderWrapWidth, &clipRect);
    }

    const std::string requestPrompt = TrimWhitespace(chatInput_.data());
    const std::string generatedBrief = TrimWhitespace(composerPromptInput_.data());
    const std::string briefRequest = TrimWhitespace(composerRequestInput_.data());
    const bool hasGeneratedBrief =
        !generatedBrief.empty() && !briefRequest.empty() && PromptTextMatchesUserRequest(requestPrompt, briefRequest);
    const bool willAutoGenerateBrief =
        agentAutoGenerateImplementationBriefs_ && !hasGeneratedBrief &&
        ShouldAutoGenerateImplementationBrief(selectedBackend_, requestPrompt);
    const std::string sendPrompt = hasGeneratedBrief ? generatedBrief : requestPrompt;
    const bool canSend = state_.IsEditMode() && !agentBusy && !sendPrompt.empty();
    const bool buildLaunchIntent = PromptLooksLikeBuildLaunchIntent(requestPrompt);
    const bool willBuildLaunchBrief = agentAutoGenerateImplementationBriefs_ && buildLaunchIntent;

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Agent commands are edit-time changes; stop Play Mode before sending a prompt.");
    }
    if (willAutoGenerateBrief || willBuildLaunchBrief) {
        DrawMutedWrapped(willBuildLaunchBrief
                             ? "Send will create a build brief and launch the development backend."
                             : "This looks like implementation work, so Send will create a full brief before launching the backend.");
    }

    const float fullWidth = ImGui::GetContentRegionAvail().x;
    const float gap = ImGui::GetStyle().ItemSpacing.x;
    const float rowStartX = ImGui::GetCursorPosX();
    const float actionRowStartScreenX = ImGui::GetCursorScreenPos().x;
    const float actionRowMaxScreenX = actionRowStartScreenX + fullWidth;
    const float sendWidth = Scaled(82.0f);
    const bool compactControls = fullWidth < Scaled(360.0f);

    ImGui::BeginDisabled(agentBusy || requestPrompt.empty());
    if (DrawChip("Improve")) {
        ImproveAgentPromptDraft();
    }
    ImGui::EndDisabled();
    ImGui::SameLine(0.0f, gap);
    ImGui::BeginDisabled(agentBusy || requestPrompt.empty());
    if (DrawChip("Brief")) {
        CreateImplementationBriefFromAgentPrompt();
    }
    ImGui::EndDisabled();
    ImGui::SameLine(0.0f, gap);
    if (DrawChip("History")) {
        showAgentHistory_ = true;
    }

    if (!compactControls) {
        const float sendX = rowStartX + fullWidth - sendWidth;
        if (ImGui::GetItemRectMax().x + gap + sendWidth <= actionRowMaxScreenX) {
            ImGui::SameLine(sendX);
        } else {
            ImGui::SetCursorPosX(sendX);
        }
    }
    ImGui::BeginDisabled(!canSend);
    if (ImGui::Button("Send", compactControls ? ImVec2(-FLT_MIN, 0.0f) : ImVec2(sendWidth, 0.0f))) {
        sendRequested = true;
    }
    ImGui::EndDisabled();
    if (sendRequested && canSend) {
        const bool sentContextRich = hasGeneratedBrief || willAutoGenerateBrief;
        if (SendChatPrompt()) {
            agentSurfaceStatus_ = sentContextRich ? "Sent a context-rich implementation brief to the agent."
                                                  : "Sent prompt to the agent.";
        }
    }

    const std::vector<std::string> suggestions = requestPrompt.empty()
                                                     ? orchestrator_.PromptSuggestions(chatInput_.data(), state_)
                                                     : std::vector<std::string>{};
    if (!suggestions.empty()) {
        const size_t maxSuggestionCount = inputWidth > Scaled(680.0f) ? 3 : inputWidth > Scaled(460.0f) ? 2 : 1;
        const size_t suggestionCount = std::min<size_t>(suggestions.size(), maxSuggestionCount);
        const float chipRowStartX = ImGui::GetCursorScreenPos().x;
        const float chipRowMaxX = chipRowStartX + inputWidth;
        const float chipGap = style.ItemSpacing.x;
        for (size_t index = 0; index < suggestionCount; ++index) {
            if (index > 0) {
                const std::string probeLabel = FitChipLabelToWidth(suggestions[index], inputWidth);
                const float nextChipWidth = ChipWidthForLabel(probeLabel);
                if (ImGui::GetItemRectMax().x + chipGap + nextChipWidth <= chipRowMaxX) {
                    ImGui::SameLine(0.0f, chipGap);
                }
            }
            ImGui::PushID(static_cast<int>(index));
            const std::string chipLabel = FitChipLabelToWidth(suggestions[index], inputWidth);
            if (DrawChip(chipLabel.c_str())) {
                CopyStringToBuffer(chatInput_, suggestions[index]);
                WrapInputBufferToWidth(chatInput_, inputWidth);
            }
            if (chipLabel != suggestions[index] && ImGui::IsItemHovered()) {
                ImGui::SetTooltip("%s", suggestions[index].c_str());
            }
            ImGui::PopID();
        }
        ImGui::Spacing();
    }

    if (hasGeneratedBrief) {
        ImGui::Spacing();
        DrawStatusBadge("Brief ready", ActivityStatusColor("Saved"));
        ImGui::SameLine(0.0f, Scaled(8.0f));
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted(agentBusy ? "Agent is using this generated brief." : "Send will use the editable brief.");
        ImGui::PopStyleColor();
        ImGui::SameLine();
        if (ImGui::SmallButton("Copy Brief")) {
            ImGui::SetClipboardText(generatedBrief.c_str());
            agentSurfaceStatus_ = "Copied implementation brief.";
            state_.AddActivity("Agent brief", "Copied", composerRunId_.empty() ? "current brief" : composerRunId_);
        }
        if (ImGui::TreeNodeEx("Review generated brief", ImGuiTreeNodeFlags_SpanAvailWidth)) {
            const float generatedBriefWidth = std::max(Scaled(180.0f), ImGui::GetContentRegionAvail().x);
            WrapInputBufferToWidth(composerPromptInput_, generatedBriefWidth);
            const std::string previousBrief = composerPromptInput_.data();
            ImGui::PushStyleColor(ImGuiCol_FrameBg, OffsetColor(PanelBackgroundColor(), 0.010f));
            ImGui::PushStyleColor(ImGuiCol_FrameBgHovered, OffsetColor(PanelBackgroundColor(), 0.020f));
            ImGui::InputTextMultiline("##agent_generated_brief", composerPromptInput_.data(), composerPromptInput_.size(),
                                      ImVec2(-1.0f, Scaled(agentBusy ? 96.0f : 124.0f)),
                                      ImGuiInputTextFlags_AllowTabInput | ImGuiInputTextFlags_NoHorizontalScroll);
            ImGui::PopStyleColor(2);
            if (previousBrief != composerPromptInput_.data()) {
                WrapInputBufferToWidth(composerPromptInput_, generatedBriefWidth);
            }
            ImGui::TreePop();
        }
    }

    if (!agentSurfaceStatus_.empty()) {
        DrawMutedWrapped(TruncateForUi(agentSurfaceStatus_, 180));
    }
    if (!composerStatus_.empty() && composerStatus_ != agentSurfaceStatus_) {
        DrawMutedWrapped(TruncateForUi(composerStatus_, 180));
    }

    ImGui::EndChild();
    ImGui::PopStyleColor(2);
    ImGui::PopStyleVar(3);
}

void EditorApp::DrawAgentRunCards() {
    if (agentRunCards_.empty()) {
        return;
    }

    const size_t visibleCount = std::min<size_t>(agentRunCards_.size(), 2);
    for (size_t offset = 0; offset < visibleCount; ++offset) {
        const size_t index = agentRunCards_.size() - 1 - offset;
        DrawAgentRunCard(index);
        if (offset + 1 < visibleCount) {
            ImGui::Spacing();
        }
    }
}

void EditorApp::DrawAgentRunCard(size_t index) {
    if (index >= agentRunCards_.size()) {
        return;
    }

    AgentRunUiItem& card = agentRunCards_[index];
    const bool finished = card.finishedSeconds > 0.0;
    const double now = ImGui::GetTime();
    const float elapsed = static_cast<float>(std::max(0.0, (finished ? card.finishedSeconds : now) - card.startedSeconds));
    const bool running = card.status == "Pending" || card.status == "Running";
    const float cardHeight = running ? Scaled(142.0f) : Scaled(176.0f);

    ImGui::PushID(static_cast<int>(index));
    ImGui::BeginChild("agent_run_card", ImVec2(0.0f, cardHeight), true,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    DrawStatusBadge(card.status.c_str(), ActivityStatusColor(card.status));
    ImGui::SameLine();
    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::TextWrapped("%s", card.backendLabel.empty() ? AgentOrchestrator::BackendLabel(card.backend)
                                                       : card.backendLabel.c_str());
    ImGui::PopStyleColor();
    ImGui::SameLine();
    ImGui::TextDisabled("%s", FormatElapsedTime(elapsed).c_str());

    if (running) {
        const int dotCount = static_cast<int>(std::fmod(now * 2.0, 4.0));
        const std::string label = std::string("Thinking") + std::string(static_cast<size_t>(dotCount), '.');
        const float phase = static_cast<float>((std::sin(now * 2.8) + 1.0) * 0.5);
        ImGui::PushStyleColor(ImGuiCol_PlotHistogram, AccentColor());
        ImGui::ProgressBar(phase, ImVec2(-1.0f, 0.0f), label.c_str());
        ImGui::PopStyleColor();
        DrawMutedWrapped("Waiting for provider response. The editor stays usable; streaming is not wired yet.");
    }

    DrawKeyValue("Stage", card.stage, Scaled(70.0f));
    DrawMutedWrapped(TruncateForUi(card.summary.empty() ? "No response received yet." : card.summary, 180));

    if (ImGui::SmallButton("Copy Prompt")) {
        ImGui::SetClipboardText(card.prompt.c_str());
        card.stage = "Copied prompt";
        agentSurfaceStatus_ = "Copied run prompt.";
        state_.AddActivity("Agent run", "Copied", card.runId + " prompt");
    }
    ImGui::SameLine();
    ImGui::BeginDisabled(card.resultText.empty() || card.resultText == "No response received yet.");
    if (ImGui::SmallButton("Copy Result")) {
        ImGui::SetClipboardText(card.resultText.c_str());
        card.stage = "Copied result";
        agentSurfaceStatus_ = "Copied run result.";
        state_.AddActivity("Agent run", "Copied", card.runId + " result");
    }
    ImGui::EndDisabled();
    if (!card.logPath.empty()) {
        ImGui::SameLine();
        if (ImGui::SmallButton("Copy Log Path")) {
            ImGui::SetClipboardText(card.logPath.c_str());
            card.stage = "Copied log path";
            agentSurfaceStatus_ = "Copied run log path.";
            state_.AddActivity("Agent run", "Copied", card.logPath);
        }
    }

    if (!running) {
        ImGui::SameLine();
        if (ImGui::TreeNodeEx("Details", ImGuiTreeNodeFlags_SpanAvailWidth)) {
            DrawMutedWrapped("Prompt");
            DrawSelectableTextBlock(card.prompt, Scaled(96.0f));
            DrawMutedWrapped("Result");
            DrawSelectableTextBlock(card.resultText.empty() ? "No response received yet." : card.resultText,
                                    Scaled(120.0f));
            if (!card.logPath.empty()) {
                DrawKeyValue("Log", card.logPath, Scaled(54.0f));
            }
            ImGui::TreePop();
        }
    }

    ImGui::EndChild();
    ImGui::PopID();
}

void EditorApp::DrawAgentAdvancedDetails() {
    if (ImGui::TreeNodeEx("Advanced", ImGuiTreeNodeFlags_SpanAvailWidth)) {
        const float advancedHeight = std::min(std::max(Scaled(180.0f), ImGui::GetContentRegionAvail().y * 0.45f),
                                              Scaled(360.0f));
        ImGui::BeginChild("agent_advanced_details_body", ImVec2(0.0f, advancedHeight), true,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar);
        if (ImGui::CollapsingHeader("Provider Health")) {
            DrawProviderHealthDetails();
        }
        if (ImGui::CollapsingHeader("Tool Gateway")) {
            DrawToolGatewayDetails();
        }
        if (ImGui::CollapsingHeader("Raw Logs")) {
            DrawRawAgentLogs();
        }
        ImGui::EndChild();
        ImGui::TreePop();
    }
}

void EditorApp::DrawProviderHealthDetails() {
    if (selectedBackend_ != AgentBackend::CodexCli) {
        DrawCodexSetupSection();
    }
    for (const ProviderHealth& provider : orchestrator_.Providers()) {
        ImGui::PushID(provider.id.c_str());
        ImGui::TextUnformatted(provider.label.c_str());
        ImGui::SameLine();
        const std::string providerState = TruncateForUi(ProviderStateLabel(&provider), 24);
        DrawStatusBadge(providerState.c_str(), ProviderStatusColor(&provider));
        if (providerState != ProviderStateLabel(&provider) && ImGui::IsItemHovered()) {
            ImGui::SetTooltip("%s", ProviderStateLabel(&provider));
        }
        std::string detail = provider.detail.empty() ? provider.status : provider.detail;
        if (!provider.source.empty()) {
            detail += " | source: " + provider.source;
        }
        DrawMutedWrapped(TruncateForUi(detail, 260));
        if (!provider.executablePath.empty()) {
            DrawKeyValue("Path", provider.executablePath, Scaled(78.0f));
        }
        ImGui::Separator();
        ImGui::PopID();
    }
}

void EditorApp::DrawToolGatewayDetails() {
    DrawStatusBadge("Local Tool Gateway fallback", AccentColor());
    ImGui::SameLine();
    ImGui::TextUnformatted("Editor Tool API");
    DrawKeyValue("Transaction", state_.LastTransactionId(), Scaled(104.0f));
    DrawKeyValue("Commands", std::to_string(gateway_.SupportedCommands().size()), Scaled(104.0f));

    if (ImGui::TreeNodeEx("Supported Commands")) {
        float commandLineWidth = 0.0f;
        const float commandAvailableWidth = ImGui::GetContentRegionAvail().x;
        for (const std::string& command : gateway_.SupportedCommands()) {
            const float commandWidth = ImGui::CalcTextSize(command.c_str()).x + ImGui::GetStyle().FramePadding.x * 2.0f;
            if (commandLineWidth > 0.0f &&
                commandLineWidth + commandWidth + ImGui::GetStyle().ItemSpacing.x <= commandAvailableWidth) {
                ImGui::SameLine();
                commandLineWidth += commandWidth + ImGui::GetStyle().ItemSpacing.x;
            } else {
                commandLineWidth = commandWidth;
            }
            DrawStatusBadge(command.c_str(), AccentColor());
        }
        ImGui::TreePop();
    }

    if (!proposedActions_.empty()) {
        DrawProposedActionsSection(true);
    }

    DrawSectionTitle("Last Batch");
    if (!hasLastGatewayResult_) {
        DrawEmptyState("No command batch has run.", "Agent fallback and approved command batches will appear here.");
        return;
    }

    const ToolCommandBatch& batch = lastGatewayResult_.batch;
    DrawStatusBadge(batch.applied ? "Applied" : "Not applied", batch.applied ? ImVec4(0.50f, 0.90f, 0.62f, 1.0f)
                                                                               : ImVec4(1.0f, 0.78f, 0.32f, 1.0f));
    ImGui::SameLine();
    DrawStatusBadge(batch.ok ? "OK" : "Diagnostics", batch.ok ? ImVec4(0.50f, 0.90f, 0.62f, 1.0f)
                                                              : ImVec4(0.92f, 0.52f, 0.52f, 1.0f));
    DrawKeyValue("Name", batch.name, Scaled(92.0f));
    DrawKeyValue("Approval", batch.approval, Scaled(92.0f));
    if (!batch.diagnostics.empty()) {
        DrawSectionTitle("Diagnostics");
        for (const std::string& diagnostic : batch.diagnostics) {
            ImGui::BulletText("%s", TruncateForUi(diagnostic, 220).c_str());
        }
    }
    if (ImGui::TreeNodeEx("Commands")) {
        for (size_t commandIndex = 0; commandIndex < batch.commands.size(); ++commandIndex) {
            const ToolCommand& command = batch.commands[commandIndex];
            ImGui::BulletText("%zu. %s", commandIndex + 1, command.type.c_str());
            if (!command.summary.empty()) {
                DrawMutedWrapped(TruncateForUi(command.summary, 220));
            }
        }
        ImGui::TreePop();
    }
}

void EditorApp::DrawRawAgentLogs() {
    const std::filesystem::path logPath = AgentRunLogPath();
    DrawKeyValue("Run log", logPath.string(), Scaled(86.0f));
    if (ImGui::Button("Copy Run Log Path")) {
        const std::string logPathString = logPath.string();
        ImGui::SetClipboardText(logPathString.c_str());
        state_.AddActivity("Agent memory", "Copied", logPathString);
    }

    DrawSectionTitle("Recent Activity");
    const std::vector<AgentActivity>& activities = state_.AgentActivities();
    if (activities.empty()) {
        DrawEmptyState("No agent activity yet.", "Backend checks, command batches, and memory writes will appear here.");
    } else if (ImGui::BeginTable("agent_raw_activity", 3,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp |
                                     ImGuiTableFlags_BordersInnerV)) {
        ImGui::TableSetupColumn("State", ImGuiTableColumnFlags_WidthFixed, Scaled(108.0f));
        ImGui::TableSetupColumn("Action", ImGuiTableColumnFlags_WidthFixed, Scaled(140.0f));
        ImGui::TableSetupColumn("Detail", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableHeadersRow();
        const size_t count = std::min<size_t>(activities.size(), 10);
        for (size_t offset = 0; offset < count; ++offset) {
            const AgentActivity& activity = activities[activities.size() - 1 - offset];
            ImGui::PushID(static_cast<int>(offset));
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            const std::string activityStatus = TruncateForUi(activity.status, 22);
            DrawStatusBadge(activityStatus.c_str(), ActivityStatusColor(activity.status));
            ImGui::TableSetColumnIndex(1);
            ImGui::TextWrapped("%s", TruncateForUi(activity.label, 54).c_str());
            ImGui::TableSetColumnIndex(2);
            if (!activity.detail.empty()) {
                ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
                ImGui::TextWrapped("%s", TruncateForUi(activity.detail, 220).c_str());
                ImGui::PopStyleColor();
            } else {
                ImGui::TextDisabled("-");
            }
            ImGui::PopID();
        }
        ImGui::EndTable();
    }

    DrawSectionTitle("Run Log Preview");
    const std::string logText = ReadTextFilePreview(logPath, 12000);
    if (logText.empty()) {
        DrawEmptyState("No agent run log yet.", "Generated briefs and run summaries are written here.");
    } else {
        DrawSelectableTextBlock(logText, Scaled(180.0f));
    }
}

void EditorApp::DrawAgentChatTab() {
    DrawCodexSetupSection();

    const bool agentBusy = agentJob_ != nullptr;
    if (agentBusy) {
        DrawAgentWorkingCard(agentJobBackend_, agentJobPrompt_, agentJobStartedSeconds_, uiScale_);
    }

    const std::vector<std::string> suggestions = orchestrator_.PromptSuggestions(chatInput_.data(), state_);

    ImGui::Spacing();
    const float sendWidth = Scaled(84.0f);
    const ImGuiStyle& style = ImGui::GetStyle();
    const float inputWidth =
        std::max(Scaled(180.0f), ImGui::GetContentRegionAvail().x - sendWidth - style.ItemSpacing.x);
    WrapInputBufferToWidth(chatInput_, inputWidth);
    const std::string inputPreview = WrapTextForDisplay(chatInput_.data(), inputWidth);
    const size_t inputLineCount = CountDisplayLines(inputPreview);
    const float inputMinHeight = ImGui::GetFrameHeightWithSpacing() * 1.25f;
    const float inputMaxHeight = ImGui::GetTextLineHeightWithSpacing() * 6.0f + style.FramePadding.y * 2.0f;
    const float inputHeight = std::clamp(ImGui::GetTextLineHeightWithSpacing() * static_cast<float>(inputLineCount) +
                                             style.FramePadding.y * 2.0f,
                                         inputMinHeight, inputMaxHeight);

    bool sendRequested = false;
    ImGui::BeginDisabled(!state_.IsEditMode() || agentBusy);
    const ImVec2 inputPos = ImGui::GetCursorScreenPos();
    const std::string previousInput = chatInput_.data();
    const bool inputSubmitted = ImGui::InputTextMultiline(
        "##chat_input", chatInput_.data(), chatInput_.size(), ImVec2(inputWidth, inputHeight),
        ImGuiInputTextFlags_NoHorizontalScroll | ImGuiInputTextFlags_EnterReturnsTrue |
            ImGuiInputTextFlags_CtrlEnterForNewLine);
    const bool inputActive = ImGui::IsItemActive();
    if (inputSubmitted && !ImGui::GetIO().KeyCtrl) {
        sendRequested = true;
    }
    const bool inputEdited = previousInput != chatInput_.data();
    if (inputEdited) {
        WrapInputBufferToWidth(chatInput_, inputWidth);
    }
    if (chatInput_[0] == '\0' && !inputActive) {
        ImGui::GetWindowDrawList()->AddText(
            ImVec2(inputPos.x + style.FramePadding.x, inputPos.y + style.FramePadding.y),
            ColorU32(MutedTextColor()), "Ask the editor agent...");
    }
    ImGui::SameLine();
    if (ImGui::Button("Send", ImVec2(sendWidth, inputHeight))) {
        sendRequested = true;
    }
    if (sendRequested) {
        SendChatPrompt();
    }
    ImGui::EndDisabled();
    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Agent commands are edit-time changes; stop Play Mode before sending a prompt.");
    }

    if (!suggestions.empty()) {
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted("Prompt suggestions");
        ImGui::PopStyleColor();
        ImGui::BeginChild("suggestion_chip_strip", ImVec2(0.0f, ImGui::GetFrameHeightWithSpacing() * 1.55f), false,
                          ImGuiWindowFlags_HorizontalScrollbar);
        for (size_t index = 0; index < suggestions.size(); ++index) {
            const std::string& suggestion = suggestions[index];
            const std::string chipLabel = TruncateForUi(suggestion, 44);
            if (index > 0) {
                ImGui::SameLine();
            }
            ImGui::PushID(static_cast<int>(index));
            if (DrawChip(chipLabel.c_str())) {
                CopyStringToBuffer(chatInput_, suggestion);
                WrapInputBufferToWidth(chatInput_, inputWidth);
            }
            if (chipLabel != suggestion && ImGui::IsItemHovered()) {
                ImGui::SetTooltip("%s", suggestion.c_str());
            }
            ImGui::PopID();
        }
        ImGui::EndChild();
    }

    DrawSectionTitle("Conversation");
    const std::vector<ChatMessage>& chatHistory = state_.ChatHistory();
    ImGui::BeginChild("chat_history", ImVec2(0.0f, 0.0f), true, ImGuiWindowFlags_AlwaysVerticalScrollbar);
    if (chatHistory.empty()) {
        DrawEmptyState("No chat messages yet.", "Agent responses, system notes, and command summaries will appear here.");
    }
    for (size_t index = 0; index < chatHistory.size(); ++index) {
        DrawChatMessageCard(chatHistory[index], index, uiScale_);
        if (index + 1 < chatHistory.size()) {
            ImGui::Spacing();
        }
    }
    if (ImGui::GetScrollY() >= ImGui::GetScrollMaxY()) {
        ImGui::SetScrollHereY(1.0f);
    }
    ImGui::EndChild();
}

void EditorApp::DrawAgentTaskComposerPanel() {
    if (!BeginPanel("Agent Task Composer", ImVec2(420.0f, 420.0f))) {
        ImGui::End();
        return;
    }

    DrawAgentTaskComposerContents(true);
    ImGui::End();
}

void EditorApp::DrawAgentTaskComposerContents(bool includeHeader) {
    const ProviderHealth* codexHealth = orchestrator_.FindProvider(AgentBackend::CodexCli);
    auto drawHistoryButton = [this](const char* id) {
        if (ImGui::Button(id)) {
            showAgentHistory_ = true;
        }
    };

    if (includeHeader) {
        ImGui::BeginChild("composer_header", ImVec2(0.0f, Scaled(92.0f)), true, ImGuiWindowFlags_NoScrollbar);
        DrawStatusBadge(ProviderStateLabel(codexHealth), ProviderStatusColor(codexHealth));
        ImGui::SameLine();
        ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
        ImGui::TextUnformatted("Codex");
        ImGui::PopStyleColor();
        if (codexHealth != nullptr && !codexHealth->detail.empty() && ImGui::IsItemHovered()) {
            ImGui::SetTooltip("%s", codexHealth->detail.c_str());
        }

        const float historyWidth = ImGui::CalcTextSize("History").x + ImGui::GetStyle().FramePadding.x * 2.0f;
        const float historyX = ImGui::GetWindowContentRegionMax().x - historyWidth;
        if (historyX > ImGui::GetCursorPosX() + ImGui::GetStyle().ItemSpacing.x) {
            ImGui::SameLine(historyX);
        } else {
            ImGui::SameLine();
        }
        drawHistoryButton("History##composer_header");

        const std::string logPath = lastComposerLogPath_.empty() ? AgentRunLogPath().string() : lastComposerLogPath_;
        DrawKeyValue("Run log", TruncateForUi(logPath, 160), Scaled(86.0f));
        if (ImGui::IsItemHovered()) {
            ImGui::SetTooltip("%s", logPath.c_str());
        }
        ImGui::EndChild();
    } else {
        DrawStatusBadge(ProviderStateLabel(codexHealth), ProviderStatusColor(codexHealth));
        ImGui::SameLine();
        ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
        ImGui::TextUnformatted("Codex task composer");
        ImGui::PopStyleColor();

        const float historyWidth = ImGui::CalcTextSize("History").x + ImGui::GetStyle().FramePadding.x * 2.0f;
        if (ImGui::GetContentRegionAvail().x > historyWidth + ImGui::GetStyle().ItemSpacing.x) {
            ImGui::SameLine();
        }
        drawHistoryButton("History##composer_inline");
    }

    const bool agentBusy = agentJob_ != nullptr;
    if (agentBusy) {
        DrawAgentWorkingCard(agentJobBackend_, agentJobPrompt_, agentJobStartedSeconds_, uiScale_);
    }

    DrawSectionTitle("Request");
    ImGui::SetNextItemWidth(-1.0f);
    const float requestWidth = std::max(Scaled(180.0f), ImGui::GetContentRegionAvail().x);
    WrapInputBufferToWidth(composerRequestInput_, requestWidth);
    const std::string previousComposerRequest = composerRequestInput_.data();
    ImGui::InputTextMultiline("##composer_request", composerRequestInput_.data(), composerRequestInput_.size(),
                              ImVec2(-1.0f, Scaled(78.0f)), ImGuiInputTextFlags_NoHorizontalScroll);
    if (previousComposerRequest != composerRequestInput_.data()) {
        WrapInputBufferToWidth(composerRequestInput_, requestWidth);
    }

    const std::string generatedPrompt = TrimWhitespace(composerPromptInput_.data());
    const std::string userRequest = TrimWhitespace(composerRequestInput_.data());
    const bool hasGeneratedPrompt = !generatedPrompt.empty();

    const float fullWidth = ImGui::GetContentRegionAvail().x;
    const float gap = ImGui::GetStyle().ItemSpacing.x;
    const float halfWidth = std::floor((fullWidth - gap) * 0.5f);
    const ImVec2 halfButton(halfWidth > Scaled(96.0f) ? halfWidth : -FLT_MIN, 0.0f);

    ImGui::BeginDisabled(userRequest.empty());
    if (ImGui::Button("Improve Prompt", halfButton)) {
        ImproveComposerPrompt();
    }
    ImGui::EndDisabled();
    ImGui::SameLine(0.0f, gap);
    ImGui::BeginDisabled(userRequest.empty() && !hasGeneratedPrompt);
    if (ImGui::Button("Split Into Multiple Agents", halfButton)) {
        SplitComposerPromptIntoAgents();
    }
    ImGui::EndDisabled();

    ImGui::BeginDisabled(!state_.IsEditMode() || agentBusy || !hasGeneratedPrompt);
    if (ImGui::Button("Run With Codex", halfButton)) {
        RunComposerPromptWithCodex();
    }
    ImGui::EndDisabled();
    ImGui::SameLine(0.0f, gap);
    ImGui::BeginDisabled(!hasGeneratedPrompt);
    if (ImGui::Button("Copy Prompt", halfButton)) {
        ImGui::SetClipboardText(generatedPrompt.c_str());
        composerStatus_ = "Copied generated prompt to clipboard.";
        state_.AddActivity("Agent Task Composer", "Copied", "Prompt length: " + std::to_string(generatedPrompt.size()) + " chars");
    }
    ImGui::EndDisabled();

    ImGui::BeginDisabled(!hasGeneratedPrompt);
    if (ImGui::Button("Save As Agent Run", ImVec2(-FLT_MIN, 0.0f))) {
        SaveComposerPromptAsAgentRun("agent_run_saved");
    }
    ImGui::EndDisabled();

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Agent runs are edit-time work; stop Play Mode before launching Codex.");
    }
    if (!composerStatus_.empty()) {
        DrawMutedWrapped(composerStatus_);
    }

    DrawSectionTitle("Agent Brief");
    const float promptHeight = std::max(Scaled(220.0f), ImGui::GetContentRegionAvail().y);
    const float promptWidth = std::max(Scaled(180.0f), ImGui::GetContentRegionAvail().x);
    WrapInputBufferToWidth(composerPromptInput_, promptWidth);
    const std::string previousComposerPrompt = composerPromptInput_.data();
    ImGui::PushStyleColor(ImGuiCol_FrameBg, OffsetColor(PanelBackgroundColor(), 0.018f));
    ImGui::PushStyleColor(ImGuiCol_FrameBgHovered, OffsetColor(PanelBackgroundColor(), 0.030f));
    ImGui::InputTextMultiline("##composer_prompt", composerPromptInput_.data(), composerPromptInput_.size(),
                              ImVec2(-1.0f, promptHeight),
                              ImGuiInputTextFlags_AllowTabInput | ImGuiInputTextFlags_NoHorizontalScroll);
    ImGui::PopStyleColor(2);
    if (previousComposerPrompt != composerPromptInput_.data()) {
        WrapInputBufferToWidth(composerPromptInput_, promptWidth);
    }
}

void EditorApp::DrawAgentRunsTab() {
    const bool agentBusy = agentJob_ != nullptr;
    if (agentBusy) {
        DrawAgentWorkingCard(agentJobBackend_, agentJobPrompt_, agentJobStartedSeconds_, uiScale_);
    }

    DrawSectionTitle("Run Overview");
    ImGui::BeginChild("agent_runs_summary", ImVec2(0.0f, Scaled(188.0f)), true,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    DrawKeyValue("State", agentBusy ? std::string("Running ") + AgentOrchestrator::BackendLabel(agentJobBackend_)
                                    : state_.AgentStatus(),
                 Scaled(118.0f));
    DrawKeyValue("Current run", agentBusy && !agentJobRunLogId_.empty() ? agentJobRunLogId_ :
                                composerRunId_.empty() ? "none" : composerRunId_,
                 Scaled(118.0f));
    DrawKeyValue("Saved prompts", std::to_string(composerSavedPromptCount_), Scaled(118.0f));
    DrawKeyValue("Completed runs", std::to_string(composerCompletedRunCount_), Scaled(118.0f));
    DrawKeyValue("Run log", lastComposerLogPath_.empty() ? AgentRunLogPath().string() : lastComposerLogPath_,
                 Scaled(118.0f));
    if (ImGui::Button("Copy Run Log Path")) {
        const std::string logPath = lastComposerLogPath_.empty() ? AgentRunLogPath().string() : lastComposerLogPath_;
        ImGui::SetClipboardText(logPath.c_str());
        state_.AddActivity("Agent memory", "Copied", logPath);
    }
    ImGui::SameLine();
    if (ImGui::Button("Show History")) {
        showAgentHistory_ = true;
    }
    ImGui::EndChild();

    DrawSectionTitle("Recent Agent Activity");
    const std::vector<AgentActivity>& activities = state_.AgentActivities();
    if (activities.empty()) {
        DrawEmptyState("No agent activity yet.", "Queued runs, provider status, and memory writes will appear here.");
    } else if (ImGui::BeginTable("agent_runs_activity", 3,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp |
                                     ImGuiTableFlags_BordersInnerV)) {
        ImGui::TableSetupColumn("State", ImGuiTableColumnFlags_WidthFixed, Scaled(96.0f));
        ImGui::TableSetupColumn("Action", ImGuiTableColumnFlags_WidthFixed, Scaled(132.0f));
        ImGui::TableSetupColumn("Detail", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableHeadersRow();
        const size_t count = std::min<size_t>(activities.size(), 8);
        for (size_t offset = 0; offset < count; ++offset) {
            const AgentActivity& activity = activities[activities.size() - 1 - offset];
            ImGui::PushID(static_cast<int>(offset));
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            const std::string status = TruncateForUi(activity.status, 18);
            DrawStatusBadge(status.c_str(), ActivityStatusColor(activity.status));
            ImGui::TableSetColumnIndex(1);
            ImGui::TextWrapped("%s", TruncateForUi(activity.label, 44).c_str());
            ImGui::TableSetColumnIndex(2);
            ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
            ImGui::TextWrapped("%s", TruncateForUi(activity.detail, 160).c_str());
            ImGui::PopStyleColor();
            ImGui::PopID();
        }
        ImGui::EndTable();
    }

    DrawSectionTitle("Run Log Preview");
    const std::string logText = ReadTextFilePreview(AgentRunLogPath(), 12000);
    if (logText.empty()) {
        DrawEmptyState("No agent run log yet.", "Generated prompts and run summaries will be written here.");
    } else {
        DrawSelectableTextBlock(logText, Scaled(180.0f));
    }

    DrawProposedActionsSection(true);
}

void EditorApp::DrawAgentHistoryPanel() {
    if (!showAgentHistory_) {
        return;
    }

    ImGui::SetNextWindowSize(Scaled(ImVec2(760.0f, 560.0f)), ImGuiCond_FirstUseEver);
    ImGui::SetNextWindowSizeConstraints(Scaled(ImVec2(520.0f, 360.0f)), ImVec2(FLT_MAX, FLT_MAX));
    if (!ImGui::Begin("Agent History", &showAgentHistory_)) {
        ImGui::End();
        return;
    }

    const std::filesystem::path logPath = AgentRunLogPath();
    DrawKeyValue("Source", logPath.string(), Scaled(76.0f));
    if (ImGui::Button("Copy Log Path")) {
        const std::string logPathString = logPath.string();
        ImGui::SetClipboardText(logPathString.c_str());
        state_.AddActivity("Agent history", "Copied", logPathString);
    }
    ImGui::SameLine();
    if (ImGui::Button("Close")) {
        showAgentHistory_ = false;
    }

    const std::vector<AgentRunHistoryItem> history = ReadAgentRunHistory(logPath, 32);
    DrawSectionTitle("Recent Runs and Briefs");
    if (history.empty()) {
        DrawEmptyState("No history yet.", "Create a brief or send a prompt to save useful agent history here.");
        ImGui::End();
        return;
    }

    ImGui::BeginChild("agent_history_items", ImVec2(0.0f, 0.0f), true, ImGuiWindowFlags_AlwaysVerticalScrollbar);
    for (size_t index = 0; index < history.size(); ++index) {
        const AgentRunHistoryItem& item = history[index];
        ImGui::PushID(static_cast<int>(index));
        DrawStatusBadge(item.status.c_str(), ActivityStatusColor(item.status));
        ImGui::SameLine();
        ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
        ImGui::TextUnformatted(item.timestamp.c_str());
        ImGui::PopStyleColor();

        DrawKeyValue("Run", item.runId, Scaled(70.0f));
        DrawKeyValue("Backend", item.backend, Scaled(70.0f));
        if (!item.userRequest.empty()) {
            DrawKeyValue("Request", TruncateForUi(item.userRequest, 180), Scaled(70.0f));
        }
        if (!item.resultSummary.empty()) {
            DrawKeyValue("Result", TruncateForUi(item.resultSummary, 220), Scaled(70.0f));
        }

        if (ImGui::Button("Load Brief")) {
            CopyStringToBuffer(chatInput_, item.userRequest.empty() ? item.prompt : item.userRequest);
            CopyStringToBuffer(composerRequestInput_, item.userRequest);
            CopyStringToBuffer(composerPromptInput_, item.prompt);
            composerRunId_ = item.runId;
            composerStatus_ = "Loaded brief from history.";
            agentSurfaceStatus_ = composerStatus_;
            showAgentHistory_ = false;
            state_.AddActivity("Agent history", "Loaded", item.runId);
        }
        ImGui::SameLine();
        if (ImGui::Button("Copy Request")) {
            ImGui::SetClipboardText(item.userRequest.c_str());
            state_.AddActivity("Agent history", "Copied", item.runId + " request");
        }
        ImGui::SameLine();
        if (ImGui::Button("Copy Brief")) {
            ImGui::SetClipboardText(item.prompt.c_str());
            state_.AddActivity("Agent history", "Copied", item.runId + " brief");
        }
        ImGui::SameLine();
        if (ImGui::Button("Copy Result")) {
            ImGui::SetClipboardText(item.resultSummary.c_str());
            state_.AddActivity("Agent history", "Copied", item.runId + " result");
        }

        if (ImGui::TreeNodeEx("Generated Implementation Brief", ImGuiTreeNodeFlags_SpanAvailWidth)) {
            DrawSelectableTextBlock(item.prompt, Scaled(220.0f));
            ImGui::TreePop();
        }
        ImGui::Separator();
        ImGui::PopID();
    }
    ImGui::EndChild();
    ImGui::End();
}

void EditorApp::DrawAgentActivityPanel() {
    if (focusDefaultActivityPanel_) {
        ImGui::SetNextWindowFocus();
        focusDefaultActivityPanel_ = false;
    }
    if (!BeginPanel("Agent Activity", ImVec2(420.0f, 260.0f))) {
        ImGui::End();
        return;
    }

    ImGui::BeginChild("activity_summary", ImVec2(0.0f, Scaled(118.0f)), true,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    DrawStatusBadge(state_.AgentStatus().c_str(), ActivityStatusColor(state_.AgentStatus()));
    ImGui::SameLine();
    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::TextUnformatted("AgentOrchestrator");
    ImGui::PopStyleColor();
    DrawKeyValue("Backend", AgentOrchestrator::BackendLabel(selectedBackend_), Scaled(116.0f));
    DrawKeyValue("Last transaction", state_.LastTransactionId(), Scaled(116.0f));
    ImGui::EndChild();

    DrawSectionTitle("Provider Health");
    for (const ProviderHealth& provider : orchestrator_.Providers()) {
        ImGui::PushID(provider.id.c_str());
        ImGui::TextUnformatted(provider.label.c_str());
        ImGui::SameLine();
        const std::string providerState = TruncateForUi(ProviderStateLabel(&provider), 24);
        DrawStatusBadge(providerState.c_str(), ProviderStatusColor(&provider));
        if (providerState != ProviderStateLabel(&provider) && ImGui::IsItemHovered()) {
            ImGui::SetTooltip("%s", ProviderStateLabel(&provider));
        }
        std::string detail = provider.detail.empty() ? provider.status : provider.detail;
        if (!provider.source.empty()) {
            detail += " | source: " + provider.source;
        }
        DrawMutedWrapped(TruncateForUi(detail, 190));
        if (!provider.executablePath.empty() && ImGui::IsItemHovered()) {
            ImGui::SetTooltip("Path: %s", provider.executablePath.c_str());
        }
        ImGui::Separator();
        ImGui::PopID();
    }

    DrawSectionTitle("Recent Actions");
    const std::vector<AgentActivity>& activities = state_.AgentActivities();
    if (activities.empty()) {
        DrawEmptyState("No agent actions yet.", "Backend checks, command batches, and approvals will be listed here.");
    } else if (ImGui::BeginTable("recent_activity_table", 3,
                                 ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp |
                                     ImGuiTableFlags_BordersInnerV)) {
        ImGui::TableSetupColumn("State", ImGuiTableColumnFlags_WidthFixed, Scaled(108.0f));
        ImGui::TableSetupColumn("Action", ImGuiTableColumnFlags_WidthFixed, Scaled(140.0f));
        ImGui::TableSetupColumn("Detail", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableHeadersRow();
        const size_t count = std::min<size_t>(activities.size(), 10);
        for (size_t offset = 0; offset < count; ++offset) {
            const AgentActivity& activity = activities[activities.size() - 1 - offset];
            ImGui::PushID(static_cast<int>(offset));
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            const std::string activityStatus = TruncateForUi(activity.status, 22);
            DrawStatusBadge(activityStatus.c_str(), ActivityStatusColor(activity.status));
            if (activityStatus != activity.status && ImGui::IsItemHovered()) {
                ImGui::SetTooltip("%s", activity.status.c_str());
            }
            ImGui::TableSetColumnIndex(1);
            ImGui::TextWrapped("%s", TruncateForUi(activity.label, 54).c_str());
            ImGui::TableSetColumnIndex(2);
            if (!activity.detail.empty()) {
                ImGui::PushStyleColor(ImGuiCol_Text, MutedTextColor());
                ImGui::TextWrapped("%s", TruncateForUi(activity.detail, 180).c_str());
                ImGui::PopStyleColor();
            } else {
                ImGui::TextDisabled("-");
            }
            ImGui::PopID();
        }
        ImGui::EndTable();
    }

    DrawSectionTitle("Proposed Actions");
    DrawProposedActionsSection(false);

    ImGui::End();
}

void EditorApp::DrawProjectTreePanel(EditorPanelInstance& panel) {
    PerformanceScope scope(&profiler_, PerformanceDomain::Editor, "Editor.ProjectTree");
    if (!BeginPanel(panel, ImVec2(360.0f, 250.0f))) {
        ImGui::End();
        return;
    }

    const std::filesystem::path selectedPath = EnsureProjectExplorerSelection();
    DrawProjectExplorerToolbar(selectedPath);
    DrawProjectExplorerBreadcrumb(selectedPath);
    ImGui::Separator();

    const ImVec2 available = ImGui::GetContentRegionAvail();
    const bool wideLayout = available.x >= Scaled(560.0f);
    if (wideLayout) {
        const float sidebarWidth = std::clamp(available.x * 0.30f, Scaled(185.0f), Scaled(280.0f));
        ImGui::BeginChild("project_explorer_sidebar", ImVec2(sidebarWidth, 0.0f), true,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar);
        DrawProjectExplorerSidebar(selectedPath);
        ImGui::EndChild();
        ImGui::SameLine();
        ImGui::BeginChild("project_explorer_contents", ImVec2(0.0f, 0.0f), true,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar | ImGuiWindowFlags_HorizontalScrollbar);
        DrawProjectExplorerContents(selectedPath);
        ImGui::EndChild();
    } else {
        const float sidebarHeight = std::clamp(available.y * 0.38f, Scaled(120.0f), Scaled(210.0f));
        ImGui::BeginChild("project_explorer_sidebar", ImVec2(0.0f, sidebarHeight), true,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar);
        DrawProjectExplorerSidebar(selectedPath);
        ImGui::EndChild();
        ImGui::BeginChild("project_explorer_contents", ImVec2(0.0f, 0.0f), true,
                          ImGuiWindowFlags_AlwaysVerticalScrollbar | ImGuiWindowFlags_HorizontalScrollbar);
        DrawProjectExplorerContents(selectedPath);
        ImGui::EndChild();
    }

    DrawProjectTreeDeleteConfirmation();
    ImGui::End();
}

std::filesystem::path EditorApp::ProjectExplorerVisibleRoot() const {
    std::error_code filesystemError;
    const std::filesystem::path assetRoot = state_.AssetRootPathString();
    if (!assetRoot.empty() && std::filesystem::is_directory(assetRoot, filesystemError)) {
        return assetRoot;
    }

    filesystemError.clear();
    const std::filesystem::path projectRoot = state_.ProjectRootPathString();
    if (!projectRoot.empty() && std::filesystem::is_directory(projectRoot, filesystemError)) {
        return projectRoot;
    }
    return projectRoot;
}

std::filesystem::path EditorApp::EnsureProjectExplorerSelection() {
    const std::filesystem::path projectRoot = state_.ProjectRootPathString();
    const std::filesystem::path fallback = ProjectExplorerVisibleRoot();

    std::error_code filesystemError;
    const bool hasUsableSelection =
        !projectExplorerSelectedPath_.empty() &&
        std::filesystem::is_directory(projectExplorerSelectedPath_, filesystemError) &&
        IsPathInsideOrSame(projectRoot, projectExplorerSelectedPath_);

    if (!hasUsableSelection) {
        projectExplorerSelectedPath_ = fallback;
    }
    return projectExplorerSelectedPath_;
}

void EditorApp::SelectProjectExplorerPath(const std::filesystem::path& path) {
    if (path.empty()) {
        return;
    }

    std::error_code filesystemError;
    std::filesystem::path selectedPath = std::filesystem::absolute(path, filesystemError);
    if (filesystemError) {
        selectedPath = path;
        filesystemError.clear();
    }
    selectedPath = selectedPath.lexically_normal();

    if (!IsPathInsideOrSame(state_.ProjectRootPathString(), selectedPath)) {
        state_.AddLog(LogLevel::Warning, "Project Explorer refused a path outside the current project: " +
                                           selectedPath.string());
        return;
    }

    if (!std::filesystem::is_directory(selectedPath, filesystemError)) {
        selectedPath = selectedPath.parent_path();
        filesystemError.clear();
    }
    if (selectedPath.empty() || !std::filesystem::is_directory(selectedPath, filesystemError)) {
        return;
    }

    projectExplorerSelectedPath_ = selectedPath;
}

void EditorApp::DrawProjectExplorerToolbar(const std::filesystem::path& selectedPath) {
    const std::string title = state_.ProjectName().empty() ? "Project" : state_.ProjectName();
    const bool singleLineToolbar = ImGui::GetContentRegionAvail().x >= Scaled(760.0f);
    ImGui::PushStyleColor(ImGuiCol_Text, BrightTextColor());
    ImGui::TextUnformatted(TruncateForUi(title, 72).c_str());
    ImGui::PopStyleColor();
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", state_.ProjectRootPathString().c_str());
    }

    if (singleLineToolbar) {
        ImGui::SameLine();
    }
    if (ImGui::SmallButton("Refresh")) {
        state_.RefreshProjectTree();
        state_.AddActivity("project.tree", "Refreshed", state_.ProjectRootPathString());
    }
    ImGui::SameLine();
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::SmallButton("New Folder")) {
        CreateFolderInProjectTree(selectedPath);
    }
    ImGui::EndDisabled();
    ImGui::SameLine();
    if (ImGui::SmallButton("Open")) {
        std::string error;
        if (!ShowPathInExplorer(selectedPath, &error)) {
            state_.AddLog(LogLevel::Error, "Show In Explorer failed: " + error);
        }
    }
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("Show selected folder in Windows Explorer.");
    }
    ImGui::SameLine();
    if (ImGui::SmallButton("Copy Path")) {
        const std::string pathString = selectedPath.string();
        ImGui::SetClipboardText(pathString.c_str());
        state_.AddActivity("project.tree", "Copied", pathString);
    }
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("Copy selected folder path.");
    }
    ImGui::SameLine();
    if (ImGui::SmallButton("Locations")) {
        RefreshPathInputs();
        showProjectLocationsDialog_ = true;
    }
    if (singleLineToolbar) {
        ImGui::SameLine();
    }
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::SmallButton("Save As...")) {
        SaveProjectAsFromUi();
    }
    ImGui::EndDisabled();
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("Choose a project folder and save the current project there.");
    }
    ImGui::SameLine();
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::SmallButton("Stage Assets")) {
        StageExternalAssetFolderFromUi();
    }
    ImGui::EndDisabled();
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("Stage an external asset folder as a preview project.");
    }

    const float availableWidth = ImGui::GetContentRegionAvail().x;
    const float searchWidth = std::clamp(ImGui::GetWindowWidth() * 0.24f, Scaled(130.0f), Scaled(270.0f));
    if (availableWidth > searchWidth + Scaled(18.0f)) {
        ImGui::SameLine(ImGui::GetCursorPosX() + availableWidth - searchWidth);
    }
    ImGui::SetNextItemWidth(searchWidth);
    ImGui::InputTextWithHint("##project_explorer_search", "Search", projectExplorerSearchInput_.data(),
                             projectExplorerSearchInput_.size());

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Project asset actions are disabled during Play Mode.");
    }
}

void EditorApp::DrawProjectExplorerBreadcrumb(const std::filesystem::path& selectedPath) {
    const std::filesystem::path projectRoot = state_.ProjectRootPathString();
    const std::string projectLabel = state_.ProjectName().empty() ? "Project" : TruncateForUi(state_.ProjectName(), 26);
    if (ImGui::SmallButton(projectLabel.c_str())) {
        SelectProjectExplorerPath(projectRoot);
    }
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", projectRoot.string().c_str());
    }

    std::error_code filesystemError;
    const std::filesystem::path relative = std::filesystem::relative(selectedPath, projectRoot, filesystemError);
    if (filesystemError || relative.empty() || relative == ".") {
        return;
    }

    std::filesystem::path current = projectRoot;
    for (const std::filesystem::path& part : relative) {
        current /= part;
        const std::string partLabel = part.string();
        ImGui::SameLine();
        ImGui::TextDisabled(">");
        ImGui::SameLine();
        ImGui::PushID(current.string().c_str());
        if (ImGui::SmallButton(TruncateForUi(partLabel, 24).c_str())) {
            SelectProjectExplorerPath(current);
        }
        if (ImGui::IsItemHovered()) {
            ImGui::SetTooltip("%s", current.string().c_str());
        }
        ImGui::PopID();
    }
}

void EditorApp::DrawProjectExplorerSidebar(const std::filesystem::path& selectedPath) {
    DrawSectionTitle("Favorites");
    const std::filesystem::path projectRoot = state_.ProjectRootPathString();
    const std::filesystem::path assetRoot = state_.AssetRootPathString();
    DrawProjectExplorerFavorite("Project", projectRoot, selectedPath);
    DrawProjectExplorerFavorite("Assets", assetRoot, selectedPath);
    DrawProjectExplorerFavorite("Scenes", std::filesystem::path(state_.SceneRootPathString()), selectedPath);
    DrawProjectExplorerFavorite("Scripts", assetRoot / "Scripts", selectedPath);
    DrawProjectExplorerFavorite("Materials", assetRoot / "Materials", selectedPath);
    DrawProjectExplorerFavorite("Prefabs", assetRoot / "Prefabs", selectedPath);

    DrawSectionTitle("Folders");
    const ProjectTreeNode& tree = state_.ProjectTree();
    if (tree.children.size() == 1) {
        DrawProjectExplorerSidebarNode(tree.children.front(), selectedPath);
    } else {
        DrawProjectExplorerSidebarNode(tree, selectedPath);
    }
}

void EditorApp::DrawProjectExplorerFavorite(const char* label, const std::filesystem::path& path,
                                            const std::filesystem::path& selectedPath) {
    std::error_code filesystemError;
    if (path.empty() || !std::filesystem::is_directory(path, filesystemError)) {
        return;
    }

    bool samePath = false;
    IsPathInsideOrSame(path, selectedPath, &samePath);
    ImGui::PushID(path.string().c_str());
    if (ImGui::Selectable(label, samePath, ImGuiSelectableFlags_SpanAvailWidth)) {
        SelectProjectExplorerPath(path);
    }
    if (ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", path.string().c_str());
    }
    ProjectTreeNode node;
    node.name = label;
    node.path = path.string();
    node.folder = true;
    node.filesystemBacked = true;
    DrawProjectTreeNodeContextMenu(node);
    ImGui::PopID();
}

void EditorApp::DrawProjectExplorerSidebarNode(const ProjectTreeNode& node,
                                               const std::filesystem::path& selectedPath) {
    if (!node.folder) {
        return;
    }

    const std::string contextId = node.path.empty() ? node.name : node.path;
    ImGui::PushID(contextId.c_str());

    bool samePath = false;
    bool containsSelection = false;
    if (node.filesystemBacked && !node.path.empty()) {
        containsSelection = IsPathInsideOrSame(node.path, selectedPath, &samePath);
    }

    const bool hasFolderChildren =
        std::any_of(node.children.begin(), node.children.end(), [](const ProjectTreeNode& child) {
            return child.folder;
        });
    ImGuiTreeNodeFlags flags = ImGuiTreeNodeFlags_OpenOnArrow | ImGuiTreeNodeFlags_SpanAvailWidth;
    if (samePath) {
        flags |= ImGuiTreeNodeFlags_Selected;
    }
    if (containsSelection || node.name.rfind("Project:", 0) == 0) {
        flags |= ImGuiTreeNodeFlags_DefaultOpen;
    }
    if (!hasFolderChildren) {
        flags |= ImGuiTreeNodeFlags_Leaf | ImGuiTreeNodeFlags_NoTreePushOnOpen;
    }

    const std::string label = TruncateForUi(node.name, 64);
    const bool open = ImGui::TreeNodeEx("folder", flags, "%s", label.c_str());
    if (ImGui::IsItemClicked() && node.filesystemBacked && !node.path.empty()) {
        SelectProjectExplorerPath(node.path);
    }
    if (label != node.name && ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", node.name.c_str());
    } else if (ImGui::IsItemHovered() && !node.path.empty()) {
        ImGui::SetTooltip("%s", node.path.c_str());
    }
    DrawProjectTreeNodeContextMenu(node);

    if (open && hasFolderChildren) {
        for (const ProjectTreeNode& child : node.children) {
            if (child.folder) {
                DrawProjectExplorerSidebarNode(child, selectedPath);
            }
        }
        ImGui::TreePop();
    }

    ImGui::PopID();
}

void EditorApp::DrawProjectExplorerContents(const std::filesystem::path& selectedPath) {
    std::error_code filesystemError;
    if (selectedPath.empty() || !std::filesystem::is_directory(selectedPath, filesystemError)) {
        DrawEmptyState("Folder unavailable.", selectedPath.string().c_str());
        return;
    }

    std::vector<std::filesystem::directory_entry> entries;
    std::filesystem::directory_iterator iterator(selectedPath, filesystemError);
    const std::filesystem::directory_iterator end;
    while (!filesystemError && iterator != end) {
        entries.push_back(*iterator);
        iterator.increment(filesystemError);
    }
    if (filesystemError) {
        const std::string detail = filesystemError.message();
        DrawEmptyState("Could not read folder.", detail.c_str());
        return;
    }

    std::sort(entries.begin(), entries.end(), [](const std::filesystem::directory_entry& left,
                                                 const std::filesystem::directory_entry& right) {
        std::error_code leftError;
        std::error_code rightError;
        const bool leftDirectory = left.is_directory(leftError);
        const bool rightDirectory = right.is_directory(rightError);
        if (leftDirectory != rightDirectory) {
            return leftDirectory;
        }
        return ToLower(left.path().filename().string()) < ToLower(right.path().filename().string());
    });

    const float footerHeight = ImGui::GetFrameHeightWithSpacing() + Scaled(8.0f);
    const float gridHeight = std::max(Scaled(96.0f), ImGui::GetContentRegionAvail().y - footerHeight);
    int visibleCount = 0;
    ImGui::BeginChild("project_explorer_tile_grid", ImVec2(0.0f, gridHeight), false,
                      ImGuiWindowFlags_AlwaysVerticalScrollbar);
    const float iconSize = Scaled(projectExplorerIconSize_);
    const float tileWidth = iconSize + Scaled(22.0f);
    const float availableWidth = std::max(tileWidth, ImGui::GetContentRegionAvail().x);
    const int columns = std::max(1, static_cast<int>(availableWidth / tileWidth));
    for (int index = 0; index < static_cast<int>(entries.size()); ++index) {
        if (!ProjectExplorerSearchMatches(entries[static_cast<size_t>(index)])) {
            continue;
        }
        if (visibleCount > 0 && visibleCount % columns != 0) {
            ImGui::SameLine(0.0f, Scaled(4.0f));
        }
        DrawProjectExplorerEntry(entries[static_cast<size_t>(index)], visibleCount);
        ++visibleCount;
    }

    if (visibleCount == 0) {
        const std::string query = TrimWhitespace(projectExplorerSearchInput_.data());
        DrawEmptyState(query.empty() ? "Folder is empty." : "No matching files.", selectedPath.string().c_str());
    }

    if (ImGui::BeginPopupContextWindow("project_explorer_content_context",
                                       ImGuiPopupFlags_MouseButtonRight | ImGuiPopupFlags_NoOpenOverItems)) {
        ImGui::TextUnformatted(TruncateForUi(selectedPath.filename().string().empty()
                                                 ? selectedPath.string()
                                                 : selectedPath.filename().string(),
                                             48)
                                   .c_str());
        ImGui::Separator();
        ImGui::BeginDisabled(!state_.IsEditMode());
        if (ImGui::Button("New Folder", ImVec2(-FLT_MIN, 0.0f))) {
            CreateFolderInProjectTree(selectedPath);
        }
        ImGui::EndDisabled();
        if (ImGui::MenuItem("Show In Explorer")) {
            std::string error;
            if (!ShowPathInExplorer(selectedPath, &error)) {
                state_.AddLog(LogLevel::Error, "Show In Explorer failed: " + error);
            }
        }
        if (ImGui::MenuItem("Copy Path")) {
            const std::string pathString = selectedPath.string();
            ImGui::SetClipboardText(pathString.c_str());
            state_.AddActivity("project.tree", "Copied", pathString);
        }
        if (ImGui::MenuItem("Copy Project Relative Path")) {
            const std::string pathString = RelativeProjectPathString(state_.ProjectRootPathString(), selectedPath);
            ImGui::SetClipboardText(pathString.c_str());
            state_.AddActivity("project.tree", "Copied", pathString);
        }
        if (ImGui::MenuItem("Refresh")) {
            state_.RefreshProjectTree();
            state_.AddActivity("project.tree", "Refreshed", state_.ProjectRootPathString());
        }
        ImGui::EndPopup();
    }
    ImGui::EndChild();

    ImGui::Separator();
    const float sliderWidth = Scaled(150.0f);
    const float sliderX = std::max(ImGui::GetCursorPosX(), ImGui::GetWindowContentRegionMax().x - sliderWidth);
    ImGui::SetCursorPosX(sliderX);
    ImGui::SetNextItemWidth(sliderWidth);
    ImGui::SliderFloat("##project_explorer_icon_size", &projectExplorerIconSize_, 32.0f, 72.0f, "");
}

void EditorApp::DrawProjectExplorerEntry(const std::filesystem::directory_entry& entry, int index) {
    std::error_code filesystemError;
    const bool isDirectory = entry.is_directory(filesystemError);
    const std::filesystem::path entryPath = entry.path();
    std::string name = entryPath.filename().string();
    if (name.empty()) {
        name = entryPath.string();
    }

    const float iconSize = Scaled(projectExplorerIconSize_);
    const float tileWidth = iconSize + Scaled(22.0f);
    const float labelHeight = ImGui::GetTextLineHeightWithSpacing() + Scaled(2.0f);
    const float tileHeight = iconSize + labelHeight + Scaled(10.0f);
    ImGui::PushID(entryPath.string().c_str());
    const ImVec2 tileMin = ImGui::GetCursorScreenPos();
    ImGui::InvisibleButton("tile", ImVec2(tileWidth, tileHeight),
                           ImGuiButtonFlags_MouseButtonLeft | ImGuiButtonFlags_MouseButtonRight);
    const bool hovered = ImGui::IsItemHovered();
    const bool active = ImGui::IsItemActive();
    if (hovered && isDirectory && ImGui::IsMouseDoubleClicked(ImGuiMouseButton_Left)) {
        SelectProjectExplorerPath(entryPath);
    }
    if (hovered) {
        ImGui::SetTooltip("%s", entryPath.string().c_str());
    }
    ProjectTreeNode node = ProjectExplorerNodeForEntry(entry);
    DrawProjectTreeNodeContextMenu(node);

    ImDrawList* drawList = ImGui::GetWindowDrawList();
    const ImVec2 tileMax(tileMin.x + tileWidth, tileMin.y + tileHeight);
    if (hovered || active) {
        drawList->AddRectFilled(tileMin, tileMax,
                                ColorU32(WithAlpha(SelectionHighlightColor(), hovered ? 0.105f : 0.070f)),
                                Scaled(2.0f));
    }

    const ImVec2 iconMin(tileMin.x + (tileWidth - iconSize) * 0.5f, tileMin.y + Scaled(5.0f));
    DrawProjectExplorerIcon(entry, iconMin, iconSize, hovered || active);

    const float maxLabelWidth = tileWidth - Scaled(8.0f);
    const std::string label = TruncateToPixelWidth(name, maxLabelWidth);
    const ImVec2 labelSize = ImGui::CalcTextSize(label.c_str());
    const float labelX = tileMin.x + (tileWidth - labelSize.x) * 0.5f;
    const float labelY = tileMin.y + iconSize + Scaled(8.0f);
    drawList->AddText(ImVec2(labelX, labelY), ColorU32(hovered ? BrightTextColor() : TextColor()), label.c_str());

    ImGui::PopID();
    (void)index;
}

void EditorApp::DrawProjectExplorerIcon(const std::filesystem::directory_entry& entry, ImVec2 iconMin,
                                        float iconSize, bool highlighted) const {
    std::error_code filesystemError;
    const bool isDirectory = entry.is_directory(filesystemError);
    ImDrawList* drawList = ImGui::GetWindowDrawList();
    if (isDirectory) {
        const ImVec4 folderColor = highlighted ? ImVec4(0.43f, 0.50f, 0.57f, 1.0f)
                                               : ImVec4(0.33f, 0.38f, 0.44f, 1.0f);
        const ImVec4 folderShade = MixColor(folderColor, PanelBackgroundColor(), 0.24f);
        const float rounding = std::max(2.0f, iconSize * 0.045f);
        const ImVec2 tabMin(iconMin.x + iconSize * 0.08f, iconMin.y + iconSize * 0.16f);
        const ImVec2 tabMax(iconMin.x + iconSize * 0.48f, iconMin.y + iconSize * 0.38f);
        const ImVec2 bodyMin(iconMin.x + iconSize * 0.05f, iconMin.y + iconSize * 0.30f);
        const ImVec2 bodyMax(iconMin.x + iconSize * 0.95f, iconMin.y + iconSize * 0.84f);
        drawList->AddRectFilled(tabMin, tabMax, ColorU32(folderShade), rounding);
        drawList->AddRectFilled(bodyMin, bodyMax, ColorU32(folderColor), rounding);
        drawList->AddRect(bodyMin, bodyMax, ColorU32(WithAlpha(OffsetColor(folderColor, 0.10f), 0.55f)), rounding,
                          0, std::max(1.0f, iconSize * 0.018f));
        return;
    }

    std::string extension = ToLower(entry.path().extension().string());
    if (extension == ".png" || extension == ".jpg" || extension == ".jpeg" || extension == ".tga" ||
        extension == ".bmp") {
        if (TerrainGlTexture* texture = GetTerrainGlTexture(entry.path().string());
            texture != nullptr && texture->loaded && texture->id != 0 && texture->width > 0 && texture->height > 0) {
            const float rounding = std::max(2.0f, iconSize * 0.045f);
            const ImVec2 frameMin(iconMin.x + iconSize * 0.06f, iconMin.y + iconSize * 0.06f);
            const ImVec2 frameMax(iconMin.x + iconSize * 0.94f, iconMin.y + iconSize * 0.88f);
            drawList->AddRectFilled(frameMin, frameMax, ColorU32(OffsetColor(PanelBackgroundColor(), 0.035f)), rounding);
            const float frameWidth = frameMax.x - frameMin.x;
            const float frameHeight = frameMax.y - frameMin.y;
            const float imageAspect = static_cast<float>(texture->width) / static_cast<float>(std::max(1, texture->height));
            float imageWidth = frameWidth;
            float imageHeight = frameWidth / imageAspect;
            if (imageHeight > frameHeight) {
                imageHeight = frameHeight;
                imageWidth = frameHeight * imageAspect;
            }
            const ImVec2 imageMin(frameMin.x + (frameWidth - imageWidth) * 0.5f,
                                  frameMin.y + (frameHeight - imageHeight) * 0.5f);
            const ImVec2 imageMax(imageMin.x + imageWidth, imageMin.y + imageHeight);
            drawList->AddImage((ImTextureID)(intptr_t)texture->id, imageMin, imageMax, ImVec2(0.0f, 1.0f),
                               ImVec2(1.0f, 0.0f), IM_COL32_WHITE);
            drawList->AddRect(frameMin, frameMax, ColorU32(WithAlpha(highlighted ? AccentColor() : MutedTextColor(), 0.45f)),
                              rounding, 0, std::max(1.0f, iconSize * 0.014f));
            return;
        }
    }

    const ImVec4 pageColor = highlighted ? ImVec4(0.70f, 0.74f, 0.78f, 1.0f)
                                         : ImVec4(0.56f, 0.59f, 0.63f, 1.0f);
    const ImVec4 foldColor = MixColor(pageColor, AccentColor(), 0.10f);
    const float rounding = std::max(2.0f, iconSize * 0.045f);
    const ImVec2 pageMin(iconMin.x + iconSize * 0.22f, iconMin.y + iconSize * 0.10f);
    const ImVec2 pageMax(iconMin.x + iconSize * 0.78f, iconMin.y + iconSize * 0.88f);
    drawList->AddRectFilled(pageMin, pageMax, ColorU32(pageColor), rounding);
    drawList->AddRect(pageMin, pageMax, ColorU32(WithAlpha(PanelBackgroundColor(), 0.55f)), rounding, 0,
                      std::max(1.0f, iconSize * 0.016f));
    const ImVec2 foldA(pageMax.x - iconSize * 0.18f, pageMin.y);
    const ImVec2 foldB(pageMax.x, pageMin.y + iconSize * 0.18f);
    const ImVec2 foldC(pageMax.x - iconSize * 0.18f, pageMin.y + iconSize * 0.18f);
    drawList->AddTriangleFilled(foldA, foldB, foldC, ColorU32(foldColor));
    drawList->AddLine(foldC, foldB, ColorU32(WithAlpha(PanelBackgroundColor(), 0.45f)),
                      std::max(1.0f, iconSize * 0.012f));
}

bool EditorApp::ProjectExplorerSearchMatches(const std::filesystem::directory_entry& entry) const {
    const std::string query = ToLower(TrimWhitespace(projectExplorerSearchInput_.data()));
    if (query.empty()) {
        return true;
    }

    const std::filesystem::path entryPath = entry.path();
    const std::string filename = ToLower(entryPath.filename().string());
    const std::string extension = ToLower(entryPath.extension().string());
    const std::string fullPath = ToLower(entryPath.generic_string());
    return filename.find(query) != std::string::npos ||
           extension.find(query) != std::string::npos ||
           fullPath.find(query) != std::string::npos;
}

ProjectTreeNode EditorApp::ProjectExplorerNodeForEntry(const std::filesystem::directory_entry& entry) const {
    std::error_code filesystemError;
    ProjectTreeNode node;
    node.name = entry.path().filename().string();
    if (node.name.empty()) {
        node.name = entry.path().string();
    }
    node.path = entry.path().string();
    node.folder = entry.is_directory(filesystemError);
    node.filesystemBacked = true;
    return node;
}

void EditorApp::DrawProjectLocationsDialog() {
    if (!showProjectLocationsDialog_) {
        return;
    }

    ImGui::SetNextWindowSize(ImVec2(Scaled(720.0f), Scaled(390.0f)), ImGuiCond_FirstUseEver);
    if (!ImGui::Begin("Project Locations", &showProjectLocationsDialog_)) {
        ImGui::End();
        return;
    }

    ImGui::BeginDisabled(!state_.IsEditMode());
    DrawSectionTitle("Project");
    ImGui::TextUnformatted("Project Folder");
    ImGui::SetNextItemWidth(-1.0f);
    ImGui::InputText("##locations_project_root", projectRootInput_.data(), projectRootInput_.size());
    if (ImGui::Button("Browse Project Folder", ImVec2(-FLT_MIN, 0.0f))) {
        BrowseProjectFolderFromUi();
    }
    if (ImGui::Button("Save Project As...", ImVec2(-FLT_MIN, 0.0f))) {
        SaveProjectAsFromUi();
    }

    ImGui::TextUnformatted("Project File");
    ImGui::BeginDisabled();
    ImGui::SetNextItemWidth(-1.0f);
    ImGui::InputText("##locations_project_file", projectFileInput_.data(), projectFileInput_.size());
    ImGui::EndDisabled();

    ImGui::TextUnformatted("Scene File");
    ImGui::SetNextItemWidth(-1.0f);
    ImGui::InputText("##locations_scene_file", scenePathInput_.data(), scenePathInput_.size());
    if (ImGui::Button("Save Scene As...", ImVec2(-FLT_MIN, 0.0f))) {
        SaveSceneAsWithDialogFromUi();
    }

    ImGui::TextUnformatted("Game Save Folder");
    ImGui::SetNextItemWidth(-1.0f);
    ImGui::InputText("##locations_game_save_folder", gameSavePathInput_.data(), gameSavePathInput_.size());
    if (ImGui::BeginTable("locations_game_save_actions", 2, ImGuiTableFlags_SizingStretchSame)) {
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        if (ImGui::Button("Browse Save Folder", ImVec2(-FLT_MIN, 0.0f))) {
            BrowseGameSaveFolderFromUi();
        }
        ImGui::TableSetColumnIndex(1);
        if (ImGui::Button("Apply Save Folder", ImVec2(-FLT_MIN, 0.0f))) {
            ApplyGameSaveFolderFromUi();
        }
        ImGui::EndTable();
    }

    if (ImGui::BeginTable("locations_project_actions", 4, ImGuiTableFlags_SizingStretchSame)) {
        ImGui::TableNextRow();
        ImGui::TableSetColumnIndex(0);
        if (ImGui::Button("New", ImVec2(-FLT_MIN, 0.0f))) {
            NewProjectFromUi();
        }
        ImGui::TableSetColumnIndex(1);
        if (ImGui::Button("Open", ImVec2(-FLT_MIN, 0.0f))) {
            OpenProjectFromUi();
        }
        ImGui::TableSetColumnIndex(2);
        if (ImGui::Button("Save", ImVec2(-FLT_MIN, 0.0f))) {
            SaveProjectFromUi();
        }
        ImGui::TableSetColumnIndex(3);
        if (ImGui::Button("Save As...", ImVec2(-FLT_MIN, 0.0f))) {
            SaveProjectAsFromUi();
        }
        ImGui::EndTable();
    }
    ImGui::EndDisabled();

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Project location actions are disabled during Play Mode.");
    }

    ImGui::End();
}

void EditorApp::DrawBuildSettingsPanel() {
    if (!showBuildSettings_) {
        return;
    }

    ImGui::SetNextWindowSize(ImVec2(Scaled(760.0f), Scaled(620.0f)), ImGuiCond_FirstUseEver);
    if (!ImGui::Begin("Build Settings", &showBuildSettings_)) {
        ImGui::End();
        return;
    }

    DrawSectionTitle("Target");
    const char* targetPlatforms[] = {"Windows", "Linux", "macOS"};
    buildTargetPlatformIndex_ =
        std::clamp(buildTargetPlatformIndex_, 0, static_cast<int>(IM_ARRAYSIZE(targetPlatforms)) - 1);
    SetNextInlineLabeledItemWidth("Platform");
    const int previousTargetPlatformIndex = buildTargetPlatformIndex_;
    if (ImGui::Combo("Platform", &buildTargetPlatformIndex_, targetPlatforms, IM_ARRAYSIZE(targetPlatforms)) &&
        buildTargetPlatformIndex_ != previousTargetPlatformIndex) {
        const std::string currentOutput = TrimWhitespace(buildOutputDirectoryInput_.data());
        if (currentOutput.empty() || IsKnownDefaultBuildOutputDirectory(currentOutput)) {
            CopyStringToBuffer(buildOutputDirectoryInput_,
                               DefaultBuildOutputDirectoryForTarget(targetPlatforms[buildTargetPlatformIndex_]));
        }
    }
    const char* configurations[] = {"Debug", "Release"};
    buildConfigurationIndex_ = std::clamp(buildConfigurationIndex_, 0, 1);
    SetNextInlineLabeledItemWidth("Configuration");
    ImGui::Combo("Configuration", &buildConfigurationIndex_, configurations, IM_ARRAYSIZE(configurations));
    ImGui::Checkbox("Development Build", &buildDevelopmentBuild_);
    ImGui::Checkbox("Copy Project Data", &buildCopyProjectFiles_);
    ImGui::Checkbox("Run Player Smoke After Package", &buildRunPlayerSmokeAfterBuild_);

    DrawSectionTitle("Output");
    ImGui::TextUnformatted("Executable Name");
    ImGui::SetNextItemWidth(-1.0f);
    ImGui::InputText("##build_executable_name", buildExecutableNameInput_.data(), buildExecutableNameInput_.size());
    ImGui::TextUnformatted("Output Directory");
    ImGui::SetNextItemWidth(-1.0f);
    ImGui::InputText("##build_output_directory", buildOutputDirectoryInput_.data(), buildOutputDirectoryInput_.size());
    if (ImGui::Button("Browse Build Folder", ImVec2(Scaled(190.0f), 0.0f))) {
        BrowseBuildOutputFolderFromUi();
    }
    ImGui::SameLine();
    if (ImGui::Button("Use Project Default", ImVec2(Scaled(180.0f), 0.0f))) {
        const std::string defaultOutput = DefaultBuildOutputDirectoryForTarget(targetPlatforms[buildTargetPlatformIndex_]);
        CopyStringToBuffer(buildOutputDirectoryInput_, defaultOutput);
        state_.AddActivity("build.output", "Selected", defaultOutput);
    }

    ProjectBuildSettings preview = state_.BuildSettings();
    preview.targetPlatform = targetPlatforms[buildTargetPlatformIndex_];
    preview.configuration = configurations[buildConfigurationIndex_];
    preview.executableName = buildExecutableNameInput_.data();
    preview.outputDirectory = buildOutputDirectoryInput_.data();
    preview.developmentBuild = buildDevelopmentBuild_;
    preview.copyProjectFiles = buildCopyProjectFiles_;
    preview.runPlayerSmokeAfterBuild = buildRunPlayerSmokeAfterBuild_;
    preview.multiplayer.enabled = multiplayerEnabled_;
    const char* topologies[] = {"Single Player", "Host Client", "Client Server", "Dedicated Server"};
    const char* transports[] = {"Local Loopback", "UDP", "WebSocket"};
    multiplayerTopologyIndex_ = std::clamp(multiplayerTopologyIndex_, 0, static_cast<int>(IM_ARRAYSIZE(topologies)) - 1);
    multiplayerTransportIndex_ = std::clamp(multiplayerTransportIndex_, 0, static_cast<int>(IM_ARRAYSIZE(transports)) - 1);
    preview.multiplayer.topology = topologies[multiplayerTopologyIndex_];
    preview.multiplayer.transport = transports[multiplayerTransportIndex_];
    preview.multiplayer.bindAddress = multiplayerBindAddressInput_.data();
    preview.multiplayer.port = multiplayerPort_;
    preview.multiplayer.maxPlayers = multiplayerMaxPlayers_;

    const std::filesystem::path previewOutput =
        std::filesystem::path(preview.outputDirectory).is_absolute()
            ? std::filesystem::path(preview.outputDirectory)
            : std::filesystem::path(state_.ProjectRootPathString()) / preview.outputDirectory;
    DrawKeyValue("Resolved Output", previewOutput.string(), Scaled(124.0f));

    DrawSectionTitle("Scenes");
    const std::vector<std::string>& scenes = state_.BuildSettings().scenes;
    if (scenes.empty()) {
        DrawMutedWrapped("Active scene will be included on save.");
    } else {
        for (const std::string& scene : scenes) {
            ImGui::BulletText("%s", scene.c_str());
        }
    }
    if (ImGui::Button("Use Active Scene", ImVec2(Scaled(180.0f), 0.0f))) {
        ProjectBuildSettings settings = state_.BuildSettings();
        settings.scenes = {std::filesystem::path(state_.SceneFilePathString()).is_absolute()
                               ? std::filesystem::relative(state_.SceneFilePathString(), state_.ProjectRootPathString()).generic_string()
                               : state_.SceneFilePathString()};
        state_.SetBuildSettings(std::move(settings));
        RefreshBuildSettingsInputs();
        state_.AddActivity("build.settings", "Updated", "Build scenes set to active scene.");
    }

    DrawSectionTitle("Multiplayer");
    ImGui::Checkbox("Enable Multiplayer Settings", &multiplayerEnabled_);
    ImGui::BeginDisabled(!multiplayerEnabled_);
    SetNextInlineLabeledItemWidth("Topology");
    ImGui::Combo("Topology", &multiplayerTopologyIndex_, topologies, IM_ARRAYSIZE(topologies));
    SetNextInlineLabeledItemWidth("Transport");
    ImGui::Combo("Transport", &multiplayerTransportIndex_, transports, IM_ARRAYSIZE(transports));
    ImGui::TextUnformatted("Bind Address");
    ImGui::SetNextItemWidth(Scaled(260.0f));
    ImGui::InputText("##multiplayer_bind_address", multiplayerBindAddressInput_.data(), multiplayerBindAddressInput_.size());
    SetNextInlineLabeledItemWidth("Port");
    ImGui::InputInt("Port", &multiplayerPort_);
    SetNextInlineLabeledItemWidth("Max Players");
    ImGui::InputInt("Max Players", &multiplayerMaxPlayers_);
    ImGui::EndDisabled();

    DrawSectionTitle("Validation");
    const SceneValidationResult validation = state_.ValidateProject();
    DrawStatusBadge(validation.ok ? "Ready" : "Fix Required", validation.ok ? ImVec4(0.50f, 0.90f, 0.62f, 1.0f)
                                                                              : ImVec4(0.92f, 0.52f, 0.52f, 1.0f));
    for (const std::string& diagnostic : validation.diagnostics) {
        DrawMutedWrapped(diagnostic);
    }

    if (!lastBuildStatus_.empty()) {
        DrawSectionTitle("Last Build");
        DrawMutedWrapped(lastBuildStatus_);
    }

    ImGui::Separator();
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::Button("Apply Settings", ImVec2(Scaled(160.0f), 0.0f))) {
        ApplyBuildSettingsFromUi();
    }
    ImGui::SameLine();
    if (ImGui::Button("Package Selected Target", ImVec2(Scaled(230.0f), 0.0f))) {
        PackageProjectFromUi();
    }
    ImGui::SameLine();
    if (ImGui::Button("Package All Available Targets", ImVec2(Scaled(260.0f), 0.0f))) {
        PackageAllTargetsFromUi();
    }
    ImGui::EndDisabled();
    if (!lastBuildOutputPath_.empty()) {
        ImGui::SameLine();
        if (ImGui::Button("Show Output", ImVec2(Scaled(140.0f), 0.0f))) {
            std::string error;
            if (!ShowPathInExplorer(lastBuildOutputPath_, &error)) {
                state_.AddLog(LogLevel::Error, "Show Output failed: " + error);
            }
        }
    }

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Build settings are edit-time project actions.");
    }

    ImGui::End();
}

void EditorApp::PersistProjectSettingsFromUi(const std::string& action) {
    std::string error;
    if (state_.SaveProject(&error)) {
        projectSettingsStatus_ = action + " saved.";
        state_.AddActivity("project.settings", "Saved", action);
    } else {
        projectSettingsStatus_ = action + " save failed: " + error;
        state_.AddLog(LogLevel::Error, "Project settings save failed: " + error);
    }
}

void EditorApp::DrawProjectSettingsPanel() {
    if (!showProjectSettings_) {
        return;
    }

    ImGui::SetNextWindowSize(ImVec2(Scaled(820.0f), Scaled(640.0f)), ImGuiCond_FirstUseEver);
    if (!ImGui::Begin("Project Settings", &showProjectSettings_)) {
        ImGui::End();
        return;
    }

    if (!projectSettingsStatus_.empty()) {
        DrawMutedWrapped(projectSettingsStatus_);
        ImGui::Spacing();
    }

    if (ImGui::BeginTabBar("project_settings_tabs")) {
        if (ImGui::BeginTabItem("Overview")) {
            DrawSectionTitle("Project");
            DrawKeyValue("Project", state_.ProjectName(), Scaled(110.0f));
            DrawKeyValue("File", state_.ProjectFilePathString(), Scaled(110.0f));
            DrawKeyValue("Tags", std::to_string(state_.ProjectTags().size()), Scaled(110.0f));
            DrawKeyValue("Layers", std::to_string(state_.ProjectLayers().size()), Scaled(110.0f));
            DrawKeyValue("Disabled Pairs",
                         std::to_string(state_.ProjectSettings().disabledLayerCollisionPairs.size()), Scaled(110.0f));
            const RenderProfileSettings* activeProfile = state_.ActiveRenderProfile();
            DrawKeyValue("Renderer", activeProfile == nullptr ? state_.RenderingSettings().activeProfile
                                                              : activeProfile->displayName,
                         Scaled(110.0f));
            DrawKeyValue("Backend", state_.RenderingSettings().graphicsBackend.preferred + " -> " +
                                        state_.RenderingSettings().graphicsBackend.fallback,
                         Scaled(110.0f));

            DrawSectionTitle("Open Settings");
            if (ImGui::Button("Build Settings", ImVec2(Scaled(180.0f), 0.0f))) {
                RefreshBuildSettingsInputs();
                showBuildSettings_ = true;
            }
            ImGui::SameLine();
            if (ImGui::Button("Project Locations", ImVec2(Scaled(190.0f), 0.0f))) {
                RefreshPathInputs();
                showProjectLocationsDialog_ = true;
            }
            ImGui::SameLine();
            if (ImGui::Button("Appearance", ImVec2(Scaled(150.0f), 0.0f))) {
                showAppearancePreferences_ = true;
            }

            ImGui::BeginDisabled(!state_.IsEditMode());
            if (ImGui::Button("Reset Tags, Layers, and Matrix", ImVec2(Scaled(260.0f), 0.0f))) {
                state_.ResetProjectSettingsToDefaults();
                std::fill(projectSettingsRenameTagInput_.begin(), projectSettingsRenameTagInput_.end(), '\0');
                std::fill(projectSettingsRenameLayerInput_.begin(), projectSettingsRenameLayerInput_.end(), '\0');
                PersistProjectSettingsFromUi("Project settings reset");
            }
            ImGui::EndDisabled();
            if (!state_.IsEditMode()) {
                DrawMutedWrapped("Project settings are edit-time data and are disabled during Play Mode.");
            }
            ImGui::EndTabItem();
        }
        if (ImGui::BeginTabItem("Tags")) {
            DrawProjectTagSettings();
            ImGui::EndTabItem();
        }
        if (ImGui::BeginTabItem("Rendering")) {
            DrawProjectRenderingSettings();
            ImGui::EndTabItem();
        }
        if (ImGui::BeginTabItem("Layers")) {
            DrawProjectLayerSettings();
            ImGui::EndTabItem();
        }
        if (ImGui::BeginTabItem("Physics Matrix")) {
            DrawProjectPhysicsSettings();
            ImGui::EndTabItem();
        }
        ImGui::EndTabBar();
    }

    ImGui::End();
}

void EditorApp::DrawProjectRenderingSettings() {
    const ProjectRenderingSettings& rendering = state_.RenderingSettings();
    const RenderProfileSettings* activeProfile = state_.ActiveRenderProfile();

    DrawSectionTitle("Renderer Profile");
    DrawKeyValue("Active", activeProfile == nullptr ? rendering.activeProfile : activeProfile->displayName,
                 Scaled(130.0f));
    DrawKeyValue("Profile Id", rendering.activeProfile, Scaled(130.0f));
    DrawKeyValue("Backend", rendering.graphicsBackend.preferred + " -> " + rendering.graphicsBackend.fallback,
                 Scaled(130.0f));
    DrawKeyValue("Allowed", JoinStrings(rendering.graphicsBackend.allowed, ", "), Scaled(130.0f));

    ImGui::BeginDisabled(!state_.IsEditMode());
    std::string selectedProfile = rendering.activeProfile;
    const std::string comboLabel = activeProfile == nullptr ? selectedProfile : activeProfile->displayName;
    ImGui::SetNextItemWidth(Scaled(280.0f));
    if (ImGui::BeginCombo("Active Profile", comboLabel.c_str())) {
        for (const RenderProfileSettings& profile : rendering.profiles) {
            const bool selected = selectedProfile == profile.id;
            std::string label = profile.displayName + "##" + profile.id;
            if (ImGui::Selectable(label.c_str(), selected)) {
                selectedProfile = profile.id;
            }
            if (selected) {
                ImGui::SetItemDefaultFocus();
            }
            if (ImGui::IsItemHovered()) {
                ImGui::SetTooltip("%s", RenderProfileFeatureSummary(profile).c_str());
            }
        }
        ImGui::EndCombo();
    }
    if (selectedProfile != rendering.activeProfile) {
        std::string error;
        if (state_.SetActiveRenderProfile(selectedProfile, &error)) {
            PersistProjectSettingsFromUi("Render profile changed");
        } else {
            projectSettingsStatus_ = error;
        }
    }
    ImGui::EndDisabled();

    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Rendering project settings are disabled during Play Mode.");
    }
    if (activeProfile != nullptr && !activeProfile->requirements.empty()) {
        DrawMutedWrapped(activeProfile->displayName + " is registered as a future profile and requires " +
                         JoinStrings(activeProfile->requirements, ", ") + ".");
    }

    DrawSectionTitle("Profiles");
    if (ImGui::BeginTable("render_profiles_table", 6,
                          ImGuiTableFlags_BordersInnerV | ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("Profile", ImGuiTableColumnFlags_WidthFixed, Scaled(160.0f));
        ImGui::TableSetupColumn("Mode", ImGuiTableColumnFlags_WidthFixed, Scaled(86.0f));
        ImGui::TableSetupColumn("Material", ImGuiTableColumnFlags_WidthFixed, Scaled(126.0f));
        ImGui::TableSetupColumn("Lighting", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableSetupColumn("Resources", ImGuiTableColumnFlags_WidthFixed, Scaled(112.0f));
        ImGui::TableSetupColumn("Features", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableHeadersRow();
        for (const RenderProfileSettings& profile : rendering.profiles) {
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            const bool selected = profile.id == rendering.activeProfile;
            ImGui::Text("%s%s", selected ? "* " : "", profile.displayName.c_str());
            ImGui::TableSetColumnIndex(1);
            ImGui::TextUnformatted(profile.dimensionMode.c_str());
            ImGui::TableSetColumnIndex(2);
            ImGui::TextUnformatted(profile.materialModel.c_str());
            ImGui::TableSetColumnIndex(3);
            ImGui::TextUnformatted(profile.lightingModel.c_str());
            ImGui::TableSetColumnIndex(4);
            ImGui::TextUnformatted(profile.resourceBackedModels.c_str());
            ImGui::TableSetColumnIndex(5);
            ImGui::TextWrapped("%s", RenderProfileFeatureSummary(profile).c_str());
        }
        ImGui::EndTable();
    }
}

void EditorApp::DrawProjectTagSettings() {
    const std::vector<std::string>& tags = state_.ProjectTags();
    if (tags.empty()) {
        DrawEmptyState("No tags.", "Reset project settings to restore default tags.");
        return;
    }

    projectSettingsSelectedTag_ = std::clamp(projectSettingsSelectedTag_, 0, static_cast<int>(tags.size()) - 1);
    if (projectSettingsRenameTagInput_[0] == '\0') {
        CopyStringToBuffer(projectSettingsRenameTagInput_, tags[static_cast<size_t>(projectSettingsSelectedTag_)]);
    }

    DrawSectionTitle("Project Tags");
    if (ImGui::BeginTable("project_tags_table", 3,
                          ImGuiTableFlags_BordersInnerV | ImGuiTableFlags_RowBg | ImGuiTableFlags_SizingStretchProp)) {
        ImGui::TableSetupColumn("Index", ImGuiTableColumnFlags_WidthFixed, Scaled(54.0f));
        ImGui::TableSetupColumn("Tag", ImGuiTableColumnFlags_WidthStretch);
        ImGui::TableSetupColumn("Use", ImGuiTableColumnFlags_WidthFixed, Scaled(96.0f));
        ImGui::TableHeadersRow();
        for (size_t i = 0; i < tags.size(); ++i) {
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            ImGui::Text("%zu", i);
            ImGui::TableSetColumnIndex(1);
            const bool selected = projectSettingsSelectedTag_ == static_cast<int>(i);
            if (ImGui::Selectable(tags[i].c_str(), selected, ImGuiSelectableFlags_SpanAllColumns)) {
                projectSettingsSelectedTag_ = static_cast<int>(i);
                CopyStringToBuffer(projectSettingsRenameTagInput_, tags[i]);
            }
            ImGui::TableSetColumnIndex(2);
            const int useCount = static_cast<int>(std::count_if(state_.Entities().begin(), state_.Entities().end(),
                                                                 [&tags, i](const Entity& entity) {
                                                                     return entity.tag == tags[i];
                                                                 }));
            ImGui::Text("%d", useCount);
        }
        ImGui::EndTable();
    }

    ImGui::BeginDisabled(!state_.IsEditMode());
    DrawSectionTitle("Add Tag");
    ImGui::SetNextItemWidth(Scaled(260.0f));
    ImGui::InputText("##new_project_tag", projectSettingsNewTagInput_.data(), projectSettingsNewTagInput_.size());
    ImGui::SameLine();
    if (ImGui::Button("Add Tag", ImVec2(Scaled(120.0f), 0.0f))) {
        std::string error;
        if (state_.AddProjectTag(projectSettingsNewTagInput_.data(), &error)) {
            projectSettingsSelectedTag_ = static_cast<int>(state_.ProjectTags().size()) - 1;
            CopyStringToBuffer(projectSettingsRenameTagInput_, state_.ProjectTags().back());
            std::fill(projectSettingsNewTagInput_.begin(), projectSettingsNewTagInput_.end(), '\0');
            PersistProjectSettingsFromUi("Tag added");
        } else {
            projectSettingsStatus_ = error;
        }
    }

    DrawSectionTitle("Edit Selected Tag");
    const std::string selectedTag = tags[static_cast<size_t>(projectSettingsSelectedTag_)];
    const bool locked = IsBuiltInProjectTagForUi(selectedTag);
    ImGui::BeginDisabled(locked);
    ImGui::SetNextItemWidth(Scaled(260.0f));
    ImGui::InputText("##rename_project_tag", projectSettingsRenameTagInput_.data(),
                     projectSettingsRenameTagInput_.size());
    ImGui::SameLine();
    if (ImGui::Button("Rename", ImVec2(Scaled(110.0f), 0.0f))) {
        std::string error;
        if (state_.RenameProjectTag(selectedTag, projectSettingsRenameTagInput_.data(), &error)) {
            PersistProjectSettingsFromUi("Tag renamed");
        } else {
            projectSettingsStatus_ = error;
        }
    }
    ImGui::SameLine();
    if (ImGui::Button("Remove", ImVec2(Scaled(110.0f), 0.0f))) {
        std::string error;
        if (state_.RemoveProjectTag(selectedTag, &error)) {
            projectSettingsSelectedTag_ = std::clamp(projectSettingsSelectedTag_, 0,
                                                     static_cast<int>(state_.ProjectTags().size()) - 1);
            CopyStringToBuffer(projectSettingsRenameTagInput_,
                               state_.ProjectTags()[static_cast<size_t>(projectSettingsSelectedTag_)]);
            PersistProjectSettingsFromUi("Tag removed");
        } else {
            projectSettingsStatus_ = error;
        }
    }
    ImGui::EndDisabled();
    ImGui::EndDisabled();
    if (locked) {
        DrawMutedWrapped("Built-in tags are kept for compatibility. Add custom tags below them.");
    }
}

