void EditorApp::DrawProjectPhysicsSettings() {
    const std::vector<std::string>& layers = state_.ProjectLayers();
    DrawSectionTitle("Physics");
    DrawKeyValue("Layers", std::to_string(layers.size()), Scaled(120.0f));
    DrawKeyValue("Disabled Pairs", std::to_string(state_.ProjectSettings().disabledLayerCollisionPairs.size()),
                 Scaled(120.0f));

    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::Button("Create / Select Physics Settings Entity", ImVec2(Scaled(280.0f), 0.0f))) {
        const int settingsId = state_.EnsurePhysicsSettingsEntity();
        if (settingsId != 0) {
            state_.SelectEntity(settingsId);
            projectSettingsStatus_ = "Physics Settings entity selected.";
        }
    }

    DrawSectionTitle("Layer Collision Matrix");
    if (layers.empty()) {
        DrawEmptyState("No layers.", "Add a layer before editing collision pairs.");
        ImGui::EndDisabled();
        return;
    }

    const int columnCount = static_cast<int>(layers.size()) + 1;
    if (ImGui::BeginTable("layer_collision_matrix", columnCount,
                          ImGuiTableFlags_Borders | ImGuiTableFlags_RowBg | ImGuiTableFlags_ScrollX |
                              ImGuiTableFlags_SizingFixedFit,
                          ImVec2(0.0f, Scaled(360.0f)))) {
        ImGui::TableSetupColumn("Layer", ImGuiTableColumnFlags_WidthFixed, Scaled(132.0f));
        for (const std::string& layer : layers) {
            ImGui::TableSetupColumn(TruncateForUi(layer, 14).c_str(), ImGuiTableColumnFlags_WidthFixed,
                                    Scaled(46.0f));
        }
        ImGui::TableHeadersRow();

        for (size_t row = 0; row < layers.size(); ++row) {
            ImGui::TableNextRow();
            ImGui::TableSetColumnIndex(0);
            ImGui::TextUnformatted(TruncateForUi(layers[row], 18).c_str());
            if (ImGui::IsItemHovered()) {
                ImGui::SetTooltip("%s", layers[row].c_str());
            }
            for (size_t column = 0; column < layers.size(); ++column) {
                ImGui::TableSetColumnIndex(static_cast<int>(column) + 1);
                if (column > row) {
                    ImGui::TextUnformatted("-");
                    continue;
                }
                bool enabled = state_.LayerCollisionEnabled(layers[row], layers[column]);
                ImGui::PushID(static_cast<int>(row * layers.size() + column));
                if (ImGui::Checkbox("##collision_pair", &enabled)) {
                    std::string error;
                    if (state_.SetLayerCollisionEnabled(layers[row], layers[column], enabled, &error)) {
                        PersistProjectSettingsFromUi("Physics collision matrix");
                    } else {
                        projectSettingsStatus_ = error;
                    }
                }
                if (ImGui::IsItemHovered()) {
                    ImGui::SetTooltip("%s %s %s", layers[row].c_str(), enabled ? "collides with" : "ignores",
                                      layers[column].c_str());
                }
                ImGui::PopID();
            }
        }
        ImGui::EndTable();
    }
    ImGui::EndDisabled();
    if (!state_.IsEditMode()) {
        DrawMutedWrapped("Physics collision settings are disabled during Play Mode.");
    }
}

void EditorApp::DrawToolGatewayPanel() {
    if (!BeginPanel("Tool Gateway", ImVec2(420.0f, 240.0f))) {
        ImGui::End();
        return;
    }

    ImGui::BeginChild("gateway_summary", ImVec2(0.0f, Scaled(82.0f)), true, ImGuiWindowFlags_NoScrollbar);
    DrawStatusBadge("Offline fallback", AccentColor());
    ImGui::SameLine();
    ImGui::TextUnformatted("Editor Tool API");
    DrawKeyValue("Transaction", state_.LastTransactionId(), Scaled(104.0f));
    DrawKeyValue("Commands", std::to_string(gateway_.SupportedCommands().size()), Scaled(104.0f));
    ImGui::EndChild();

    if (ImGui::TreeNodeEx("Supported Commands")) {
        float commandLineWidth = 0.0f;
        const float commandAvailableWidth = ImGui::GetContentRegionAvail().x;
        for (const std::string& command : gateway_.SupportedCommands()) {
            const float commandWidth = ImGui::CalcTextSize(command.c_str()).x + ImGui::GetStyle().FramePadding.x * 2.0f;
            if (commandLineWidth > 0.0f &&
                commandLineWidth + commandWidth + ImGui::GetStyle().ItemSpacing.x <= commandAvailableWidth) {
                ImGui::SameLine();
                commandLineWidth += commandWidth + ImGui::GetStyle().ItemSpacing.x;
            } else {
                commandLineWidth = commandWidth;
            }
            DrawStatusBadge(command.c_str(), AccentColor());
        }
        ImGui::TreePop();
    }

    if (!proposedActions_.empty()) {
        DrawProposedActionsSection();
    }

    DrawSectionTitle("Last Batch");
    if (!hasLastGatewayResult_) {
        DrawEmptyState("No command batch has run.", "Submit a prompt through AI Chat or run a gateway command from the Tools menu.");
        ImGui::End();
        return;
    }

    const ToolCommandBatch& batch = lastGatewayResult_.batch;
    DrawStatusBadge(batch.applied ? "Applied" : "Not applied", batch.applied ? ImVec4(0.50f, 0.90f, 0.62f, 1.0f)
                                                                               : ImVec4(1.0f, 0.78f, 0.32f, 1.0f));
    ImGui::SameLine();
    DrawStatusBadge(batch.ok ? "OK" : "Diagnostics", batch.ok ? ImVec4(0.50f, 0.90f, 0.62f, 1.0f)
                                                              : ImVec4(0.92f, 0.52f, 0.52f, 1.0f));
    DrawKeyValue("Name", batch.name, Scaled(92.0f));
    DrawKeyValue("Approval", batch.approval, Scaled(92.0f));

    if (!batch.changedEntities.empty()) {
        DrawSectionTitle("Changed Entities");
        for (const std::string& entity : batch.changedEntities) {
            ImGui::BulletText("%s", entity.c_str());
        }
    }

    if (!batch.changedFiles.empty()) {
        DrawSectionTitle("Changed Files");
        for (const std::string& file : batch.changedFiles) {
            ImGui::BulletText("%s", TruncateForUi(file, 140).c_str());
        }
    }

    if (!batch.diagnostics.empty()) {
        DrawSectionTitle("Diagnostics");
        for (const std::string& diagnostic : batch.diagnostics) {
            ImGui::BulletText("%s", TruncateForUi(diagnostic, 180).c_str());
        }
    }

    DrawSectionTitle("Commands");
    for (size_t index = 0; index < batch.commands.size(); ++index) {
        const ToolCommand& command = batch.commands[index];
        std::string label = std::to_string(index + 1) + ". " + command.type;
        if (ImGui::TreeNodeEx(label.c_str())) {
            DrawMutedWrapped(command.summary);
            if (!command.payloadJson.empty() && ImGui::TreeNodeEx("Raw payload JSON")) {
                ImGui::BeginChild(("payload_" + std::to_string(index)).c_str(), ImVec2(0.0f, Scaled(82.0f)), true,
                                  ImGuiWindowFlags_HorizontalScrollbar);
                ImGui::TextUnformatted(command.payloadJson.c_str());
                ImGui::EndChild();
                ImGui::TreePop();
            }
            ImGui::TreePop();
        }
    }

    ImGui::End();
}

void EditorApp::DrawAppearancePreferencesPanel() {
    if (!showAppearancePreferences_) {
        return;
    }

    ImGui::SetNextWindowSize(Scaled(ImVec2(460.0f, 430.0f)), ImGuiCond_FirstUseEver);
    ImGui::SetNextWindowSizeConstraints(Scaled(ImVec2(380.0f, 330.0f)), ImVec2(FLT_MAX, FLT_MAX));
    if (!ImGui::Begin("Editor Preferences / Appearance", &showAppearancePreferences_)) {
        ImGui::End();
        return;
    }

    bool changed = false;
    bool manualChange = false;
    const char* presetNames[] = {"Dark Default", "Midnight", "Slate", "High Contrast"};

    DrawSectionTitle("Theme Profile");
    SetNextInlineLabeledItemWidth("Preset theme");
    if (ImGui::BeginCombo("Preset theme", appearance_.presetName.c_str())) {
        for (const char* presetName : presetNames) {
            const bool selected = appearance_.presetName == presetName;
            if (ImGui::Selectable(presetName, selected)) {
                ApplyAppearancePreset(presetName);
                changed = true;
            }
            if (selected) {
                ImGui::SetItemDefaultFocus();
            }
        }
        ImGui::EndCombo();
    }

    DrawSectionTitle("Editor Chrome");
    auto colorEdit = [](const char* label, ImVec4& color) {
        float values[3] = {color.x, color.y, color.z};
        SetNextInlineLabeledItemWidth(label);
        if (ImGui::ColorEdit3(label, values, ImGuiColorEditFlags_DisplayRGB | ImGuiColorEditFlags_InputRGB)) {
            color = ClampColor(ImVec4(values[0], values[1], values[2], 1.0f));
            return true;
        }
        return false;
    };

    if (colorEdit("Accent colour", appearance_.accentColor)) {
        changed = true;
        manualChange = true;
    }
    if (colorEdit("Panel background colour", appearance_.panelBackgroundColor)) {
        changed = true;
        manualChange = true;
    }

    DrawSectionTitle("Scene View");
    if (colorEdit("Scene background colour", appearance_.sceneBackgroundColor)) {
        changed = true;
        manualChange = true;
    }
    if (colorEdit("Viewport grid colour", appearance_.viewportGridColor)) {
        changed = true;
        manualChange = true;
    }
    if (colorEdit("Selected object highlight colour", appearance_.selectedObjectHighlightColor)) {
        changed = true;
        manualChange = true;
    }

    DrawSectionTitle("Text");
    SetNextInlineLabeledItemWidth("Brightness");
    if (ImGui::SliderFloat("Brightness", &appearance_.textBrightness, 0.72f, 1.30f, "%.2f")) {
        changed = true;
        manualChange = true;
    }
    SetNextInlineLabeledItemWidth("Contrast");
    if (ImGui::SliderFloat("Contrast", &appearance_.textContrast, 0.75f, 1.35f, "%.2f")) {
        changed = true;
        manualChange = true;
    }

    if (ImGui::Button("Reset to Dark Default")) {
        ApplyAppearancePreset("Dark Default");
        changed = true;
        manualChange = false;
    }

    DrawSectionTitle("Settings");
    DrawKeyValue("Profile", editorProfilePath_.string(), Scaled(74.0f));
    DrawKeyValue("Layout", imguiIniFilename_, Scaled(74.0f));

    if (changed) {
        if (manualChange) {
            appearance_.presetName = "Custom";
        }
        ApplyEditorTheme();

        std::string error;
        if (!SaveEditorProfile(&error)) {
            state_.AddLog(LogLevel::Error, "Editor profile save failed: " + error);
        }
    }

    ImGui::End();
}

void EditorApp::DrawProposedActionsSection(bool includeHeader) {
    if (includeHeader) {
        DrawSectionTitle("Proposed Actions");
    }
    if (proposedActions_.empty()) {
        DrawEmptyState("No proposed actions.", "Provider command batches that require approval will appear here.");
        return;
    }

    for (size_t index = 0; index < proposedActions_.size(); ++index) {
        NormalizedProviderResult& action = proposedActions_[index];
        std::string label = action.title.empty() ? ProviderResultNormalizer::TypeId(action.type) : action.title;
        label = std::to_string(index + 1) + ". " + TruncateForUi(label, 90);

        ImGui::PushID(static_cast<int>(index));
        DrawStatusBadge(ActionStateLabel(action).c_str(), ActionStateColor(action));
        ImGui::SameLine();
        const ImGuiTreeNodeFlags flags = action.canApprove && !action.applied && !action.rejected
                                             ? ImGuiTreeNodeFlags_DefaultOpen
                                             : ImGuiTreeNodeFlags_None;
        if (ImGui::TreeNodeEx("action", flags, "%s", label.c_str())) {
            DrawMutedWrapped(ProviderResultNormalizer::TypeId(action.type));
            if (!action.message.empty()) {
                DrawMutedWrapped(TruncateForUi(action.message, 260));
                if (action.message.size() > 260 && ImGui::IsItemHovered()) {
                    ImGui::SetTooltip("%s", action.message.c_str());
                }
            }
            if (action.type == ProviderResultType::ProposedCommandBatch && action.hasCommandBatch) {
                DrawKeyValue("Batch", action.commandBatch.name, Scaled(86.0f));
                DrawKeyValue("Commands", std::to_string(action.commandBatch.commands.size()), Scaled(86.0f));
                DrawStatusBadge(action.schemaValid ? "Schema valid" : "Schema invalid",
                                action.schemaValid ? ImVec4(0.50f, 0.90f, 0.62f, 1.0f)
                                                   : ImVec4(0.92f, 0.52f, 0.52f, 1.0f));
                ImGui::SameLine();
                DrawStatusBadge(ActionStateLabel(action).c_str(), ActionStateColor(action));

                if (!action.commandBatch.changedEntities.empty()) {
                    DrawKeyValue("Entities", JoinInline(action.commandBatch.changedEntities), Scaled(86.0f));
                }
                if (!action.commandBatch.changedFiles.empty()) {
                    DrawKeyValue("Files", JoinInline(action.commandBatch.changedFiles, 4), Scaled(86.0f));
                }

                if (!action.diagnostics.empty()) {
                    if (ImGui::TreeNodeEx("Diagnostics")) {
                        for (const std::string& diagnostic : action.diagnostics) {
                            ImGui::BulletText("%s", TruncateForUi(diagnostic, 180).c_str());
                        }
                        ImGui::TreePop();
                    }
                }

                if (action.canApprove && !action.applied && !action.rejected) {
                    ImGui::BeginDisabled(!state_.IsEditMode());
                    if (ImGui::Button("Approve")) {
                        ApproveProposedAction(index);
                    }
                    ImGui::EndDisabled();
                    ImGui::SameLine();
                    if (ImGui::Button("Reject")) {
                        RejectProposedAction(index);
                    }
                    if (!state_.IsEditMode()) {
                        DrawMutedWrapped("Approval applies edit-time commands and is disabled during Play Mode.");
                    }
                }

                DrawSectionTitle("Commands");
                for (size_t commandIndex = 0; commandIndex < action.commandBatch.commands.size(); ++commandIndex) {
                    const ToolCommand& command = action.commandBatch.commands[commandIndex];
                    ImGui::BulletText("%zu. %s", commandIndex + 1, command.type.c_str());
                    if (!command.summary.empty()) {
                        DrawMutedWrapped(TruncateForUi(command.summary, 180));
                    }
                }
            } else if (action.type == ProviderResultType::ProposedFileChange && action.hasFileChange) {
                DrawKeyValue("Path", TruncateForUi(action.fileChange.path, 160), Scaled(86.0f));
                if (!action.fileChange.changeType.empty()) {
                    DrawKeyValue("Type", action.fileChange.changeType, Scaled(86.0f));
                }
                if (!action.fileChange.sessionId.empty()) {
                    DrawKeyValue("Session", TruncateForUi(action.fileChange.sessionId, 120), Scaled(86.0f));
                }
                if (!action.fileChange.summary.empty()) {
                    DrawMutedWrapped(TruncateForUi(action.fileChange.summary, 220));
                }
                const std::string preview = BuildFileChangePreview(action.fileChange);
                DrawSectionTitle("Preview");
                ImGui::BeginChild("file_change_preview", ImVec2(0.0f, Scaled(170.0f)), true,
                                  ImGuiWindowFlags_HorizontalScrollbar);
                ImGui::TextUnformatted(preview.c_str());
                ImGui::EndChild();

                if (!action.diagnostics.empty()) {
                    if (ImGui::TreeNodeEx("Diagnostics")) {
                        for (const std::string& diagnostic : action.diagnostics) {
                            ImGui::BulletText("%s", TruncateForUi(diagnostic, 180).c_str());
                        }
                        ImGui::TreePop();
                    }
                }

                if (action.applied) {
                    if (!action.fileChange.appliedPath.empty()) {
                        DrawKeyValue("Applied", TruncateForUi(action.fileChange.appliedPath, 160), Scaled(86.0f));
                    }
                    ImGui::BeginDisabled(!state_.IsEditMode() || !action.fileChange.previousContentCaptured);
                    if (ImGui::Button("Revert")) {
                        RevertProposedFileChange(index);
                    }
                    ImGui::EndDisabled();
                } else if (action.canApprove && !action.rejected) {
                    const bool canApplyFile = !TrimWhitespace(action.fileChange.content).empty();
                    ImGui::BeginDisabled(!state_.IsEditMode() || !canApplyFile);
                    if (ImGui::Button("Apply")) {
                        ApplyProposedFileChange(index);
                    }
                    ImGui::EndDisabled();
                    ImGui::SameLine();
                    if (ImGui::Button("Reject")) {
                        RejectProposedAction(index);
                    }
                    if (!state_.IsEditMode()) {
                        DrawMutedWrapped("File changes are disabled during Play Mode.");
                    } else if (!canApplyFile) {
                        DrawMutedWrapped("Diff-only proposals can be previewed, but applying requires full replacement content.");
                    }
                }
            } else if (!action.diagnostics.empty()) {
                for (const std::string& diagnostic : action.diagnostics) {
                    ImGui::BulletText("%s", TruncateForUi(diagnostic, 180).c_str());
                }
            }
            ImGui::TreePop();
        }
        ImGui::PopID();
        ImGui::Spacing();
    }
}

void EditorApp::DrawProjectTreeNode(const ProjectTreeNode& node) {
    const std::string contextId = node.path.empty() ? node.name : node.path;
    if (!node.folder) {
        const std::string label = TruncateForUi(node.name, 64);
        ImGui::PushID(contextId.c_str());
        ImGui::BulletText("%s", label.c_str());
        if (label != node.name && ImGui::IsItemHovered()) {
            ImGui::SetTooltip("%s", node.name.c_str());
        }
        DrawProjectTreeNodeContextMenu(node);
        ImGui::PopID();
        return;
    }

    const std::string label = TruncateForUi(node.name, 64);
    ImGui::PushID(contextId.c_str());
    const bool open = ImGui::TreeNodeEx("node", ImGuiTreeNodeFlags_DefaultOpen, "%s", label.c_str());
    if (label != node.name && ImGui::IsItemHovered()) {
        ImGui::SetTooltip("%s", node.name.c_str());
    }
    DrawProjectTreeNodeContextMenu(node);
    if (open) {
        for (const ProjectTreeNode& child : node.children) {
            DrawProjectTreeNode(child);
        }
        ImGui::TreePop();
    }
    ImGui::PopID();
}

void EditorApp::DrawProjectTreeNodeContextMenu(const ProjectTreeNode& node) {
    if (!node.filesystemBacked || node.path.empty()) {
        return;
    }

    if (!ImGui::BeginPopupContextItem("project_tree_context")) {
        return;
    }

    const std::filesystem::path path = node.path;
    ImGui::TextUnformatted(TruncateForUi(node.name, 48).c_str());
    ImGui::Separator();

    ImGui::BeginDisabled(!state_.IsEditMode());
    if (node.folder && ImGui::MenuItem("New Folder")) {
        CreateFolderInProjectTree(path);
    }
    ImGui::EndDisabled();

    if (ImGui::MenuItem("Show In Explorer")) {
        std::string error;
        if (ShowPathInExplorer(path, &error)) {
            state_.AddActivity("project.tree", "Explorer", path.string());
        } else {
            state_.AddLog(LogLevel::Error, "Show In Explorer failed: " + error);
        }
    }
    if (ImGui::MenuItem("Copy Path")) {
        const std::string pathString = path.string();
        ImGui::SetClipboardText(pathString.c_str());
        state_.AddActivity("project.tree", "Copied", pathString);
    }
    if (ImGui::MenuItem("Copy Project Relative Path")) {
        const std::string pathString = RelativeProjectPathString(state_.ProjectRootPathString(), path);
        ImGui::SetClipboardText(pathString.c_str());
        state_.AddActivity("project.tree", "Copied", pathString);
    }
    if (ImGui::MenuItem(node.folder ? "Copy Folder Name" : "Copy File Name")) {
        const std::string name = path.filename().string().empty() ? node.name : path.filename().string();
        ImGui::SetClipboardText(name.c_str());
        state_.AddActivity("project.tree", "Copied", name);
    }
    if (ImGui::MenuItem("Refresh")) {
        state_.RefreshProjectTree();
        state_.AddActivity("project.tree", "Refreshed", state_.ProjectRootPathString());
    }

    ImGui::Separator();
    ImGui::BeginDisabled(!state_.IsEditMode());
    if (ImGui::MenuItem("Delete...")) {
        pendingProjectTreeDeletePath_ = path;
        pendingProjectTreeDeleteName_ = node.name;
        pendingProjectTreeDeleteIsFolder_ = node.folder;
        openProjectTreeDeleteConfirmation_ = true;
    }
    ImGui::EndDisabled();

    ImGui::EndPopup();
}

void EditorApp::DrawProjectTreeDeleteConfirmation() {
    if (openProjectTreeDeleteConfirmation_) {
        ImGui::OpenPopup("Delete Project Item");
        openProjectTreeDeleteConfirmation_ = false;
    }

    bool open = true;
    if (!ImGui::BeginPopupModal("Delete Project Item", &open, ImGuiWindowFlags_AlwaysAutoResize)) {
        return;
    }

    const std::string displayName = pendingProjectTreeDeleteName_.empty()
                                        ? pendingProjectTreeDeletePath_.filename().string()
                                        : pendingProjectTreeDeleteName_;
    ImGui::TextWrapped("Delete %s?", displayName.c_str());
    DrawMutedWrapped(pendingProjectTreeDeletePath_.string());
    if (pendingProjectTreeDeleteIsFolder_) {
        DrawMutedWrapped("This will delete the folder and everything inside it.");
    }

    ImGui::Separator();
    if (ImGui::Button("Cancel", ImVec2(Scaled(124.0f), 0.0f))) {
        ImGui::CloseCurrentPopup();
    }
    ImGui::SameLine();
    ImGui::PushStyleColor(ImGuiCol_Button, ImVec4(0.52f, 0.18f, 0.16f, 1.0f));
    ImGui::PushStyleColor(ImGuiCol_ButtonHovered, ImVec4(0.64f, 0.22f, 0.19f, 1.0f));
    ImGui::PushStyleColor(ImGuiCol_ButtonActive, ImVec4(0.44f, 0.12f, 0.11f, 1.0f));
    if (ImGui::Button("Delete", ImVec2(Scaled(124.0f), 0.0f))) {
        std::string error;
        if (DeleteProjectTreePath(pendingProjectTreeDeletePath_, pendingProjectTreeDeleteIsFolder_, &error)) {
            state_.AddActivity("project.tree.delete", "Deleted", pendingProjectTreeDeletePath_.string());
        } else {
            state_.AddLog(LogLevel::Error, "Project tree delete failed: " + error);
        }
        pendingProjectTreeDeletePath_.clear();
        pendingProjectTreeDeleteName_.clear();
        pendingProjectTreeDeleteIsFolder_ = false;
        ImGui::CloseCurrentPopup();
    }
    ImGui::PopStyleColor(3);

    ImGui::EndPopup();
}

bool EditorApp::DeleteProjectTreePath(const std::filesystem::path& path, bool folder, std::string* error) {
    if (path.empty()) {
        if (error != nullptr) {
            *error = "Path is empty.";
        }
        return false;
    }
    if (!state_.IsEditMode()) {
        if (error != nullptr) {
            *error = "Delete is disabled during Play Mode.";
        }
        return false;
    }

    bool sameAsProjectRoot = false;
    if (!IsPathInsideOrSame(state_.ProjectRootPathString(), path, &sameAsProjectRoot)) {
        if (error != nullptr) {
            *error = "Refusing to delete a path outside the current project.";
        }
        return false;
    }
    if (sameAsProjectRoot) {
        if (error != nullptr) {
            *error = "Refusing to delete the active project root.";
        }
        return false;
    }

    std::error_code filesystemError;
    if (!std::filesystem::exists(path, filesystemError)) {
        if (error != nullptr) {
            *error = "Path does not exist: " + path.string();
        }
        return false;
    }

    const bool selectionWasInsideDeletedPath =
        !projectExplorerSelectedPath_.empty() && IsPathInsideOrSame(path, projectExplorerSelectedPath_);

    if (folder) {
        if (!std::filesystem::is_directory(path, filesystemError)) {
            if (error != nullptr) {
                *error = "Expected folder but target is not a folder: " + path.string();
            }
            return false;
        }
        std::filesystem::remove_all(path, filesystemError);
    } else {
        std::filesystem::remove(path, filesystemError);
    }

    if (filesystemError) {
        if (error != nullptr) {
            *error = filesystemError.message();
        }
        return false;
    }

    if (selectionWasInsideDeletedPath) {
        projectExplorerSelectedPath_ = path.parent_path();
    }
    state_.RefreshProjectTree();
    return true;
}

bool EditorApp::StageExternalAssetFolderFromUi() {
    if (!state_.IsEditMode()) {
        state_.AddLog(LogLevel::Warning, "Asset staging is disabled during Play Mode.");
        return false;
    }

    std::filesystem::path sourceFolder;
    std::string error;
    if (!PickFolderWithDialog("Select external asset folder", state_.ProjectRootPathString(), &sourceFolder, &error)) {
        if (!error.empty()) {
            state_.AddLog(LogLevel::Error, "Asset staging picker failed: " + error);
        }
        return false;
    }

    const std::string projectName = SanitizePathSegment(sourceFolder.filename().string(), "ExternalAssetPreview");
    std::filesystem::path stagedProjectFile;
    std::string summary;
    if (!StageExternalAssetFolder(sourceFolder, projectName, &stagedProjectFile, &summary, &error)) {
        state_.AddLog(LogLevel::Error, "Asset staging failed: " + error);
        return false;
    }

    state_.AddActivity("asset.staging", "Complete", summary);
    state_.AddLog(LogLevel::Info, "Staged external assets: " + stagedProjectFile.string());
    return true;
}

bool EditorApp::StageExternalAssetFolder(const std::filesystem::path& sourceFolder,
                                         const std::string& tempProjectName,
                                         std::filesystem::path* stagedProjectFile,
                                         std::string* summary,
                                         std::string* error) {
    if (sourceFolder.empty()) {
        if (error != nullptr) {
            *error = "Source folder is empty.";
        }
        return false;
    }

    try {
        const std::filesystem::path sourcePath = std::filesystem::absolute(sourceFolder).lexically_normal();
        if (!std::filesystem::exists(sourcePath) || !std::filesystem::is_directory(sourcePath)) {
            if (error != nullptr) {
                *error = "Source folder does not exist: " + sourcePath.string();
            }
            return false;
        }

        const std::filesystem::path activeProjectRoot = std::filesystem::absolute(state_.ProjectRootPathString()).lexically_normal();
        const std::filesystem::path stagingRoot = activeProjectRoot / "Temp" / "AssetPreviews";
        const std::string projectName = SanitizePathSegment(tempProjectName, "ExternalAssetPreview");
        const std::string sourceName = SanitizePathSegment(sourcePath.filename().string(), "ExternalAssets");
        const std::filesystem::path previewRoot = stagingRoot / projectName;
        const std::filesystem::path assetRoot = previewRoot / "Assets";
        const std::filesystem::path externalRoot = assetRoot / "External";
        const std::filesystem::path stagedSourceRoot = externalRoot / sourceName;
        const std::filesystem::path sceneRoot = assetRoot / "Scenes";
        const std::filesystem::path previewScene = sceneRoot / "AssetPreview.scene.json";
        const std::filesystem::path projectFile = previewRoot / "AI Native Project.aineproject.json";
        const std::filesystem::path manifestPath = externalRoot / "import-manifest.json";

        std::filesystem::create_directories(stagingRoot);
        std::error_code removeError;
        std::filesystem::remove_all(previewRoot, removeError);
        if (removeError) {
            if (error != nullptr) {
                *error = "Could not clear previous preview project: " + removeError.message();
            }
            return false;
        }

        std::filesystem::create_directories(stagedSourceRoot);
        std::filesystem::create_directories(sceneRoot);
        std::filesystem::create_directories(assetRoot / "Materials");
        std::filesystem::create_directories(assetRoot / "Meshes");
        std::filesystem::create_directories(assetRoot / "Prefabs");
        std::filesystem::create_directories(assetRoot / "Scripts" / "Gameplay");
        std::filesystem::create_directories(previewRoot / "ProjectSettings");
        std::filesystem::create_directories(previewRoot / "Library");
        std::filesystem::create_directories(previewRoot / "Logs");
        std::filesystem::create_directories(previewRoot / "Saved");

        int assetCount = 0;
        int modelCount = 0;
        int animationCount = 0;
        std::vector<std::string> importedFiles;
        std::string firstModelName = "ExternalAssetPreview";

        for (const std::filesystem::directory_entry& entry :
             std::filesystem::recursive_directory_iterator(sourcePath)) {
            const std::filesystem::path relativePath = std::filesystem::relative(entry.path(), sourcePath);
            const std::filesystem::path targetPath = stagedSourceRoot / relativePath;
            if (entry.is_directory()) {
                std::filesystem::create_directories(targetPath);
                continue;
            }
            if (!entry.is_regular_file()) {
                continue;
            }

            std::filesystem::create_directories(targetPath.parent_path());
            std::filesystem::copy_file(entry.path(), targetPath, std::filesystem::copy_options::overwrite_existing);

            if (IsAssetImportCandidate(entry.path())) {
                ++assetCount;
                importedFiles.push_back((std::filesystem::path("Assets") / "External" / sourceName / relativePath).generic_string());
            }
            if (IsModelImportCandidate(entry.path())) {
                ++modelCount;
                if (firstModelName == "ExternalAssetPreview") {
                    firstModelName = entry.path().stem().string();
                }
            }
            if (IsAnimationImportCandidate(entry.path())) {
                ++animationCount;
            }
        }

        json manifest = {
            {"format", "aine.externalAssetImport"},
            {"version", 1},
            {"sourceFolder", sourcePath.string()},
            {"sourcePreserved", true},
            {"stagedProject", previewRoot.string()},
            {"stagedAssetRoot", stagedSourceRoot.string()},
            {"assetCount", assetCount},
            {"modelCount", modelCount},
            {"animationCount", animationCount},
            {"importedFiles", importedFiles},
        };
        std::ofstream manifestOutput(manifestPath);
        manifestOutput << manifest.dump(2) << '\n';

        json previewSceneJson = {
            {"format", "aine.scene"},
            {"version", 1},
            {"name", "AssetPreview.scene.json"},
            {"entities",
             json::array({
                 {
                     {"id", 1},
                     {"parentId", 0},
                     {"name", "Preview Camera"},
                     {"active", true},
                     {"tag", "MainCamera"},
                     {"layer", "Default"},
                     {"isStatic", false},
                     {"transform",
                      {{"position", Float3ToJson({0.0f, 2.5f, 6.0f})},
                       {"rotation", Float3ToJson({-18.0f, 0.0f, 0.0f})},
                       {"scale", Float3ToJson({1.0f, 1.0f, 1.0f})}}},
                     {"components", ComponentsForPreviewToJson({MakeTransformComponent(), MakeCameraComponent()})},
                 },
                 {
                     {"id", 2},
                     {"parentId", 0},
                     {"name", "Preview Key Light"},
                     {"active", true},
                     {"tag", "Untagged"},
                     {"layer", "Default"},
                     {"isStatic", false},
                     {"transform",
                      {{"position", Float3ToJson({0.0f, 4.0f, 2.0f})},
                       {"rotation", Float3ToJson({45.0f, -35.0f, 0.0f})},
                       {"scale", Float3ToJson({1.0f, 1.0f, 1.0f})}}},
                     {"components", ComponentsForPreviewToJson({MakeTransformComponent(), MakeLightComponent("Directional")})},
                 },
                 {
                     {"id", 3},
                     {"parentId", 0},
                     {"name", "Imported Asset Preview"},
                     {"active", true},
                     {"tag", "Untagged"},
                     {"layer", "Default"},
                     {"isStatic", false},
                     {"transform",
                      {{"position", Float3ToJson({0.0f, 0.75f, 0.0f})},
                       {"rotation", Float3ToJson({0.0f, 0.0f, 0.0f})},
                       {"scale", Float3ToJson({1.25f, 1.25f, 1.25f})}}},
                     {"components",
                      ComponentsForPreviewToJson({MakeTransformComponent(),
                                                  MakeMeshPlaceholderComponent(firstModelName, "PrototypeBlue"),
                                                  MakeSpinRuntimeComponent(35.0f)})},
                 },
             })},
        };
        std::ofstream sceneOutput(previewScene);
        sceneOutput << previewSceneJson.dump(2) << '\n';

        const std::string activeScene = std::filesystem::relative(previewScene, previewRoot).generic_string();
        json project = {
            {"format", "aine.project"},
            {"version", 1},
            {"projectName", projectName},
            {"engineVersion", "0.1.0"},
            {"assetRoot", "Assets"},
            {"sceneRoot", "Assets/Scenes"},
            {"gameSaveRoot", "Saved"},
            {"directories",
             {
                 {"assetRoot", "Assets"},
                 {"sceneRoot", "Assets/Scenes"},
                 {"saveDataRoot", "Saved"},
             }},
            {"activeScene", activeScene},
            {"scenes", json::array({activeScene})},
            {"enabledPlugins", json::array()},
        };
        std::ofstream projectOutput(projectFile);
        projectOutput << project.dump(2) << '\n';

        state_.RefreshProjectTree();
        if (stagedProjectFile != nullptr) {
            *stagedProjectFile = projectFile;
        }
        if (summary != nullptr) {
            std::ostringstream stream;
            stream << "Staged " << assetCount << " importable assets from " << sourcePath.filename().string()
                   << " into " << previewRoot.string();
            *summary = stream.str();
        }
        return true;
    } catch (const std::exception& exception) {
        if (error != nullptr) {
            *error = exception.what();
        }
        return false;
    }
}

void EditorApp::CreateFolderInProjectTree(const std::filesystem::path& parentPath) {
    if (!state_.IsEditMode()) {
        state_.AddLog(LogLevel::Warning, "New folder is disabled during Play Mode.");
        return;
    }

    if (!IsPathInsideOrSame(state_.ProjectRootPathString(), parentPath)) {
        state_.AddLog(LogLevel::Error, "New folder failed: parent is outside the current project.");
        return;
    }

    std::error_code filesystemError;
    if (!std::filesystem::is_directory(parentPath, filesystemError)) {
        state_.AddLog(LogLevel::Error, "New folder failed: parent is not a folder: " + parentPath.string());
        return;
    }

    std::filesystem::path folderPath = parentPath / "New Folder";
    for (int index = 2; std::filesystem::exists(folderPath, filesystemError) && index < 1000; ++index) {
        folderPath = parentPath / ("New Folder " + std::to_string(index));
    }

    std::filesystem::create_directories(folderPath, filesystemError);
    if (filesystemError) {
        state_.AddLog(LogLevel::Error, "New folder failed: " + filesystemError.message());
        return;
    }

    state_.RefreshProjectTree();
    projectExplorerSelectedPath_ = folderPath;
    state_.AddActivity("project.tree.newFolder", "Created", folderPath.string());
}

std::filesystem::path EditorApp::AgentMemoryDirectoryPath() const {
    return std::filesystem::current_path() / "docs" / "agent-memory";
}

std::filesystem::path EditorApp::AgentRunLogPath() const {
    return AgentMemoryDirectoryPath() / "run_log.jsonl";
}

std::filesystem::path EditorApp::AgentVisualsDirectoryPath() const {
    return AgentMemoryDirectoryPath() / "visuals";
}

std::string EditorApp::GenerateAgentRunId() const {
    std::string stamp = CurrentTimestampUtc();
    std::replace(stamp.begin(), stamp.end(), ':', '-');
    const auto ticks = std::chrono::steady_clock::now().time_since_epoch().count();
    std::ostringstream stream;
    stream << "agent-run-" << stamp << "-" << ticks;
    return stream.str();
}

std::string EditorApp::AgentVisualCaptureSummary(const std::vector<AgentVisualCapture>& captures) const {
    if (captures.empty()) {
        return "- none\n";
    }

    std::ostringstream stream;
    for (const AgentVisualCapture& capture : captures) {
        stream << "- " << capture.view << (capture.recordingFrame ? " recording frame" : " screenshot")
               << ": " << capture.path << " (" << capture.width << "x" << capture.height << ")";
        if (capture.frameIndex > 0) {
            stream << " frame=" << capture.frameIndex;
        }
        if (!capture.reason.empty()) {
            stream << " reason=" << capture.reason;
        }
        stream << "\n";
    }
    return stream.str();
}

std::string EditorApp::BuildAgentImplementationBrief(const std::string& userRequest) const {
    const std::string request = TrimWhitespace(userRequest);
    const std::string normalizedRequest = ToLower(request);
    const bool improvementReviewTask = PromptLooksLikeEditorImprovementReview(request);
    const bool buildLaunchTask = PromptLooksLikeBuildLaunchIntent(request);
    const bool conversationTask = !improvementReviewTask && !buildLaunchTask && (PromptLooksLikeConversationTask(request) ||
                                                       PromptLooksTooBroadForAutoImplementation(request));
    const bool sceneCommandTask = PromptLooksLikeDeterministicSceneEdit(request);
    const std::string taskMode = improvementReviewTask ? "Editor Improvement Review"
                                 : conversationTask ? "Conversation"
                                 : sceneCommandTask ? "Scene Command"
                                                    : "Repository Implementation";
    const ProjectContextSnapshot context =
        orchestrator_.CaptureProjectContext(state_, hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
    const SceneValidationResult validation = state_.ValidateScene();

    std::string inferredIntent = "Implement the requested editor change end to end.";
    if (improvementReviewTask) {
        inferredIntent = "Inspect the visible editor workflow and repository context, then suggest prioritized, actionable improvements without editing files.";
    } else if (conversationTask) {
        inferredIntent = "Answer the user in a real conversation using the recent chat, run status, and editor context.";
    } else if (sceneCommandTask) {
        inferredIntent = "Apply or propose a deterministic scene/project command through the editor command path.";
    } else if (buildLaunchTask) {
        inferredIntent = "Start a concrete, narrowly scoped repository implementation task using the current project context and backlog.";
    } else if (normalizedRequest.find("fix") != std::string::npos || normalizedRequest.find("bug") != std::string::npos ||
        normalizedRequest.find("broken") != std::string::npos || normalizedRequest.find("regression") != std::string::npos) {
        inferredIntent = "Diagnose and repair an existing behavior while preserving unrelated editor systems.";
    } else if (normalizedRequest.find("add") != std::string::npos || normalizedRequest.find("implement") != std::string::npos ||
               normalizedRequest.find("create") != std::string::npos || normalizedRequest.find("build") != std::string::npos) {
        inferredIntent = "Add a production-shaped feature using the existing editor architecture and UI patterns.";
    } else if (normalizedRequest.find("test") != std::string::npos || normalizedRequest.find("smoke") != std::string::npos ||
               normalizedRequest.find("verify") != std::string::npos) {
        inferredIntent = "Strengthen verification for the existing behavior and report the proof boundary clearly.";
    }

    std::vector<std::string> likelyFiles;
    if (conversationTask) {
        AddUniqueLine(likelyFiles, "Recent conversation and Agent Activity - answer follow-ups using visible run state and chat history");
    } else {
        AddUniqueLine(likelyFiles, "src/EditorApp.h / src/EditorApp.cpp - docked panels, ImGui controls, async agent lifecycle, smoke hooks");
    }
    if (improvementReviewTask) {
        AddUniqueLine(likelyFiles, "Current scene, selected entity, logs, and Agent Activity - identify workflow friction visible to the user");
        AddUniqueLine(likelyFiles, "docs/planning and docs/architecture - compare the current editor against planned product direction");
    }
    if (normalizedRequest.find("agent") != std::string::npos || normalizedRequest.find("codex") != std::string::npos ||
        normalizedRequest.find("backend") != std::string::npos || normalizedRequest.find("prompt") != std::string::npos ||
        normalizedRequest.find("composer") != std::string::npos) {
        AddUniqueLine(likelyFiles, "src/AgentOrchestrator.h / src/AgentOrchestrator.cpp - provider health, prompt wrapping, backend execution");
        AddUniqueLine(likelyFiles, "src/ProviderResult.h / src/ProviderResult.cpp - normalized provider result parsing");
    }
    if (normalizedRequest.find("scene") != std::string::npos || normalizedRequest.find("entity") != std::string::npos ||
        normalizedRequest.find("state") != std::string::npos || normalizedRequest.find("project") != std::string::npos) {
        AddUniqueLine(likelyFiles, "src/EditorState.h / src/EditorState.cpp - project paths, scene state, logs, activity, validation");
        AddUniqueLine(likelyFiles, "src/ToolGateway.h / src/ToolGateway.cpp - structured scene/project command batches");
    }
    if (normalizedRequest.find("test") != std::string::npos || normalizedRequest.find("smoke") != std::string::npos ||
        normalizedRequest.find("build") != std::string::npos || normalizedRequest.find("verify") != std::string::npos) {
        AddUniqueLine(likelyFiles, "scripts/run-smoke-tests.ps1 - automated smoke coverage");
        AddUniqueLine(likelyFiles, "CMakeLists.txt / CMakePresets.json - build integration");
    }
    if (!conversationTask) {
        AddUniqueLine(likelyFiles, "docs/agent-memory/run_log.jsonl - generated prompts and agent run summaries");
        AddUniqueLine(likelyFiles, "docs/ai and docs/planning - local product, architecture, and backlog context");
    }

    std::vector<std::string> recentActivities;
    const std::vector<AgentActivity>& activities = state_.AgentActivities();
    const size_t activityStart = activities.size() > 10 ? activities.size() - 10 : 0;
    for (size_t index = activityStart; index < activities.size(); ++index) {
        const AgentActivity& activity = activities[index];
        recentActivities.push_back(activity.label + " [" + activity.status + "]: " + activity.detail);
    }

    std::ostringstream docsContext;
    const std::filesystem::path docsRoot = std::filesystem::current_path() / "docs";
    std::vector<std::filesystem::path> docCandidates{
        docsRoot / "agent-memory" / "README.md",
        docsRoot / "agent-memory" / "memory.md",
        docsRoot / "planning" / "implementation-backlog.md",
        docsRoot / "planning" / "risks-and-license-notes.md",
        docsRoot / "ai" / "agent-backends-and-local-assist.md",
        docsRoot / "architecture" / "system-architecture.md",
    };

    const std::filesystem::path agentMemoryRoot = AgentMemoryDirectoryPath();
    const std::filesystem::path runLogPath = AgentRunLogPath();
    if (std::filesystem::exists(runLogPath)) {
        docsContext << "### " << runLogPath.lexically_relative(std::filesystem::current_path()).generic_string() << "\n";
        docsContext << ReadRunLogSummaryPreview(runLogPath) << "\n";
    }
    if (std::filesystem::exists(agentMemoryRoot)) {
        std::error_code error;
        int extraMemoryFiles = 0;
        for (const std::filesystem::directory_entry& entry : std::filesystem::directory_iterator(agentMemoryRoot, error)) {
            if (error || extraMemoryFiles >= 4 || !entry.is_regular_file()) {
                continue;
            }
            const std::string extension = ToLower(entry.path().extension().string());
            if (entry.path().filename() == "run_log.jsonl") {
                continue;
            }
            if (extension == ".md" || extension == ".txt" || extension == ".jsonl" || extension == ".json") {
                docCandidates.push_back(entry.path());
                ++extraMemoryFiles;
            }
        }
    }

    std::vector<std::string> seenDocs;
    for (const std::filesystem::path& docPath : docCandidates) {
        std::error_code error;
        const std::filesystem::path absolutePath = std::filesystem::absolute(docPath, error);
        const std::string key = ToLower(error ? docPath.string() : absolutePath.string());
        if (std::find(seenDocs.begin(), seenDocs.end(), key) != seenDocs.end()) {
            continue;
        }
        seenDocs.push_back(key);
        if (!std::filesystem::exists(docPath, error) || error || !std::filesystem::is_regular_file(docPath, error)) {
            continue;
        }
        docsContext << "### " << docPath.lexically_relative(std::filesystem::current_path()).generic_string() << "\n";
        docsContext << ReadTextFilePreview(docPath, 1600) << "\n\n";
    }
    if (docsContext.str().empty()) {
        docsContext << "- No docs/agent-memory files or planning docs were available.\n";
    }

    std::ostringstream validationText;
    validationText << (validation.ok ? "Scene validation currently passes." : "Scene validation currently has issues.") << "\n";
    for (const std::string& diagnostic : validation.diagnostics) {
        validationText << "- " << diagnostic << "\n";
    }

    std::ostringstream brief;
    brief << "# Codex Implementation Brief\n\n";
    brief << "You are working inside AI Native Editor. Use the task mode to choose the lightest correct response path: "
             "conversation, deterministic scene command, or repository implementation.\n\n";
    brief << "## Task Mode\n";
    brief << taskMode << "\n\n";
    brief << "## User Goal\n";
    brief << (request.empty() ? "No short request was provided." : request) << "\n\n";
    brief << "## Inferred Intent\n";
    brief << inferredIntent << "\n\n";
    brief << "## Relevant Project Context\n";
    brief << "- Workspace root: " << std::filesystem::current_path().string() << "\n";
    brief << "- Project root: " << state_.ProjectRootPathString() << "\n";
    brief << "- Project file: " << state_.ProjectFilePathString() << "\n";
    brief << "- Scene file: " << state_.SceneFilePathString() << "\n";
    brief << "- Game save folder: " << state_.GameSaveRootPathString() << "\n";
    brief << "- Editor state: " << state_.GetProjectStateSummary() << "\n";
    brief << "- Agent status: " << state_.AgentStatus() << "\n";
    brief << "- Last transaction: " << state_.LastTransactionId() << "\n\n";
    brief << "### Scene State\n";
    brief << context.ToCompactText() << "\n";
    brief << "### Scene Validation\n";
    brief << validationText.str() << "\n";
    brief << "### Recent Agent Activity\n";
    brief << JoinLines(recentActivities);
    brief << "\n### Latest Visual Context\n";
    if (agentVisualCaptures_.empty()) {
        brief << "- none captured yet\n";
    } else {
        const size_t visualStart = agentVisualCaptures_.size() > 8 ? agentVisualCaptures_.size() - 8 : 0;
        std::vector<AgentVisualCapture> recentCaptures(agentVisualCaptures_.begin() +
                                                           static_cast<std::ptrdiff_t>(visualStart),
                                                       agentVisualCaptures_.end());
        brief << AgentVisualCaptureSummary(recentCaptures);
    }
    brief << "\n### Local Docs And Agent Memory\n";
    brief << docsContext.str();
    brief << "## Likely Files And Systems\n";
    brief << JoinLines(likelyFiles);
    brief << "\n## Implementation Requirements\n";
    if (improvementReviewTask) {
        brief << "- Review the editor as a product surface using the current scene, selected entity, recent logs, agent status, and local planning docs.\n";
        brief << "- Return a prioritized improvement list with severity, user impact, implementation scope, and the first concrete next step for each item.\n";
        brief << "- Include at least one quick-win UI/workflow improvement, one reliability/diagnostics improvement, and one longer-term product improvement when supported by the context.\n";
        brief << "- Do not edit repository files or mutate scene state for this review unless the user explicitly asks to implement a selected item.\n\n";
    } else if (conversationTask) {
        brief << "- Answer the current user prompt directly and conversationally.\n";
        brief << "- Use Recent conversation and Agent Activity to explain what happened and what the user can do next.\n";
        brief << "- Do not edit files, run builds, or propose command batches unless the user asks for implementation.\n";
        brief << "- Keep the answer concise, concrete, and grounded in the visible editor state.\n\n";
    } else if (sceneCommandTask) {
        brief << "- Prefer deterministic ToolGateway scene/project commands over repository source edits.\n";
        brief << "- If command execution is supported locally, apply the smallest command batch that satisfies the request.\n";
        brief << "- If an external provider must propose actions, return one valid ToolGateway-compatible command batch.\n";
        brief << "- Validate/save only when the command path normally requires it; do not run CMake for scene-only edits.\n\n";
    } else {
        brief << "- Convert the short user request into working editor behavior, not just a mock or static note.\n";
        brief << "- Follow existing ownership: UI in EditorApp, persistent editor/project state in EditorState, provider execution in AgentOrchestrator, structured scene commands in ToolGateway.\n";
        brief << "- Keep the editor responsive while provider or build work runs; do not block the render loop with long external work.\n";
        brief << "- Make generated text editable before it is sent to an agent when the task involves prompt composition.\n";
        brief << "- Store generated prompts and run summaries as JSONL under docs/agent-memory/run_log.jsonl when agent-run artifacts are created.\n";
        brief << "- Surface failures in Agent Activity and Console with enough detail to diagnose launch, provider, schema, or verification problems.\n\n";
    }
    brief << "## Constraints\n";
    brief << "- Keep the change narrow and additive unless the request explicitly requires removing behavior.\n";
    brief << "- Preserve backend health checks, provider fallback behavior, command approval gates, and existing smoke-test semantics.\n";
    brief << "- Do not require users to know prompt-engineering terms to use the feature.\n";
    brief << "- Do not store API keys or credentials in project files or agent memory logs.\n";
    brief << "- Treat compile/build success as separate from runtime or UI smoke proof; report exactly what was verified.\n\n";
    brief << "## Acceptance Criteria\n";
    if (improvementReviewTask) {
        brief << "- The response gives a ranked list of concrete editor improvements grounded in the visible project/scene/log context.\n";
        brief << "- Each recommendation names the affected area, why it matters to the user, and a scoped implementation path.\n";
        brief << "- The response separates quick wins from larger work and avoids claiming runtime verification that was not performed.\n";
        brief << "- No files or scene data are changed during a suggestion-only review.\n\n";
    } else if (conversationTask) {
        brief << "- The response answers the user's actual confusion and references relevant recent context.\n";
        brief << "- The response does not pretend that a backend connection means a completed run.\n";
        brief << "- The response gives a concrete next step when the editor state is failed, empty, or waiting.\n\n";
    } else if (sceneCommandTask) {
        brief << "- The requested scene/project change is represented as deterministic editor commands.\n";
        brief << "- Changed entities/files and validation diagnostics are reported clearly.\n";
        brief << "- The command path avoids unnecessary external provider work for simple scene edits.\n\n";
    } else {
        brief << "- The requested feature is reachable from the editor UI and works with the current project/scene context.\n";
        brief << "- The generated or agent-facing prompt includes user goal, inferred intent, relevant project context, likely files/systems, implementation requirements, constraints, acceptance criteria, required verification, and final report format.\n";
        brief << "- Running through Codex or another provider uses the improved/generated prompt, not the raw short request.\n";
        brief << "- Agent work remains asynchronous for external backends and the UI remains usable while a run is active.\n";
        brief << "- docs/agent-memory/run_log.jsonl receives JSONL entries for generated prompts and completed run summaries.\n";
        brief << "- Existing chat, provider health, proposed actions, project save/load, and scene smoke behavior continue to pass.\n\n";
    }
    brief << "## Required Build And Test Verification\n";
    if (improvementReviewTask) {
        brief << "1. No build is required for a suggestion-only review.\n";
        brief << "2. If you inspect files or run commands, report exactly what was checked.\n";
        brief << "3. If you identify implementation follow-ups, list the smallest safe verification gate for each.\n\n";
    } else if (conversationTask) {
        brief << "1. No build is required for a pure conversational answer.\n";
        brief << "2. If you inspect files or run commands, report exactly what was checked.\n\n";
    } else if (sceneCommandTask) {
        brief << "1. Run or cite the local command path that applied/proposed the scene change.\n";
        brief << "2. Confirm scene validation and changed entities/files.\n";
        brief << "3. Run CMake only if repository source files are changed.\n\n";
    } else {
        brief << "1. Run the smallest build/test gate that covers the changed source.\n";
        brief << "2. Prefer cmake --build on the active build directory when already configured.\n";
        brief << "3. Run focused smoke coverage for provider routing, prompt generation, or UI behavior when touched.\n";
        brief << "4. Use the full scripts/run-smoke-tests.ps1 suite only when the change has broad cross-system risk.\n\n";
    }
    brief << "## Expected Final Report Format\n";
    brief << "- Summary: concise result or answer.\n";
    brief << "- Files changed: important files and why they changed, if any.\n";
    brief << "- Verification: exact commands run and pass/fail result, if any.\n";
    brief << "- Notes: fallback, limitation, or proof boundary that remains.\n";
    return brief.str();
}

std::string EditorApp::BuildSplitAgentBrief(const std::string& userRequest) const {
    const std::string baseBrief = BuildAgentImplementationBrief(userRequest);
    const std::string request = TrimWhitespace(userRequest).empty() ? TrimWhitespace(composerPromptInput_.data())
                                                                    : TrimWhitespace(userRequest);

    std::ostringstream brief;
    brief << "# Multi-Agent Codex Implementation Brief\n\n";
    brief << "Coordinator goal: " << (request.empty() ? "Implement the composed editor task." : request) << "\n\n";
    brief << "Use the shared context and acceptance criteria below. Each agent should keep changes scoped, report files touched, "
             "and avoid overwriting another agent's work.\n\n";
    brief << "## Agent 1 - Context And UI Owner\n";
    brief << "- Inspect EditorApp and existing dock/panel patterns.\n";
    brief << "- Implement the user-facing controls and editable state.\n";
    brief << "- Report UI state, disabled states, and how the feature is reached.\n\n";
    brief << "## Agent 2 - Backend And Persistence Owner\n";
    brief << "- Inspect AgentOrchestrator, EditorState, ToolGateway, and provider result flow.\n";
    brief << "- Wire backend execution so agent runs receive the generated prompt.\n";
    brief << "- Persist generated prompts and run summaries to docs/agent-memory/run_log.jsonl.\n\n";
    brief << "## Agent 3 - Verification Owner\n";
    brief << "- Add or update smoke coverage for the new behavior.\n";
    brief << "- Run the required CMake build and smoke-test script.\n";
    brief << "- Report proof boundaries separately from compile success.\n\n";
    brief << "## Merge Contract\n";
    brief << "- Resolve conflicts by preserving existing editor behavior and the narrowest working implementation.\n";
    brief << "- Final response must merge all agent reports into one concise summary with exact verification commands.\n\n";
    brief << "## Shared Brief\n\n";
    brief << baseBrief;
    return brief.str();
}

bool EditorApp::AppendAgentRunLogEntry(const std::string& eventType, const std::string& runId,
                                       const std::string& userRequest, const std::string& prompt,
                                       const std::string& summary, const AgentOrchestratorResult* result) {
    try {
        const std::filesystem::path logPath = AgentRunLogPath();
        std::filesystem::create_directories(logPath.parent_path());

        const bool keepFullPrompt = eventType == "prompt_generated" || eventType == "prompt_split" ||
                                    eventType == "agent_run_saved";
        json entry = {
            {"timestamp_utc", CurrentTimestampUtc()},
            {"event", eventType},
            {"run_id", runId},
            {"project_root", state_.ProjectRootPathString()},
            {"project_file", state_.ProjectFilePathString()},
            {"scene_file", state_.SceneFilePathString()},
            {"game_save_folder", state_.GameSaveRootPathString()},
            {"user_request", userRequest},
            {"prompt_preview", TruncateForUi(prompt, 240)},
            {"prompt_char_count", prompt.size()},
            {"summary", summary},
        };
        if (keepFullPrompt) {
            entry["prompt"] = prompt;
        }

        const Entity* selected = state_.FindEntity(state_.SelectedEntityId());
        entry["selected_entity"] = selected == nullptr ? "none" : selected->name;
        entry["agent_status"] = state_.AgentStatus();
        entry["last_transaction_id"] = state_.LastTransactionId();
        if (!agentVisualCaptures_.empty()) {
            json visualCaptures = json::array();
            const size_t visualStart = agentVisualCaptures_.size() > 8 ? agentVisualCaptures_.size() - 8 : 0;
            for (size_t index = visualStart; index < agentVisualCaptures_.size(); ++index) {
                const AgentVisualCapture& capture = agentVisualCaptures_[index];
                visualCaptures.push_back(json{{"view", capture.view},
                                              {"path", capture.path},
                                              {"timestamp_utc", capture.timestampUtc},
                                              {"reason", capture.reason},
                                              {"width", capture.width},
                                              {"height", capture.height},
                                              {"frame_index", capture.frameIndex},
                                              {"recording_frame", capture.recordingFrame}});
            }
            entry["visual_captures"] = visualCaptures;
        }

        if (result != nullptr) {
            json resultJson = {
                {"backend", AgentOrchestrator::BackendId(result->backend)},
                {"backend_label", AgentOrchestrator::BackendLabel(result->backend)},
                {"ok", result->ok},
                {"used_fallback", result->usedFallback},
                {"has_gateway_result", result->hasGatewayResult},
                {"has_normalized_result", result->hasNormalizedResult},
                {"exit_code", result->exitCode},
                {"diagnostics", result->diagnostics},
                {"stdout_char_count", result->stdoutText.size()},
                {"stderr_char_count", result->stderrText.size()},
            };
            if (result->hasGatewayResult) {
                resultJson["gateway_transaction_id"] = result->gatewayResult.batch.transactionId;
                resultJson["gateway_batch_name"] = result->gatewayResult.batch.name;
                resultJson["gateway_applied"] = result->gatewayResult.batch.applied;
                resultJson["gateway_ok"] = result->gatewayResult.batch.ok;
                resultJson["changed_entities"] = result->gatewayResult.batch.changedEntities;
                resultJson["changed_files"] = result->gatewayResult.batch.changedFiles;
            }
            if (result->hasNormalizedResult) {
                resultJson["normalized_result_type"] = ProviderResultNormalizer::TypeId(result->normalizedResult.type);
                resultJson["normalized_title"] = result->normalizedResult.title;
            }
            entry["result"] = resultJson;
        }

        std::ofstream output(logPath, std::ios::app | std::ios::binary);
        if (!output) {
            state_.AddLog(LogLevel::Error, "Agent memory log failed to open: " + logPath.string());
            return false;
        }
        output << entry.dump() << '\n';
        if (!output.good()) {
            state_.AddLog(LogLevel::Error, "Agent memory log write failed: " + logPath.string());
            return false;
        }

        lastComposerLogPath_ = logPath.string();
        if (eventType == "run_completed") {
            ++composerCompletedRunCount_;
        } else if (eventType == "prompt_generated" || eventType == "prompt_split" || eventType == "agent_run_saved") {
            ++composerSavedPromptCount_;
        }
        state_.AddActivity("Agent memory", "Saved", eventType + " -> " + logPath.string());
        return true;
    } catch (const std::exception& exception) {
        state_.AddLog(LogLevel::Error, std::string("Agent memory log failed: ") + exception.what());
        return false;
    }
}

void EditorApp::ImproveComposerPrompt() {
    const std::string userRequest = TrimWhitespace(composerRequestInput_.data());
    if (userRequest.empty()) {
        composerStatus_ = "Add a request before improving the prompt.";
        return;
    }

    composerRunId_ = GenerateAgentRunId();
    const std::string prompt = BuildAgentImplementationBrief(userRequest);
    CopyStringToBuffer(composerPromptInput_, prompt);
    const bool saved = AppendAgentRunLogEntry("prompt_generated", composerRunId_, userRequest, prompt,
                                              "Generated implementation brief from short request.");
    composerStatus_ = saved ? "Improved prompt generated and saved to agent memory."
                            : "Improved prompt generated, but agent memory logging failed.";
}

void EditorApp::SplitComposerPromptIntoAgents() {
    const std::string userRequest = TrimWhitespace(composerRequestInput_.data());
    const std::string splitSource = userRequest.empty() ? TrimWhitespace(composerPromptInput_.data()) : userRequest;
    if (splitSource.empty()) {
        composerStatus_ = "Add a request or generated brief before splitting.";
        return;
    }

    composerRunId_ = GenerateAgentRunId();
    const std::string prompt = BuildSplitAgentBrief(splitSource);
    CopyStringToBuffer(composerPromptInput_, prompt);
    const bool saved = AppendAgentRunLogEntry("prompt_split", composerRunId_, splitSource, prompt,
                                              "Generated multi-agent implementation brief.");
    composerStatus_ = saved ? "Split prompt generated and saved to agent memory."
                            : "Split prompt generated, but agent memory logging failed.";
}

bool EditorApp::SaveComposerPromptAsAgentRun(const std::string& eventType) {
    const std::string prompt = TrimWhitespace(composerPromptInput_.data());
    if (prompt.empty()) {
        composerStatus_ = "Nothing to save.";
        return false;
    }
    if (composerRunId_.empty()) {
        composerRunId_ = GenerateAgentRunId();
    }

    const std::string userRequest = TrimWhitespace(composerRequestInput_.data());
    const bool saved = AppendAgentRunLogEntry(eventType, composerRunId_, userRequest, prompt,
                                              "Saved editable generated prompt as an agent run artifact.");
    composerStatus_ = saved ? "Saved generated prompt to agent memory." : "Agent memory save failed.";
    return saved;
}

void EditorApp::RecordAgentRunSummary(const std::string& runId, const std::string& userRequest,
                                      const std::string& prompt, const AgentOrchestratorResult& result) {
    std::ostringstream summary;
    summary << AgentOrchestrator::BackendLabel(result.backend) << " finished with "
            << (result.ok ? "ok" : "failure");
    if (result.usedFallback) {
        summary << " after fallback";
    }
    if (result.hasGatewayResult) {
        summary << "; transaction=" << result.gatewayResult.batch.transactionId
                << "; applied=" << (result.gatewayResult.batch.applied ? "true" : "false");
    }
    if (!result.diagnostics.empty()) {
        summary << "; diagnostic=" << result.diagnostics.front();
    }
    AppendAgentRunLogEntry("run_completed", runId.empty() ? GenerateAgentRunId() : runId, userRequest, prompt,
                           summary.str(), &result);
}

void EditorApp::RunComposerPromptWithCodex() {
    if (!EnsureEditModeForAction("Run generated prompt with Codex")) {
        return;
    }

    std::string prompt = TrimWhitespace(composerPromptInput_.data());
    if (prompt.empty() && !TrimWhitespace(composerRequestInput_.data()).empty()) {
        ImproveComposerPrompt();
        prompt = TrimWhitespace(composerPromptInput_.data());
    }
    if (prompt.empty()) {
        composerStatus_ = "Generate or enter a prompt before running Codex.";
        return;
    }
    if (composerRunId_.empty()) {
        composerRunId_ = GenerateAgentRunId();
    }

    selectedBackend_ = AgentBackend::CodexCli;
    if (SubmitAgentPrompt(prompt, AgentBackend::CodexCli, true)) {
        composerStatus_ = "Sent generated prompt to Codex.";
    }
}

std::string EditorApp::ActiveAgentPromptForSend() const {
    const std::string requestPrompt = TrimWhitespace(chatInput_.data());
    const std::string generatedBrief = TrimWhitespace(composerPromptInput_.data());
    const std::string briefRequest = TrimWhitespace(composerRequestInput_.data());
    if (!generatedBrief.empty() && !briefRequest.empty() && PromptTextMatchesUserRequest(requestPrompt, briefRequest)) {
        return generatedBrief;
    }
    return requestPrompt;
}

void EditorApp::ImproveAgentPromptDraft() {
    const std::string request = TrimWhitespace(chatInput_.data());
    if (request.empty()) {
        agentSurfaceStatus_ = "Add a prompt before improving it.";
        return;
    }

    const std::string normalizedRequest = ToLower(request);
    std::ostringstream improved;
    if (PromptLooksLikeConversationTask(request)) {
        improved << "Please diagnose this in AI Native Editor before changing anything:\n\n";
        improved << request << "\n\n";
        improved << "Use the current scene, selected entity, recent logs, and agent run history to explain the likely cause. "
                    "If a code or scene change is needed, propose the smallest scoped next step and the exact verification gate. "
                    "Do not add unrelated scene/entity edits.";
    } else {
        improved << "Please implement this in AI Native Editor:\n\n";
        improved << request << "\n\n";
        improved << "Keep the change scoped, preserve existing backend/orchestrator behavior, make user-facing status clear, "
                    "and verify the result with the relevant build or smoke tests.";

        const std::vector<std::string> suggestions = orchestrator_.PromptSuggestions(request, state_);
        for (const std::string& suggestion : suggestions) {
            const bool genericSelectedEntityRename =
                suggestion.rfind("rename selected entity", 0) == 0 &&
                normalizedRequest.find("rename") == std::string::npos &&
                normalizedRequest.find("selected") == std::string::npos &&
                normalizedRequest.find("entity") == std::string::npos;
            if (!genericSelectedEntityRename) {
                improved << "\n\nHelpful concrete target: " << suggestion;
                break;
            }
        }
    }

    CopyStringToBuffer(chatInput_, improved.str());
    std::fill(composerPromptInput_.begin(), composerPromptInput_.end(), '\0');
    std::fill(composerRequestInput_.begin(), composerRequestInput_.end(), '\0');
    composerRunId_.clear();
    composerStatus_.clear();
    agentSurfaceStatus_ = "Improved prompt ready.";
    state_.AddActivity("Agent prompt", "Improved", "Draft length: " + std::to_string(improved.str().size()) + " chars");
}

void EditorApp::CreateImplementationBriefFromAgentPrompt() {
    const std::string request = TrimWhitespace(chatInput_.data());
    if (request.empty()) {
        agentSurfaceStatus_ = "Add a prompt before creating a brief.";
        return;
    }

    composerRunId_ = GenerateAgentRunId();
    CopyStringToBuffer(composerRequestInput_, request);
    const std::string prompt = BuildAgentImplementationBrief(request);
    CopyStringToBuffer(composerPromptInput_, prompt);
    const bool saved = AppendAgentRunLogEntry("prompt_generated", composerRunId_, request, prompt,
                                              "Generated implementation brief from Agent prompt.");
    composerStatus_ = saved ? "Implementation brief created and saved to history."
                            : "Implementation brief created, but history save failed.";
    agentSurfaceStatus_ = composerStatus_;
}

void EditorApp::AddAgentRunCard(const std::string& runId, const std::string& prompt, AgentBackend backend,
                                const std::string& logPath) {
    AgentRunUiItem card;
    card.runId = runId.empty() ? GenerateAgentRunId() : runId;
    card.conversationId = state_.ActiveChatConversationId();
    card.status = "Pending";
    card.backend = backend;
    card.backendLabel = AgentOrchestrator::BackendLabel(backend);
    card.stage = "Queued";
    card.summary = "No response received yet.";
    card.prompt = prompt;
    card.resultText = "No response received yet.";
    card.outputSummary = "Provider has not returned yet.";
    card.commandSummary.clear();
    card.changedSummary.clear();
    card.failureReason.clear();
    card.logPath = logPath;
    card.startedSeconds = ImGui::GetTime();
    agentRunCards_.push_back(std::move(card));
    if (agentRunCards_.size() > 12) {
        agentRunCards_.erase(agentRunCards_.begin());
    }
    activeAgentRunId_ = runId;
}

void EditorApp::MarkAgentRunRunning(const std::string& runId, const std::string& stage, const std::string& summary) {
    for (AgentRunUiItem& card : agentRunCards_) {
        if (card.runId != runId) {
            continue;
        }
        card.status = "Running";
        card.stage = stage;
        card.summary = summary;
        card.resultText = "No response received yet.";
        return;
    }
}

void EditorApp::CompleteAgentRunCard(const std::string& runId, AgentBackend requestedBackend,
                                     const AgentOrchestratorResult& result) {
    for (AgentRunUiItem& card : agentRunCards_) {
        if (card.runId != runId) {
            continue;
        }
        card.status = result.ok ? "Complete" : "Failed";
        card.backend = result.backend;
        card.backendLabel = BackendDisplayLabel(requestedBackend, result);
        card.stage = result.usedFallback ? "Local Tool Gateway fallback" : (result.ok ? "Finished" : "Failed");
        card.summary = BuildAgentResultSummaryText(requestedBackend, result);
        card.resultText = BuildAgentResultDisplayText(result);
        card.outputSummary = BuildAgentOutputSummaryText(result);
        card.commandSummary = BuildAgentCommandSummaryText(result);
        card.changedSummary = BuildAgentChangedSummaryText(result);
        card.failureReason = BuildAgentFailureReasonText(result);
        card.finishedSeconds = ImGui::GetTime();
        card.exitCode = result.exitCode;
        card.usedFallback = result.usedFallback;
        card.logPath = AgentRunLogPath().string();
        return;
    }
}

bool EditorApp::SubmitAgentPrompt(std::string prompt, AgentBackend backend, bool fromComposer) {
    if (!EnsureEditModeForAction("Send agent prompt")) {
        return false;
    }

    if (agentJob_ != nullptr) {
        state_.AddChat(ChatSender::System, std::string("Agent request already running: ") +
                                             AgentOrchestrator::BackendLabel(agentJobBackend_));
        return false;
    }

    prompt = TrimWhitespace(std::move(prompt));
    if (prompt.empty()) {
        return false;
    }

    const AgentBackend requestedBackend = backend;
    const bool buildLaunchIntent = PromptLooksLikeBuildLaunchIntent(prompt);
    const bool improvementReviewIntent = PromptLooksLikeEditorImprovementReview(prompt);
    if (!fromComposer && backend == AgentBackend::LocalToolGateway && (buildLaunchIntent || improvementReviewIntent)) {
        backend = AgentBackend::CodexCli;
        state_.AddActivity("Agent routing", "Codex CLI",
                           improvementReviewIntent ? "Routed editor improvement review to the development backend."
                                                   : "Routed build launch intent to the development backend.");
    }
    if (agentRouteSceneEditsLocally_ && !fromComposer && BackendRunsOnWorker(backend) &&
        PromptLooksLikeDeterministicSceneEdit(prompt)) {
        backend = AgentBackend::LocalToolGateway;
        state_.AddActivity("Agent routing", "Local Tool Gateway",
                           std::string("Routed deterministic scene edit away from ") +
                               AgentOrchestrator::BackendLabel(requestedBackend) +
                               " so the editor can apply it immediately.");
    }

    const bool shouldGenerateBrief =
        agentAutoGenerateImplementationBriefs_ && !fromComposer && ShouldAutoGenerateImplementationBrief(backend, prompt);
    const std::string rawUserRequest = prompt;
    std::string userRequest = fromComposer ? TrimWhitespace(composerRequestInput_.data()) : rawUserRequest;
    if (userRequest.empty()) {
        userRequest = rawUserRequest;
    }

    const std::string runId = fromComposer ? (composerRunId_.empty() ? GenerateAgentRunId() : composerRunId_)
                                           : GenerateAgentRunId();

    std::vector<AgentVisualCapture> preRunCaptures;
    if (agentAutoCaptureVisuals_ && BackendRunsOnWorker(backend)) {
        CaptureAgentVisualSnapshot("pre-agent run", runId, &preRunCaptures);
    }

    if (shouldGenerateBrief) {
        prompt = BuildAgentImplementationBrief(rawUserRequest);
        CopyStringToBuffer(composerRequestInput_, rawUserRequest);
        CopyStringToBuffer(composerPromptInput_, prompt);
        composerRunId_ = runId;
        composerStatus_ = std::string("Auto-generated implementation brief for ") +
                          std::string(AgentOrchestrator::BackendLabel(backend)) + ".";
        AppendAgentRunLogEntry("prompt_generated", runId, rawUserRequest, prompt,
                               "Auto-generated implementation brief from Agent send.");
        state_.AddActivity("Agent brief", "Generated",
                            std::string("Expanded short request into ") + std::to_string(prompt.size()) +
                                " chars using project context and agent memory.");
    }
    if (!preRunCaptures.empty() && prompt.find("## Latest Visual Context") == std::string::npos) {
        prompt += "\n\n## Latest Visual Context\n";
        prompt += AgentVisualCaptureSummary(preRunCaptures);
        if (fromComposer) {
            CopyStringToBuffer(composerPromptInput_, prompt);
        }
    }

    if (fromComposer) {
        composerRunId_ = runId;
    }
    AppendAgentRunLogEntry("run_started", runId, userRequest, prompt,
                           std::string("Started backend: ") + AgentOrchestrator::BackendLabel(backend));
    AddAgentRunCard(runId, prompt, backend, AgentRunLogPath().string());

    state_.AddChat(ChatSender::User, userRequest);

    if (BackendRunsOnWorker(backend)) {
        EditorState stateSnapshot = state_;
        ToolGateway gatewaySnapshot = gateway_;
        AgentOrchestrator orchestratorSnapshot = orchestrator_;
        ToolCommandBatch lastGatewayBatchSnapshot;
        const bool hasLastGatewayBatchSnapshot = hasLastGatewayResult_;
        if (hasLastGatewayBatchSnapshot) {
            lastGatewayBatchSnapshot = lastGatewayResult_.batch;
        }

        agentJob_ = std::make_shared<AsyncAgentJob>();
        agentJobBackend_ = backend;
        agentJobPrompt_ = prompt;
        agentJobPromptFromComposer_ = fromComposer || shouldGenerateBrief;
        agentJobRunLogId_ = runId;
        agentJobComposerRequest_ = userRequest;
        agentJobStartedSeconds_ = ImGui::GetTime();
        state_.SetAgentStatus(std::string("Running ") + AgentOrchestrator::BackendLabel(backend));
        MarkAgentRunRunning(runId, "Waiting for provider",
                            shouldGenerateBrief
                                ? std::string(AgentOrchestrator::BackendLabel(backend)) +
                                      " is running an implementation brief in the background."
                                : std::string(AgentOrchestrator::BackendLabel(backend)) +
                                      " is answering the chat prompt in the background.");
        state_.AddActivity("Agent request", "Queued",
                           std::string("Backend: ") + AgentOrchestrator::BackendLabel(backend));
        state_.AddActivity("Project context snapshot", "Captured",
                           std::string("Prompt length: ") + std::to_string(prompt.size()) + " chars");
        state_.AddActivity("Provider process", "Running",
                           std::string("Waiting for ") + AgentOrchestrator::BackendLabel(backend) +
                               " response");

        const bool fastTaskComposerSmoke =
            options_.smokeTestTaskComposer && options_.smokeTestFrames <= 8 && backend == AgentBackend::CodexCli;
        std::shared_ptr<AsyncAgentJob> job = agentJob_;
        std::thread([job, backend, prompt, stateSnapshot = std::move(stateSnapshot),
                     gatewaySnapshot = std::move(gatewaySnapshot),
                     orchestratorSnapshot = std::move(orchestratorSnapshot), hasLastGatewayBatchSnapshot,
                     lastGatewayBatchSnapshot = std::move(lastGatewayBatchSnapshot), fastTaskComposerSmoke]() mutable {
            AsyncAgentResult asyncResult;
            try {
                const size_t activityCountBefore = stateSnapshot.AgentActivities().size();
                if (fastTaskComposerSmoke) {
                    asyncResult.result.backend = AgentBackend::CodexCli;
                    asyncResult.result.stdoutText =
                        R"({"result_type":"chat_response","message":"Codex task composer smoke response."})";
                    asyncResult.result.normalizedResult =
                        orchestratorSnapshot.NormalizeProviderOutput(backend, asyncResult.result.stdoutText, gatewaySnapshot);
                    asyncResult.result.hasNormalizedResult = true;
                    asyncResult.result.ok = true;
                    asyncResult.result.assistantMessage =
                        "Codex CLI smoke response.\n\nGenerated prompt was routed to the Codex worker.";
                    stateSnapshot.AddActivity("Codex CLI", "Complete",
                                              "Short-frame task composer smoke used a fast local Codex response.");
                } else {
                    const ToolCommandBatch* lastBatch =
                        hasLastGatewayBatchSnapshot ? &lastGatewayBatchSnapshot : nullptr;
                    AgentProgressCallback publishProgress = [job](const AgentActivity& activity) {
                        std::lock_guard<std::mutex> lock(job->mutex);
                        job->pendingActivities.push_back(activity);
                    };
                    asyncResult.result = orchestratorSnapshot.SubmitPrompt(backend, prompt, stateSnapshot,
                                                                           gatewaySnapshot, lastBatch, publishProgress);
                }

                const std::vector<AgentActivity>& activities = stateSnapshot.AgentActivities();
                for (size_t index = activityCountBefore; index < activities.size(); ++index) {
                    asyncResult.activities.push_back(activities[index]);
                }
            } catch (const std::exception& exception) {
                asyncResult.result.backend = backend;
                asyncResult.result.ok = false;
                asyncResult.result.assistantMessage =
                    std::string("Provider worker failed before returning a response: ") + exception.what();
                asyncResult.result.diagnostics.push_back(asyncResult.result.assistantMessage);
            } catch (...) {
                asyncResult.result.backend = backend;
                asyncResult.result.ok = false;
                asyncResult.result.assistantMessage = "Provider worker failed before returning a response.";
                asyncResult.result.diagnostics.push_back(asyncResult.result.assistantMessage);
            }

            {
                std::lock_guard<std::mutex> lock(job->mutex);
                job->result = std::move(asyncResult);
                job->complete = true;
            }
        }).detach();

        RefreshPathInputs();
        return true;
    }

    MarkAgentRunRunning(runId, "Running",
                        std::string(AgentOrchestrator::BackendLabel(backend)) + " is processing the prompt.");
    AgentOrchestratorResult agentResult =
        orchestrator_.SubmitPrompt(backend, prompt, state_, gateway_,
                                   hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
    AgentOrchestratorResult finalResult = ApplyAgentResultToUi(std::move(agentResult), prompt, false);
    CompleteAgentRunCard(runId, backend, finalResult);
    RecordAgentRunSummary(runId, userRequest, prompt, finalResult);
    agentSurfaceStatus_ =
        finalResult.ok ? (finalResult.hasNormalizedResult &&
                                  finalResult.normalizedResult.type == ProviderResultType::ChatResponse
                              ? "Agent replied."
                              : "Agent run finished.")
                       : "Agent run failed. Open Activity details or Advanced logs for the next action.";
    RefreshPathInputs();
    return true;
}

bool EditorApp::SendChatPrompt() {
    const std::string requestPrompt = TrimWhitespace(chatInput_.data());
    const std::string generatedBrief = TrimWhitespace(composerPromptInput_.data());
    const std::string briefRequest = TrimWhitespace(composerRequestInput_.data());
    const bool hasGeneratedBrief =
        !generatedBrief.empty() && !briefRequest.empty() && PromptTextMatchesUserRequest(requestPrompt, briefRequest);
    const std::string prompt = hasGeneratedBrief ? generatedBrief : requestPrompt;
    selectedBackend_ = AgentBackend::CodexCli;
    if (!SubmitAgentPrompt(prompt, AgentBackend::CodexCli, hasGeneratedBrief)) {
        return false;
    }
    std::fill(chatInput_.begin(), chatInput_.end(), '\0');
    std::fill(composerPromptInput_.begin(), composerPromptInput_.end(), '\0');
    std::fill(composerRequestInput_.begin(), composerRequestInput_.end(), '\0');
    composerRunId_.clear();
    composerStatus_.clear();
    return true;
}

void EditorApp::PollAgentJob() {
    if (agentJob_ == nullptr) {
        return;
    }

    AsyncAgentResult completed;
    std::vector<AgentActivity> pendingActivities;
    bool jobComplete = false;
    {
        std::lock_guard<std::mutex> lock(agentJob_->mutex);
        pendingActivities = std::move(agentJob_->pendingActivities);
        agentJob_->pendingActivities.clear();
        jobComplete = agentJob_->complete;
        if (jobComplete) {
            completed = std::move(agentJob_->result);
        }
    }

    auto importLiveActivity = [this](const AgentActivity& activity) {
        state_.AddActivity(activity.label, activity.status, activity.detail);
        if (!agentJobRunLogId_.empty()) {
            const std::string summary =
                activity.detail.empty() ? activity.label : activity.label + ": " + activity.detail;
            MarkAgentRunRunning(agentJobRunLogId_, activity.status, TruncateForUi(summary, 220));
        }
        agentSurfaceStatus_ = TruncateForUi(activity.label + " - " + activity.status, 180);
    };

    for (const AgentActivity& activity : pendingActivities) {
        importLiveActivity(activity);
    }

    if (!jobComplete) {
        return;
    }

    const AgentBackend completedBackend = agentJobBackend_;
    const std::string completedPrompt = agentJobPrompt_;
    const bool completedFromComposer = agentJobPromptFromComposer_;
    const std::string completedRunLogId = agentJobRunLogId_;
    const std::string completedComposerRequest = agentJobComposerRequest_;
    agentJob_.reset();
    agentJobPrompt_.clear();
    agentJobPromptFromComposer_ = false;
    agentJobRunLogId_.clear();
    agentJobComposerRequest_.clear();
    agentJobStartedSeconds_ = 0.0;
    state_.SetAgentStatus("Idle");

    const bool activityWasStreamedLive = completedBackend == AgentBackend::CodexCli;
    if (!activityWasStreamedLive) {
        for (const AgentActivity& activity : completed.activities) {
            if (completed.result.usedFallback && activity.label == "Local Tool Gateway fallback") {
                break;
            }
            state_.AddActivity(activity.label, activity.status, activity.detail);
        }
    }

    std::ostringstream detail;
    detail << "Backend: " << AgentOrchestrator::BackendLabel(completedBackend);
    if (completed.result.exitCode != 0) {
        detail << " | exit=" << completed.result.exitCode;
    }
    if (!completed.result.diagnostics.empty()) {
        detail << " | " << completed.result.diagnostics.front();
    }
    state_.AddActivity("Agent request", completed.result.ok ? "Complete" : "Failed", detail.str());

    AgentOrchestratorResult finalResult = ApplyAgentResultToUi(std::move(completed.result), completedPrompt, true);
    CompleteAgentRunCard(completedRunLogId, completedBackend, finalResult);
    RecordAgentRunSummary(completedRunLogId,
                          completedComposerRequest.empty() ? completedPrompt : completedComposerRequest,
                          completedPrompt, finalResult);
    agentSurfaceStatus_ =
        finalResult.ok ? (finalResult.hasNormalizedResult &&
                                  finalResult.normalizedResult.type == ProviderResultType::ChatResponse
                              ? "Agent replied."
                              : "Agent run finished.")
                       : "Agent run failed. Open Activity details or Advanced logs for the next action.";
    if (completedFromComposer) {
        composerStatus_ = "Codex run finished; summary saved to agent memory.";
    }
    RefreshPathInputs();
}

void EditorApp::RequestProviderHealthRefresh(const std::string& reason) {
    if (providerHealthJob_ != nullptr) {
        state_.AddActivity("Provider health", "Already running", reason);
        return;
    }

    providerHealthJob_ = std::make_shared<AsyncProviderHealthJob>();
    providerHealthJob_->reason = reason;
    state_.AddActivity("Provider health", "Queued", reason);
    agentSurfaceStatus_ = "Refreshing provider health in background.";

    std::shared_ptr<AsyncProviderHealthJob> job = providerHealthJob_;
    AgentOrchestrator orchestratorSnapshot = orchestrator_;
    std::thread([job, orchestratorSnapshot = std::move(orchestratorSnapshot)]() mutable {
        orchestratorSnapshot.RefreshProviderHealth();
        std::lock_guard<std::mutex> lock(job->mutex);
        job->orchestrator = std::move(orchestratorSnapshot);
        job->complete = true;
    }).detach();
}

void EditorApp::PollProviderHealthJob() {
    if (providerHealthJob_ == nullptr) {
        return;
    }

    bool complete = false;
    AgentOrchestrator refreshed;
    std::string reason;
    {
        std::lock_guard<std::mutex> lock(providerHealthJob_->mutex);
        complete = providerHealthJob_->complete;
        if (complete) {
            refreshed = std::move(providerHealthJob_->orchestrator);
            reason = providerHealthJob_->reason;
        }
    }
    if (!complete) {
        return;
    }

    orchestrator_ = std::move(refreshed);
    providerHealthJob_.reset();
    const ProviderHealth* selected = orchestrator_.FindProvider(selectedBackend_);
    state_.AddActivity("Provider health", selected == nullptr ? "Complete" : selected->status,
                       reason.empty() ? "Provider table refreshed." : reason);
    agentSurfaceStatus_ = "Provider health refreshed.";
}

AgentOrchestratorResult EditorApp::ApplyAgentResultToUi(AgentOrchestratorResult result, const std::string& prompt,
                                                        bool rerunGatewayFallbackOnMainThread) {
    if (rerunGatewayFallbackOnMainThread && result.usedFallback) {
        const std::string reason =
            result.diagnostics.empty() ? "External provider did not complete successfully" : result.diagnostics.front();
        ToolGatewayResult liveFallback = gateway_.SubmitPrompt(prompt, state_);

        result.backend = AgentBackend::LocalToolGateway;
        result.gatewayResult = std::move(liveFallback);
        result.hasGatewayResult = true;
        result.hasNormalizedResult = false;
        result.ok = result.gatewayResult.batch.ok;

        std::ostringstream message;
        message << reason << ".\n\n";
        message << "Used Local Tool Gateway fallback on the live editor state.\n\n";
        message << result.gatewayResult.assistantMessage;
        result.assistantMessage = message.str();

        state_.AddActivity("Local Tool Gateway fallback", result.ok ? "Complete" : "Failed", reason);
    }

    if (result.hasGatewayResult) {
        lastGatewayResult_ = result.gatewayResult;
        hasLastGatewayResult_ = true;
        ApplyEditorOwnedAgentVisualCommands(result.gatewayResult.batch, activeAgentRunId_);
    }

    if (agentAutoApplyCodexCommandBatches_ && result.backend == AgentBackend::CodexCli && result.hasNormalizedResult &&
        result.normalizedResult.type == ProviderResultType::ProposedCommandBatch &&
        result.normalizedResult.canApprove && result.normalizedResult.hasCommandBatch) {
        ToolGatewayResult applyResult =
            gateway_.ApplyApprovedCommandBatch(result.normalizedResult.commandBatch, state_,
                                               "codex_cli_validated_auto_apply");
        lastGatewayResult_ = applyResult;
        hasLastGatewayResult_ = true;
        ApplyEditorOwnedAgentVisualCommands(applyResult.batch, activeAgentRunId_);
        result.gatewayResult = applyResult;
        result.hasGatewayResult = true;
        result.normalizedResult.commandBatch = applyResult.batch;
        result.normalizedResult.approved = true;
        result.normalizedResult.applied = applyResult.batch.applied && applyResult.batch.ok;
        result.normalizedResult.canApprove = false;
        result.normalizedResult.requiresApproval = false;
        result.ok = result.ok && result.normalizedResult.applied;

        std::ostringstream message;
        message << "Codex CLI returned a valid ToolGateway command batch, so the editor applied it directly.\n\n";
        if (!TrimWhitespace(result.normalizedResult.message).empty()) {
            message << result.normalizedResult.message << "\n\n";
        }
        message << applyResult.assistantMessage;
        result.assistantMessage = message.str();
        state_.AddActivity("Codex direct apply", result.normalizedResult.applied ? "Applied" : "Failed",
                           applyResult.batch.name + " | " + std::to_string(applyResult.batch.commands.size()) +
                               " commands");
    }

    StoreProviderResult(result);

    std::string response = BuildAgentResultDisplayText(result);
    if (result.hasGatewayResult && !result.gatewayResult.batch.commands.empty()) {
        response += "\n\nCommand preview:";
        for (const ToolCommand& command : result.gatewayResult.batch.commands) {
            response += "\n- " + command.type + ": " + command.summary;
        }
    }
    state_.AddChat(ChatSender::Assistant, response);
    AddProviderOutcomeSystemMessage(result);
    return result;
}

bool EditorApp::RunAgentTaskComposerSmokeTest() {
    if (!options_.smokeTestTaskComposer) {
        return true;
    }

    const std::string request = options_.smokeTestTaskComposerRequest.empty()
                                    ? "add an agent task composer smoke verification path"
                                    : options_.smokeTestTaskComposerRequest;
    CopyStringToBuffer(composerRequestInput_, request);
    const int promptsBefore = composerSavedPromptCount_;

    ImproveComposerPrompt();
    const std::string generatedPrompt = TrimWhitespace(composerPromptInput_.data());
    if (generatedPrompt.empty()) {
        state_.AddLog(LogLevel::Error, "Task composer smoke failed: prompt generation returned empty text.");
        return false;
    }
    if (composerSavedPromptCount_ <= promptsBefore || !std::filesystem::exists(AgentRunLogPath())) {
        state_.AddLog(LogLevel::Error, "Task composer smoke failed: generated prompt was not saved to run_log.jsonl.");
        return false;
    }

    const std::vector<std::string> requiredSections{
        "## Task Mode",
        "## User Goal",
        "## Inferred Intent",
        "## Relevant Project Context",
        "## Likely Files And Systems",
        "## Implementation Requirements",
        "## Constraints",
        "## Acceptance Criteria",
        "## Required Build And Test Verification",
        "## Expected Final Report Format",
    };
    for (const std::string& section : requiredSections) {
        if (generatedPrompt.find(section) == std::string::npos) {
            state_.AddLog(LogLevel::Error, "Task composer smoke failed: generated prompt missing section " + section + ".");
            return false;
        }
    }
    if (PromptLooksLikeBuildLaunchIntent(request) &&
        generatedPrompt.find("## Task Mode\nRepository Implementation") == std::string::npos) {
        state_.AddLog(LogLevel::Error,
                      "Task composer smoke failed: build launch request was not classified as repository implementation.");
        return false;
    }
    if (PromptLooksLikeEditorImprovementReview(request)) {
        if (generatedPrompt.find("## Task Mode\nEditor Improvement Review") == std::string::npos ||
            generatedPrompt.find("prioritized improvement list") == std::string::npos ||
            generatedPrompt.find("No files or scene data are changed during a suggestion-only review.") == std::string::npos) {
            state_.AddLog(LogLevel::Error,
                          "Task composer smoke failed: editor improvement review request did not generate review-specific guidance.");
            return false;
        }
    }

    if (generatedPrompt.find(request) == std::string::npos ||
        generatedPrompt.find(state_.ProjectRootPathString()) == std::string::npos ||
        generatedPrompt.find("Recent Agent Activity") == std::string::npos ||
        generatedPrompt.find("docs/agent-memory/run_log.jsonl") == std::string::npos) {
        state_.AddLog(LogLevel::Error,
                      "Task composer smoke failed: generated prompt did not include request, project context, activity, and memory path.");
        return false;
    }

    RunComposerPromptWithCodex();
    if (agentJob_ == nullptr || agentJobBackend_ != AgentBackend::CodexCli) {
        state_.AddLog(LogLevel::Error, "Task composer smoke failed: Run With Codex did not start a Codex worker.");
        return false;
    }
    if (agentJobPrompt_ == request || agentJobPrompt_.find("# Codex Implementation Brief") == std::string::npos) {
        state_.AddLog(LogLevel::Error, "Task composer smoke failed: Codex worker did not receive the generated prompt.");
        return false;
    }

    state_.AddActivity("smoke.agent-task-composer", "Running",
                       "Generated prompt saved and sent to Codex worker.");
    return true;
}

bool EditorApp::RunAgentVisualsSmokeTest() {
    if (!options_.smokeTestAgentVisuals) {
        return true;
    }

    auto fail = [this](const std::string& message) {
        state_.AddLog(LogLevel::Error, "Agent visuals smoke failed: " + message);
        std::fprintf(stderr, "Agent visuals smoke failed: %s\n", message.c_str());
        return false;
    };
    auto isPng = [](const std::filesystem::path& path) {
        std::ifstream input(path, std::ios::binary);
        if (!input) {
            return false;
        }
        unsigned char signature[8]{};
        input.read(reinterpret_cast<char*>(signature), sizeof(signature));
        const unsigned char expected[8]{0x89u, 0x50u, 0x4Eu, 0x47u, 0x0Du, 0x0Au, 0x1Au, 0x0Au};
        return input.gcount() == static_cast<std::streamsize>(sizeof(signature)) &&
               std::equal(signature, signature + sizeof(signature), expected);
    };

    std::vector<AgentVisualCapture> captures;
    if (!CaptureAgentVisualSnapshot("agent visuals smoke", "agent-visuals-smoke", &captures)) {
        return fail("manual snapshot capture returned false.");
    }
    if (captures.size() < 2) {
        return fail("expected Scene and Game screenshots.");
    }
    for (const AgentVisualCapture& capture : captures) {
        if (capture.width != 960 || capture.height != 540) {
            return fail("capture dimensions were not 960x540 for " + capture.view + ".");
        }
        if (!std::filesystem::exists(capture.path) || !isPng(capture.path)) {
            return fail("capture was not a PNG file: " + capture.path);
        }
    }

    const std::string brief = BuildAgentImplementationBrief("review current editor visuals");
    if (brief.find("## Relevant Project Context") == std::string::npos ||
        brief.find("### Latest Visual Context") == std::string::npos ||
        brief.find(captures.front().path) == std::string::npos) {
        return fail("generated brief did not include latest visual context.");
    }

    if (!AppendAgentRunLogEntry("agent_visuals_smoke", "agent-visuals-smoke", "visual capture smoke", brief,
                                "Recorded visual capture smoke artifacts.")) {
        return fail("visual capture run-log entry failed.");
    }
    bool runLogRecordedVisuals = false;
    const std::string firstCaptureFileName = std::filesystem::path(captures.front().path).filename().string();
    {
        std::ifstream logInput(AgentRunLogPath(), std::ios::binary);
        std::string line;
        while (std::getline(logInput, line)) {
            if (line.find("\"event\":\"agent_visuals_smoke\"") != std::string::npos &&
                line.find("\"visual_captures\"") != std::string::npos &&
                line.find(firstCaptureFileName) != std::string::npos) {
                runLogRecordedVisuals = true;
            }
        }
    }
    if (!runLogRecordedVisuals) {
        return fail("run_log.jsonl did not record visual capture metadata.");
    }

    if (std::find(gateway_.SupportedCommands().begin(), gateway_.SupportedCommands().end(),
                  "runtime.captureScreenshot") == gateway_.SupportedCommands().end() ||
        std::find(gateway_.SupportedCommands().begin(), gateway_.SupportedCommands().end(),
                  "runtime.startRecording") == gateway_.SupportedCommands().end() ||
        std::find(gateway_.SupportedCommands().begin(), gateway_.SupportedCommands().end(),
                  "runtime.stopRecording") == gateway_.SupportedCommands().end()) {
        return fail("visual runtime commands are not exposed by ToolGateway.");
    }

    StartAgentVisualRecording();
    ++agentVisualRecordingFrameCount_;
    CaptureAgentVisualSnapshot("agent visuals smoke recording", agentVisualRecordingId_, nullptr,
                               agentVisualRecordingFrameCount_);
    StopAgentVisualRecording();
    if (agentVisualRecordingFrameCount_ < 1 || agentVisualRecordingFolder_.empty()) {
        return fail("frame recording did not save a frame set.");
    }
    const std::filesystem::path recordingFolder = agentVisualRecordingFolder_;
    int recordingPngCount = 0;
    std::error_code directoryError;
    for (const std::filesystem::directory_entry& entry : std::filesystem::directory_iterator(recordingFolder, directoryError)) {
        if (!directoryError && entry.is_regular_file() && entry.path().extension() == ".png" && isPng(entry.path())) {
            ++recordingPngCount;
        }
    }
    if (recordingPngCount < 2) {
        return fail("frame recording did not produce Scene and Game PNGs.");
    }

    state_.AddActivity("smoke.agent-visuals", "Passed",
                       "Captured Scene/Game screenshots, logged metadata, and recorded frame PNGs.");
    return true;
}

bool EditorApp::RunProjectFolderSmokeTest() {
    if (!options_.smokeTestProjectFolder) {
        return true;
    }

    std::error_code filesystemError;
    const std::filesystem::path projectRoot = std::filesystem::absolute(state_.ProjectRootPathString());
    const std::filesystem::path expectedSceneRoot = projectRoot / "Assets" / "Scenes";
    const std::filesystem::path expectedSceneFile = expectedSceneRoot / "Prototype.scene.json";
    if (!std::filesystem::exists(state_.ProjectFilePathString(), filesystemError)) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: project file was not created: " + state_.ProjectFilePathString());
        return false;
    }
    if (!std::filesystem::exists(expectedSceneFile, filesystemError)) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: new-project scene was not saved under Assets/Scenes.");
        return false;
    }
    if (std::filesystem::absolute(state_.SceneRootPathString()).lexically_normal() !=
        expectedSceneRoot.lexically_normal()) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: scene root is not Assets/Scenes: " + state_.SceneRootPathString());
        return false;
    }
    if (!std::filesystem::exists(state_.GameSaveRootPathString(), filesystemError)) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: default game save folder was not created: " +
                          state_.GameSaveRootPathString());
        return false;
    }

    std::string error;
    const std::filesystem::path customSaveRoot = std::filesystem::path("SavedGames") / "SmokeSlot";
    if (!state_.SetGameSaveRootPath(customSaveRoot, &error)) {
        state_.AddLog(LogLevel::Error, "Project folder smoke failed: could not set custom save root: " + error);
        return false;
    }
    if (!state_.SaveProject(&error)) {
        state_.AddLog(LogLevel::Error, "Project folder smoke failed: could not save custom save root: " + error);
        return false;
    }

    const std::filesystem::path projectFile = state_.ProjectFilePathString();
    try {
        std::ifstream input(projectFile);
        const json document = json::parse(input);
        const json directories = document.contains("directories") && document.at("directories").is_object()
                                     ? document.at("directories")
                                     : json::object();
        if (document.value("activeScene", std::string{}) != "Assets/Scenes/Prototype.scene.json" ||
            directories.value("sceneRoot", std::string{}) != "Assets/Scenes" ||
            directories.value("saveDataRoot", std::string{}) != "SavedGames/SmokeSlot") {
            state_.AddLog(LogLevel::Error,
                          "Project folder smoke failed: project metadata did not persist scene/save directories.");
            return false;
        }
    } catch (const std::exception& exception) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: project metadata could not be parsed: " +
                          std::string(exception.what()));
        return false;
    }

    if (!state_.OpenProject(projectFile, &error)) {
        state_.AddLog(LogLevel::Error, "Project folder smoke failed: reopen failed: " + error);
        return false;
    }
    const std::filesystem::path expectedSaveRoot = projectRoot / customSaveRoot;
    if (std::filesystem::absolute(state_.GameSaveRootPathString()).lexically_normal() !=
        expectedSaveRoot.lexically_normal()) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: reopened save root mismatch: " + state_.GameSaveRootPathString());
        return false;
    }

    const std::filesystem::path saveAsRoot = projectRoot.parent_path() / (projectRoot.filename().string() + "-save-as");
    if (!state_.SaveProjectAs(saveAsRoot, &error)) {
        state_.AddLog(LogLevel::Error, "Project folder smoke failed: SaveProjectAs failed: " + error);
        return false;
    }
    if (std::filesystem::absolute(state_.ProjectRootPathString()).lexically_normal() !=
            std::filesystem::absolute(saveAsRoot).lexically_normal() ||
        !std::filesystem::exists(state_.ProjectFilePathString(), filesystemError) ||
        !std::filesystem::exists(state_.SceneFilePathString(), filesystemError)) {
        state_.AddLog(LogLevel::Error,
                      "Project folder smoke failed: SaveProjectAs did not relocate project and active scene.");
        return false;
    }

    RefreshPathInputs();
    state_.AddActivity("smoke.project-folder", "Passed",
                       "Project folder, Save As, Assets/Scenes, and save-data root persisted across reload.");
    return true;
}

bool EditorApp::RunProjectTreeActionsSmokeTest() {
    if (!options_.smokeTestProjectTreeActions) {
        return true;
    }

    state_.RefreshProjectTree();
    const ProjectTreeNode& root = state_.ProjectTree();
    if (root.children.size() != 1 || root.children.front().name.rfind("Project:", 0) != 0) {
        state_.AddLog(LogLevel::Error, "Project tree actions smoke failed: tree is not focused on the active project.");
        return false;
    }

    const ProjectTreeNode& projectNode = root.children.front();
    bool sawAssets = false;
    std::filesystem::path assetsPath;
    for (const ProjectTreeNode& child : projectNode.children) {
        if (child.name == "Assets") {
            sawAssets = true;
            assetsPath = child.path;
        }
        if (child.name == "Source" || child.name == "Docs" || child.name == "Library" || child.name == "Temp" ||
            child.name == "Logs" || child.name == "Saved" || child.name == "AI Native Project.aineproject.json") {
            state_.AddLog(LogLevel::Error,
                          "Project tree actions smoke failed: non-work item is visible in project tree: " + child.name);
            return false;
        }
        if (child.filesystemBacked && child.path.empty()) {
            state_.AddLog(LogLevel::Error,
                          "Project tree actions smoke failed: filesystem tree node has no path: " + child.name);
            return false;
        }
    }
    if (!sawAssets) {
        state_.AddLog(LogLevel::Error, "Project tree actions smoke failed: Assets folder is missing.");
        return false;
    }
    if (RelativeProjectPathString(state_.ProjectRootPathString(), assetsPath) != "Assets") {
        state_.AddLog(LogLevel::Error,
                      "Project tree actions smoke failed: Assets relative copy path is not stable.");
        return false;
    }

    const std::filesystem::path createdFolder = std::filesystem::path(state_.AssetRootPathString()) / "New Folder";
    std::error_code cleanupError;
    std::filesystem::remove_all(createdFolder, cleanupError);
    CreateFolderInProjectTree(state_.AssetRootPathString());
    if (!std::filesystem::exists(createdFolder)) {
        state_.AddLog(LogLevel::Error, "Project tree actions smoke failed: New Folder was not created in Assets.");
        return false;
    }
    if (RelativeProjectPathString(state_.ProjectRootPathString(), createdFolder) != "Assets/New Folder") {
        state_.AddLog(LogLevel::Error,
                      "Project tree actions smoke failed: created folder relative copy path is not stable.");
        return false;
    }

    std::string error;
    if (!DeleteProjectTreePath(state_.ProjectRootPathString(), true, &error)) {
        if (error.find("project root") == std::string::npos) {
            state_.AddLog(LogLevel::Error,
                          "Project tree actions smoke failed: root delete was blocked for the wrong reason: " + error);
            return false;
        }
    } else {
        state_.AddLog(LogLevel::Error, "Project tree actions smoke failed: active project root delete was allowed.");
        return false;
    }

    if (!DeleteProjectTreePath(createdFolder, true, &error)) {
        state_.AddLog(LogLevel::Error, "Project tree actions smoke failed: folder delete failed: " + error);
        return false;
    }
    if (std::filesystem::exists(createdFolder)) {
        state_.AddLog(LogLevel::Error, "Project tree actions smoke failed: deleted folder still exists.");
        return false;
    }

    state_.AddActivity("smoke.project-tree-actions", "Passed",
                       "Focused project tree, node paths, new folder, root guard, and delete path passed.");
    return true;
}

bool EditorApp::RunConsoleSmokeTest() {
    if (!options_.smokeTestConsole) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        state_.AddLog(LogLevel::Error, "Console smoke failed: " + message);
        return false;
    };

    state_.ClearConsole();
    state_.AddLog(LogLevel::Info, "Duplicate diagnostic line");
    state_.AddLog(LogLevel::Info, "Duplicate diagnostic line");
    state_.AddLog(LogLevel::Warning, "Warning diagnostic line");
    state_.AddLog(LogLevel::Error, "Error diagnostic line");

    const std::vector<LogEntry>& logs = state_.Logs();
    if (logs.size() != 4) {
        return fail("expected four seeded entries.");
    }
    for (size_t index = 1; index < logs.size(); ++index) {
        if (logs[index].sequence <= logs[index - 1].sequence) {
            return fail("log sequence values are not monotonic.");
        }
    }
    if (std::any_of(logs.begin(), logs.end(), [](const LogEntry& entry) {
            return entry.timestamp.time_since_epoch().count() == 0;
        })) {
        return fail("seeded entries are missing timestamps.");
    }

    const std::vector<ConsoleLogDisplayEntry> allEntries =
        BuildConsoleDisplayEntries(logs, true, true, true, "", false);
    if (allEntries.size() != 4) {
        return fail("unfiltered console view did not include every entry.");
    }

    const std::vector<ConsoleLogDisplayEntry> warningErrorEntries =
        BuildConsoleDisplayEntries(logs, false, true, true, "", false);
    if (warningErrorEntries.size() != 2) {
        return fail("severity filters did not hide info entries.");
    }

    const std::vector<ConsoleLogDisplayEntry> searchedEntries =
        BuildConsoleDisplayEntries(logs, true, true, true, "error", false);
    if (searchedEntries.size() != 1 || searchedEntries.front().entry == nullptr ||
        searchedEntries.front().entry->level != LogLevel::Error) {
        return fail("search filter did not isolate the error entry.");
    }

    const std::vector<ConsoleLogDisplayEntry> collapsedEntries =
        BuildConsoleDisplayEntries(logs, true, true, true, "", true);
    const auto duplicate = std::find_if(collapsedEntries.begin(), collapsedEntries.end(),
                                        [](const ConsoleLogDisplayEntry& entry) {
                                            return entry.entry != nullptr &&
                                                   entry.entry->message == "Duplicate diagnostic line";
                                        });
    if (collapsedEntries.size() != 3 || duplicate == collapsedEntries.end() || duplicate->count != 2) {
        return fail("collapse did not group duplicate entries.");
    }

    const std::string clipboard = BuildConsoleClipboardText(collapsedEntries);
    if (clipboard.find("Info x2: Duplicate diagnostic line") == std::string::npos ||
        clipboard.find("Error: Error diagnostic line") == std::string::npos) {
        return fail("copy-visible text did not include formatted severity, count, and message.");
    }

    state_.AddActivity("smoke.console", "Passed",
                       "Console filtering, search, collapse, timestamps, and copy text passed.");
    return true;
}

bool EditorApp::RunAssetStagingSmokeTest() {
    if (!options_.smokeTestAssetStaging) {
        return true;
    }

    std::filesystem::path sourceFolder = options_.smokeTestAssetSource;
    if (sourceFolder.empty()) {
        sourceFolder = std::filesystem::path(state_.ProjectRootPathString()) / "Temp" / "SmokeExternalAssetSource";
        try {
            std::filesystem::create_directories(sourceFolder / "Models");
            std::filesystem::create_directories(sourceFolder / "Animations");
            std::ofstream(sourceFolder / "Models" / "TinyHero.fbx") << "smoke model fixture\n";
            std::ofstream(sourceFolder / "Animations" / "TinyHero_Wave.anim") << "smoke animation fixture\n";
            std::ofstream(sourceFolder / "TinyHero.png") << "smoke texture fixture\n";
        } catch (const std::exception& exception) {
            state_.AddLog(LogLevel::Error,
                          "Asset staging smoke failed: could not create source fixture: " + std::string(exception.what()));
            return false;
        }
    }

    std::filesystem::path stagedProjectFile;
    std::string summary;
    std::string error;
    if (!StageExternalAssetFolder(sourceFolder, "SmokeHeroAssetPreview", &stagedProjectFile, &summary, &error)) {
        state_.AddLog(LogLevel::Error, "Asset staging smoke failed: " + error);
        return false;
    }

    const std::filesystem::path stagedRoot = stagedProjectFile.parent_path();
    const std::filesystem::path manifestPath = stagedRoot / "Assets" / "External" / "import-manifest.json";
    const std::filesystem::path previewScene = stagedRoot / "Assets" / "Scenes" / "AssetPreview.scene.json";
    const std::filesystem::path copiedModel = stagedRoot / "Assets" / "External" / sourceFolder.filename() /
                                              "Models" / "TinyHero.fbx";
    if (!std::filesystem::exists(stagedProjectFile) || !std::filesystem::exists(manifestPath) ||
        !std::filesystem::exists(previewScene) || !std::filesystem::exists(copiedModel)) {
        state_.AddLog(LogLevel::Error,
                      "Asset staging smoke failed: staged project, manifest, preview scene, or copied model is missing.");
        return false;
    }

    try {
        std::ifstream manifestInput(manifestPath);
        const json manifest = json::parse(manifestInput);
        if (manifest.value("sourcePreserved", false) != true || manifest.value("assetCount", 0) < 3 ||
            manifest.value("animationCount", 0) < 1) {
            state_.AddLog(LogLevel::Error,
                          "Asset staging smoke failed: manifest did not record preserved source and detected assets.");
            return false;
        }

        std::ifstream sceneInput(previewScene);
        const json scene = json::parse(sceneInput);
        bool sawSpinRuntime = false;
        for (const json& entity : scene.value("entities", json::array())) {
            for (const json& component : entity.value("components", json::array())) {
                sawSpinRuntime = sawSpinRuntime || component.value("type", std::string{}) == "SpinRuntime";
            }
        }
        if (!sawSpinRuntime) {
            state_.AddLog(LogLevel::Error,
                          "Asset staging smoke failed: preview scene does not contain an animated SpinRuntime entity.");
            return false;
        }
    } catch (const std::exception& exception) {
        state_.AddLog(LogLevel::Error,
                      "Asset staging smoke failed: could not inspect staged artifacts: " + std::string(exception.what()));
        return false;
    }

    state_.AddActivity("smoke.asset-staging", "Passed", summary);
    return true;
}

bool EditorApp::RunAssetPipelineSmokeTest() {
    if (!options_.smokeTestAssetPipeline) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        state_.AddLog(LogLevel::Error, "Asset pipeline smoke failed: " + message);
        return false;
    };

    const std::filesystem::path sourceFolder =
        std::filesystem::path(state_.ProjectRootPathString()) / "Temp" / "AssetPipelineSource";
    const std::filesystem::path gltfPath = sourceFolder / "SmokeModel.gltf";
    const std::filesystem::path bufferPath = sourceFolder / "mesh.bin";
    const std::filesystem::path texturePath = sourceFolder / "albedo.png";
    try {
        std::filesystem::create_directories(sourceFolder);
        std::ofstream(bufferPath, std::ios::binary) << "mesh bytes\n";
        std::ofstream(texturePath, std::ios::binary) << "texture bytes\n";
        const json gltf{
            {"asset", json{{"version", "2.0"}, {"generator", "AI Native smoke"}}},
            {"buffers", json::array({json{{"uri", "mesh.bin"}, {"byteLength", 11}}})},
            {"images", json::array({json{{"uri", "albedo.png"}}})},
            {"meshes", json::array({json{{"name", "SmokeMesh"}}})},
        };
        std::ofstream(gltfPath) << gltf.dump(2) << '\n';
    } catch (const std::exception& exception) {
        return fail(std::string("could not create source fixture: ") + exception.what());
    }

    AssetRecord imported;
    std::string error;
    if (!state_.ImportAsset(gltfPath, "asset-pipeline-smoke", "test-fixture", &imported, &error)) {
        return fail("import failed: " + error);
    }
    if (imported.type != "Model" || imported.sourceHash.empty() || imported.resourcePath.empty() ||
        imported.metadataPath.empty() || imported.thumbnailPath.empty()) {
        return fail("imported model record is missing type/hash/artifact paths.");
    }
    if (imported.dependencies.size() != 2) {
        return fail("glTF dependencies were not discovered.");
    }
    const std::filesystem::path projectRoot = state_.ProjectRootPathString();
    for (const std::string& dependency : imported.dependencies) {
        const std::filesystem::path dependencyPath = std::filesystem::path(dependency).is_absolute()
                                                        ? std::filesystem::path(dependency)
                                                        : projectRoot / dependency;
        if (!std::filesystem::exists(dependencyPath)) {
            return fail("copied dependency is missing: " + dependencyPath.string());
        }
    }
    if (!std::filesystem::exists(projectRoot / imported.importedPath) ||
        !std::filesystem::exists(projectRoot / imported.resourcePath) ||
        !std::filesystem::exists(projectRoot / imported.metadataPath) ||
        !std::filesystem::exists(projectRoot / imported.thumbnailPath)) {
        return fail("imported model or generated resource metadata files are missing.");
    }

    try {
        std::ifstream resourceInput(projectRoot / imported.resourcePath);
        const json resource = json::parse(resourceInput);
        if (resource.value("format", "") != "aine.importedResource" ||
            resource.value("type", "") != "Model" || !resource.contains("renderer") ||
            resource.at("renderer").value("runtimeShape", "") != "resource-backed-model") {
            return fail("resource JSON does not expose a renderer model resource.");
        }

        std::ifstream metadataInput(projectRoot / imported.metadataPath);
        const json metadata = json::parse(metadataInput);
        if (metadata.value("license", "") != "test-fixture" ||
            metadata.value("sourceLabel", "") != "asset-pipeline-smoke") {
            return fail("asset metadata did not preserve license/source labels.");
        }
    } catch (const std::exception& exception) {
        return fail(std::string("could not parse generated asset artifacts: ") + exception.what());
    }

    const SceneValidationResult assetValidation = state_.ValidateAssets();
    if (!assetValidation.ok) {
        return fail("asset validation failed after import: " + JoinInline(assetValidation.diagnostics, 4));
    }

    Entity& entity = state_.CreateEntity("Asset Pipeline Render Probe",
                                         {MakeTransformComponent(),
                                          MakeMeshPlaceholderComponent(imported.id, "PrototypeBlue")});
    entity.position = {0.0f, 0.5f, 0.0f};
    state_.SelectEntity(entity.id);
    RenderViewportScene(640, 360);
    if (viewportLastRenderedResourceMeshCount_ < 1) {
        return fail("viewport renderer did not resolve the imported model as a resource-backed mesh.");
    }

    state_.AddActivity("smoke.asset-pipeline", "Passed",
                       "glTF import, dependency copy, resource/metadata/thumbnail artifacts, validation, and renderer lookup passed.");
    return true;
}

bool EditorApp::RunExpandedToolApiSmokeTest() {
    if (!options_.smokeTestExpandedTools) {
        return true;
    }

    const std::filesystem::path sourceFolder =
        std::filesystem::path(state_.ProjectRootPathString()) / "Temp" / "ExpandedToolApiSource";
    const std::filesystem::path sourceTexture = sourceFolder / "SmokeTexture.png";
    try {
        std::filesystem::create_directories(sourceFolder);
        std::ofstream(sourceTexture, std::ios::binary) << "smoke texture placeholder\n";
    } catch (const std::exception& exception) {
        state_.AddLog(LogLevel::Error,
                      "Expanded tool API smoke failed: could not create asset fixture: " + std::string(exception.what()));
        return false;
    }

    json commands = json::array({
        json{{"type", "scene.createEntity"},
             {"name", "Expanded Smoke Parent"},
             {"components", json::array({
                  json{{"type", "Transform"}, {"properties", json::object()}},
                  json{{"type", "MeshRenderer"},
                       {"properties", json{{"mesh", "UnitCube"}, {"material", "PrototypeGray"}}}},
              })}},
        json{{"type", "scene.createEntity"},
             {"name", "Expanded Smoke Child"},
             {"components", json::array({json{{"type", "Transform"}, {"properties", json::object()}}})}},
        json{{"type", "scene.setParent"}, {"targetName", "Expanded Smoke Child"}, {"parentName", "Expanded Smoke Parent"}},
        json{{"type", "asset.import"},
             {"path", sourceTexture.string()},
             {"source", "expanded-tool-smoke"},
             {"license", "test-fixture"}},
        json{{"type", "asset.createMaterial"}, {"name", "SmokeMaterial"}, {"color", "0.25, 0.70, 1.00"}},
        json{{"type", "asset.assignMaterial"}, {"targetName", "Expanded Smoke Parent"}, {"material", "SmokeMaterial"}},
        json{{"type", "script.create"},
             {"path", "Assets/Scripts/Gameplay/SmokeToolScript.cs"},
             {"content", "public class SmokeToolScript\n{\n    public bool enabled = true;\n}\n"}},
        json{{"type", "script.attachToEntity"},
             {"targetName", "Expanded Smoke Parent"},
             {"path", "Assets/Scripts/Gameplay/SmokeToolScript.cs"},
             {"componentType", "SmokeToolScript"}},
        json{{"type", "scene.setComponentProperty"},
             {"targetName", "Expanded Smoke Parent"},
             {"componentType", "MeshRenderer"},
             {"propertyName", "material"},
             {"value", "SmokeMaterial"}},
        json{{"type", "script.getDiagnostics"}, {"path", "Assets/Scripts/Gameplay/SmokeToolScript.cs"}},
        json{{"type", "script.compile"}},
        json{{"type", "validate.project"}},
        json{{"type", "validate.assets"}},
        json{{"type", "validate.scripts"}},
        json{{"type", "plugin.create"}, {"name", "SmokeGeneratedTool"}},
        json{{"type", "plugin.compile"}, {"name", "SmokeGeneratedTool"}},
        json{{"type", "plugin.test"}, {"name", "SmokeGeneratedTool"}},
        json{{"type", "plugin.install"}, {"name", "SmokeGeneratedTool"}},
        json{{"type", "plugin.enable"}, {"name", "SmokeGeneratedTool"}},
        json{{"type", "build.runSmokeTest"}},
        json{{"type", "runtime.play"}},
        json{{"type", "runtime.pause"}},
        json{{"type", "runtime.stop"}},
        json{{"type", "runtime.getLogs"}},
        json{{"type", "scene.deleteEntity"}, {"targetName", "Expanded Smoke Child"}},
        json{{"type", "scene.save"}},
    });

    const json providerResult{
        {"result_type", "proposed_command_batch"},
        {"message", "Expanded tool API smoke command batch."},
        {"command_batch", json{{"version", 1}, {"name", "Expanded tool API smoke"}, {"commands", commands}}},
    };

    const NormalizedProviderResult normalized =
        orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, providerResult.dump(), gateway_);
    proposedActions_.push_back(normalized);
    const size_t actionIndex = proposedActions_.size() - 1;
    if (normalized.type != ProviderResultType::ProposedCommandBatch || !normalized.schemaValid ||
        !normalized.canApprove) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: expanded provider batch was not approvable.");
        for (const std::string& diagnostic : normalized.diagnostics) {
            state_.AddLog(LogLevel::Error, diagnostic);
        }
        return false;
    }

    ApproveProposedAction(actionIndex);
    if (!hasLastGatewayResult_ || !lastGatewayResult_.batch.applied || !lastGatewayResult_.batch.ok) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: approved batch did not apply cleanly.");
        return false;
    }

    Entity* parent = state_.FindEntityByName("Expanded Smoke Parent");
    if (parent == nullptr || state_.FindEntityByName("Expanded Smoke Child") != nullptr) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: scene create/delete commands had wrong result.");
        return false;
    }

    bool materialAssigned = false;
    bool scriptAttached = false;
    for (const Component& component : parent->components) {
        if (component.type == "MeshRenderer") {
            for (const ComponentProperty& property : component.properties) {
                materialAssigned = materialAssigned || (property.name == "material" && property.value == "SmokeMaterial");
            }
        }
        if (component.type == "SmokeToolScript") {
            scriptAttached = true;
        }
    }
    if (!materialAssigned || !scriptAttached) {
        state_.AddLog(LogLevel::Error,
                      "Expanded tool API smoke failed: material assignment or script attach did not persist on entity.");
        return false;
    }

    if (state_.Assets().size() < 2 || !std::filesystem::exists(state_.AssetDatabasePathString()) ||
        !std::filesystem::exists(std::filesystem::path(state_.ProjectRootPathString()) /
                                 "Assets" / "Scripts" / "Gameplay" / "SmokeToolScript.cs") ||
        !std::filesystem::exists(state_.ScriptCompileManifestPathString()) ||
        !std::filesystem::exists(std::filesystem::path(state_.ProjectRootPathString()) /
                                 "Library" / "Scripts" / "bin" / "AINative.GameScripts.dll") ||
        !std::filesystem::exists(std::filesystem::path(state_.ProjectRootPathString()) /
                                 "Plugins" / "GeneratedTools" / "SmokeGeneratedTool" / "plugin.json") ||
        !std::filesystem::exists(std::filesystem::path(state_.ProjectRootPathString()) /
                                 "Library" / "Plugins" / "SmokeGeneratedTool" / "compile_report.json") ||
        !std::filesystem::exists(std::filesystem::path(state_.ProjectRootPathString()) /
                                 "Library" / "Plugins" / "SmokeGeneratedTool" / "test_report.json") ||
        !std::filesystem::exists(std::filesystem::path(state_.ProjectRootPathString()) /
                                 "Library" / "Plugins" / "SmokeGeneratedTool" / "install_manifest.json")) {
        state_.AddLog(LogLevel::Error,
                      "Expanded tool API smoke failed: asset metadata, script compiler output, plugin reports, or plugin install metadata is missing.");
        return false;
    }

    const bool pluginEnabled = std::any_of(state_.Plugins().begin(), state_.Plugins().end(), [](const PluginRecord& plugin) {
        return plugin.name == "SmokeGeneratedTool" && plugin.installed && plugin.enabled &&
               plugin.installPath == "Library/Plugins/SmokeGeneratedTool";
    });
    if (!pluginEnabled) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: plugin install/enable state was not stored.");
        return false;
    }

    if (!state_.CanUndoSceneEdit() || !lastGatewayResult_.batch.undoAvailable) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: undo was not available after scene command batch.");
        return false;
    }
    if (!state_.UndoSceneEdit() || state_.FindEntityByName("Expanded Smoke Parent") != nullptr) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: undo did not restore the pre-batch scene.");
        return false;
    }
    if (!state_.RedoSceneEdit() || state_.FindEntityByName("Expanded Smoke Parent") == nullptr ||
        state_.FindEntityByName("Expanded Smoke Child") != nullptr) {
        state_.AddLog(LogLevel::Error, "Expanded tool API smoke failed: redo did not restore the applied scene state.");
        return false;
    }

    state_.AddActivity("smoke.expanded-tool-api", "Passed",
                       "Expanded commands, provider approval, asset/script/plugin persistence, and undo/redo passed.");
    return true;
}

bool EditorApp::RunProviderFileChangeSmokeTest() {
    if (!options_.smokeTestProviderFileChange) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        state_.AddLog(LogLevel::Error, "Provider file-change smoke failed: " + message);
        return false;
    };

    std::error_code filesystemError;
    const std::filesystem::path targetPath =
        std::filesystem::path(state_.ProjectRootPathString()) / "Assets" / "ProviderChangeSmoke.txt";
    std::filesystem::remove(targetPath, filesystemError);
    std::filesystem::create_directories(targetPath.parent_path(), filesystemError);
    if (filesystemError) {
        return fail("could not prepare target folder: " + filesystemError.message());
    }

    const std::filesystem::path relativeTarget = std::filesystem::relative(targetPath, std::filesystem::current_path(),
                                                                          filesystemError);
    if (filesystemError) {
        return fail("could not derive relative target path: " + filesystemError.message());
    }

    const std::string sessionId = "provider-file-change-smoke";
    const std::string installedContent = "installed provider file change\n";
    const json providerResult{
        {"result_type", "proposed_file_change"},
        {"message", "Install provider file-change smoke fixture."},
        {"file_change",
         json{{"path", relativeTarget.generic_string()},
              {"change_type", "create"},
              {"summary", "Create a provider file-change smoke fixture."},
              {"session_id", sessionId},
              {"content", installedContent},
              {"diff", "--- /dev/null\n+++ " + relativeTarget.generic_string() + "\n@@\n+installed provider file change\n"}}},
    };

    const NormalizedProviderResult normalized =
        orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, providerResult.dump(), gateway_);
    proposedActions_.push_back(normalized);
    const size_t actionIndex = proposedActions_.size() - 1;
    if (normalized.type != ProviderResultType::ProposedFileChange || !normalized.schemaValid ||
        !normalized.canApprove || !normalized.hasFileChange) {
        return fail("full-content proposed_file_change was not normalized as an approvable action.");
    }

    if (!ApplyProposedFileChange(actionIndex)) {
        return fail("full-content proposed_file_change did not apply.");
    }
    if (!std::filesystem::exists(targetPath, filesystemError) ||
        ReadTextFilePreview(targetPath, 1024) != installedContent) {
        return fail("applied file content was not written to the target.");
    }

    const std::filesystem::path logPath = AgentMemoryDirectoryPath() / "provider_file_changes.jsonl";
    const std::string afterApplyLog = ReadTextFilePreview(logPath, 64000);
    if (afterApplyLog.find(sessionId) == std::string::npos ||
        afterApplyLog.find("\"event\":\"applied\"") == std::string::npos) {
        return fail("provider_file_changes.jsonl did not record the apply session.");
    }

    if (!RevertProposedFileChange(actionIndex)) {
        return fail("applied file change did not revert.");
    }
    if (std::filesystem::exists(targetPath, filesystemError)) {
        return fail("revert did not remove the created target file.");
    }
    const std::string afterRevertLog = ReadTextFilePreview(logPath, 64000);
    if (afterRevertLog.find(sessionId) == std::string::npos ||
        afterRevertLog.find("\"event\":\"reverted\"") == std::string::npos) {
        return fail("provider_file_changes.jsonl did not record the revert session.");
    }

    const std::filesystem::path diffOnlyPath =
        std::filesystem::path(state_.ProjectRootPathString()) / "Assets" / "ProviderDiffOnlySmoke.txt";
    const std::filesystem::path diffOnlyRelative =
        std::filesystem::relative(diffOnlyPath, std::filesystem::current_path(), filesystemError);
    const json diffOnlyProviderResult{
        {"result_type", "proposed_file_change"},
        {"message", "Diff-only provider file-change smoke fixture."},
        {"file_change",
         json{{"path", diffOnlyRelative.generic_string()},
              {"change_type", "modify"},
              {"summary", "Preview a diff-only change."},
              {"session_id", "provider-file-change-diff-only-smoke"},
              {"diff", "--- a/file\n+++ b/file\n@@\n+diff only\n"}}},
    };
    const NormalizedProviderResult diffOnly =
        orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, diffOnlyProviderResult.dump(), gateway_);
    proposedActions_.push_back(diffOnly);
    const size_t diffOnlyIndex = proposedActions_.size() - 1;
    if (diffOnly.type != ProviderResultType::ProposedFileChange || !diffOnly.canApprove ||
        !diffOnly.hasFileChange) {
        return fail("diff-only proposed_file_change did not remain previewable.");
    }
    if (ApplyProposedFileChange(diffOnlyIndex) || proposedActions_[diffOnlyIndex].applied ||
        std::filesystem::exists(diffOnlyPath, filesystemError)) {
        return fail("diff-only proposed_file_change wrote a file instead of failing safely.");
    }
    if (proposedActions_[diffOnlyIndex].diagnostics.empty()) {
        return fail("diff-only proposed_file_change failure did not record diagnostics.");
    }

    state_.AddActivity("smoke.provider-file-change", "Passed",
                       "Provider file-change preview, apply, JSONL session log, revert, and diff-only failure recovery passed.");
    return true;
}

bool EditorApp::RunSceneIntegrationSmokeTest() {
    if (!options_.smokeTestSceneIntegration) {
        return true;
    }

    const Entity* renderable = nullptr;
    for (const Entity& entity : state_.Entities()) {
        if (HasRenderableMesh(state_, entity)) {
            renderable = &entity;
            break;
        }
    }

    if (renderable == nullptr) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: no renderable entity was available.");
        return false;
    }

    const int selectedId = renderable->id;
    const std::array<float, 3> updatedPosition{renderable->position[0] + 2.5f, renderable->position[1],
                                               renderable->position[2]};
    state_.SelectEntity(selectedId);
    if (state_.SelectedEntityId() != selectedId) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: hierarchy selection did not update editor state.");
        return false;
    }

    if (!state_.SetEntityTransform(selectedId, &updatedPosition, nullptr, nullptr)) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: inspector transform edit could not be applied.");
        return false;
    }

    const Entity* selected = state_.FindEntity(selectedId);
    if (selected == nullptr || selected->position != updatedPosition) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: selected transform did not update state.");
        return false;
    }

    const std::string expectedPositionText = Vec3ToUiString(updatedPosition);
    bool transformComponentSynced = false;
    for (const Component& component : selected->components) {
        if (component.type != "Transform") {
            continue;
        }
        for (const ComponentProperty& property : component.properties) {
            if (property.name == "position" && property.value == expectedPositionText) {
                transformComponentSynced = true;
                break;
            }
        }
    }

    if (!transformComponentSynced) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: Transform component properties were not synced.");
        return false;
    }

    const std::string smokeRename = "Smoke Hero Spawn";
    CopyStringToBuffer(inspectorNameInput_, smokeRename);
    if (!RenameSelectedEntityFromInspector(inspectorNameInput_.data())) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: inspector rename path rejected a valid name.");
        return false;
    }
    selected = state_.FindEntity(selectedId);
    if (selected == nullptr || selected->name != smokeRename ||
        inspectorNameCommittedValue_ != smokeRename || inspectorNameStatus_.find("Renamed") == std::string::npos) {
        state_.AddLog(LogLevel::Error,
                      "Scene integration smoke failed: inspector rename did not update selected entity state and status.");
        return false;
    }

    FocusSelectedEntity();
    if (viewportCameraTarget_ != updatedPosition ||
        viewportCameraDistance_ < 2.49f || viewportCameraDistance_ > 60.01f) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: Frame Selected did not move the Scene camera pivot.");
        return false;
    }

    const ImVec2 smokeViewportSize(900.0f, 540.0f);
    const CameraBasis smokeCamera =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    const Vec3 gizmoOrigin = MakeVec3(selected->position);
    const float gizmoLength = MaxAbsScale(*selected) * 1.35f;
    ImVec2 gizmoDragStart;
    ImVec2 gizmoDragEnd;
    if (!ProjectWorldToViewport(gizmoOrigin + AxisVector(1) * (gizmoLength * 0.35f), smokeCamera, smokeViewportSize,
                                &gizmoDragStart) ||
        !ProjectWorldToViewport(gizmoOrigin + AxisVector(1) * (gizmoLength * 0.85f), smokeCamera, smokeViewportSize,
                                &gizmoDragEnd)) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: move gizmo axis could not be projected.");
        return false;
    }
    if (PickMoveGizmoAxis(gizmoDragStart, smokeViewportSize) != 1) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: move gizmo X axis was not pickable.");
        return false;
    }

    const float xBeforeGizmoDrag = selected->position[0];
    BeginMoveGizmoDrag(1, gizmoDragStart, smokeViewportSize);
    UpdateMoveGizmoDrag(gizmoDragEnd, smokeViewportSize);
    EndMoveGizmoDrag();
    selected = state_.FindEntity(selectedId);
    if (selected == nullptr || selected->position[0] <= xBeforeGizmoDrag + 0.05f) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: move gizmo drag did not move the selected entity.");
        return false;
    }

    ImVec2 centerHandleStart;
    if (!ProjectWorldToViewport(MakeVec3(selected->position), smokeCamera, smokeViewportSize, &centerHandleStart)) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: move gizmo center handle could not be projected.");
        return false;
    }
    if (PickMoveGizmoAxis(centerHandleStart, smokeViewportSize) != kViewportMoveCenterHandle) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: move gizmo center handle was not pickable.");
        return false;
    }
    const std::array<float, 3> beforeCenterDrag = selected->position;
    const ImVec2 centerHandleEnd(centerHandleStart.x + 44.0f, centerHandleStart.y - 26.0f);
    BeginMoveGizmoDrag(kViewportMoveCenterHandle, centerHandleStart, smokeViewportSize);
    UpdateMoveGizmoDrag(centerHandleEnd, smokeViewportSize);
    EndMoveGizmoDrag();
    selected = state_.FindEntity(selectedId);
    if (selected == nullptr ||
        (NearlyEqual(selected->position[0], beforeCenterDrag[0]) &&
         NearlyEqual(selected->position[1], beforeCenterDrag[1]) &&
         NearlyEqual(selected->position[2], beforeCenterDrag[2]))) {
        state_.AddLog(LogLevel::Error, "Scene integration smoke failed: center handle drag did not move the selected entity.");
        return false;
    }

    state_.AddActivity("smoke.scene-integration", "Passed",
                       "Selected " + selected->name + ", edited its transform, and dragged the X axis plus center move handle.");
    return true;
}

bool EditorApp::RunPlayModeSmokeTest() {
    if (!options_.smokeTestPlayMode) {
        return true;
    }

    Entity* spinEntity = nullptr;
    for (const Entity& entity : state_.Entities()) {
        if (HasRenderableMesh(state_, entity)) {
            spinEntity = state_.FindEntity(entity.id);
            break;
        }
    }

    if (spinEntity == nullptr) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: no renderable entity was available.");
        return false;
    }

    const int spinEntityId = spinEntity->id;
    const std::array<float, 3> originalRotation = spinEntity->rotation;
    state_.SelectEntity(spinEntityId);
    if (!HasComponentType(*spinEntity, "SpinRuntime")) {
        state_.AddComponentToEntity(spinEntityId, MakeSpinRuntimeComponent());
    }

    StartOrResumePlayMode();
    if (!state_.IsPlaying()) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: Play did not enter Playing state.");
        return false;
    }
    if (state_.PlayElapsedSeconds() != 0.0f) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: elapsed time was not reset on Play.");
        return false;
    }

    state_.UpdatePlayMode(0.5f);
    const Entity* runtimeEntity = state_.FindEntity(spinEntityId);
    if (runtimeEntity == nullptr || state_.PlayElapsedSeconds() <= 0.0f) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: runtime update did not advance elapsed time.");
        return false;
    }
    if (NearlyEqual(runtimeEntity->rotation[1], originalRotation[1])) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: SpinRuntime did not rotate during Playing state.");
        return false;
    }

    PausePlayMode();
    if (!state_.IsPaused()) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: Pause did not enter Paused state.");
        return false;
    }

    const float pausedElapsed = state_.PlayElapsedSeconds();
    const std::array<float, 3> pausedRotation = runtimeEntity->rotation;
    state_.UpdatePlayMode(0.5f);
    runtimeEntity = state_.FindEntity(spinEntityId);
    if (runtimeEntity == nullptr || !NearlyEqual(state_.PlayElapsedSeconds(), pausedElapsed) ||
        !NearlyEqual(runtimeEntity->rotation[1], pausedRotation[1])) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: Pause did not freeze elapsed time and SpinRuntime.");
        return false;
    }

    StopPlayMode();
    const Entity* restoredEntity = state_.FindEntity(spinEntityId);
    if (!state_.IsEditMode() || restoredEntity == nullptr ||
        !NearlyEqual(restoredEntity->rotation[0], originalRotation[0]) ||
        !NearlyEqual(restoredEntity->rotation[1], originalRotation[1]) ||
        !NearlyEqual(restoredEntity->rotation[2], originalRotation[2])) {
        state_.AddLog(LogLevel::Error, "Play mode smoke failed: Stop did not restore the edit-mode transform.");
        return false;
    }

    state_.AddActivity("smoke.play-mode", "Passed",
                       "Enter, elapsed update, pause freeze, and stop restore all passed.");
    return true;
}

bool EditorApp::RunPhysicsSmokeTest() {
    if (!options_.smokeTestPhysics) {
        return true;
    }

    std::vector<std::string> diagnostics;
    if (!RunPhysicsSelfTests(&diagnostics)) {
        for (const std::string& diagnostic : diagnostics) {
            state_.AddLog(LogLevel::Error, "Physics smoke failed: " + diagnostic);
        }
        return false;
    }

    state_.AddActivity("smoke.physics", "Passed", diagnostics.empty() ? "physics.selftest passed." : diagnostics.back());
    return true;
}

bool EditorApp::RunUnifiedTerrainProofSmokeTest() {
    if (!options_.smokeTestUnifiedTerrainProof) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Unified terrain proof failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Unified terrain proof failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot =
        std::filesystem::current_path() / "projects" / "UnifiedVolumetricTerrainProof";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create proof project: " + error);
    }
    if (!state_.CreateScene(std::filesystem::path("Assets") / "Scenes" / "UnifiedVolumetricTerrainProof.scene.json",
                            &error)) {
        return fail("could not create proof scene: " + error);
    }
    state_.ClearScene();

    auto makeVolumeLayer = [](std::string name, std::array<float, 4> color, std::string material) {
        TerrainVolumeLayer layer;
        layer.name = std::move(name);
        layer.displayColor = color;
        layer.material = std::move(material);
        layer.tiling = 9.0f;
        layer.roughness = 0.92f;
        layer.metalness = 0.0f;
        return layer;
    };

    TerrainData data;
    data.resolution = 33;
    data.chunkSize = 8;
    data.size = {40.0f, 4.0f, 28.0f};
    data.layers = {MakeTerrainLayerFromPreset(kTerrainLayerPresets[0]),
                   MakeTerrainLayerFromPreset(kTerrainLayerPresets[1]),
                   MakeTerrainLayerFromPreset(kTerrainLayerPresets[2])};
    NormalizeTerrainData(&data);
    data.backend = TerrainBackend::Volumetric;
    data.volumeEnabled = true;
    data.volume.resolution = {49, 25, 33};
    data.volume.chunkSize = 12;
    data.volume.size = {40.0f, 16.0f, 28.0f};
    data.volume.collisionEnabled = true;
    data.volume.layers = {
        makeVolumeLayer("Surface Grass", {0.34f, 0.47f, 0.26f, 1.0f}, "TerrainSurfaceGrass"),
        makeVolumeLayer("Interior Stone", {0.42f, 0.43f, 0.40f, 1.0f}, "TerrainInteriorStone"),
        makeVolumeLayer("Packed Soil", {0.34f, 0.29f, 0.22f, 1.0f}, "TerrainPackedSoil"),
    };
    data.volume.densities.clear();
    data.volume.weights.clear();
    EnsureTerrainVolume(&data);

    const float densityBelow = SampleCaveLocal(data.volume, {0.0f, -5.0f, 0.0f}).density;
    const float densityAbove = SampleCaveLocal(data.volume, {0.0f, 5.0f, 0.0f}).density;
    if (densityBelow <= 0.0f || densityAbove >= 0.0f) {
        return fail("flat seed density sign convention is wrong.");
    }

    auto applyTunnel = [&](std::array<float, 3> a, std::array<float, 3> b, float radius) {
        TerrainVolumeBrushSettings brush;
        brush.mode = TerrainVolumeBrushMode::RemoveMaterial;
        brush.falloff = TerrainVolumeFalloffCurve::Smooth;
        brush.radius = radius;
        brush.strength = 1.0f;
        brush.opacity = 1.0f;
        brush.useSegment = true;
        brush.segmentStart = a;
        brush.segmentEnd = b;
        return ApplyTerrainVolumeBrush(&data, b, brush);
    };
    auto addUniqueChunk = [](std::vector<int>* chunks, int chunk) {
        if (chunks != nullptr && std::find(chunks->begin(), chunks->end(), chunk) == chunks->end()) {
            chunks->push_back(chunk);
        }
    };

    std::vector<int> proofDirtyChunks;
    const std::vector<std::array<float, 3>> tunnelPath = {
        {-16.0f, 1.0f, 0.0f},  {-14.0f, 0.0f, 0.0f},  {-12.0f, -1.2f, 0.0f},
        {-9.0f, -2.4f, 0.0f}, {-5.0f, -3.0f, 0.0f},  {0.0f, -3.0f, 0.0f},
        {5.0f, -3.0f, 0.0f},  {9.0f, -2.5f, 0.0f},
    };
    bool tunnelChanged = false;
    for (size_t index = 1; index < tunnelPath.size(); ++index) {
        const TerrainVolumeBrushResult result = applyTunnel(tunnelPath[index - 1], tunnelPath[index], 2.25f);
        tunnelChanged = tunnelChanged || result.changed;
        for (int chunk : result.dirty.chunks) {
            addUniqueChunk(&proofDirtyChunks, chunk);
        }
    }
    if (!tunnelChanged || proofDirtyChunks.size() < 3) {
        return fail("proof tunnel did not carve across at least three terrain-volume chunks.");
    }

    TerrainVolumeBrushSettings entranceBowl;
    entranceBowl.mode = TerrainVolumeBrushMode::RemoveMaterial;
    entranceBowl.falloff = TerrainVolumeFalloffCurve::Smooth;
    entranceBowl.radius = 3.4f;
    entranceBowl.strength = 1.0f;
    entranceBowl.opacity = 1.0f;
    const TerrainVolumeBrushResult entranceBowlResult =
        ApplyTerrainVolumeBrush(&data, {-14.0f, 0.0f, 0.0f}, entranceBowl);
    if (!entranceBowlResult.changed) {
        return fail("proof entrance bowl did not carve a visible terrain-volume opening.");
    }
    for (int chunk : entranceBowlResult.dirty.chunks) {
        addUniqueChunk(&proofDirtyChunks, chunk);
    }

    TerrainVolumeBrushSettings chamber;
    chamber.mode = TerrainVolumeBrushMode::RemoveMaterial;
    chamber.falloff = TerrainVolumeFalloffCurve::Smooth;
    chamber.radius = 4.0f;
    chamber.strength = 1.0f;
    chamber.opacity = 1.0f;
    const TerrainVolumeBrushResult chamberResult = ApplyTerrainVolumeBrush(&data, {9.0f, -2.5f, 0.0f}, chamber);
    if (!chamberResult.changed) {
        return fail("proof chamber brush did not carve terrain-owned empty space.");
    }
    for (int chunk : chamberResult.dirty.chunks) {
        addUniqueChunk(&proofDirtyChunks, chunk);
    }

    const TerrainVolumeBrushResult shaftResult = applyTunnel({9.0f, -2.5f, 0.0f}, {11.0f, 1.0f, 3.0f}, 1.7f);
    if (!shaftResult.changed) {
        return fail("proof upward exit brush did not carve terrain-owned empty space.");
    }
    for (int chunk : shaftResult.dirty.chunks) {
        addUniqueChunk(&proofDirtyChunks, chunk);
    }

    TerrainVolumeBrushSettings addMaterial;
    addMaterial.mode = TerrainVolumeBrushMode::AddMaterial;
    addMaterial.falloff = TerrainVolumeFalloffCurve::Smooth;
    addMaterial.radius = 2.2f;
    addMaterial.strength = 1.0f;
    addMaterial.opacity = 1.0f;
    const TerrainVolumeBrushResult addResult = ApplyTerrainVolumeBrush(&data, {4.0f, 1.2f, -7.0f}, addMaterial);
    if (!addResult.changed || SampleCaveLocal(data.volume, {4.0f, 1.2f, -7.0f}).density <= 0.0f) {
        return fail("AddMaterial did not create positive-density terrain-owned solid material.");
    }

    TerrainVolumeBrushSettings paintInterior;
    paintInterior.mode = TerrainVolumeBrushMode::PaintMaterial;
    paintInterior.falloff = TerrainVolumeFalloffCurve::Smooth;
    paintInterior.radius = 4.5f;
    paintInterior.strength = 1.0f;
    paintInterior.opacity = 1.0f;
    paintInterior.activeLayerIndex = 1;
    ApplyTerrainVolumeBrush(&data, {-14.0f, -0.6f, 0.0f}, paintInterior);
    ApplyTerrainVolumeBrush(&data, {2.0f, -3.0f, 0.0f}, paintInterior);
    ApplyTerrainVolumeBrush(&data, {9.0f, -2.5f, 0.0f}, paintInterior);

    const float digCenterDensity = SampleCaveLocal(data.volume, {-5.0f, -3.0f, 0.0f}).density;
    const float outsideUndergroundDensity = SampleCaveLocal(data.volume, {16.0f, -3.0f, 8.0f}).density;
    if (digCenterDensity >= 0.0f || outsideUndergroundDensity <= 0.0f) {
        return fail("RemoveMaterial did not create empty space while leaving outside underground terrain solid.");
    }
    if (SampleCaveLocal(data.volume, {-10.0f, -2.2f, 0.0f}).density >= 0.0f ||
        SampleCaveLocal(data.volume, {0.0f, -3.0f, 0.0f}).density >= 0.0f ||
        SampleCaveLocal(data.volume, {10.0f, -2.0f, 0.5f}).density >= 0.0f) {
        return fail("chunk-border tunnel samples were not continuous empty terrain volume.");
    }

    TerrainVolumeMesh proofMesh = TerrainSurfaceExtractor::Extract(data.volume);
    if (proofMesh.chunks.empty() || proofMesh.boundsMax[1] <= proofMesh.boundsMin[1]) {
        return fail("terrain volume surface extractor produced an invalid proof mesh.");
    }
    if (!RebuildCaveMeshChunks(data.volume, proofDirtyChunks, &proofMesh)) {
        return fail("terrain volume dirty chunk rebuild failed for proof tunnel.");
    }

    Entity& terrain = state_.CreateEntity("Unified Volumetric Terrain",
                                          {MakeTransformComponent(),
                                           MakeTerrainComponent(data.resolution, data.size, data.chunkSize)});
    terrain.isStatic = true;
    Component* terrainComponent = FindTerrainComponent(terrain);
    if (terrainComponent == nullptr) {
        return fail("created proof terrain has no Terrain component.");
    }
    SaveTerrainDataToComponent(data, terrainComponent);

    Entity& sun = state_.CreateEntity("Sun", {MakeTransformComponent(), MakeLightComponent("Directional")});
    sun.rotation = {48.0f, -32.0f, 0.0f};

    Component cameraComponent = MakeCameraComponent();
    SetComponentPropertyForUi(cameraComponent, "clearColor", "0.05, 0.065, 0.075, 1");
    Entity& camera = state_.CreateEntity("Main Camera", {MakeTransformComponent(), cameraComponent});
    camera.position = {-20.0f, 4.2f, 8.0f};
    camera.rotation = {-24.0f, 37.0f, 0.0f};

    state_.SelectEntity(terrain.id);
    state_.MarkSceneDirty("Generated unified volumetric terrain proof scene.");
    if (!state_.SaveProject(&error)) {
        return fail("could not save proof project: " + error);
    }

    if (!state_.OpenProject(projectRoot, &error)) {
        return fail("could not reload proof project: " + error);
    }

    const std::vector<std::string> bannedTokens = {"cavesystem",           "cavevolume",
                                                   "cavebranch",           "caveworm",
                                                   "main worm",            "lower branch",
                                                   "upper shaft",          "cave collision probe",
                                                   "cave system a",        "cave system b",
                                                   "cave system c"};
    auto containsBanned = [&](const std::string& value) {
        const std::string lower = ToLower(value);
        return std::any_of(bannedTokens.begin(), bannedTokens.end(), [&](const std::string& token) {
            return lower.find(token) != std::string::npos;
        });
    };

    Entity* reloadedTerrain = state_.FindEntityByName("Unified Volumetric Terrain");
    Entity* reloadedCamera = state_.FindEntityByName("Main Camera");
    Entity* reloadedSun = state_.FindEntityByName("Sun");
    if (reloadedTerrain == nullptr || reloadedCamera == nullptr || reloadedSun == nullptr) {
        return fail("proof scene reload is missing terrain, camera, or sun.");
    }
    state_.SelectEntity(reloadedTerrain->id);

    int terrainCount = 0;
    int cameraCount = 0;
    int lightCount = 0;
    std::ostringstream audit;
    audit << "UnifiedVolumetricTerrainProof active render/collision audit\n";
    for (const Entity& entity : state_.Entities()) {
        if (!state_.IsEntityActiveInHierarchy(entity.id)) {
            continue;
        }
        if (containsBanned(entity.name)) {
            return fail("proof scene contains banned legacy cave entity name: " + entity.name);
        }
        const bool hasTerrain = FindTerrainComponent(entity) != nullptr;
        const bool hasCamera = HasComponentType(entity, "Camera");
        const bool hasLight = HasComponentType(entity, "Light");
        const bool hasMesh = HasComponentType(entity, "MeshRenderer");
        const bool hasCave = HasComponentType(entity, "CaveVolume");
        if (hasTerrain) {
            ++terrainCount;
        }
        if (hasCamera) {
            ++cameraCount;
        }
        if (hasLight) {
            ++lightCount;
        }
        for (const Component& component : entity.components) {
            if (containsBanned(component.type)) {
                return fail("proof scene contains banned legacy cave component: " + component.type);
            }
        }
        std::string meshSource = "none";
        std::string materialSource = "none";
        std::string collisionSource = "none";
        bool terrainOwned = false;
        bool heightfieldRenderer = false;
        bool volumeMesher = false;
        bool legacyCave = hasCave;
        if (hasTerrain) {
            TerrainData terrainData;
            const Component* component = FindTerrainComponent(entity);
            if (component != nullptr && LoadTerrainDataFromComponent(*component, &terrainData) &&
                TerrainUsesVolumetric(terrainData)) {
                meshSource = "TerrainVolumeData -> TerrainSurfaceExtractor";
                materialSource = "TerrainMaterialField";
                collisionSource = "TerrainVolumeData -> Terrain.VolumeSurface";
                terrainOwned = true;
                volumeMesher = true;
            } else {
                meshSource = "Legacy Terrain Heightfield";
                materialSource = "Terrain heightfield layers";
                collisionSource = "Terrain.Heightfield";
                heightfieldRenderer = true;
            }
        } else if (hasMesh) {
            meshSource = "MeshRenderer";
            materialSource = "MeshRenderer material";
        } else if (hasCamera) {
            meshSource = "Camera view";
        } else if (hasLight) {
            meshSource = "Light";
        }
        audit << "- " << entity.name << " | components=";
        for (size_t componentIndex = 0; componentIndex < entity.components.size(); ++componentIndex) {
            if (componentIndex > 0) {
                audit << ",";
            }
            audit << entity.components[componentIndex].type;
        }
        audit << " | meshSource=" << meshSource << " | materialSource=" << materialSource
              << " | collisionSource=" << collisionSource << " | terrainOwned="
              << (terrainOwned ? "true" : "false") << " | standaloneCave=" << (hasCave ? "true" : "false")
              << " | legacyCave=" << (legacyCave ? "true" : "false")
              << " | heightfieldRenderer=" << (heightfieldRenderer ? "true" : "false")
              << " | terrainVolumeMesher=" << (volumeMesher ? "true" : "false") << "\n";
    }
    if (terrainCount != 1 || cameraCount != 1 || lightCount != 1 || state_.Entities().size() != 3) {
        return fail("proof scene hierarchy is not exactly one terrain, one camera, and one sun.");
    }

    const std::filesystem::path auditPath = projectRoot / "UnifiedVolumetricTerrainProof.audit.txt";
    {
        std::ofstream auditOutput(auditPath);
        auditOutput << audit.str();
    }

    const Component* reloadedTerrainComponent = FindTerrainComponent(*reloadedTerrain);
    TerrainData reloadedData;
    if (reloadedTerrainComponent == nullptr ||
        !LoadTerrainDataFromComponent(*reloadedTerrainComponent, &reloadedData) ||
        !TerrainUsesVolumetric(reloadedData)) {
        return fail("reloaded proof terrain does not own valid TerrainVolumeData.");
    }
    if (std::any_of(reloadedData.holes.begin(), reloadedData.holes.end(), [](std::uint8_t value) {
            return value != 0;
        })) {
        return fail("proof scene used old heightfield holes instead of terrain volume carving.");
    }

    const float reloadedBelow = SampleCaveLocal(reloadedData.volume, {0.0f, -5.0f, 0.0f}).density;
    const float reloadedAbove = SampleCaveLocal(reloadedData.volume, {0.0f, 5.0f, 0.0f}).density;
    const float reloadedDigCenter = SampleCaveLocal(reloadedData.volume, {-5.0f, -3.0f, 0.0f}).density;
    const float reloadedOutsideSolid = SampleCaveLocal(reloadedData.volume, {16.0f, -3.0f, 8.0f}).density;
    if (reloadedBelow <= 0.0f || reloadedAbove >= 0.0f || reloadedDigCenter >= 0.0f ||
        reloadedOutsideSolid <= 0.0f) {
        return fail("reloaded proof density sign or carved-space samples are invalid.");
    }

    const std::array<float, 3> entranceWorld =
        TerrainVolumeLocalToWorld(reloadedData, *reloadedTerrain, {-14.0f, 0.0f, 0.0f});
    const std::array<float, 3> chamberWorld =
        TerrainVolumeLocalToWorld(reloadedData, *reloadedTerrain, {9.0f, -2.5f, 0.0f});
    const std::array<float, 3> tunnelProbeWorld =
        TerrainVolumeLocalToWorld(reloadedData, *reloadedTerrain, {-5.0f, -3.0f, 0.0f});
    if (!TerrainVolumeContainsAirAtWorld(reloadedData, *reloadedTerrain, entranceWorld) ||
        !TerrainVolumeContainsAirAtWorld(reloadedData, *reloadedTerrain, chamberWorld) ||
        !TerrainVolumeContainsAirAtWorld(reloadedData, *reloadedTerrain, tunnelProbeWorld)) {
        return fail("proof tunnel entrance, tunnel body, or chamber is not empty terrain-owned volume.");
    }

    TerrainVolumeRayHit floorHit;
    TerrainVolumeRayHit ceilingHit;
    TerrainVolumeRayHit wallHit;
    if (!TerrainVolumeRaycastWorld(reloadedData, *reloadedTerrain, tunnelProbeWorld, {0.0f, -1.0f, 0.0f}, 8.0f,
                                   &floorHit) ||
        !TerrainVolumeRaycastWorld(reloadedData, *reloadedTerrain, tunnelProbeWorld, {0.0f, 1.0f, 0.0f}, 8.0f,
                                   &ceilingHit) ||
        !TerrainVolumeRaycastWorld(reloadedData, *reloadedTerrain, tunnelProbeWorld, {0.0f, 0.0f, 1.0f}, 8.0f,
                                   &wallHit)) {
        return fail("proof tunnel did not expose volume floor, ceiling, and wall raycast surfaces.");
    }

    PhysicsRayHit3D entrancePhysicsHit;
    if (!state_.Physics().Raycast3D(state_.Entities(), {entranceWorld[0], 6.0f, entranceWorld[2]},
                                    {0.0f, -1.0f, 0.0f}, 20.0f, &entrancePhysicsHit) ||
        !entrancePhysicsHit.hit || entrancePhysicsHit.entityId != reloadedTerrain->id ||
        entrancePhysicsHit.colliderType != "Terrain.VolumeSurface" || entrancePhysicsHit.point.y > -0.35f) {
        return fail("volume collision/raycast proof hit the hidden heightfield plane or missed the tunnel floor.");
    }
    PhysicsRayHit3D chamberPhysicsHit;
    if (!state_.Physics().Raycast3D(state_.Entities(),
                                    {chamberWorld[0], chamberWorld[1], chamberWorld[2]},
                                    {0.0f, 0.0f, 1.0f}, 8.0f, &chamberPhysicsHit) ||
        !chamberPhysicsHit.hit || chamberPhysicsHit.entityId != reloadedTerrain->id ||
        chamberPhysicsHit.colliderType != "Terrain.VolumeSurface") {
        return fail("physics collision source did not come from the terrain volume wall.");
    }

    TerrainVolumeMesh reloadedVolumeMesh = TerrainMeshBuilder::Build(reloadedData.volume);
    if (reloadedVolumeMesh.chunks.empty() || reloadedVolumeMesh.boundsMax[1] <= reloadedVolumeMesh.boundsMin[1]) {
        return fail("reloaded proof volume mesh is invalid.");
    }
    if (!RebuildCaveMeshChunks(reloadedData.volume, reloadedData.volume.dirtyChunks, &reloadedVolumeMesh)) {
        return fail("reloaded proof volume dirty chunk rebuild failed.");
    }

    const std::filesystem::path scenePath =
        projectRoot / "Assets" / "Scenes" / "UnifiedVolumetricTerrainProof.scene.json";
    {
        std::ifstream sceneInput(scenePath, std::ios::binary);
        std::ostringstream sceneBuffer;
        sceneBuffer << sceneInput.rdbuf();
        const std::string sceneText = sceneBuffer.str();
        for (const std::string& token : bannedTokens) {
            if (ToLower(sceneText).find(token) != std::string::npos) {
                return fail("proof scene file contains banned legacy cave token: " + token);
            }
        }
    }

    viewportCameraTarget_ = {-12.0f, -0.6f, 0.0f};
    viewportCameraYaw_ = -48.0f;
    viewportCameraPitch_ = 14.0f;
    viewportCameraDistance_ = 21.0f;
    viewportGridVisible_ = false;
    std::vector<AgentVisualCapture> captures;
    if (!CaptureAgentVisualSnapshot("unified volumetric terrain proof", "unified-volumetric-terrain-proof",
                                    &captures) ||
        captures.empty()) {
        return fail("proof visual capture did not produce screenshots.");
    }

    std::ostringstream summary;
    summary << "Created and reloaded UnifiedVolumetricTerrainProof.scene.json with one Terrain entity, no standalone "
            << "cave objects, densityBelow=" << reloadedBelow << ", densityAbove=" << reloadedAbove
            << ", digCenter=" << reloadedDigCenter << ", dirtyChunks=" << proofDirtyChunks.size()
            << ", audit=" << auditPath.string();
    if (!captures.empty()) {
        summary << ", capture=" << captures.front().path;
    }
    state_.AddActivity("smoke.unified-terrain-proof", "Passed", summary.str());
    std::fprintf(stdout, "%s\n", summary.str().c_str());
    return true;
}

bool EditorApp::RunTerrainPerformanceSmokeTest() {
    if (!options_.smokeTestTerrainPerformance) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Terrain performance smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Terrain performance smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot =
        std::filesystem::current_path() / "projects" / "UnifiedVolumetricTerrainProof";
    const std::filesystem::path proofScene =
        projectRoot / "Assets" / "Scenes" / "UnifiedVolumetricTerrainProof.scene.json";
    std::error_code filesystemError;
    if (!std::filesystem::exists(proofScene, filesystemError)) {
        const bool originalProofSmoke = options_.smokeTestUnifiedTerrainProof;
        options_.smokeTestUnifiedTerrainProof = true;
        const bool generated = RunUnifiedTerrainProofSmokeTest();
        options_.smokeTestUnifiedTerrainProof = originalProofSmoke;
        if (!generated) {
            return fail("could not generate UnifiedVolumetricTerrainProof fixture before performance test.");
        }
    }

    std::string error;
    if (!state_.OpenProject(projectRoot, &error)) {
        return fail("could not open UnifiedVolumetricTerrainProof project: " + error);
    }

    Entity* terrain = state_.FindEntityByName("Unified Volumetric Terrain");
    if (terrain == nullptr) {
        return fail("proof scene is missing Unified Volumetric Terrain.");
    }
    Component* terrainComponent = FindTerrainComponent(*terrain);
    if (terrainComponent == nullptr) {
        return fail("proof terrain entity has no Terrain component.");
    }

    TerrainData initialTerrain;
    if (!LoadTerrainDataFromComponent(*terrainComponent, &initialTerrain) || !TerrainUsesVolumetric(initialTerrain)) {
        return fail("proof terrain does not contain TerrainVolumeData.");
    }
    const int totalVolumeChunks = CaveChunkCountX(initialTerrain.volume) * CaveChunkCountY(initialTerrain.volume) *
                                  CaveChunkCountZ(initialTerrain.volume);
    if (totalVolumeChunks <= 0) {
        return fail("proof terrain volume has no chunks.");
    }

    const bool originalGridVisible = viewportGridVisible_;
    const bool originalPhysicsDebugVisible = viewportPhysicsDebugVisible_;
    const bool originalSceneGizmosVisible = viewportSceneGizmosVisible_;
    const int originalSceneToolMode = sceneToolMode_;
    const bool originalTerrainToolActive = terrainToolActive_;
    const bool originalTerrainBrushPreviewVisible = terrainBrushPreviewVisible_;
    const float originalYaw = viewportCameraYaw_;
    const float originalPitch = viewportCameraPitch_;
    const float originalDistance = viewportCameraDistance_;
    const std::array<float, 3> originalTarget = viewportCameraTarget_;

    viewportGridVisible_ = false;
    viewportPhysicsDebugVisible_ = false;
    viewportSceneGizmosVisible_ = false;
    sceneToolMode_ = 0;
    terrainToolActive_ = false;
    terrainBrushPreviewVisible_ = false;
    viewportCameraTarget_ = {-8.0f, -0.8f, 0.0f};
    viewportCameraYaw_ = -52.0f;
    viewportCameraPitch_ = 12.0f;
    viewportCameraDistance_ = 22.0f;
    state_.SelectEntity(terrain->id);

    profiler_.Clear();
    profiler_.SetEnabled(true);
    profiler_.SetPaused(false);

    auto restoreViewportState = [&]() {
        viewportGridVisible_ = originalGridVisible;
        viewportPhysicsDebugVisible_ = originalPhysicsDebugVisible;
        viewportSceneGizmosVisible_ = originalSceneGizmosVisible;
        sceneToolMode_ = originalSceneToolMode;
        terrainToolActive_ = originalTerrainToolActive;
        terrainBrushPreviewVisible_ = originalTerrainBrushPreviewVisible;
        viewportCameraYaw_ = originalYaw;
        viewportCameraPitch_ = originalPitch;
        viewportCameraDistance_ = originalDistance;
        viewportCameraTarget_ = originalTarget;
        gDisableTerrainComponentCacheForPerf = false;
    };

    auto renderPerfFrame = [&]() {
        profiler_.BeginFrame();
        {
            PerformanceScope editorFrame(&profiler_, PerformanceDomain::Editor, "Editor.Frame");
            PerformanceScope sceneView(&profiler_, PerformanceDomain::Editor, "Editor.SceneView");
            RenderViewportScene(960, 540);
        }
        profiler_.EndFrame();
        return gTerrainPerfFrame;
    };

    auto runCameraPass = [&](bool cacheDisabled) {
        gDisableTerrainComponentCacheForPerf = cacheDisabled;
        ClearParsedTerrainComponentCaches();
        gCaveRenderCache.erase(TerrainVolumeCacheId(terrain->id));
        renderPerfFrame();

        TerrainPerfAggregate aggregate;
        const int frames = std::max(60, std::min(options_.smokeTestFrames, 180));
        for (int frame = 0; frame < frames; ++frame) {
            viewportCameraYaw_ += 0.42f;
            viewportCameraPitch_ = std::clamp(12.0f + std::sin(static_cast<float>(frame) * 0.08f) * 3.5f, -60.0f, 60.0f);
            viewportCameraTarget_[0] += std::sin(static_cast<float>(frame) * 0.05f) * 0.015f;
            aggregate.Add(renderPerfFrame());
        }
        return aggregate;
    };

    const TerrainPerfAggregate baseline = runCameraPass(true);
    const TerrainPerfAggregate cached = runCameraPass(false);

    auto avg = [](double value, int frames) {
        return frames <= 0 ? 0.0 : value / static_cast<double>(frames);
    };
    auto avgInt = [](int value, int frames) {
        return frames <= 0 ? 0.0 : static_cast<double>(value) / static_cast<double>(frames);
    };

    if (baseline.totals.terrainLoadParses <= cached.totals.terrainLoadParses) {
        restoreViewportState();
        return fail("cached camera pass did not reduce terrain component parses.");
    }
    if (cached.totals.terrainLoadParses != 0 || cached.totals.terrainLoadCacheHits <= 0) {
        restoreViewportState();
        return fail("cached camera pass still reparsed terrain volume data.");
    }
    if (cached.maxFrame.pendingDirtyChunks != 0 || cached.maxFrame.chunksMeshedThisFrame != 0 ||
        cached.maxFrame.fullTerrainRebuilds != 0 || cached.maxFrame.collisionChunksRebuilt != 0 ||
        cached.maxFrame.meshUploadCount != 0) {
        restoreViewportState();
        return fail("camera movement caused terrain dirty work, meshing, collision rebuild, or mesh upload.");
    }
    if (cached.maxFrame.legacyHeightfieldSubmitCount != 0 || cached.totals.volumeRenderChunkSubmitCount <= 0) {
        restoreViewportState();
        return fail("volume mode rendered the legacy heightfield or failed to submit volume chunks.");
    }
    if (viewportPhysicsDebugVisible_) {
        restoreViewportState();
        return fail("heavy physics/collision debug visualization defaulted on during terrain performance test.");
    }

    TerrainData brushTerrain;
    if (!LoadTerrainDataFromComponent(*terrainComponent, &brushTerrain)) {
        restoreViewportState();
        return fail("could not reload proof terrain for brush dirty-chunk test.");
    }
    if (brushTerrain.volume.collisionUpdateMode != "Deferred") {
        restoreViewportState();
        return fail("terrain volume collision update mode did not default to Deferred.");
    }
    CaveBrushSettings addMaterial;
    addMaterial.mode = CaveBrushMode::AddMaterial;
    addMaterial.falloff = CaveFalloffCurve::Smooth;
    addMaterial.radius = 7.5f;
    addMaterial.strength = 1.0f;
    addMaterial.opacity = 1.0f;
    const CaveBrushResult brushResult = ApplyTerrainVolumeBrush(&brushTerrain, {0.0f, -3.0f, 0.0f}, addMaterial);
    if (!brushResult.changed || brushResult.dirty.chunks.empty() ||
        brushResult.dirty.chunks.size() >= static_cast<size_t>(totalVolumeChunks)) {
        restoreViewportState();
        return fail("single terrain volume brush did not dirty a bounded set of chunks.");
    }
    SaveTerrainDataToComponent(brushTerrain, terrainComponent);
    ClearParsedTerrainComponentCaches();
    TerrainPerfFrameStats editFrame = renderPerfFrame();
    if (editFrame.chunksMeshedThisFrame <= 0 ||
        editFrame.chunksMeshedThisFrame > kMaxTerrainVolumeMeshBuildsPerFrame ||
        editFrame.fullTerrainRebuilds != 0 ||
        editFrame.collisionChunksRebuilt > kMaxTerrainVolumeCollisionBuildsPerFrame) {
        restoreViewportState();
        return fail("brush edit did not use throttled dirty chunk rendering/collision limits.");
    }
    int drainFrames = 0;
    while (gCaveRenderCache[TerrainVolumeCacheId(terrain->id)].editRevision != brushTerrain.volume.editRevision &&
           drainFrames < 16) {
        editFrame = renderPerfFrame();
        if (editFrame.chunksMeshedThisFrame > kMaxTerrainVolumeMeshBuildsPerFrame ||
            editFrame.collisionChunksRebuilt > kMaxTerrainVolumeCollisionBuildsPerFrame) {
            restoreViewportState();
            return fail("dirty terrain volume queue exceeded per-frame rebuild limits while draining.");
        }
        ++drainFrames;
    }
    if (gCaveRenderCache[TerrainVolumeCacheId(terrain->id)].editRevision != brushTerrain.volume.editRevision) {
        restoreViewportState();
        return fail("dirty terrain volume queue did not drain within the expected frame budget.");
    }
    const TerrainPerfFrameStats postEditIdle = renderPerfFrame();
    if (postEditIdle.chunksMeshedThisFrame != 0 || postEditIdle.meshUploadCount != 0 ||
        postEditIdle.collisionChunksRebuilt != 0 || postEditIdle.pendingDirtyChunks != 0) {
        restoreViewportState();
        return fail("terrain volume kept rebuilding after the dirty chunk queue drained.");
    }

    const std::filesystem::path auditPath = projectRoot / "UnifiedVolumetricTerrainPerformance.audit.txt";
    std::ofstream audit(auditPath);
    if (audit.is_open()) {
        audit << "UnifiedVolumetricTerrainProof performance audit\n";
        audit << "baseline.cacheDisabled=true\n";
        audit << "baseline.frames=" << baseline.frames << "\n";
        audit << "baseline.avgTerrainUpdateMs="
              << avg(baseline.totals.terrainComponentParseMs + baseline.totals.terrainVolumeMesherBuildAllMs +
                         baseline.totals.terrainVolumeMesherBuildChunkMs,
                     baseline.frames)
              << "\n";
        audit << "baseline.avgRenderSubmitMs=" << avg(baseline.totals.terrainRenderSubmitMs, baseline.frames) << "\n";
        audit << "baseline.avgTerrainParses=" << avgInt(baseline.totals.terrainLoadParses, baseline.frames) << "\n";
        audit << "cached.cacheDisabled=false\n";
        audit << "cached.frames=" << cached.frames << "\n";
        audit << "cached.avgTerrainUpdateMs="
              << avg(cached.totals.terrainComponentParseMs + cached.totals.terrainVolumeMesherBuildAllMs +
                         cached.totals.terrainVolumeMesherBuildChunkMs,
                     cached.frames)
              << "\n";
        audit << "cached.avgRenderSubmitMs=" << avg(cached.totals.terrainRenderSubmitMs, cached.frames) << "\n";
        audit << "cached.avgTerrainParses=" << avgInt(cached.totals.terrainLoadParses, cached.frames) << "\n";
        audit << "cached.maxDirtyChunks=" << cached.maxFrame.pendingDirtyChunks << "\n";
        audit << "cached.maxChunksMeshed=" << cached.maxFrame.chunksMeshedThisFrame << "\n";
        audit << "cached.maxCollisionChunks=" << cached.maxFrame.collisionChunksRebuilt << "\n";
        audit << "cached.maxMeshUploads=" << cached.maxFrame.meshUploadCount << "\n";
        audit << "cached.maxLegacyHeightfieldSubmits=" << cached.maxFrame.legacyHeightfieldSubmitCount << "\n";
        audit << "cached.collisionUpdateMode=" << brushTerrain.volume.collisionUpdateMode << "\n";
        audit << "brush.dirtyChunks=" << brushResult.dirty.chunks.size() << "\n";
        audit << "brush.firstFrameChunksMeshed=" << editFrame.chunksMeshedThisFrame << "\n";
        audit << "brush.drainFrames=" << drainFrames << "\n";
    }

    std::ostringstream summary;
    summary << std::fixed << std::setprecision(3)
            << "Terrain performance smoke passed: baseline avg update "
            << avg(baseline.totals.terrainComponentParseMs + baseline.totals.terrainVolumeMesherBuildAllMs +
                       baseline.totals.terrainVolumeMesherBuildChunkMs,
                   baseline.frames)
            << " ms, cached avg update "
            << avg(cached.totals.terrainComponentParseMs + cached.totals.terrainVolumeMesherBuildAllMs +
                       cached.totals.terrainVolumeMesherBuildChunkMs,
                   cached.frames)
            << " ms, cached max dirty chunks " << cached.maxFrame.pendingDirtyChunks
            << ", max chunks meshed while moving camera " << cached.maxFrame.chunksMeshedThisFrame
            << ", max collision chunks " << cached.maxFrame.collisionChunksRebuilt
            << ", max mesh uploads " << cached.maxFrame.meshUploadCount
            << ", brush dirty chunks " << brushResult.dirty.chunks.size()
            << ", audit=" << auditPath;
    state_.AddActivity("smoke.terrain-performance", "Passed", summary.str());
    std::fprintf(stdout, "%s\n", summary.str().c_str());

    restoreViewportState();
    return true;
}

bool EditorApp::RunTerrainSmokeTest() {
    if (!options_.smokeTestTerrain) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Terrain smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Terrain smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot = std::filesystem::current_path() / "projects" / "TerrainDemos";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create TerrainDemos project: " + error);
    }

    state_.ClearScene();

    TerrainData data;
    data.resolution = 33;
    data.chunkSize = 8;
    data.size = {40.0f, 6.0f, 40.0f};
    data.layers = {MakeTerrainLayerFromPreset(kTerrainLayerPresets[0]),
                   MakeTerrainLayerFromPreset(kTerrainLayerPresets[1]),
                   MakeTerrainLayerFromPreset(kTerrainLayerPresets[2]),
                   MakeTerrainLayerFromPreset(kTerrainLayerPresets[3])};
    NormalizeTerrainData(&data);
    std::error_code textureSourceError;
    const bool terrainTestTexturesAvailable =
        std::filesystem::is_directory(std::filesystem::path(kTerrainTestTextureSourceRoot), textureSourceError);
    if (terrainTestTexturesAvailable) {
        std::string textureCopyError;
        if (!CopyTerrainTestTexturesToProject(projectRoot, &data, &textureCopyError)) {
            return fail("could not copy temp terrain test textures: " + textureCopyError);
        }
    }

    TerrainBrushSettings raise;
    raise.mode = TerrainBrushMode::RaiseLower;
    raise.falloff = TerrainFalloffCurve::Smooth;
    raise.radius = 7.0f;
    raise.strength = 1.75f;
    const TerrainBrushResult raised = ApplyTerrainBrush(&data, {0.50f, 0.50f}, raise);
    if (!raised.changed || raised.dirty.chunks.empty()) {
        return fail("raise brush did not modify the demo terrain.");
    }
    if (raised.dirty.chunks.size() >= static_cast<size_t>(TerrainChunkCountX(data) * TerrainChunkCountZ(data))) {
        return fail("focused raise brush dirtied every terrain chunk.");
    }

    TerrainBrushSettings noise;
    noise.mode = TerrainBrushMode::Noise;
    noise.falloff = TerrainFalloffCurve::Bell;
    noise.radius = 12.0f;
    noise.strength = 0.34f;
    noise.opacity = 0.75f;
    noise.noiseSeed = 20260628;
    ApplyTerrainBrush(&data, {0.45f, 0.52f}, noise);

    TerrainBrushSettings flatten;
    flatten.mode = TerrainBrushMode::Flatten;
    flatten.falloff = TerrainFalloffCurve::Linear;
    flatten.radius = 4.5f;
    flatten.strength = 0.52f;
    flatten.opacity = 0.85f;
    flatten.targetHeight = 0.9f;
    ApplyTerrainBrush(&data, {0.28f, 0.34f}, flatten);

    TerrainBrushSettings smooth;
    smooth.mode = TerrainBrushMode::Smooth;
    smooth.falloff = TerrainFalloffCurve::Smooth;
    smooth.radius = 5.5f;
    smooth.strength = 0.42f;
    ApplyTerrainBrush(&data, {0.52f, 0.48f}, smooth);

    if (!AutoTextureTerrainLayers(data)) {
        return fail("auto-texture did not modify the demo terrain layers.");
    }

    TerrainBrushSettings paintRock;
    paintRock.mode = TerrainBrushMode::Paint;
    paintRock.falloff = TerrainFalloffCurve::Smooth;
    paintRock.radius = 8.0f;
    paintRock.strength = 0.86f;
    paintRock.opacity = 0.95f;
    paintRock.activeLayerIndex = 1;
    const TerrainBrushResult paintedRock = ApplyTerrainBrush(&data, {0.50f, 0.50f}, paintRock);

    TerrainBrushSettings paintDirt = paintRock;
    paintDirt.radius = 5.5f;
    paintDirt.strength = 0.74f;
    paintDirt.activeLayerIndex = 2;
    const TerrainBrushResult paintedDirt = ApplyTerrainBrush(&data, {0.28f, 0.34f}, paintDirt);

    TerrainBrushSettings paintGrass = paintRock;
    paintGrass.radius = 6.0f;
    paintGrass.strength = 0.66f;
    paintGrass.activeLayerIndex = 3;
    const TerrainBrushResult paintedGrass = ApplyTerrainBrush(&data, {0.68f, 0.62f}, paintGrass);

    if (!paintedRock.changed || !paintedDirt.changed || !paintedGrass.changed) {
        return fail("paint brushes did not modify demo terrain layers.");
    }

    const float centerRockWeight = TerrainLayerWeightAtUv(data, 1, {0.50f, 0.50f});
    const float dirtWeight = TerrainLayerWeightAtUv(data, 2, {0.28f, 0.34f});
    const float grassWeight = TerrainLayerWeightAtUv(data, 3, {0.68f, 0.62f});
    if (centerRockWeight <= 0.20f || dirtWeight <= 0.20f || grassWeight <= 0.15f) {
        return fail("painted terrain layer weights were too small after normalization.");
    }

    TerrainBrushSettings cutHole;
    cutHole.mode = TerrainBrushMode::Hole;
    cutHole.falloff = TerrainFalloffCurve::Constant;
    cutHole.radius = 2.2f;
    cutHole.strength = 1.0f;
    cutHole.opacity = 1.0f;
    const std::array<float, 2> holeUv{0.78f, 0.24f};
    const TerrainBrushResult cutHoleResult = ApplyTerrainBrush(&data, holeUv, cutHole);
    if (!cutHoleResult.changed || !TerrainIsHoleAtUv(data, holeUv)) {
        return fail("hole brush did not cut a clean demo terrain opening.");
    }

    TerrainData heightfieldOnlyProof = data;
    Component heightfieldOnlyComponent;
    SaveTerrainDataToComponent(heightfieldOnlyProof, &heightfieldOnlyComponent);
    TerrainData reloadedHeightfieldOnly;
    if (!LoadTerrainDataFromComponent(heightfieldOnlyComponent, &reloadedHeightfieldOnly) ||
        !TerrainUsesHeightfield(reloadedHeightfieldOnly) || TerrainUsesVolumetric(reloadedHeightfieldOnly) ||
        TerrainHasVolume(reloadedHeightfieldOnly) ||
        !TerrainIsHoleAtUv(reloadedHeightfieldOnly, holeUv) ||
        TerrainLayerWeightAtUv(reloadedHeightfieldOnly, 1, {0.50f, 0.50f}) <= 0.20f) {
        return fail("heightfield-only sculpt/paint/hole regression proof failed before volume opt-in.");
    }

    EnsureTerrainVolume(&data);
    data.volume.resolution = {25, 17, 25};
    data.volume.chunkSize = 8;
    data.volume.size = {data.size[0], 12.0f, data.size[2]};
    data.volume.layers = {MakeCaveLayerFromPreset(kCaveLayerPresets[0]), MakeCaveLayerFromPreset(kCaveLayerPresets[1]),
                          MakeCaveLayerFromPreset(kCaveLayerPresets[2]), MakeCaveLayerFromPreset(kCaveLayerPresets[3])};
    data.volume.densities.clear();
    EnsureTerrainVolume(&data);

    TerrainVolumeBrushSettings shaftBrush;
    shaftBrush.mode = TerrainVolumeBrushMode::Tunnel;
    shaftBrush.falloff = TerrainVolumeFalloffCurve::Smooth;
    shaftBrush.radius = 2.2f;
    shaftBrush.strength = 2.0f;
    shaftBrush.opacity = 1.0f;
    shaftBrush.useSegment = true;
    shaftBrush.segmentStart = {(holeUv[0] - 0.5f) * data.size[0], data.volume.size[1] * 0.5f,
                               (holeUv[1] - 0.5f) * data.size[2]};
    shaftBrush.segmentEnd = {shaftBrush.segmentStart[0], -data.volume.size[1] * 0.5f,
                             shaftBrush.segmentStart[2]};
    const TerrainVolumeBrushResult shaftResult = ApplyTerrainVolumeBrush(&data, shaftBrush.segmentEnd, shaftBrush);
    if (!shaftResult.changed) {
        return fail("volume shaft brush did not remove material for the demo terrain opening.");
    }

    auto terrainTunnel = [&](std::array<float, 3> a, std::array<float, 3> b, float radius, float strength) {
        CaveBrushSettings brush;
        brush.mode = CaveBrushMode::Tunnel;
        brush.falloff = CaveFalloffCurve::Smooth;
        brush.radius = radius;
        brush.strength = strength;
        brush.opacity = 1.0f;
        brush.segmentStart = a;
        brush.segmentEnd = b;
        brush.useSegment = true;
        return ApplyTerrainVolumeBrush(&data, b, brush);
    };
    const int terrainRevisionBeforeVolumeEdit = data.editRevision;
    const std::array<float, 3> terrainVolumeTunnelSample{-5.0f, -2.8f, 0.4f};
    CaveBrushResult terrainVolumeTunnel =
        terrainTunnel({-11.5f, -2.8f, 0.0f}, {9.5f, -2.8f, 1.4f}, 1.65f, 1.0f);
    CaveBrushSettings volumeChamber;
    volumeChamber.mode = CaveBrushMode::Dig;
    volumeChamber.falloff = CaveFalloffCurve::Smooth;
    volumeChamber.radius = 2.45f;
    volumeChamber.strength = 1.0f;
    volumeChamber.opacity = 1.0f;
    const std::array<float, 3> terrainVolumeChamberSample{1.0f, -2.8f, 1.0f};
    const CaveBrushResult terrainVolumeChamber = ApplyTerrainVolumeBrush(&data, terrainVolumeChamberSample, volumeChamber);
    CaveBrushSettings volumePaint;
    volumePaint.mode = CaveBrushMode::Paint;
    volumePaint.falloff = CaveFalloffCurve::Smooth;
    volumePaint.radius = 3.0f;
    volumePaint.strength = 0.9f;
    volumePaint.opacity = 0.95f;
    volumePaint.activeLayerIndex = 1;
    const CaveBrushResult terrainVolumePaint = ApplyTerrainVolumeBrush(&data, {0.0f, -3.2f, 1.0f}, volumePaint);
    if (!terrainVolumeTunnel.changed || !terrainVolumeChamber.changed || !terrainVolumePaint.changed ||
        terrainVolumeTunnel.dirty.chunks.empty()) {
        return fail("terrain-owned volume brushes did not carve and paint the demo tunnel.");
    }
    const int totalTerrainVolumeChunks =
        CaveChunkCountX(data.volume) * CaveChunkCountY(data.volume) * CaveChunkCountZ(data.volume);
    if (terrainVolumeTunnel.dirty.chunks.size() >= static_cast<size_t>(totalTerrainVolumeChunks)) {
        return fail("focused terrain-owned tunnel dirtied every volume chunk.");
    }
    if (data.editRevision != terrainRevisionBeforeVolumeEdit) {
        return fail("terrain-owned volume edit invalidated the heightfield edit revision.");
    }

    const int terrainVolumeCacheKey = -92029;
    CaveRenderCache& initialVolumeCache = UpdateCaveRenderCache(terrainVolumeCacheKey, data.volume);
    const int volumeFullRebuildsAfterInitial = initialVolumeCache.fullRebuilds;
    CaveBrushSettings volumeSmooth;
    volumeSmooth.mode = CaveBrushMode::Smooth;
    volumeSmooth.falloff = CaveFalloffCurve::Smooth;
    volumeSmooth.radius = 2.25f;
    volumeSmooth.strength = 0.38f;
    volumeSmooth.opacity = 0.7f;
    const CaveBrushResult volumeSmoothResult = ApplyTerrainVolumeBrush(&data, terrainVolumeChamberSample, volumeSmooth);
    CaveRenderCache& updatedVolumeCache = UpdateCaveRenderCache(terrainVolumeCacheKey, data.volume);
    if (!volumeSmoothResult.changed || updatedVolumeCache.fullRebuilds != volumeFullRebuildsAfterInitial ||
        updatedVolumeCache.chunkRebuilds <= 0) {
        return fail("terrain-owned volume cache did not use partial chunk rebuilds after a focused brush edit.");
    }
    const int terrainVolumeFullRebuildProof = updatedVolumeCache.fullRebuilds;
    const int terrainVolumeChunkRebuildProof = updatedVolumeCache.chunkRebuilds;

    TerrainMesh fullMesh = BuildTerrainMesh(data);
    TerrainMesh partialMesh = fullMesh;
    if (fullMesh.chunks.empty() || fullMesh.chunks.front().vertices.empty() ||
        !RebuildTerrainMeshChunks(data, data.dirtyChunks, &partialMesh)) {
        return fail("mesh build or chunk rebuild failed for the demo terrain.");
    }
    CaveMesh terrainVolumeMesh = BuildCaveMesh(data.volume);
    CaveMesh partialTerrainVolumeMesh = terrainVolumeMesh;
    if (terrainVolumeMesh.chunks.empty() || terrainVolumeMesh.boundsMax[1] <= terrainVolumeMesh.boundsMin[1] ||
        !RebuildCaveMeshChunks(data.volume, data.volume.dirtyChunks, &partialTerrainVolumeMesh)) {
        return fail("terrain-owned volume mesh build or chunk rebuild failed.");
    }

    Entity& terrain =
        state_.CreateEntity("Sculpted Terrain", {MakeTransformComponent(), MakeTerrainComponent(33, {40.0f, 6.0f, 40.0f}, 8)});
    terrain.isStatic = true;
    Component* terrainComponent = FindTerrainComponent(terrain);
    if (terrainComponent == nullptr) {
        return fail("created terrain entity has no Terrain component.");
    }
    SaveTerrainDataToComponent(data, terrainComponent);

    Entity& light = state_.CreateEntity("Terrain Sun", {MakeTransformComponent(), MakeLightComponent("Directional")});
    light.rotation = {45.0f, -35.0f, 0.0f};

    Component terrainFog = MakeFogComponent();
    SetComponentPropertyForUi(terrainFog, "mode", "Exponential");
    SetComponentPropertyForUi(terrainFog, "color", "0.48, 0.57, 0.63, 1");
    SetComponentPropertyForUi(terrainFog, "density", "0.026");
    SetComponentPropertyForUi(terrainFog, "startDistance", "10");
    SetComponentPropertyForUi(terrainFog, "endDistance", "86");
    SetComponentPropertyForUi(terrainFog, "heightEnabled", "true");
    SetComponentPropertyForUi(terrainFog, "heightStart", "2.4");
    SetComponentPropertyForUi(terrainFog, "heightFalloff", "20");
    SetComponentPropertyForUi(terrainFog, "skyBlend", "0.58");
    state_.CreateEntity("Terrain Atmosphere", {MakeTransformComponent(), terrainFog});

    const TerrainSample playerSample = SampleTerrainLocal(data, -6.0f, -6.0f);
    Entity& player = state_.CreateEntity("Terrain Player",
                                         {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube", "PlayerBlue"),
                                          MakeCharacterControllerRuntimeComponent(), MakeInputActionMapRuntimeComponent(),
                                          MakeRigidbody3DComponent("Kinematic"), MakeCollider3DComponent("Box")});
    player.position = {-6.0f, (playerSample.valid ? playerSample.height : 0.0f) + 0.55f, -6.0f};
    player.scale = {0.7f, 1.1f, 0.7f};

    Component fallingBody = MakeRigidbody3DComponent("Dynamic");
    SetComponentPropertyForUi(fallingBody, "restitution", "0");
    Component fallingCollider = MakeCollider3DComponent("Sphere");
    SetComponentPropertyForUi(fallingCollider, "radius", "0.35");
    Entity& fallingProbe =
        state_.CreateEntity("Terrain Collision Probe",
                            {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitSphere", "PrototypeGray"),
                             fallingBody, fallingCollider});
    const TerrainSample probeSample = SampleTerrainLocal(data, 0.0f, 0.0f);
    fallingProbe.position = {0.0f, (probeSample.valid ? probeSample.height : 0.0f) + 3.0f, 0.0f};
    fallingProbe.scale = {0.7f, 0.7f, 0.7f};

    Component volumeProbeBody = MakeRigidbody3DComponent("Dynamic");
    SetComponentPropertyForUi(volumeProbeBody, "restitution", "0");
    Component volumeProbeCollider = MakeCollider3DComponent("Sphere");
    SetComponentPropertyForUi(volumeProbeCollider, "radius", "0.32");
    Entity& terrainVolumeProbe =
        state_.CreateEntity("Terrain Volume Collision Probe",
                            {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitSphere", "PrototypeGray"),
                             volumeProbeBody, volumeProbeCollider});
    terrainVolumeProbe.position = TerrainVolumeLocalToWorld(data, terrain, terrainVolumeChamberSample);
    terrainVolumeProbe.scale = {0.64f, 0.64f, 0.64f};

    Entity& camera = state_.CreateEntity("Main Camera",
                                         {MakeTransformComponent(), MakeCameraComponent(),
                                          MakeCameraFollowRuntimeComponent("Terrain Player")});
    camera.position = {-6.0f, player.position[1] + 5.5f, player.position[2] + 7.0f};
    camera.rotation = {-38.0f, 0.0f, 0.0f};

    state_.SelectEntity(terrain.id);
    state_.MarkSceneDirty("Generated TerrainDemos sculpted and painted terrain fixture.");
    if (!state_.SaveProject(&error)) {
        return fail("could not save TerrainDemos project: " + error);
    }

    if (!state_.OpenProject(projectRoot, &error)) {
        return fail("could not reload TerrainDemos project: " + error);
    }

    Entity* reloadedTerrain = state_.FindEntityByName("Sculpted Terrain");
    Entity* reloadedProbe = state_.FindEntityByName("Terrain Collision Probe");
    Entity* reloadedVolumeProbe = state_.FindEntityByName("Terrain Volume Collision Probe");
    Entity* reloadedCamera = state_.FindEntityByName("Main Camera");
    Entity* reloadedFog = state_.FindEntityByName("Terrain Atmosphere");
    if (reloadedTerrain == nullptr || reloadedProbe == nullptr || reloadedVolumeProbe == nullptr ||
        reloadedCamera == nullptr || reloadedFog == nullptr || !HasComponentType(*reloadedFog, "Fog")) {
        return fail("reloaded demo is missing terrain, collision probes, camera, or fog.");
    }
    for (const Entity& entity : state_.Entities()) {
        if (HasComponentType(entity, "CaveVolume")) {
            return fail("TerrainDemos generated a standalone CaveVolume instead of using TerrainVolumeData.");
        }
    }

    const Component* reloadedTerrainComponent = FindTerrainComponent(*reloadedTerrain);
    TerrainData reloadedData;
    if (reloadedTerrainComponent == nullptr || !LoadTerrainDataFromComponent(*reloadedTerrainComponent, &reloadedData)) {
        return fail("reloaded terrain data could not be parsed.");
    }
    if (reloadedData.resolution != 33 || TerrainLayerCount(reloadedData) < 4 ||
        reloadedData.heights.size() != static_cast<size_t>(TerrainSampleCount(reloadedData)) ||
        reloadedData.dirtyChunks.empty()) {
        return fail("reloaded terrain metadata, heights, layers, or dirty chunks did not survive.");
    }
    if (!TerrainUsesVolumetric(reloadedData) ||
        reloadedData.volume.densities.size() != static_cast<size_t>(CaveSampleCount(reloadedData.volume)) ||
        reloadedData.volume.dirtyChunks.empty() || CaveLayerCount(reloadedData.volume) < 4) {
        return fail("reloaded terrain-owned volume metadata, density field, layers, or dirty chunks did not survive.");
    }
    if (reloadedData.layers[1].detailStrength <= 0.0f || reloadedData.layers[1].detailScale <= 0.1f ||
        reloadedData.layers[3].material != "TerrainGrass") {
        return fail("reloaded terrain layer material/detail settings did not survive.");
    }
    if (terrainTestTexturesAvailable) {
        for (int layerIndex = 0; layerIndex < 4; ++layerIndex) {
            if (reloadedData.layers[static_cast<size_t>(layerIndex)].albedoTexture.empty()) {
                return fail("reloaded terrain layer lost its copied albedo texture reference.");
            }
            const std::filesystem::path copiedTexture =
                projectRoot / reloadedData.layers[static_cast<size_t>(layerIndex)].albedoTexture;
            std::error_code copiedTextureError;
            if (!std::filesystem::exists(copiedTexture, copiedTextureError)) {
                return fail("reloaded terrain layer references a missing copied temp texture: " +
                            copiedTexture.string());
            }
        }
    }
    if (!TerrainIsHoleAtUv(reloadedData, holeUv)) {
        return fail("reloaded terrain hole mask did not survive.");
    }

    const TerrainSample centerSample = SampleTerrainLocal(reloadedData, 0.0f, 0.0f);
    const float centerNormalLength =
        std::sqrt(centerSample.normal[0] * centerSample.normal[0] +
                  centerSample.normal[1] * centerSample.normal[1] +
                  centerSample.normal[2] * centerSample.normal[2]);
    if (!centerSample.valid || centerSample.height <= 0.25f ||
        std::fabs(centerNormalLength - 1.0f) > 0.08f) {
        return fail("reloaded terrain height or normal sampling returned invalid data.");
    }
    float centerWeightSum = 0.0f;
    for (float weight : centerSample.layerWeights) {
        centerWeightSum += weight;
    }
    if (std::fabs(centerWeightSum - 1.0f) > 0.01f ||
        TerrainLayerWeightAtUv(reloadedData, 1, {0.50f, 0.50f}) <= 0.20f ||
        TerrainLayerWeightAtUv(reloadedData, 3, {0.68f, 0.62f}) <= 0.15f) {
        return fail("reloaded terrain layer weights were not normalized/preserved.");
    }
    const std::array<float, 3> terrainVolumeChamberWorld =
        TerrainVolumeLocalToWorld(reloadedData, *reloadedTerrain, terrainVolumeChamberSample);
    const std::array<float, 3> terrainVolumeTunnelWorld =
        TerrainVolumeLocalToWorld(reloadedData, *reloadedTerrain, terrainVolumeTunnelSample);
    if (!TerrainVolumeContainsAirAtWorld(reloadedData, *reloadedTerrain, terrainVolumeChamberWorld) ||
        CaveLayerWeightAtLocal(reloadedData.volume, 1, {0.0f, -3.2f, 1.0f}) <= 0.10f) {
        return fail("reloaded terrain-owned volume did not preserve carved space or painted cave/rock layer.");
    }
    CaveRayHit terrainVolumeFloorHit;
    if (!TerrainVolumeRaycastWorld(reloadedData, *reloadedTerrain, terrainVolumeTunnelWorld, {0.0f, -1.0f, 0.0f},
                                   7.0f, &terrainVolumeFloorHit) ||
        !terrainVolumeFloorHit.hit) {
        return fail("terrain-owned volume API raycast did not hit tunnel floor.");
    }
    CaveRayHit terrainVolumeCeilingHit;
    if (!TerrainVolumeRaycastWorld(reloadedData, *reloadedTerrain, terrainVolumeTunnelWorld, {0.0f, 1.0f, 0.0f},
                                   7.0f, &terrainVolumeCeilingHit) ||
        !terrainVolumeCeilingHit.hit) {
        return fail("terrain-owned volume API raycast did not hit tunnel ceiling.");
    }
    CaveRayHit terrainVolumeWallHit;
    if (!TerrainVolumeRaycastWorld(reloadedData, *reloadedTerrain, terrainVolumeTunnelWorld, {0.0f, 0.0f, 1.0f},
                                   7.0f, &terrainVolumeWallHit) ||
        !terrainVolumeWallHit.hit) {
        return fail("terrain-owned volume API raycast did not hit tunnel wall.");
    }

    TerrainMesh reloadedMesh = BuildTerrainMesh(reloadedData);
    if (reloadedMesh.chunks.empty() || reloadedMesh.boundsMax[1] <= reloadedMesh.boundsMin[1]) {
        return fail("reloaded terrain mesh bounds are invalid.");
    }
    if (!RebuildTerrainMeshChunks(reloadedData, reloadedData.dirtyChunks, &reloadedMesh)) {
        return fail("reloaded terrain chunk rebuild failed.");
    }
    CaveMesh reloadedTerrainVolumeMesh = BuildCaveMesh(reloadedData.volume);
    if (reloadedTerrainVolumeMesh.chunks.empty() ||
        reloadedTerrainVolumeMesh.boundsMax[1] <= reloadedTerrainVolumeMesh.boundsMin[1]) {
        return fail("reloaded terrain-owned volume mesh bounds are invalid.");
    }
    if (!RebuildCaveMeshChunks(reloadedData.volume, reloadedData.volume.dirtyChunks, &reloadedTerrainVolumeMesh)) {
        return fail("reloaded terrain-owned volume chunk rebuild failed.");
    }

    PhysicsRayHit3D rayHit;
    if (!state_.Physics().Raycast3D(state_.Entities(), {14.0f, 10.0f, 14.0f}, {0.0f, -1.0f, 0.0f}, 30.0f, &rayHit) ||
        !rayHit.hit || rayHit.entityId != reloadedTerrain->id || rayHit.colliderType != "Terrain.VolumeSurface") {
        return fail("physics raycast did not hit the reloaded terrain volume surface.");
    }
    const std::array<float, 3> holeWorld = TerrainUvToWorld(reloadedData, *reloadedTerrain, holeUv, 0.0f);
    PhysicsRayHit3D holeRayHit;
    if (state_.Physics().Raycast3D(state_.Entities(), {holeWorld[0], 10.0f, holeWorld[2]}, {0.0f, -1.0f, 0.0f},
                                   30.0f, &holeRayHit) &&
        holeRayHit.entityId == reloadedTerrain->id) {
        return fail("physics raycast hit the cut-through terrain hole.");
    }
    PhysicsRayHit3D terrainVolumePhysicsHit;
    if (!state_.Physics().Raycast3D(state_.Entities(),
                                    {terrainVolumeTunnelWorld[0], terrainVolumeTunnelWorld[1],
                                     terrainVolumeTunnelWorld[2]},
                                    {0.0f, 0.0f, 1.0f}, 8.0f, &terrainVolumePhysicsHit) ||
        !terrainVolumePhysicsHit.hit || terrainVolumePhysicsHit.entityId != reloadedTerrain->id ||
        terrainVolumePhysicsHit.colliderType != "Terrain.VolumeSurface") {
        return fail("physics raycast did not hit the terrain-owned volume wall.");
    }

    const float probeStartY = reloadedProbe->position[1];
    const float volumeProbeStartY = reloadedVolumeProbe->position[1];
    if (!state_.BeginPlayMode()) {
        return fail("could not enter play mode for terrain collision proof.");
    }
    bool sawTerrainCollision = false;
    bool sawTerrainVolumeCollision = false;
    for (int step = 0; step < 160; ++step) {
        state_.UpdatePlayMode(1.0f / 60.0f);
        for (const PhysicsEvent& event : state_.PhysicsEvents()) {
            const bool includesTerrain = event.entityAId == reloadedTerrain->id || event.entityBId == reloadedTerrain->id;
            const bool includesProbe = event.entityAName == "Terrain Collision Probe" ||
                                       event.entityBName == "Terrain Collision Probe";
            sawTerrainCollision = sawTerrainCollision || (includesTerrain && includesProbe && !event.trigger);
            const bool includesVolumeProbe = event.entityAName == "Terrain Volume Collision Probe" ||
                                             event.entityBName == "Terrain Volume Collision Probe";
            sawTerrainVolumeCollision =
                sawTerrainVolumeCollision || (includesTerrain && includesVolumeProbe && !event.trigger);
        }
        if (sawTerrainCollision && sawTerrainVolumeCollision) {
            break;
        }
    }
    const Entity* runtimeProbe = state_.FindEntityByName("Terrain Collision Probe");
    const Entity* runtimeVolumeProbe = state_.FindEntityByName("Terrain Volume Collision Probe");
    const bool probeMoved = runtimeProbe != nullptr && runtimeProbe->position[1] < probeStartY - 0.05f;
    const bool volumeProbeMoved =
        runtimeVolumeProbe != nullptr && runtimeVolumeProbe->position[1] < volumeProbeStartY - 0.05f;
    state_.StopPlayMode();
    if (!probeMoved || !sawTerrainCollision || !volumeProbeMoved || !sawTerrainVolumeCollision) {
        return fail("play-mode physics did not move probes onto the terrain volume surface and owned volume colliders.");
    }

    std::ostringstream terrainSmokeSummary;
    terrainSmokeSummary << "Created TerrainDemos, sculpted/painted/cut terrain, carved terrain-owned tunnel, "
                        << "saved/reloaded, raycasted terrain volume surface/floor/ceiling/wall, collided in play "
                        << "mode, and kept volume cache partial (full=" << terrainVolumeFullRebuildProof
                        << ", chunk=" << terrainVolumeChunkRebuildProof << ").";
    state_.AddActivity("smoke.terrain", "Passed", terrainSmokeSummary.str());
    return true;
}

bool EditorApp::RunCaveSmokeTest() {
    if (!options_.smokeTestCaves) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Cave smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Cave smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot = std::filesystem::current_path() / "projects" / "CaveDemos";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create CaveDemos project: " + error);
    }

    state_.ClearScene();

    TerrainData terrainData;
    terrainData.resolution = 33;
    terrainData.chunkSize = 8;
    terrainData.size = {42.0f, 5.5f, 42.0f};
    terrainData.layers = {MakeTerrainLayerFromPreset(kTerrainLayerPresets[0]),
                          MakeTerrainLayerFromPreset(kTerrainLayerPresets[1]),
                          MakeTerrainLayerFromPreset(kTerrainLayerPresets[2]),
                          MakeTerrainLayerFromPreset(kTerrainLayerPresets[3])};
    NormalizeTerrainData(&terrainData);
    TerrainBrushSettings terrainNoise;
    terrainNoise.mode = TerrainBrushMode::Noise;
    terrainNoise.falloff = TerrainFalloffCurve::Bell;
    terrainNoise.radius = 16.0f;
    terrainNoise.strength = 0.28f;
    terrainNoise.opacity = 0.80f;
    terrainNoise.noiseSeed = 20260629;
    ApplyTerrainBrush(&terrainData, {0.48f, 0.52f}, terrainNoise);
    TerrainBrushSettings entranceFlatten;
    entranceFlatten.mode = TerrainBrushMode::Flatten;
    entranceFlatten.falloff = TerrainFalloffCurve::Smooth;
    entranceFlatten.radius = 5.0f;
    entranceFlatten.strength = 0.75f;
    entranceFlatten.opacity = 0.92f;
    entranceFlatten.targetHeight = 0.55f;
    ApplyTerrainBrush(&terrainData, {0.31f, 0.50f}, entranceFlatten);
    const std::array<float, 2> entranceUv{0.31f, 0.50f};
    if (TerrainIsHoleAtUv(terrainData, entranceUv)) {
        return fail("demo terrain started with a hole before cave/terrain coupling.");
    }
    AutoTextureTerrainLayers(terrainData);

    CaveVolumeData caveData;
    caveData.resolution = {25, 17, 25};
    caveData.chunkSize = 8;
    caveData.size = {34.0f, 16.0f, 28.0f};
    caveData.layers = {MakeCaveLayerFromPreset(kCaveLayerPresets[0]), MakeCaveLayerFromPreset(kCaveLayerPresets[1]),
                       MakeCaveLayerFromPreset(kCaveLayerPresets[2]), MakeCaveLayerFromPreset(kCaveLayerPresets[3])};
    NormalizeCaveVolumeData(&caveData);

    auto tunnel = [&](std::array<float, 3> a, std::array<float, 3> b, float radius, float strength) {
        CaveBrushSettings brush;
        brush.mode = CaveBrushMode::Tunnel;
        brush.falloff = CaveFalloffCurve::Smooth;
        brush.radius = radius;
        brush.strength = strength;
        brush.opacity = 1.0f;
        brush.segmentStart = a;
        brush.segmentEnd = b;
        brush.useSegment = true;
        return ApplyCaveBrush(&caveData, b, brush);
    };

    CaveBrushResult entranceTunnel = tunnel({-16.5f, 1.1f, 0.0f}, {-8.0f, 0.1f, 0.8f}, 2.25f, 1.35f);
    CaveBrushResult mainTunnel = tunnel({-8.0f, 0.1f, 0.8f}, {1.5f, -0.2f, 5.2f}, 2.05f, 1.25f);
    CaveBrushResult chamberTunnel = tunnel({1.5f, -0.2f, 5.2f}, {9.5f, 0.6f, 1.2f}, 1.9f, 1.15f);
    CaveBrushResult verticalTunnel = tunnel({6.0f, -0.4f, 2.8f}, {6.0f, 5.6f, 2.8f}, 1.55f, 1.15f);
    if (!entranceTunnel.changed || !mainTunnel.changed || !chamberTunnel.changed || !verticalTunnel.changed ||
        entranceTunnel.dirty.chunks.empty()) {
        return fail("tunnel brush did not carve expected cave chunks.");
    }
    const int totalCaveChunks = CaveChunkCountX(caveData) * CaveChunkCountY(caveData) * CaveChunkCountZ(caveData);
    if (entranceTunnel.dirty.chunks.size() >= static_cast<size_t>(totalCaveChunks)) {
        return fail("focused cave tunnel dirtied every cave chunk.");
    }

    CaveBrushSettings chamber;
    chamber.mode = CaveBrushMode::Dig;
    chamber.falloff = CaveFalloffCurve::Smooth;
    chamber.radius = 4.2f;
    chamber.strength = 1.45f;
    chamber.opacity = 1.0f;
    ApplyCaveBrush(&caveData, {2.5f, 0.3f, 4.2f}, chamber);
    chamber.radius = 2.6f;
    ApplyCaveBrush(&caveData, {8.8f, 1.0f, 0.2f}, chamber);

    CaveBrushSettings smooth;
    smooth.mode = CaveBrushMode::Smooth;
    smooth.falloff = CaveFalloffCurve::Smooth;
    smooth.radius = 3.2f;
    smooth.strength = 0.42f;
    smooth.opacity = 0.65f;
    ApplyCaveBrush(&caveData, {2.0f, 0.3f, 4.0f}, smooth);

    ApplyCaveStarterLayerSet(caveData);
    AutoPaintCaveLayers(caveData);
    CaveBrushSettings paintDirt;
    paintDirt.mode = CaveBrushMode::Paint;
    paintDirt.falloff = CaveFalloffCurve::Smooth;
    paintDirt.radius = 4.0f;
    paintDirt.strength = 0.90f;
    paintDirt.opacity = 0.95f;
    paintDirt.activeLayerIndex = 1;
    const CaveBrushResult paintedDirt = ApplyCaveBrush(&caveData, {2.0f, -1.3f, 4.0f}, paintDirt);
    CaveBrushSettings paintDamp = paintDirt;
    paintDamp.activeLayerIndex = 2;
    paintDamp.radius = 3.0f;
    const CaveBrushResult paintedDamp = ApplyCaveBrush(&caveData, {6.0f, 0.4f, 2.8f}, paintDamp);
    if (!paintedDirt.changed || !paintedDamp.changed ||
        CaveLayerWeightAtLocal(caveData, 1, {2.0f, -1.3f, 4.0f}) <= 0.10f ||
        CaveLayerWeightAtLocal(caveData, 2, {6.0f, 0.4f, 2.8f}) <= 0.10f) {
        return fail("cave layer painting did not modify normalized layer weights.");
    }

    std::error_code textureSourceError;
    const bool caveTestTexturesAvailable =
        std::filesystem::is_directory(std::filesystem::path(kTerrainTestTextureSourceRoot), textureSourceError);
    if (caveTestTexturesAvailable) {
        std::string textureCopyError;
        if (!CopyCaveTestTexturesToProject(projectRoot, &caveData, &textureCopyError)) {
            return fail("could not copy temp cave test textures: " + textureCopyError);
        }
    }

    CaveMesh caveMesh = BuildCaveMesh(caveData);
    CaveMesh partialCaveMesh = caveMesh;
    if (caveMesh.chunks.empty() || caveMesh.boundsMax[0] <= caveMesh.boundsMin[0] ||
        !RebuildCaveMeshChunks(caveData, caveData.dirtyChunks, &partialCaveMesh)) {
        return fail("cave mesh build or chunk rebuild failed.");
    }

    Entity& terrain =
        state_.CreateEntity("Cave Entrance Terrain", {MakeTransformComponent(), MakeTerrainComponent(33, {42.0f, 5.5f, 42.0f}, 8)});
    terrain.isStatic = true;
    if (Component* terrainComponent = FindTerrainComponent(terrain)) {
        SaveTerrainDataToComponent(terrainData, terrainComponent);
    } else {
        return fail("created cave demo terrain has no Terrain component.");
    }

    Entity& cave =
        state_.CreateEntity("Worm Cave Volume",
                            {MakeTransformComponent(), MakeCaveVolumeComponent({25, 17, 25}, {34.0f, 16.0f, 28.0f}, 8)});
    cave.isStatic = true;
    cave.position = {8.5f, 0.3f, 0.0f};
    Component* caveComponent = FindCaveVolumeComponent(cave);
    if (caveComponent == nullptr) {
        return fail("created cave entity has no CaveVolume component.");
    }
    CaveBrushSettings entranceCouplingBrush;
    entranceCouplingBrush.mode = CaveBrushMode::Tunnel;
    entranceCouplingBrush.falloff = CaveFalloffCurve::Smooth;
    entranceCouplingBrush.radius = 2.35f;
    entranceCouplingBrush.strength = 1.35f;
    entranceCouplingBrush.opacity = 1.0f;
    if (!ApplyCaveTerrainCoupling(cave, &caveData, CaveLocalToWorld(caveData, cave, {-16.5f, 1.1f, 0.0f}),
                                  entranceCouplingBrush)) {
        return fail("cave/terrain coupling did not cut the terrain entrance.");
    }
    SaveCaveVolumeDataToComponent(caveData, caveComponent);
    if (Component* terrainComponent = FindTerrainComponent(terrain)) {
        TerrainData coupledTerrain;
        if (!LoadTerrainDataFromComponent(*terrainComponent, &coupledTerrain) ||
            !TerrainIsHoleAtUv(coupledTerrain, entranceUv)) {
            return fail("coupled cave edit did not persist a terrain hole at the entrance.");
        }
    }

    Entity& light = state_.CreateEntity("Cave Demo Sun", {MakeTransformComponent(), MakeLightComponent("Directional")});
    light.rotation = {50.0f, -28.0f, 0.0f};

    Component caveFog = MakeFogComponent();
    SetComponentPropertyForUi(caveFog, "mode", "Exponential");
    SetComponentPropertyForUi(caveFog, "color", "0.34, 0.38, 0.40, 1");
    SetComponentPropertyForUi(caveFog, "density", "0.034");
    SetComponentPropertyForUi(caveFog, "startDistance", "4");
    SetComponentPropertyForUi(caveFog, "endDistance", "68");
    SetComponentPropertyForUi(caveFog, "heightEnabled", "true");
    SetComponentPropertyForUi(caveFog, "heightStart", "2.5");
    SetComponentPropertyForUi(caveFog, "heightFalloff", "18");
    state_.CreateEntity("Cave Atmosphere", {MakeTransformComponent(), caveFog});

    Entity& player = state_.CreateEntity("Cave Player",
                                         {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube", "PlayerBlue"),
                                          MakeCharacterControllerRuntimeComponent(), MakeInputActionMapRuntimeComponent(),
                                          MakeRigidbody3DComponent("Kinematic"), MakeCollider3DComponent("Box")});
    player.position = CaveLocalToWorld(caveData, cave, {-6.0f, 0.65f, 1.0f});
    player.scale = {0.7f, 1.1f, 0.7f};

    Component fallingBody = MakeRigidbody3DComponent("Dynamic");
    SetComponentPropertyForUi(fallingBody, "restitution", "0");
    Component fallingCollider = MakeCollider3DComponent("Sphere");
    SetComponentPropertyForUi(fallingCollider, "radius", "0.35");
    Entity& fallingProbe =
        state_.CreateEntity("Cave Collision Probe",
                            {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitSphere", "PrototypeGray"),
                             fallingBody, fallingCollider});
    const std::array<float, 3> caveProbeStart = CaveLocalToWorld(caveData, cave, {2.0f, 0.4f, 4.0f});
    CaveRayHit caveProbeFloor;
    if (!CaveRaycastWorld(caveData, cave, caveProbeStart, {0.0f, -1.0f, 0.0f}, 7.0f, &caveProbeFloor) ||
        !caveProbeFloor.hit) {
        return fail("could not place cave collision probe above a generated cave floor.");
    }
    fallingProbe.position = {caveProbeStart[0], caveProbeFloor.point[1] + 1.0f, caveProbeStart[2]};
    fallingProbe.scale = {0.7f, 0.7f, 0.7f};

    Entity& camera =
        state_.CreateEntity("Main Camera",
                            {MakeTransformComponent(), MakeCameraComponent(), MakeCameraFollowRuntimeComponent("Cave Player")});
    camera.position = {player.position[0] - 6.0f, player.position[1] + 4.2f, player.position[2] + 8.5f};
    camera.rotation = {-30.0f, -18.0f, 0.0f};

    state_.SelectEntity(cave.id);
    state_.MarkSceneDirty("Generated CaveDemos terrain entrance and worm cave fixture.");
    if (!state_.SaveProject(&error)) {
        return fail("could not save CaveDemos project: " + error);
    }

    if (!state_.OpenProject(projectRoot, &error)) {
        return fail("could not reload CaveDemos project: " + error);
    }

    Entity* reloadedTerrain = state_.FindEntityByName("Cave Entrance Terrain");
    Entity* reloadedCave = state_.FindEntityByName("Worm Cave Volume");
    Entity* reloadedProbe = state_.FindEntityByName("Cave Collision Probe");
    Entity* reloadedCamera = state_.FindEntityByName("Main Camera");
    if (reloadedTerrain == nullptr || reloadedCave == nullptr || reloadedProbe == nullptr || reloadedCamera == nullptr) {
        return fail("reloaded cave demo is missing terrain, cave, probe, or camera.");
    }

    const Component* reloadedTerrainComponent = FindTerrainComponent(*reloadedTerrain);
    TerrainData reloadedTerrainData;
    if (reloadedTerrainComponent == nullptr ||
        !LoadTerrainDataFromComponent(*reloadedTerrainComponent, &reloadedTerrainData) ||
        !TerrainIsHoleAtUv(reloadedTerrainData, entranceUv)) {
        return fail("reloaded cave entrance terrain hole did not survive.");
    }

    const Component* reloadedCaveComponent = FindCaveVolumeComponent(*reloadedCave);
    CaveVolumeData reloadedCaveData;
    if (reloadedCaveComponent == nullptr || !LoadCaveVolumeDataFromComponent(*reloadedCaveComponent, &reloadedCaveData)) {
        return fail("reloaded cave volume data could not be parsed.");
    }
    if (reloadedCaveData.resolution != std::array<int, 3>{25, 17, 25} || CaveLayerCount(reloadedCaveData) < 4 ||
        reloadedCaveData.densities.size() != static_cast<size_t>(CaveSampleCount(reloadedCaveData)) ||
        reloadedCaveData.dirtyChunks.empty()) {
        return fail("reloaded cave metadata, density field, layers, or dirty chunks did not survive.");
    }
    if (reloadedCaveData.layers[0].material != "CaveRock" || reloadedCaveData.layers[2].roughness < 0.90f) {
        return fail("reloaded cave layer material settings did not survive.");
    }
    if (caveTestTexturesAvailable) {
        for (int layerIndex = 0; layerIndex < 4; ++layerIndex) {
            if (reloadedCaveData.layers[static_cast<size_t>(layerIndex)].albedoTexture.empty()) {
                return fail("reloaded cave layer lost its copied albedo texture reference.");
            }
            const std::filesystem::path copiedTexture =
                projectRoot / reloadedCaveData.layers[static_cast<size_t>(layerIndex)].albedoTexture;
            std::error_code copiedTextureError;
            if (!std::filesystem::exists(copiedTexture, copiedTextureError)) {
                return fail("reloaded cave layer references a missing copied temp texture: " + copiedTexture.string());
            }
        }
    }

    const CaveSample chamberSample = SampleCaveLocal(reloadedCaveData, {2.0f, 0.2f, 4.0f});
    if (!chamberSample.valid || chamberSample.density >= 0.0f) {
        return fail("reloaded cave chamber sampling did not find empty carved space.");
    }
    float caveWeightSum = 0.0f;
    for (float weight : chamberSample.layerWeights) {
        caveWeightSum += weight;
    }
    if (std::fabs(caveWeightSum - 1.0f) > 0.02f) {
        return fail("reloaded cave layer weights are not normalized.");
    }

    CaveMesh reloadedCaveMesh = BuildCaveMesh(reloadedCaveData);
    if (reloadedCaveMesh.chunks.empty() || reloadedCaveMesh.boundsMax[1] <= reloadedCaveMesh.boundsMin[1]) {
        return fail("reloaded cave mesh bounds are invalid.");
    }
    if (!RebuildCaveMeshChunks(reloadedCaveData, reloadedCaveData.dirtyChunks, &reloadedCaveMesh)) {
        return fail("reloaded cave chunk rebuild failed.");
    }

    const std::array<float, 3> chamberWorld = CaveLocalToWorld(reloadedCaveData, *reloadedCave, {2.0f, 0.4f, 4.0f});
    CaveRayHit floorHit;
    if (!CaveRaycastWorld(reloadedCaveData, *reloadedCave, chamberWorld, {0.0f, -1.0f, 0.0f}, 7.0f, &floorHit) ||
        !floorHit.hit) {
        return fail("cave API raycast did not hit the chamber floor.");
    }
    CaveRayHit ceilingHit;
    if (!CaveRaycastWorld(reloadedCaveData, *reloadedCave, chamberWorld, {0.0f, 1.0f, 0.0f}, 7.0f, &ceilingHit) ||
        !ceilingHit.hit) {
        return fail("cave API raycast did not hit the chamber ceiling.");
    }
    CaveRayHit wallHit;
    if (!CaveRaycastWorld(reloadedCaveData, *reloadedCave, chamberWorld, {1.0f, 0.0f, 0.0f}, 8.0f, &wallHit) ||
        !wallHit.hit) {
        return fail("cave API raycast did not hit a chamber wall.");
    }

    PhysicsRayHit3D physicsCaveHit;
    const bool physicsRayHit = state_.Physics().Raycast3D(
        state_.Entities(), {chamberWorld[0], chamberWorld[1], chamberWorld[2]}, {1.0f, 0.0f, 0.0f}, 8.0f,
        &physicsCaveHit);
    if (!physicsRayHit || !physicsCaveHit.hit || physicsCaveHit.entityId != reloadedCave->id ||
        physicsCaveHit.colliderType != "CaveVolume.Surface") {
        std::ostringstream diagnostic;
        diagnostic << "physics raycast did not hit the reloaded cave volume";
        if (physicsRayHit) {
            diagnostic << " (hit entity " << physicsCaveHit.entityId << " " << physicsCaveHit.entityName
                       << ", type " << physicsCaveHit.colliderType << ", distance " << physicsCaveHit.distance
                       << ")";
        } else {
            diagnostic << " (no hit)";
        }
        diagnostic << ".";
        return fail(diagnostic.str());
    }

    const float probeStartY = reloadedProbe->position[1];
    if (!state_.BeginPlayMode()) {
        return fail("could not enter play mode for cave collision proof.");
    }
    bool sawCaveCollision = false;
    for (int step = 0; step < 180; ++step) {
        state_.UpdatePlayMode(1.0f / 60.0f);
        for (const PhysicsEvent& event : state_.PhysicsEvents()) {
            const bool includesCave = event.entityAId == reloadedCave->id || event.entityBId == reloadedCave->id;
            const bool includesProbe = event.entityAName == "Cave Collision Probe" ||
                                       event.entityBName == "Cave Collision Probe";
            sawCaveCollision = sawCaveCollision || (includesCave && includesProbe && !event.trigger);
        }
        if (sawCaveCollision) {
            break;
        }
    }
    const Entity* runtimeProbe = state_.FindEntityByName("Cave Collision Probe");
    const bool probeMoved = runtimeProbe != nullptr && runtimeProbe->position[1] < probeStartY - 0.05f;
    state_.StopPlayMode();
    if (!probeMoved || !sawCaveCollision) {
        return fail("play-mode physics did not move the falling probe onto the cave collider.");
    }

    state_.AddActivity("smoke.caves", "Passed",
                       "Created CaveDemos, cut a terrain entrance, carved worm tunnels/chamber/shaft, painted cave layers, saved/reloaded, raycasted floor/ceiling/walls, and collided in play mode.");
    return true;
}

bool EditorApp::RunFogSmokeTest() {
    if (!options_.smokeTestFog) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Fog smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Fog smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot = std::filesystem::current_path() / "build" / "fog-smoke-project";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create fog smoke project: " + error);
    }

    state_.ClearScene();
    Component fog = MakeFogComponent();
    SetComponentPropertyForUi(fog, "mode", "Exponential");
    SetComponentPropertyForUi(fog, "density", "0.045");
    SetComponentPropertyForUi(fog, "startDistance", "2");
    SetComponentPropertyForUi(fog, "endDistance", "34");
    SetComponentPropertyForUi(fog, "heightEnabled", "true");
    SetComponentPropertyForUi(fog, "heightStart", "1.8");
    SetComponentPropertyForUi(fog, "heightFalloff", "12");
    Entity& fogEntity = state_.CreateEntity("Smoke Fog Environment", {MakeTransformComponent(), fog});

    Entity& nearCube =
        state_.CreateEntity("Near Fog Cube", {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube", "PlayerBlue")});
    nearCube.position = {0.0f, 0.5f, -3.0f};
    Entity& farCube =
        state_.CreateEntity("Far Fog Cube", {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube", "WallSlate")});
    farCube.position = {0.0f, 0.5f, -18.0f};
    farCube.scale = {1.4f, 1.4f, 1.4f};
    Entity& camera = state_.CreateEntity("Main Camera", {MakeTransformComponent(), MakeCameraComponent()});
    camera.position = {0.0f, 3.2f, 6.0f};
    camera.rotation = {-18.0f, 0.0f, 0.0f};

    const SceneValidationResult validation = state_.ValidateScene();
    if (!validation.ok) {
        return fail("valid fog scene did not validate: " + JoinInline(validation.diagnostics, 4));
    }

    state_.SelectEntity(fogEntity.id);
    if (!state_.SaveProject(&error)) {
        return fail("could not save fog smoke project: " + error);
    }
    if (!state_.OpenProject(projectRoot, &error)) {
        return fail("could not reload fog smoke project: " + error);
    }
    const Entity* reloadedFog = state_.FindEntityByName("Smoke Fog Environment");
    const Component* reloadedFogComponent = reloadedFog == nullptr ? nullptr : FindComponent(*reloadedFog, "Fog");
    if (reloadedFogComponent == nullptr || ComponentPropertyValue(*reloadedFogComponent, "mode") != "Exponential" ||
        ComponentPropertyValue(*reloadedFogComponent, "heightEnabled") != "true") {
        return fail("fog component properties did not survive save/reload.");
    }

    RenderViewportScene(640, 360);
    RenderGameViewportScene(640, 360);
    if (!viewportFramebufferComplete_ || !gameFramebufferComplete_) {
        return fail("Scene or Game framebuffer was incomplete.");
    }
    if (!viewportLastFogApplied_ || !gameLastFogApplied_) {
        return fail("fog settings were not applied to both Scene and Game views.");
    }
    if (viewportLastRenderedCubeCount_ < 2 || gameLastRenderedCubeCount_ < 2) {
        return fail("fog smoke scene did not render both probe cubes.");
    }

    state_.AddActivity("smoke.fog", "Passed",
                       "Fog component validated, saved/reloaded, and rendered in Scene and Game view framebuffers.");
    return true;
}

bool EditorApp::RunSpriteSmokeTest() {
    if (!options_.smokeTestSprites) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Sprite smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Sprite smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot = std::filesystem::current_path() / "build" / "sprite-smoke-project";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create sprite smoke project: " + error);
    }
    state_.ClearScene();

    const std::filesystem::path sourcePath = projectRoot / "ExternalSources" / "SmokeSpriteSheet.png";
    constexpr int sheetWidth = 96;
    constexpr int sheetHeight = 32;
    std::vector<unsigned char> pixels(static_cast<size_t>(sheetWidth * sheetHeight * 4), 255u);
    for (int y = 0; y < sheetHeight; ++y) {
        for (int x = 0; x < sheetWidth; ++x) {
            const int frame = x / 32;
            const bool checker = ((x / 4) + (y / 4)) % 2 == 0;
            const size_t offset = static_cast<size_t>(y * sheetWidth + x) * 4u;
            pixels[offset + 0] = frame == 0 ? (checker ? 220u : 120u) : (frame == 1 ? 80u : 210u);
            pixels[offset + 1] = frame == 0 ? 90u : (frame == 1 ? (checker ? 220u : 140u) : 110u);
            pixels[offset + 2] = frame == 0 ? 80u : (frame == 1 ? 120u : (checker ? 230u : 150u));
            pixels[offset + 3] = 255u;
        }
    }
    if (!EncodeImagePngBgra(sourcePath, sheetWidth, sheetHeight, pixels, &error)) {
        return fail("could not encode sprite sheet: " + error);
    }

    AssetRecord textureAsset;
    if (!state_.ImportAsset(sourcePath, "sprite-smoke", "test-fixture", &textureAsset, &error)) {
        return fail("could not import sprite sheet: " + error);
    }
    if (textureAsset.type != "Texture" || textureAsset.importSettings.find("spriteMode=Single") == std::string::npos) {
        return fail("imported sheet did not receive texture sprite import settings.");
    }

    try {
        std::ifstream metadataInput(projectRoot / textureAsset.metadataPath);
        const json metadata = json::parse(metadataInput);
        if (!metadata.contains("textureImport") ||
            metadata.at("textureImport").value("pixelsPerUnit", 0) != 100 ||
            metadata.at("textureImport").value("spriteMode", "") != "Single") {
            return fail("texture metadata did not include sprite import defaults.");
        }
        std::ifstream resourceInput(projectRoot / textureAsset.resourcePath);
        const json resource = json::parse(resourceInput);
        if (!resource.contains("sprite") || resource.at("sprite").value("textureAsset", "") != textureAsset.id) {
            return fail("texture resource did not include default sprite metadata.");
        }
    } catch (const std::exception& exception) {
        return fail("could not parse imported sprite metadata: " + std::string(exception.what()));
    }

    Component camera = MakeCameraComponent();
    SetComponentPropertyForUi(camera, "projection", "Orthographic");
    SetComponentPropertyForUi(camera, "orthographicSize", "3");
    Entity& cameraEntity = state_.CreateEntity("2D Camera", {MakeTransformComponent(), camera});
    cameraEntity.position = {0.0f, 0.0f, 10.0f};
    cameraEntity.rotation = {0.0f, 0.0f, 0.0f};

    Component backgroundSprite = MakeSpriteRendererComponent(textureAsset.id);
    SetComponentPropertyForUi(backgroundSprite, "rect", "64, 0, 32, 32");
    SetComponentPropertyForUi(backgroundSprite, "pixelsPerUnit", "32");
    SetComponentPropertyForUi(backgroundSprite, "sortingLayer", "Background");
    SetComponentPropertyForUi(backgroundSprite, "orderInLayer", "-10");
    Entity& background = state_.CreateEntity("Background Sprite", {MakeTransformComponent(), backgroundSprite});
    background.position = {0.0f, 0.0f, -0.1f};
    background.scale = {1.5f, 1.5f, 1.0f};

    Component sprite = MakeSpriteRendererComponent(textureAsset.id);
    SetComponentPropertyForUi(sprite, "rect", "0, 0, 32, 32");
    SetComponentPropertyForUi(sprite, "pixelsPerUnit", "32");
    SetComponentPropertyForUi(sprite, "pivot", "0.5, 0.5");
    SetComponentPropertyForUi(sprite, "sortingLayer", "Default");
    SetComponentPropertyForUi(sprite, "orderInLayer", "5");
    Component animation = MakeSpriteAnimationRuntimeComponent();
    SetComponentPropertyForUi(animation, "frames", "0, 0, 32, 32;32, 0, 32, 32;64, 0, 32, 32");
    SetComponentPropertyForUi(animation, "frameRate", "10");
    Component body = MakeRigidbody2DComponent("Static");
    Component collider = MakeCollider2DComponent("Box");
    SetComponentPropertyForUi(collider, "size", "1, 1");
    SetComponentPropertyForUi(collider, "offset", "0, 0");
    Entity& actor = state_.CreateEntity("Animated Sprite", {MakeTransformComponent(), sprite, animation, body, collider});
    actor.position = {0.0f, 0.0f, 0.0f};
    state_.SelectEntity(actor.id);

    const SceneValidationResult validation = state_.ValidateScene();
    if (!validation.ok) {
        return fail("sprite scene did not validate: " + JoinInline(validation.diagnostics, 4));
    }
    if (!state_.SaveProject(&error)) {
        return fail("could not save sprite smoke project: " + error);
    }
    if (!state_.OpenProject(projectRoot, &error)) {
        return fail("could not reload sprite smoke project: " + error);
    }

    Entity* reloadedActor = state_.FindEntityByName("Animated Sprite");
    Entity* reloadedBackground = state_.FindEntityByName("Background Sprite");
    if (reloadedActor == nullptr || reloadedBackground == nullptr ||
        FindSpriteRendererComponent(*reloadedActor) == nullptr ||
        FindSpriteRendererComponent(*reloadedBackground) == nullptr ||
        !HasComponentType(*reloadedActor, "Collider2D")) {
        return fail("reloaded sprite scene lost sprite renderer or collider components.");
    }
    const Component* reloadedCollider = FindComponent(*reloadedActor, "Collider2D");
    if (reloadedCollider == nullptr || ComponentPropertyValue(*reloadedCollider, "size") != "1, 1") {
        return fail("sprite collider bounds did not preserve the expected size.");
    }

    PhysicsRayHit2D hit;
    if (!state_.Physics().Raycast2D(state_.Entities(), {-2.0f, 0.0f}, {1.0f, 0.0f}, 4.0f, &hit) ||
        !hit.hit || hit.entityId != reloadedActor->id) {
        return fail("2D physics raycast did not hit the sprite collider.");
    }

    if (!state_.BeginPlayMode()) {
        return fail("could not start play mode for sprite animation.");
    }
    state_.UpdatePlayMode(0.16f);
    Entity* runtimeActor = state_.FindEntityByName("Animated Sprite");
    Component* runtimeSprite = runtimeActor == nullptr ? nullptr : FindSpriteRendererComponent(*runtimeActor);
    const Component* runtimeAnimation = runtimeActor == nullptr ? nullptr : FindComponent(*runtimeActor, "SpriteAnimationRuntime");
    if (runtimeSprite == nullptr || runtimeAnimation == nullptr ||
        ComponentPropertyValue(*runtimeSprite, "rect") != "32, 0, 32, 32" ||
        ComponentPropertyValue(*runtimeAnimation, "currentFrame") != "1") {
        state_.StopPlayMode();
        return fail("SpriteAnimationRuntime did not advance the SpriteRenderer frame.");
    }
    state_.StopPlayMode();

    RenderViewportScene(640, 360);
    RenderGameViewportScene(640, 360);
    if (!viewportFramebufferComplete_ || !gameFramebufferComplete_ ||
        viewportLastRenderedSpriteCount_ < 2 || gameLastRenderedSpriteCount_ < 2) {
        return fail("Scene/Game sprite render pass did not submit both sprite quads.");
    }

    state_.AddActivity("smoke.sprites", "Passed",
                       "Imported a sprite sheet, validated sprite metadata, rendered sorted SpriteRenderer quads, raycasted Collider2D, and advanced frame animation in play mode.");
    return true;
}

bool EditorApp::RunProjectBuilderSmokeTest() {
    if (!options_.smokeTestProjectBuilder) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Project builder smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Project builder smoke failed: " + message);
        return false;
    };

    const ProjectBuildSettings originalSettings = state_.BuildSettings();

    ProjectBuildSettings settings = originalSettings;
    settings.targetPlatform = "Windows";
    settings.architecture = "x64";
    settings.configuration = "Debug";
    const std::filesystem::path selectedOutputDirectory =
        std::filesystem::absolute(std::filesystem::current_path() / "build" / "User Selected Client Build").lexically_normal();
    settings.outputDirectory = selectedOutputDirectory.string();
    settings.executableName = "Smoke Multiplayer Game";
    settings.developmentBuild = true;
    settings.copyProjectFiles = true;
    settings.runPlayerSmokeAfterBuild = true;
    std::error_code relativeError;
    const std::filesystem::path activeScene =
        std::filesystem::relative(state_.SceneFilePathString(), state_.ProjectRootPathString(), relativeError);
    settings.scenes = {relativeError ? state_.SceneFilePathString() : activeScene.generic_string()};
    settings.multiplayer.enabled = true;
    settings.multiplayer.topology = "Host Client";
    settings.multiplayer.transport = "UDP";
    settings.multiplayer.bindAddress = "127.0.0.1";
    settings.multiplayer.port = 7788;
    settings.multiplayer.maxPlayers = 8;
    state_.SetBuildSettings(settings);
    RefreshBuildSettingsInputs();

    ProjectBuildReport report;
    std::string error;
    if (!state_.PackagePlayerBuild(PlayerExecutablePathForCurrentBuild(), &report, &error)) {
        state_.SetBuildSettings(originalSettings);
        state_.SaveProject();
        RefreshBuildSettingsInputs();
        return fail(error);
    }

    if (std::filesystem::absolute(report.outputDirectory).lexically_normal() != selectedOutputDirectory) {
        state_.SetBuildSettings(originalSettings);
        state_.SaveProject();
        RefreshBuildSettingsInputs();
        return fail("package did not honor the selected client build folder.");
    }

    const std::filesystem::path multiplayerSettingsPath =
        report.outputDirectory / "Data" / "ProjectSettings" / "MultiplayerSettings.json";
    const std::filesystem::path installerManifestPath = report.outputDirectory / "installer-manifest.aineinstaller.json";
    const std::filesystem::path updaterManifestPath = report.outputDirectory / "latest.aineupdate.json";
    if (!std::filesystem::exists(report.executablePath) || !std::filesystem::exists(report.manifestPath) ||
        !std::filesystem::exists(report.launcherPath) || !std::filesystem::exists(report.packagedProjectFile) ||
        !std::filesystem::exists(multiplayerSettingsPath) ||
        !std::filesystem::exists(installerManifestPath) || !std::filesystem::exists(updaterManifestPath)) {
        state_.SetBuildSettings(originalSettings);
        state_.SaveProject();
        RefreshBuildSettingsInputs();
        return fail("package output is missing executable, launcher, manifest, installer/update manifests, project file, or multiplayer settings.");
    }

    try {
        std::ifstream manifestInput(report.manifestPath);
        const json manifest = json::parse(manifestInput);
        if (manifest.value("format", "") != "aine.buildManifest" ||
            manifest.value("packageType", "") != "WindowsPlayer" ||
            manifest.value("launcher", "").empty() ||
            manifest.value("releaseChannel", "") != "internal" ||
            manifest.value("executableHash", "").empty() ||
            !manifest.contains("target") ||
            manifest.at("target").value("platform", "") != "Windows" ||
            !manifest.contains("signing") ||
            manifest.at("signing").value("mode", "") != "Unsigned" ||
            !manifest.contains("multiplayer") ||
            !manifest.at("multiplayer").value("enabled", false) ||
            manifest.at("multiplayer").value("port", 0) != 7788) {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail("build manifest did not preserve Windows player and multiplayer settings.");
        }

        std::ifstream installerInput(installerManifestPath);
        const json installer = json::parse(installerInput);
        if (installer.value("format", "") != "aine.installerManifest" ||
            installer.value("releaseChannel", "") != "internal" ||
            installer.value("entryPointHash", "").empty() ||
            installer.value("requiresAdmin", true)) {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail("installer manifest did not preserve release, hash, or per-user settings.");
        }

        std::ifstream updaterInput(updaterManifestPath);
        const json updater = json::parse(updaterInput);
        if (updater.value("format", "") != "aine.updateManifest" ||
            updater.value("packageManifest", "") != report.manifestPath.filename().generic_string() ||
            updater.value("executableHash", "").empty()) {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail("updater manifest did not preserve package manifest or executable hash.");
        }

        std::ifstream projectInput(report.packagedProjectFile);
        const json packagedProject = json::parse(projectInput);
        if (!packagedProject.contains("buildSettings") ||
            packagedProject.at("buildSettings").value("targetPlatform", "") != "Windows" ||
            !packagedProject.at("buildSettings").contains("multiplayer") ||
            !packagedProject.at("buildSettings").at("multiplayer").value("enabled", false)) {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail("packaged project did not include persisted target and multiplayer build settings.");
        }
    } catch (const std::exception& exception) {
        state_.SetBuildSettings(originalSettings);
        state_.SaveProject();
        RefreshBuildSettingsInputs();
        return fail(std::string("could not inspect package JSON: ") + exception.what());
    }

    for (const std::string& targetPlatform : std::vector<std::string>{"Linux", "macOS"}) {
        ProjectBuildSettings targetSettings = settings;
        targetSettings.targetPlatform = targetPlatform;
        targetSettings.outputDirectory =
            (std::filesystem::current_path() / "build" / ("project-builder-" + ToLower(targetPlatform) + "-smoke")).string();
        targetSettings.executableName = "Smoke " + targetPlatform + " Game";
        targetSettings.runPlayerSmokeAfterBuild = true;
        state_.SetBuildSettings(targetSettings);
        RefreshBuildSettingsInputs();

        ProjectBuildReport targetReport;
        std::string targetError;
        const bool packagedTarget =
            state_.PackagePlayerBuild(PlayerExecutablePathForCurrentBuild(), &targetReport, &targetError);
        if (!packagedTarget) {
            if (targetError.find("unavailable") == std::string::npos ||
                targetError.find(targetPlatform) == std::string::npos) {
                state_.SetBuildSettings(originalSettings);
                state_.SaveProject();
                RefreshBuildSettingsInputs();
                return fail(targetPlatform + " target did not package and did not report a clear unavailable runtime: " +
                            targetError);
            }
            continue;
        }

        if (std::filesystem::absolute(targetReport.outputDirectory).lexically_normal() == selectedOutputDirectory ||
            !std::filesystem::exists(targetReport.executablePath) ||
            !std::filesystem::exists(targetReport.launcherPath) ||
            !std::filesystem::exists(targetReport.manifestPath) ||
            !std::filesystem::exists(targetReport.packagedProjectFile)) {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail(targetPlatform + " structural package is missing output, executable, launcher, manifest, or project data.");
        }

        std::ifstream targetManifestInput(targetReport.manifestPath);
        const json targetManifest = json::parse(targetManifestInput);
        if (!targetManifest.contains("target") ||
            targetManifest.at("target").value("platform", "") != targetPlatform ||
            targetManifest.value("launcher", "").empty() ||
            targetManifest.value("packageType", "") != targetPlatform + "Player") {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail(targetPlatform + " structural package manifest did not preserve platform metadata.");
        }
        if (targetReport.runtimeSmokeStatus.find("not executable on this host") == std::string::npos) {
            state_.SetBuildSettings(originalSettings);
            state_.SaveProject();
            RefreshBuildSettingsInputs();
            return fail(targetPlatform + " structural package did not mark runtime launch as host-incompatible.");
        }
    }

    lastBuildOutputPath_ = report.outputDirectory.string();
    lastBuildStatus_ = "Project builder smoke package: " + report.executablePath.string();
    state_.SetBuildSettings(originalSettings);
    state_.SaveProject();
    RefreshBuildSettingsInputs();
    state_.AddActivity("smoke.project-builder", "Passed",
                       "Packaged Windows player with launch smoke, then verified Linux/macOS package availability diagnostics or structural metadata.");
    return true;
}

bool EditorApp::RunProjectSettingsSmokeTest() {
    if (!options_.smokeTestProjectSettings) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Project settings smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Project settings smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot = std::filesystem::current_path() / "projects" / "ProjectSettingsSmoke";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create smoke project: " + error);
    }

    if (!state_.AddProjectTag("Boss", &error) ||
        !state_.AddProjectLayer("Actors", &error) ||
        !state_.AddProjectLayer("Projectiles", &error) ||
        !state_.SetLayerCollisionEnabled("Actors", "Projectiles", false, &error)) {
        return fail(error);
    }

    state_.ClearScene();
    aine::Component actorBody = MakeRigidbody3DComponent("Kinematic");
    SetComponentPropertyForUi(actorBody, "useGravity", "false");
    aine::Component actorCollider = MakeCollider3DComponent("Box");
    Entity& actor = state_.CreateEntity(
        "Smoke Actor", {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube"), actorBody, actorCollider});
    actor.tag = "Boss";
    actor.layer = "Actors";
    const std::array<float, 3> actorPosition{0.0f, 0.5f, 0.0f};
    state_.SetEntityTransform(actor.id, &actorPosition, nullptr, nullptr);

    aine::Component projectileBody = MakeRigidbody3DComponent("Static");
    SetComponentPropertyForUi(projectileBody, "useGravity", "false");
    aine::Component projectileCollider = MakeCollider3DComponent("Box");
    Entity& projectile =
        state_.CreateEntity("Smoke Projectile",
                            {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube"), projectileBody,
                             projectileCollider});
    projectile.layer = "Projectiles";
    const std::array<float, 3> projectilePosition{0.0f, 0.5f, 0.0f};
    state_.SetEntityTransform(projectile.id, &projectilePosition, nullptr, nullptr);
    const int actorId = actor.id;
    const int projectileId = projectile.id;
    state_.EnsurePhysicsSettingsEntity();

    if (!state_.SaveProject(&error)) {
        return fail("could not save smoke project: " + error);
    }

    auto hasCollisionPair = [](const std::vector<PhysicsEvent>& events, int firstId, int secondId) {
        return std::any_of(events.begin(), events.end(), [firstId, secondId](const PhysicsEvent& event) {
            if (event.trigger) {
                return false;
            }
            return (event.entityAId == firstId && event.entityBId == secondId) ||
                   (event.entityAId == secondId && event.entityBId == firstId);
        });
    };

    if (!state_.BeginPlayMode()) {
        return fail("play mode did not start for disabled collision matrix check.");
    }
    state_.UpdatePlayMode(1.0f / 60.0f);
    if (hasCollisionPair(state_.PhysicsEvents(), actorId, projectileId)) {
        state_.StopPlayMode();
        return fail("disabled layer pair still emitted a collision event.");
    }
    state_.StopPlayMode();

    if (!state_.SetLayerCollisionEnabled("Actors", "Projectiles", true, &error)) {
        return fail(error);
    }
    if (!state_.BeginPlayMode()) {
        return fail("play mode did not start for enabled collision matrix check.");
    }
    state_.UpdatePlayMode(1.0f / 60.0f);
    if (!hasCollisionPair(state_.PhysicsEvents(), actorId, projectileId)) {
        state_.StopPlayMode();
        return fail("enabled layer pair did not emit a collision event.");
    }
    state_.StopPlayMode();

    if (!state_.SetLayerCollisionEnabled("Actors", "Projectiles", false, &error) ||
        !state_.SaveProject(&error)) {
        return fail("could not persist final collision matrix: " + error);
    }

    EditorState reopened;
    if (!reopened.OpenProject(projectRoot / "AI Native Project.aineproject.json", &error)) {
        return fail("could not reopen smoke project: " + error);
    }
    const bool hasBossTag = std::find(reopened.ProjectTags().begin(), reopened.ProjectTags().end(), "Boss") !=
                            reopened.ProjectTags().end();
    const bool hasActorsLayer = std::find(reopened.ProjectLayers().begin(), reopened.ProjectLayers().end(), "Actors") !=
                                reopened.ProjectLayers().end();
    const bool hasProjectilesLayer =
        std::find(reopened.ProjectLayers().begin(), reopened.ProjectLayers().end(), "Projectiles") !=
        reopened.ProjectLayers().end();
    if (!hasBossTag || !hasActorsLayer || !hasProjectilesLayer ||
        reopened.LayerCollisionEnabled("Actors", "Projectiles")) {
        return fail("reopened project did not preserve tags, layers, or disabled collision matrix pair.");
    }

    state_.AddActivity("smoke.project-settings", "Passed",
                       "Tags, layers, collision matrix runtime behavior, and project persistence passed.");
    return true;
}

bool EditorApp::RunRenderProfileSmokeTest() {
    if (!options_.smokeTestRenderProfiles) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Render profile smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Render profile smoke failed: " + message);
        return false;
    };

    const std::filesystem::path projectRoot = std::filesystem::current_path() / "build" / "render-profile-smoke";
    std::string error;
    if (!state_.NewProject(projectRoot, &error)) {
        return fail("could not create smoke project: " + error);
    }

    const RenderProfileSettings* defaultProfile = state_.ActiveRenderProfile();
    if (defaultProfile == nullptr || defaultProfile->id != "basic-built-in") {
        return fail("new project did not default to the Basic Built-in render profile.");
    }
    if (state_.FindRenderProfile("2d") == nullptr || state_.FindRenderProfile("lightweight-3d") == nullptr ||
        state_.FindRenderProfile("high-fidelity-3d") == nullptr) {
        return fail("built-in render profiles were not registered.");
    }
    if (!state_.SaveProject(&error)) {
        return fail("could not save default render profile: " + error);
    }

    auto assertProjectFileProfile = [&](const std::filesystem::path& projectFile,
                                        const std::string& expectedProfile,
                                        const std::string& context) -> bool {
        try {
            std::ifstream input(projectFile);
            const json document = json::parse(input);
            if (!document.contains("rendering") || !document.at("rendering").is_object()) {
                return fail(context + " project file is missing rendering settings.");
            }
            const json& rendering = document.at("rendering");
            if (rendering.value("activeProfile", "") != expectedProfile) {
                return fail(context + " active render profile was not preserved.");
            }
            if (!rendering.contains("profiles") || !rendering.at("profiles").contains("basic-built-in") ||
                !rendering.at("profiles").contains("2d") ||
                !rendering.at("profiles").contains("lightweight-3d") ||
                !rendering.at("profiles").contains("high-fidelity-3d")) {
                return fail(context + " built-in profile definitions were not serialized.");
            }
            if (expectedProfile == "2d" &&
                !rendering.at("profiles").at("2d").at("features").value("sprites", false)) {
                return fail(context + " 2D profile did not preserve sprite feature metadata.");
            }
        } catch (const std::exception& exception) {
            return fail(context + " project file parse failed: " + std::string(exception.what()));
        }
        return true;
    };

    if (!assertProjectFileProfile(projectRoot / "AI Native Project.aineproject.json", "basic-built-in", "default")) {
        return false;
    }

    if (!state_.SetActiveRenderProfile("2d", &error) || !state_.SaveProject(&error)) {
        return fail("could not save 2D render profile: " + error);
    }
    const SceneValidationResult twoDimensionalProject = state_.ValidateProject();
    if (!twoDimensionalProject.ok) {
        return fail("2D render profile did not validate: " +
                    (twoDimensionalProject.diagnostics.empty() ? std::string{} : twoDimensionalProject.diagnostics.front()));
    }

    EditorState reopened;
    if (!reopened.OpenProject(projectRoot / "AI Native Project.aineproject.json", &error)) {
        return fail("could not reopen render profile smoke project: " + error);
    }
    const RenderProfileSettings* reopenedProfile = reopened.ActiveRenderProfile();
    if (reopenedProfile == nullptr || reopenedProfile->id != "2d" || !reopenedProfile->sprites ||
        reopenedProfile->mesh3d) {
        return fail("reopened project did not preserve the 2D render profile shape.");
    }
    if (!assertProjectFileProfile(projectRoot / "AI Native Project.aineproject.json", "2d", "2D")) {
        return false;
    }

    if (!state_.SetActiveRenderProfile("lightweight-3d", &error)) {
        return fail("could not select Lightweight 3D render profile: " + error);
    }
    const SceneValidationResult lightweightProject = state_.ValidateProject();
    if (!lightweightProject.ok) {
        return fail("Lightweight 3D render profile did not validate: " +
                    (lightweightProject.diagnostics.empty() ? std::string{} : lightweightProject.diagnostics.front()));
    }
    RenderViewportScene(640, 360);
    RenderGameViewportScene(640, 360);
    if (!viewportFramebufferComplete_ || !gameFramebufferComplete_ ||
        viewportLastRenderedCubeCount_ <= 0 || gameLastRenderedCubeCount_ <= 0) {
        return fail("Lightweight 3D profile did not preserve the current Scene/Game framebuffer render path.");
    }

    if (!state_.SetActiveRenderProfile("high-fidelity-3d", &error)) {
        return fail("could not select High Fidelity 3D render profile for validation check: " + error);
    }
    const SceneValidationResult highFidelityProject = state_.ValidateProject();
    if (highFidelityProject.ok ||
        std::none_of(highFidelityProject.diagnostics.begin(), highFidelityProject.diagnostics.end(),
                     [](const std::string& diagnostic) {
                         return diagnostic.find("future GPU buffer backend") != std::string::npos;
                     })) {
        return fail("High Fidelity 3D profile did not report the expected future-backend requirement.");
    }

    if (!state_.SetActiveRenderProfile("lightweight-3d", &error)) {
        return fail("could not restore Lightweight 3D render profile: " + error);
    }
    ProjectBuildSettings buildSettings = state_.BuildSettings();
    buildSettings.outputDirectory =
        (std::filesystem::current_path() / "build" / "render-profile-package").string();
    buildSettings.runPlayerSmokeAfterBuild = false;
    state_.SetBuildSettings(buildSettings);
    if (!state_.SaveProject(&error)) {
        return fail("could not save final Lightweight 3D profile: " + error);
    }

    ProjectBuildReport report;
    if (!state_.PackagePlayerBuild(PlayerExecutablePathForCurrentBuild(), &report, &error)) {
        return fail("could not package render profile smoke project: " + error);
    }
    if (!assertProjectFileProfile(report.packagedProjectFile, "lightweight-3d", "packaged")) {
        return false;
    }

    state_.AddActivity("smoke.render-profiles", "Passed",
                       "Default, 2D, Lightweight 3D, High Fidelity requirement validation, framebuffer rendering, and packaged project persistence passed.");
    return true;
}

bool EditorApp::RunFirstGameSmokeTest() {
    if (!options_.smokeTestFirstGame) {
        return true;
    }

    const std::filesystem::path firstGameProject =
        std::filesystem::current_path() / "projects" / "FirstGame" / "AI Native Project.aineproject.json";
    std::string error;
    if (!state_.OpenProject(firstGameProject, &error)) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: could not open fixture project: " + error);
        return false;
    }

    if (state_.ProjectName() != "First Game - Coin Dash") {
        state_.AddLog(LogLevel::Error,
                      "First game smoke failed: unexpected project name: " + state_.ProjectName());
        return false;
    }

    Entity* rules = state_.FindEntityByName("Game Rules");
    Entity* player = state_.FindEntityByName("Player");
    Entity* camera = state_.FindEntityByName("Main Camera");
    Entity* coinA = state_.FindEntityByName("Coin A");
    Entity* coinB = state_.FindEntityByName("Coin B");
    Entity* coinC = state_.FindEntityByName("Coin C");
    Entity* goal = state_.FindEntityByName("Goal Gate");
    if (rules == nullptr || player == nullptr || camera == nullptr || coinA == nullptr || coinB == nullptr || coinC == nullptr ||
        goal == nullptr) {
        state_.AddLog(LogLevel::Error,
                      "First game smoke failed: fixture is missing rules, player, camera, coins, or goal entities.");
        return false;
    }

    if (!HasComponentType(*rules, "GameRulesRuntime") || !HasComponentType(*rules, "InputActionMapRuntime") ||
        !HasComponentType(*camera, "CameraFollowRuntime") || !HasComponentType(*player, "CharacterControllerRuntime") ||
        !HasComponentType(*coinA, "CollectibleRuntime") || !HasComponentType(*coinB, "CollectibleRuntime") ||
        !HasComponentType(*coinC, "CollectibleRuntime") || !HasComponentType(*goal, "GoalRuntime")) {
        state_.AddLog(LogLevel::Error,
                      "First game smoke failed: fixture entities are missing required runtime components.");
        return false;
    }

    if (!HasComponentType(*player, "Collider3D")) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: Player is missing Collider3D.");
        return false;
    }
    for (const Entity& entity : state_.Entities()) {
        if (HasRenderableMesh(state_, entity) && !HasComponentType(entity, "Collider3D")) {
            state_.AddLog(LogLevel::Error,
                          "First game smoke failed: renderable entity is missing Collider3D: " + entity.name);
            return false;
        }
    }

    const SceneValidationResult validation = state_.ValidateScene();
    if (!validation.ok) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: scene validation failed before play.");
        return false;
    }

    const int playerId = player->id;
    const int cameraId = camera->id;
    const std::array<float, 3> originalPosition = player->position;
    const std::array<float, 3> originalCameraPosition = camera->position;
    state_.SelectEntity(playerId);

    StartOrResumePlayMode();
    if (!state_.IsPlaying() || state_.PlayScore() != 0 || state_.PlayGoalReached() || state_.PlayFailed()) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: play mode did not start with a clean game state.");
        return false;
    }
    if (!IsGameViewportInputActiveForTesting()) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: Play did not capture Game viewport input.");
        return false;
    }

    RuntimeInputState input;
    input.captured = true;
    input.captureSurface = "Game";
    input.character.moveZ = -1.0f;
    input.actions.push_back({"Move Z", "KeyboardMove", -1.0f, true});
    state_.SetRuntimeInputState(input);
    for (int step = 0; step < 28 && !state_.PlayGoalReached() && !state_.PlayFailed(); ++step) {
        state_.UpdatePlayMode(0.125f);
    }

    const Entity* runtimePlayer = state_.FindEntity(playerId);
    const Entity* runtimeCamera = state_.FindEntity(cameraId);
    if (runtimePlayer == nullptr || NearlyEqual(runtimePlayer->position[2], originalPosition[2])) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: player did not move during runtime simulation.");
        return false;
    }
    if (runtimeCamera == nullptr || NearlyEqual(runtimeCamera->position[2], originalCameraPosition[2])) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: CameraFollowRuntime did not move the camera.");
        return false;
    }

    if (state_.PlayFailed()) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: player triggered a hazard on the intended lane.");
        return false;
    }

    if (state_.PlayScore() != 3 || !state_.PlayGoalReached()) {
        state_.AddLog(LogLevel::Error,
                      "First game smoke failed: expected score 3 and completed goal, got score " +
                          std::to_string(state_.PlayScore()) + ".");
        return false;
    }

    StopPlayMode();
    const Entity* restoredPlayer = state_.FindEntity(playerId);
    const Entity* restoredCamera = state_.FindEntity(cameraId);
    if (!state_.IsEditMode() || restoredPlayer == nullptr ||
        restoredCamera == nullptr ||
        !NearlyEqual(restoredPlayer->position[0], originalPosition[0]) ||
        !NearlyEqual(restoredPlayer->position[1], originalPosition[1]) ||
        !NearlyEqual(restoredPlayer->position[2], originalPosition[2]) ||
        !NearlyEqual(restoredCamera->position[0], originalCameraPosition[0]) ||
        !NearlyEqual(restoredCamera->position[1], originalCameraPosition[1]) ||
        !NearlyEqual(restoredCamera->position[2], originalCameraPosition[2]) || state_.PlayScore() != 0 ||
        state_.PlayGoalReached() || state_.PlayFailed() || IsGameViewportInputActiveForTesting()) {
        state_.AddLog(LogLevel::Error, "First game smoke failed: Stop did not restore the edit-mode game state.");
        return false;
    }

    state_.AddActivity("smoke.first-game", "Passed",
                       "Opened FirstGame, collected 3 coins, reached the goal, and restored edit state.");
    return true;
}

bool EditorApp::RunRuntimeLogSmokeTest() {
    if (!options_.smokeTestRuntimeLogs) {
        return true;
    }

    const auto hasRuntimeEvent = [this](const std::string& eventName) {
        const std::vector<RuntimeLogEntry>& logs = state_.RuntimeLogs();
        return std::any_of(logs.begin(), logs.end(), [&eventName](const RuntimeLogEntry& entry) {
            return entry.event == eventName;
        });
    };

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Runtime log smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Runtime log smoke failed: " + message);
        return false;
    };

    const std::filesystem::path firstGameProject =
        std::filesystem::current_path() / "projects" / "FirstGame" / "AI Native Project.aineproject.json";
    std::string error;
    if (!state_.OpenProject(firstGameProject, &error)) {
        return fail("could not open FirstGame fixture: " + error);
    }

    Entity* player = state_.FindEntityByName("Player");
    Entity* camera = state_.FindEntityByName("Main Camera");
    Entity* goal = state_.FindEntityByName("Goal Gate");
    if (player == nullptr || camera == nullptr || goal == nullptr) {
        return fail("fixture is missing Player, Main Camera, or Goal Gate.");
    }

    const int playerId = player->id;
    const int cameraId = camera->id;
    const std::array<float, 3> originalPlayerPosition = player->position;
    const std::array<float, 3> originalCameraPosition = camera->position;

    StartOrResumePlayMode();
    if (!state_.IsPlaying()) {
        return fail("Play did not enter Playing state.");
    }
    if (!hasRuntimeEvent("play.start")) {
        return fail("play.start was not captured.");
    }

    RuntimeInputState input;
    input.captured = true;
    input.captureSurface = "Game";
    input.character.moveZ = -1.0f;
    input.actions.push_back({"Move Z", "KeyboardMove", -1.0f, true});
    state_.SetRuntimeInputState(input);
    if (!hasRuntimeEvent("input.capture")) {
        return fail("input.capture was not captured.");
    }

    for (int step = 0; step < 28 && !state_.PlayGoalReached() && !state_.PlayFailed(); ++step) {
        state_.UpdatePlayMode(0.125f);
    }

    const Entity* runtimePlayer = state_.FindEntity(playerId);
    const Entity* runtimeCamera = state_.FindEntity(cameraId);
    if (runtimePlayer == nullptr || runtimeCamera == nullptr ||
        NearlyEqual(runtimePlayer->position[2], originalPlayerPosition[2]) ||
        NearlyEqual(runtimeCamera->position[2], originalCameraPosition[2])) {
        return fail("runtime route did not move the player and camera.");
    }
    if (state_.PlayFailed()) {
        return fail("player triggered a hazard on the intended lane.");
    }
    if (state_.PlayScore() != 3 || !state_.PlayGoalReached()) {
        return fail("expected score 3 and completed goal, got score " + std::to_string(state_.PlayScore()) + ".");
    }
    if (!hasRuntimeEvent("runtime.collectible")) {
        return fail("runtime.collectible was not captured.");
    }
    if (!hasRuntimeEvent("runtime.goal")) {
        return fail("runtime.goal was not captured.");
    }

    StopPlayMode();
    if (!state_.IsEditMode() || !state_.RuntimeLogs().empty()) {
        return fail("Stop did not restore edit mode and clear transient runtime logs.");
    }

    const Entity* restoredPlayer = state_.FindEntity(playerId);
    const Entity* restoredCamera = state_.FindEntity(cameraId);
    if (restoredPlayer == nullptr || restoredCamera == nullptr ||
        !NearlyEqual(restoredPlayer->position[0], originalPlayerPosition[0]) ||
        !NearlyEqual(restoredPlayer->position[1], originalPlayerPosition[1]) ||
        !NearlyEqual(restoredPlayer->position[2], originalPlayerPosition[2]) ||
        !NearlyEqual(restoredCamera->position[0], originalCameraPosition[0]) ||
        !NearlyEqual(restoredCamera->position[1], originalCameraPosition[1]) ||
        !NearlyEqual(restoredCamera->position[2], originalCameraPosition[2])) {
        return fail("Stop did not restore the edit-mode transforms.");
    }

    state_.AddActivity("smoke.runtime-logs", "Passed",
                       "Captured play, input, physics, collectible, and goal events, then cleared after Stop.");
    return true;
}

bool EditorApp::RunCameraEditorSmokeTest() {
    if (!options_.smokeTestCameraEditor) {
        return true;
    }

    const int originalCameraMode = viewportCameraMode_;
    const float originalYaw = viewportCameraYaw_;
    const float originalPitch = viewportCameraPitch_;
    const float originalDistance = viewportCameraDistance_;
    const float originalFlySpeed = viewportFlySpeed_;
    const float originalLookSensitivity = viewportLookSensitivity_;
    const float originalPanSensitivity = viewportPanSensitivity_;
    const bool originalFlyLevelMovement = viewportFlyLevelMovement_;
    const std::array<float, 3> originalTarget = viewportCameraTarget_;
    auto restoreViewportNavigation = [&]() {
        viewportCameraMode_ = originalCameraMode;
        viewportCameraYaw_ = originalYaw;
        viewportCameraPitch_ = originalPitch;
        viewportCameraDistance_ = originalDistance;
        viewportFlySpeed_ = originalFlySpeed;
        viewportLookSensitivity_ = originalLookSensitivity;
        viewportPanSensitivity_ = originalPanSensitivity;
        viewportFlyLevelMovement_ = originalFlyLevelMovement;
        viewportCameraTarget_ = originalTarget;
    };

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Camera editor smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Camera editor smoke failed: " + message);
        return false;
    };

    const CameraIconGlyphGeometry glyph =
        BuildCameraIconGlyphGeometry(ImVec2(0.0f, 0.0f), ImVec2(24.0f, 18.0f));
    if (!glyph.valid || glyph.bodyMin.x <= 0.0f || glyph.bodyMax.x >= glyph.lensB.x ||
        glyph.aperture.x <= glyph.bodyMin.x || glyph.aperture.x >= glyph.bodyMax.x ||
        glyph.apertureRadius <= 1.0f) {
        return fail("camera icon geometry is invalid.");
    }

    const ComponentDefinition* controllerDefinition = FindComponentDefinition("CameraFollowRuntime");
    if (controllerDefinition == nullptr || controllerDefinition->displayName != "Camera Controller") {
        return fail("CameraFollowRuntime is not exposed as Camera Controller.");
    }

    state_.ClearScene();
    Entity& target = state_.CreateEntity("Camera Smoke Target", {MakeTransformComponent()});
    if (!state_.AddComponentToEntity(target.id, MakeCameraComponent())) {
        return fail("state API could not add Camera to an existing GameObject.");
    }
    Entity* targetAfterAdd = state_.FindEntity(target.id);
    if (targetAfterAdd == nullptr || !HasComponentType(*targetAfterAdd, "Camera") ||
        !HasComponentType(*targetAfterAdd, "CameraFollowRuntime")) {
        return fail("adding Camera did not attach the Camera Controller.");
    }
    if (state_.RemoveComponentFromEntity(target.id, "Camera")) {
        return fail("built-in Camera component was removable.");
    }
    if (!state_.RemoveComponentFromEntity(target.id, "CameraFollowRuntime")) {
        return fail("optional Camera Controller was not removable.");
    }

    CreateCameraObject("camera editor smoke");
    const Entity* createdCamera = state_.FindEntityByName("Camera");
    if (createdCamera == nullptr || !HasComponentType(*createdCamera, "Camera") ||
        !HasComponentType(*createdCamera, "CameraFollowRuntime") ||
        ComponentPropertyValue(*FindComponent(*createdCamera, "Camera"), "cullingMask") != "Everything") {
        return fail("editor camera creation did not create a default Camera GameObject with controller and culling mask.");
    }

    viewportCameraMode_ = 1;
    viewportCameraYaw_ = 0.0f;
    viewportCameraPitch_ = 0.0f;
    viewportCameraDistance_ = 10.0f;
    viewportFlySpeed_ = 3.0f;
    viewportLookSensitivity_ = 0.18f;
    viewportPanSensitivity_ = 1.0f;
    viewportFlyLevelMovement_ = false;
    viewportCameraTarget_ = {0.0f, 0.0f, 0.0f};
    const CameraBasis flyBefore =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    ApplyViewportLookDelta(42.0f, -12.0f, false);
    const CameraBasis flyAfterLook =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    if (!NearlyEqual(flyBefore.position.x, flyAfterLook.position.x) ||
        !NearlyEqual(flyBefore.position.y, flyAfterLook.position.y) ||
        !NearlyEqual(flyBefore.position.z, flyAfterLook.position.z) || Dot(flyBefore.forward, flyAfterLook.forward) > 0.98f) {
        restoreViewportNavigation();
        return fail("Fly look did not rotate in place.");
    }

    MoveViewportCameraBy({2.0f, 1.5f, -3.0f});
    const CameraBasis flyAfterMove =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    if (!NearlyEqual(flyAfterMove.position.x - flyAfterLook.position.x, 2.0f) ||
        !NearlyEqual(flyAfterMove.position.y - flyAfterLook.position.y, 1.5f) ||
        !NearlyEqual(flyAfterMove.position.z - flyAfterLook.position.z, -3.0f) ||
        !NearlyEqual(flyAfterMove.target.x - flyAfterLook.target.x, 2.0f) ||
        !NearlyEqual(flyAfterMove.target.y - flyAfterLook.target.y, 1.5f) ||
        !NearlyEqual(flyAfterMove.target.z - flyAfterLook.target.z, -3.0f)) {
        restoreViewportNavigation();
        return fail("Fly movement did not translate the Scene camera and target together.");
    }

    viewportCameraMode_ = 0;
    viewportCameraYaw_ = 0.0f;
    viewportCameraPitch_ = 0.0f;
    viewportCameraDistance_ = 10.0f;
    viewportCameraTarget_ = {2.0f, 1.0f, -4.0f};
    const CameraBasis orbitBefore =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    ApplyViewportLookDelta(28.0f, 10.0f, true);
    const CameraBasis orbitAfter =
        BuildCameraBasis(viewportCameraTarget_, viewportCameraYaw_, viewportCameraPitch_, viewportCameraDistance_);
    if (!NearlyEqual(orbitAfter.target.x, 2.0f) || !NearlyEqual(orbitAfter.target.y, 1.0f) ||
        !NearlyEqual(orbitAfter.target.z, -4.0f) ||
        (NearlyEqual(orbitBefore.position.x, orbitAfter.position.x) &&
         NearlyEqual(orbitBefore.position.y, orbitAfter.position.y) &&
         NearlyEqual(orbitBefore.position.z, orbitAfter.position.z))) {
        restoreViewportNavigation();
        return fail("Orbit look did not keep the Scene camera pivot stable.");
    }

    restoreViewportNavigation();
    state_.AddActivity("smoke.camera-editor", "Passed",
                       "Verified Camera add path, built-in protection, Camera Controller attachment, culling defaults, icon geometry, and Scene navigation semantics.");
    state_.SeedStarterScene();
    return true;
}

bool EditorApp::RunProfilerSmokeTest() {
    if (!options_.smokeTestProfiler) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Profiler smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Profiler smoke failed: " + message);
        return false;
    };

    FocusOrOpenPanelKind(EditorPanelKind::Profiler);
    profiler_.Clear();
    profiler_.SetEnabled(true);
    profiler_.SetPaused(false);
    profilerDomainFilter_ = 2;
    state_.SetPerformanceProfiler(&profiler_);

    const std::filesystem::path firstGameProject =
        std::filesystem::current_path() / "projects" / "FirstGame" / "AI Native Project.aineproject.json";
    if (options_.openProjectOverride.empty() && std::filesystem::exists(firstGameProject)) {
        std::string error;
        if (!state_.OpenProject(firstGameProject, &error)) {
            return fail("could not open FirstGame profiler fixture: " + error);
        }
    }

    if (!state_.BeginPlayMode()) {
        return fail("could not enter Play Mode for profiling.");
    }

    const int frames = std::max(30, std::min(options_.smokeTestFrames, 240));
    for (int frame = 0; frame < frames; ++frame) {
        profiler_.BeginFrame();
        {
            PerformanceScope editorFrame(&profiler_, PerformanceDomain::Editor, "Editor.Frame");
            {
                PerformanceScope sceneView(&profiler_, PerformanceDomain::Editor, "Editor.SceneView");
                RenderViewportScene(640, 360);
            }
            {
                PerformanceScope gameView(&profiler_, PerformanceDomain::Editor, "Editor.GameView");
                state_.SetRuntimeInputState(BuildRuntimeInputState());
                state_.UpdatePlayMode(1.0f / 60.0f);
                RenderGameViewportScene(640, 360);
            }
        }
        RecordProfilerFrameCounters();
        profiler_.EndFrame();
    }

    state_.StopPlayMode();

    std::string exportError;
    const std::filesystem::path exportPath = ProfilerDefaultExportPath();
    if (!ExportProfilerReport(exportPath, &exportError)) {
        return fail(exportError.empty() ? "could not export profiler report." : exportError);
    }

    const PerformanceProfilerSnapshot snapshot = profiler_.Snapshot();
    auto hasZone = [&snapshot](const std::string& name) {
        return std::any_of(snapshot.zones.begin(), snapshot.zones.end(), [&name](const PerformanceZoneSummary& zone) {
            return zone.name == name && zone.sampleCount > 0;
        });
    };
    auto hasCounter = [&snapshot](const std::string& name) {
        return std::any_of(snapshot.counters.begin(), snapshot.counters.end(),
                           [&name](const PerformanceCounterSummary& counter) {
                               return counter.name == name;
                           });
    };

    const std::vector<std::string> requiredZones{
        "Editor.Frame",
        "Editor.SceneView",
        "Editor.GameView",
        "Editor.SceneView.RenderPrep",
        "Runtime.UpdatePlayMode",
        "Runtime.Frame",
        "Runtime.SceneSystems",
        "Runtime.Physics",
        "Runtime.Scripting",
        "Runtime.RenderPrep",
    };
    for (const std::string& zone : requiredZones) {
        if (!hasZone(zone)) {
            return fail("missing profiler zone: " + zone);
        }
    }

    const std::vector<std::string> requiredCounters{
        "Editor.Entities",
        "Editor.Components",
        "Editor.OpenPanels",
        "Runtime.Entities",
        "Runtime.Components",
        "Runtime.ActiveScripts",
        "Runtime.PhysicsBodies",
        "Runtime.PhysicsColliders",
        "Runtime.UiElements",
    };
    for (const std::string& counter : requiredCounters) {
        if (!hasCounter(counter)) {
            return fail("missing profiler counter: " + counter);
        }
    }

    if (!std::filesystem::exists(exportPath)) {
        return fail("exported profiler report was not written: " + exportPath.string());
    }
    const std::string report = ReadTextFilePreview(exportPath, 64000);
    if (report.find("\"zones\"") == std::string::npos || report.find("\"guidance\"") == std::string::npos ||
        report.find("Runtime.Physics") == std::string::npos) {
        return fail("exported profiler report is missing zones, guidance, or runtime physics data.");
    }

    state_.AddActivity("smoke.profiler", "Passed", exportPath.string());
    return true;
}

bool EditorApp::RunRuntimeScriptingSmokeTest() {
    if (!options_.smokeTestRuntimeScripting) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Runtime scripting smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Runtime scripting smoke failed: " + message);
        return false;
    };

    if (options_.projectRootOverride.empty()) {
        std::string error;
        const std::filesystem::path projectRoot = std::filesystem::current_path() / "build" / "runtime-scripting-smoke";
        if (!state_.NewProject(projectRoot, &error)) {
            return fail("could not create runtime scripting smoke project: " + error);
        }
    }

    state_.ClearScene();
    Entity& entity = state_.CreateEntity("Runtime Script Smoke Host", {MakeTransformComponent()});
    const int entityId = entity.id;
    const std::string scriptSource =
        "using System;\n"
        "using AINative.Runtime;\n"
        "\n"
        "public class RuntimeScriptSmoke : ScriptBehaviour\n"
        "{\n"
        "    [ScriptField(\"Points\")]\n"
        "    public int points = 4;\n"
        "\n"
        "    [ScriptField(\"Phase\")]\n"
        "    public string phase = \"new\";\n"
        "\n"
        "    public override void OnCreate()\n"
        "    {\n"
        "        points += 1;\n"
        "        phase = \"create\";\n"
        "    }\n"
        "\n"
        "    public override void OnStart()\n"
        "    {\n"
        "        points += 2;\n"
        "        phase += \"+start\";\n"
        "    }\n"
        "\n"
        "    public override void OnUpdate(float deltaSeconds)\n"
        "    {\n"
        "        if (Entity.Id <= 0) { throw new InvalidOperationException(\"missing entity binding\"); }\n"
        "        if (deltaSeconds > 0) { points += 3; }\n"
        "        phase += \"+update\";\n"
        "    }\n"
        "}\n";

    std::string error;
    if (!state_.CreateScript("Assets/Scripts/Gameplay/RuntimeScriptSmoke.cs", scriptSource, nullptr, &error)) {
        return fail("could not create script: " + error);
    }
    if (!state_.AttachScriptToEntity(entityId, "Assets/Scripts/Gameplay/RuntimeScriptSmoke.cs", "RuntimeScriptSmoke",
                                     &error)) {
        return fail("could not attach script: " + error);
    }
    if (!state_.SetComponentPropertyOnEntity(entityId, "RuntimeScriptSmoke", "points", "10")) {
        return fail("could not set script field before play.");
    }

    if (!state_.BeginPlayMode()) {
        return fail("play mode did not start with compiled runtime script.");
    }
    const auto runtimeScriptComponent = [this, entityId]() -> const Component* {
        const Entity* runtimeEntity = state_.FindEntity(entityId);
        if (runtimeEntity == nullptr) {
            return nullptr;
        }
        auto it = std::find_if(runtimeEntity->components.begin(), runtimeEntity->components.end(), [](const Component& component) {
            return component.type == "RuntimeScriptSmoke";
        });
        return it == runtimeEntity->components.end() ? nullptr : &(*it);
    };

    const Component* script = runtimeScriptComponent();
    if (script == nullptr || ComponentPropertyValue(*script, "points") != "13" ||
        ComponentPropertyValue(*script, "phase") != "create+start") {
        return fail("OnCreate/OnStart did not update exposed script fields.");
    }

    state_.UpdatePlayMode(1.0f / 60.0f);
    script = runtimeScriptComponent();
    if (script == nullptr || ComponentPropertyValue(*script, "points") != "16" ||
        ComponentPropertyValue(*script, "phase") != "create+start+update") {
        return fail("OnUpdate did not update exposed script fields.");
    }

    const std::vector<RuntimeLogEntry>& logs = state_.RuntimeLogs();
    const bool sawBegin = std::any_of(logs.begin(), logs.end(), [](const RuntimeLogEntry& entry) {
        return entry.event == "runtime.script.begin";
    });
    const bool sawUpdate = std::any_of(logs.begin(), logs.end(), [](const RuntimeLogEntry& entry) {
        return entry.event == "runtime.script.update";
    });
    if (!sawBegin || !sawUpdate) {
        return fail("runtime.script begin/update events were not captured.");
    }

    if (!state_.StopPlayMode() || !state_.IsEditMode()) {
        return fail("StopPlayMode failed after script runtime smoke.");
    }

    state_.ClearScene();
    state_.SeedStarterScene();
    state_.AddActivity("smoke.runtime-scripting", "Passed",
                       "Compiled, loaded, invoked lifecycle hooks, synchronized fields, and stopped cleanly.");
    return true;
}

bool EditorApp::RunRuntimeUiSmokeTest() {
    if (!options_.smokeTestRuntimeUi) {
        return true;
    }

    const auto fail = [this](const std::string& message) {
        std::fprintf(stderr, "Runtime UI smoke failed: %s\n", message.c_str());
        state_.AddLog(LogLevel::Error, "Runtime UI smoke failed: " + message);
        return false;
    };

    state_.ClearScene();
    Entity& camera = state_.CreateEntity("UI Smoke Camera", {MakeTransformComponent(), MakeCameraComponent()});
    const std::array<float, 3> cameraPosition{0.0f, 2.0f, 8.0f};
    const std::array<float, 3> cameraRotation{-15.0f, 0.0f, 0.0f};
    state_.SetEntityTransform(camera.id, &cameraPosition, &cameraRotation, nullptr);

    Entity& player =
        state_.CreateEntity("UI Smoke Player",
                            {MakeTransformComponent(), MakeMeshPlaceholderComponent("UnitCube", "PlayerBlue"),
                             MakeCharacterControllerRuntimeComponent()});
    const std::array<float, 3> playerPosition{0.0f, 0.5f, 0.0f};
    state_.SetEntityTransform(player.id, &playerPosition, nullptr, nullptr);

    Entity& rules = state_.CreateEntity("UI Smoke Game Rules",
                                        {MakeTransformComponent(), MakeInputActionMapRuntimeComponent(),
                                         MakeGameRulesRuntimeComponent("Runtime UI Smoke", 0)});
    state_.SetComponentPropertyOnEntity(rules.id, "GameRulesRuntime", "fallDeathY", "-2");
    Entity& goal = state_.CreateEntity("UI Smoke Goal", {MakeTransformComponent(), MakeGoalRuntimeComponent(0, 1.0f)});
    const std::array<float, 3> goalPosition{0.0f, 0.5f, -3.0f};
    state_.SetEntityTransform(goal.id, &goalPosition, nullptr, nullptr);

    CreateDeathScreenTemplate("runtime UI smoke");

    const SceneValidationResult validation = state_.ValidateScene();
    if (!validation.ok) {
        return fail("death screen UI scene did not validate before save.");
    }

    std::string error;
    if (!state_.SaveProject(&error)) {
        return fail("could not save UI smoke project: " + error);
    }
    const std::string projectFile = state_.ProjectFilePathString();
    if (!state_.OpenProject(projectFile, &error)) {
        return fail("could not reopen UI smoke project: " + error);
    }

    const Entity* canvas = state_.FindEntityByName("Death Screen Canvas");
    const Entity* panel = state_.FindEntityByName("Death Screen Panel");
    const Entity* title = state_.FindEntityByName("Death Screen Title");
    const Entity* button = state_.FindEntityByName("Death Screen Restart Button");
    if (canvas == nullptr || panel == nullptr || title == nullptr || button == nullptr ||
        !HasComponentType(*canvas, "UICanvasRuntime") || !HasComponentType(*panel, "UIPanelRuntime") ||
        !HasComponentType(*panel, "UIStateBindingRuntime") || !HasComponentType(*title, "UITextRuntime") ||
        !HasComponentType(*button, "UIButtonRuntime")) {
        return fail("reloaded UI scene is missing canvas, panel, text, or button components.");
    }

    const SceneValidationResult reloadValidation = state_.ValidateScene();
    if (!reloadValidation.ok) {
        return fail("death screen UI scene did not validate after reload.");
    }

    StartOrResumePlayMode();
    if (!state_.IsPlaying()) {
        return fail("play mode did not start for runtime UI smoke.");
    }

    Entity* runtimePlayer = state_.FindEntityByName("UI Smoke Player");
    if (runtimePlayer == nullptr) {
        return fail("runtime player disappeared before fall-death check.");
    }
    const std::array<float, 3> fallenPosition{0.0f, -3.5f, 0.0f};
    state_.SetEntityTransform(runtimePlayer->id, &fallenPosition, nullptr, nullptr);
    state_.UpdatePlayMode(1.0f / 60.0f);
    panel = state_.FindEntityByName("Death Screen Panel");
    if (!state_.PlayFailed() || panel == nullptr || !panel->activeSelf) {
        return fail("fall death did not set playFailed and reveal the Death Screen Panel.");
    }

    gameLastRenderedUiElementCount_ = 0;
    DrawGameRuntimeUiOverlay(nullptr, ImVec2(0.0f, 0.0f), ImVec2(960.0f, 540.0f), false);
    if (gameLastRenderedUiElementCount_ < 3) {
        return fail("Game View runtime UI overlay did not resolve visible panel/text/button elements.");
    }
    runtimeUiSmokeVerifiedOverlay_ = true;

    if (!ExecuteRuntimeUIButtonAction("restart") || !state_.IsPlaying() || state_.PlayFailed()) {
        return fail("Restart button action did not reset the failed runtime state.");
    }
    panel = state_.FindEntityByName("Death Screen Panel");
    if (panel == nullptr || panel->activeSelf) {
        return fail("Restart action did not hide the state-bound Death Screen Panel.");
    }
    StopPlayMode();

    state_.AddActivity("smoke.runtime-ui", "Passed",
                       "Death screen UI saved, reloaded, rendered, state-bound, and restarted.");
    return true;
}

bool EditorApp::RunProviderNormalizerSmokeTest() {
    if (options_.smokeTestProviderNormalizer.empty()) {
        return true;
    }

    if (options_.smokeTestProviderNormalizer == "invalid-json") {
        const NormalizedProviderResult normalized =
            orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, "{ \"result_type\": \"proposed_command_batch\",", gateway_);
        proposedActions_.push_back(normalized);
        if (normalized.type != ProviderResultType::ProviderError || normalized.canApprove || normalized.schemaValid) {
            state_.AddLog(LogLevel::Error, "Smoke invalid-json failed: invalid provider JSON was not rejected.");
            return false;
        }
        state_.AddActivity("smoke.provider.invalid-json", "Passed", normalized.message);
        state_.AddChat(ChatSender::System, "Smoke invalid-json passed: provider output was rejected.");
        return true;
    }

    if (options_.smokeTestProviderNormalizer == "valid-command-batch-approve") {
        const std::string validBatch = R"({
  "result_type": "proposed_command_batch",
  "message": "Create a provider-approved smoke cube.",
  "command_batch": {
    "version": 1,
    "name": "Provider smoke cube",
    "commands": [
      {
        "type": "scene.createEntity",
        "name": "Provider Smoke Cube",
        "components": [
          {
            "type": "Transform",
            "properties": {}
          },
          {
            "type": "MeshRenderer",
            "properties": {
              "mesh": "UnitCube",
              "material": "PrototypeGray"
            }
          }
        ]
      },
      {
        "type": "scene.setTransform",
        "targetName": "Provider Smoke Cube",
        "transform": {
          "position": [1.0, 0.5, 0.0],
          "scale": [1.0, 1.0, 1.0]
        }
      },
      {
        "type": "validate.scene"
      },
      {
        "type": "project.save"
      }
    ]
  }
})";

        const NormalizedProviderResult normalized =
            orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, validBatch, gateway_);
        proposedActions_.push_back(normalized);
        const size_t actionIndex = proposedActions_.size() - 1;
        if (normalized.type != ProviderResultType::ProposedCommandBatch || !normalized.canApprove || !normalized.schemaValid) {
            state_.AddLog(LogLevel::Error, "Smoke valid-command-batch-approve failed: valid provider batch was not approvable.");
            return false;
        }
        if (normalized.commandBatch.approval != "provider_requires_approval" || normalized.commandBatch.applied) {
            state_.AddLog(LogLevel::Error,
                          "Smoke valid-command-batch-approve failed: provider batch did not remain pending approval.");
            return false;
        }

        if (state_.FindEntityByName("Provider Smoke Cube") != nullptr) {
            state_.AddLog(LogLevel::Error, "Smoke valid-command-batch-approve failed: provider batch auto-applied before approval.");
            return false;
        }

        ApproveProposedAction(actionIndex);
        if (state_.FindEntityByName("Provider Smoke Cube") == nullptr || !hasLastGatewayResult_ || !lastGatewayResult_.batch.applied) {
            state_.AddLog(LogLevel::Error, "Smoke valid-command-batch-approve failed: approved batch did not apply.");
            return false;
        }
        state_.AddActivity("smoke.provider.valid-command-batch-approve", "Passed", "Provider batch parsed, waited for approval, and applied.");
        return true;
    }

    state_.AddLog(LogLevel::Error, "Unknown provider normalizer smoke scenario: " + options_.smokeTestProviderNormalizer);
    return false;
}

bool EditorApp::RunProviderHealthSmokeTest() {
    if (options_.smokeTestProviderHealth.empty()) {
        return true;
    }

    const ProviderHealth* codex = orchestrator_.FindProvider(AgentBackend::CodexCli);
    if (codex == nullptr) {
        state_.AddLog(LogLevel::Error, "Provider health smoke failed: Codex provider row was missing.");
        return false;
    }

    auto joinedProbeDetails = [codex]() {
        std::string details;
        for (const std::string& probe : codex->probeDetails) {
            if (!details.empty()) {
                details += " ";
            }
            details += probe;
        }
        return details;
    };

    auto expectStatus = [this, codex](const std::string& expectedStatus, const std::string& scenario) {
        if (codex->status != expectedStatus || codex->available) {
            state_.AddLog(LogLevel::Error, "Provider health smoke " + scenario + " failed: expected " + expectedStatus +
                                             " and unavailable, got " + codex->status + " | " + codex->detail);
            return false;
        }
        state_.AddActivity("smoke.provider-health." + scenario, "Passed",
                           codex->status + " | " + codex->executablePath + " | " + codex->detail);
        return true;
    };

    if (options_.smokeTestProviderHealth == "local-broad-gameplay-no-mutation") {
        const std::vector<std::string> broadPrompts{
            "Create a scene where the player can shoot game objects",
            "Let's look at building a game scene with a player object and a basic running symulator.",
        };
        for (const std::string& prompt : broadPrompts) {
            if (PromptLooksLikeDeterministicSceneEdit(prompt)) {
                state_.AddLog(LogLevel::Error,
                              "Provider health smoke local-broad-gameplay-no-mutation failed: broad gameplay prompt was classified as a deterministic scene edit.");
                return false;
            }
            if (!ShouldAutoGenerateImplementationBrief(AgentBackend::CodexCli, prompt)) {
                state_.AddLog(LogLevel::Error,
                              "Provider health smoke local-broad-gameplay-no-mutation failed: broad gameplay prompt was not routed to repository implementation for Codex.");
                return false;
            }

            const size_t entityCountBefore = state_.Entities().size();
            AgentOrchestratorResult result =
                orchestrator_.SubmitPrompt(AgentBackend::LocalToolGateway, prompt, state_, gateway_,
                                           hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
            if (!result.hasGatewayResult || !result.ok || !result.gatewayResult.batch.applied ||
                result.gatewayResult.batch.name != "Route gameplay feature to development backend") {
                state_.AddLog(LogLevel::Error,
                              "Provider health smoke local-broad-gameplay-no-mutation failed: Local Tool Gateway did not return the routing diagnostic batch.");
                return false;
            }
            if (state_.Entities().size() != entityCountBefore || !result.gatewayResult.batch.changedEntities.empty() ||
                !result.gatewayResult.batch.changedFiles.empty() || state_.FindEntityByName("AI Player Spawn") != nullptr ||
                state_.FindEntityByName("AI Main Camera") != nullptr || result.gatewayResult.batch.diagnostics.empty()) {
                state_.AddLog(LogLevel::Error,
                              "Provider health smoke local-broad-gameplay-no-mutation failed: broad gameplay prompt mutated scene state.");
                return false;
            }
        }

        state_.AddActivity("smoke.provider-health.local-broad-gameplay-no-mutation", "Passed",
                           "Broad gameplay requests produced diagnostics without canned scene mutations.");
        return true;
    }

    if (options_.smokeTestProviderHealth == "codex-not-found") {
        return expectStatus("Not found", options_.smokeTestProviderHealth);
    }
    if (options_.smokeTestProviderHealth == "codex-access-denied") {
        return expectStatus("WindowsApps alias inaccessible", options_.smokeTestProviderHealth);
    }
    if (options_.smokeTestProviderHealth == "codex-windowsapps-skipped") {
        const std::string probes = joinedProbeDetails();
        if (probes.find("WindowsApps") == std::string::npos ||
            probes.find("skipped package-private WindowsApps path") == std::string::npos) {
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-windowsapps-skipped failed: WindowsApps skip was not captured.");
            return false;
        }
        if (codex->available && (codex->source == "Env override" || codex->source == "direct executable") &&
            codex->executablePath.find("WindowsApps") != std::string::npos) {
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-windowsapps-skipped failed: WindowsApps path was selected directly.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-windowsapps-skipped", "Passed",
                           codex->status + " | " + codex->source + " | " + codex->detail);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-cmd-shim-ready") {
        if (codex->status != "Connected" || !codex->available || codex->source != "cmd shim") {
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-cmd-shim-ready failed: expected Connected via cmd shim, got " +
                                             codex->status + " | " + codex->source + " | " + codex->detail);
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-cmd-shim-ready", "Passed", codex->detail);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-scene-request-routes-local") {
        const bool originalRouteScenesLocally = agentRouteSceneEditsLocally_;
        agentRouteSceneEditsLocally_ = true;
        auto fail = [this, originalRouteScenesLocally](const std::string& message) {
            agentRouteSceneEditsLocally_ = originalRouteScenesLocally;
            state_.AddLog(LogLevel::Error, message);
            return false;
        };
        const std::string prompt =
            "Create the running simulator scene template with player controller.";
        if (!PromptLooksLikeDeterministicSceneEdit(prompt)) {
            return fail("Provider health smoke codex-scene-request-routes-local failed: prompt was not classified as a deterministic scene edit.");
        }
        if (ShouldAutoGenerateImplementationBrief(AgentBackend::CodexCli, prompt)) {
            return fail("Provider health smoke codex-scene-request-routes-local failed: prompt still auto-generates a Codex implementation brief.");
        }

        const size_t chatCountBefore = state_.ChatHistory().size();
        if (!SubmitAgentPrompt(prompt, AgentBackend::CodexCli, false)) {
            return fail("Provider health smoke codex-scene-request-routes-local failed: SubmitAgentPrompt returned false.");
        }
        if (agentJob_ != nullptr) {
            return fail("Provider health smoke codex-scene-request-routes-local failed: routed prompt started a Codex worker.");
        }
        if (state_.ChatHistory().size() < chatCountBefore + 2) {
            return fail("Provider health smoke codex-scene-request-routes-local failed: user and assistant chat messages were not recorded.");
        }
        if (!hasLastGatewayResult_ || !lastGatewayResult_.batch.applied ||
            lastGatewayResult_.batch.name != "Create running simulator scene") {
            return fail("Provider health smoke codex-scene-request-routes-local failed: running simulator batch was not applied locally.");
        }

        Entity* rules = state_.FindEntityByName("AI Runner Game Rules");
        Entity* player = state_.FindEntityByName("AI Runner Player");
        Entity* camera = state_.FindEntityByName("AI Runner Camera");
        Entity* coin = state_.FindEntityByName("AI Runner Coin 1");
        Entity* hazard = state_.FindEntityByName("AI Runner Hurdle");
        Entity* goal = state_.FindEntityByName("AI Runner Finish Gate");
        if (rules == nullptr || player == nullptr || camera == nullptr || coin == nullptr || hazard == nullptr ||
            goal == nullptr || !HasComponentType(*rules, "GameRulesRuntime") ||
            !HasComponentType(*rules, "InputActionMapRuntime") ||
            !HasComponentType(*player, "CharacterControllerRuntime") ||
            !HasComponentType(*camera, "CameraFollowRuntime") ||
            !HasComponentType(*coin, "CollectibleRuntime") || !HasComponentType(*hazard, "HazardRuntime") ||
            !HasComponentType(*goal, "GoalRuntime") || lastGatewayResult_.batch.changedFiles.empty()) {
            return fail("Provider health smoke codex-scene-request-routes-local failed: local running simulator scene was incomplete.");
        }

        agentRouteSceneEditsLocally_ = originalRouteScenesLocally;
        state_.AddActivity("smoke.provider-health.codex-scene-request-routes-local", "Passed",
                           "Codex-selected scene request routed to Local Tool Gateway and created the running simulator scene.");
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-diagnostic-request-stays-chat") {
        const std::string prompt = "colliders are not working why";
        if (!PromptLooksLikeConversationTask(prompt)) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-diagnostic-request-stays-chat failed: diagnostic prompt was not classified as conversation.");
            return false;
        }
        if (ShouldAutoGenerateImplementationBrief(AgentBackend::CodexCli, prompt)) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-diagnostic-request-stays-chat failed: raw diagnostic prompt auto-generates a Codex implementation brief.");
            return false;
        }

        CopyStringToBuffer(chatInput_, prompt);
        ImproveAgentPromptDraft();
        const std::string improvedPrompt = TrimWhitespace(chatInput_.data());
        if (improvedPrompt.find("Please diagnose this in AI Native Editor") == std::string::npos ||
            improvedPrompt.find("Please implement this in AI Native Editor") != std::string::npos ||
            improvedPrompt.find("Helpful concrete target: rename selected entity") != std::string::npos) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-diagnostic-request-stays-chat failed: Improve converted diagnostic text into implementation work.");
            return false;
        }
        if (ShouldAutoGenerateImplementationBrief(AgentBackend::CodexCli, improvedPrompt)) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-diagnostic-request-stays-chat failed: improved diagnostic prompt auto-generates a Codex implementation brief.");
            return false;
        }

        state_.AddActivity("smoke.provider-health.codex-diagnostic-request-stays-chat", "Passed",
                           "Diagnostic prompt stays a chat/diagnostic request and Improve does not append unrelated selected-entity targets.");
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-command-batch-auto-applies") {
        const std::string validBatch = R"({
  "result_type": "proposed_command_batch",
  "message": "Create a direct Codex smoke cube.",
  "command_batch": {
    "version": 1,
    "name": "Codex direct smoke cube",
    "commands": [
      {
        "type": "scene.createEntity",
        "name": "Codex Direct Smoke Cube",
        "components": [
          {
            "type": "Transform",
            "properties": {}
          },
          {
            "type": "MeshRenderer",
            "properties": {
              "mesh": "UnitCube",
              "material": "PrototypeBlue"
            }
          }
        ]
      },
      {
        "type": "scene.setTransform",
        "targetName": "Codex Direct Smoke Cube",
        "transform": {
          "position": [2.0, 0.5, 0.0],
          "scale": [1.0, 1.0, 1.0]
        }
      },
      {
        "type": "validate.scene"
      },
      {
        "type": "project.save"
      }
    ]
  }
})";

        AgentOrchestratorResult result;
        result.backend = AgentBackend::CodexCli;
        result.ok = true;
        result.exitCode = 0;
        result.hasNormalizedResult = true;
        result.normalizedResult = orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, validBatch, gateway_);
        result.assistantMessage = "Codex CLI normalized result: proposed_command_batch";

        const size_t proposedBefore = proposedActions_.size();
        AgentOrchestratorResult appliedResult = ApplyAgentResultToUi(std::move(result), "create direct smoke cube", false);
        Entity* cube = state_.FindEntityByName("Codex Direct Smoke Cube");
        if (!appliedResult.ok || cube == nullptr || !hasLastGatewayResult_ || !lastGatewayResult_.batch.applied ||
            proposedActions_.size() != proposedBefore) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-command-batch-auto-applies failed: valid Codex command batch did not apply directly.");
            return false;
        }
        if (!appliedResult.hasNormalizedResult || !appliedResult.normalizedResult.applied ||
            appliedResult.normalizedResult.canApprove) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-command-batch-auto-applies failed: normalized result did not record direct application.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-command-batch-auto-applies", "Passed",
                           "Validated Codex command batch applied directly through ToolGateway without pending approval.");
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-rigidbody-defaults-auto-apply") {
        Entity& player = state_.CreateEntity("AI Runner Player",
                                             {MakeTransformComponent(),
                                              MakeMeshPlaceholderComponent("UnitCube", "PlayerBlue"),
                                              MakeCharacterControllerRuntimeComponent(),
                                              MakeCollider3DComponent("Box")});
        state_.SelectEntity(player.id);

        const std::string validBatch = R"({
  "result_type": "proposed_command_batch",
  "message": "Add a gravity-enabled Rigidbody3D to the runner player.",
  "command_batch": {
    "version": 1,
    "name": "Enable 9.81 Gravity On Runner Player",
    "commands": [
      {
        "type": "scene.addComponent",
        "targetName": "AI Runner Player",
        "component": {
          "type": "Rigidbody3D",
          "properties": {
            "useGravity": true,
            "gravityScale": 1
          }
        }
      },
      {
        "type": "validate.scene"
      }
    ]
  }
})";

        AgentOrchestratorResult result;
        result.backend = AgentBackend::CodexCli;
        result.ok = true;
        result.exitCode = 0;
        result.hasNormalizedResult = true;
        result.normalizedResult = orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, validBatch, gateway_);
        result.assistantMessage = "Codex CLI normalized result: proposed_command_batch";

        AgentOrchestratorResult appliedResult =
            ApplyAgentResultToUi(std::move(result), "add gravity rigidbody to runner player", false);
        Entity* updatedPlayer = state_.FindEntityByName("AI Runner Player");
        bool sawRigidbody = false;
        bool sawBodyType = false;
        bool sawUseGravity = false;
        if (updatedPlayer != nullptr) {
            for (const Component& component : updatedPlayer->components) {
                if (component.type != "Rigidbody3D") {
                    continue;
                }
                sawRigidbody = true;
                for (const ComponentProperty& property : component.properties) {
                    sawBodyType = sawBodyType || (property.name == "bodyType" && property.value == "Dynamic");
                    sawUseGravity = sawUseGravity || (property.name == "useGravity" && property.value == "true");
                }
            }
        }
        if (!appliedResult.ok || updatedPlayer == nullptr || !sawRigidbody || !sawBodyType || !sawUseGravity ||
            !appliedResult.hasGatewayResult || !appliedResult.gatewayResult.batch.ok ||
            !appliedResult.normalizedResult.applied) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-rigidbody-defaults-auto-apply failed: Rigidbody3D defaults were not applied before scene validation.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-rigidbody-defaults-auto-apply", "Passed",
                           "Codex Rigidbody3D batch auto-filled bodyType and passed scene validation.");
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-command-batch-review-when-auto-apply-disabled") {
        const bool originalAutoApply = agentAutoApplyCodexCommandBatches_;
        agentAutoApplyCodexCommandBatches_ = false;
        const std::string validBatch = R"({
  "result_type": "proposed_command_batch",
  "message": "Create a review-only Codex smoke cube.",
  "command_batch": {
    "version": 1,
    "name": "Codex review smoke cube",
    "commands": [
      {
        "type": "scene.createEntity",
        "name": "Codex Review Smoke Cube",
        "components": [
          {
            "type": "Transform",
            "properties": {}
          },
          {
            "type": "MeshRenderer",
            "properties": {
              "mesh": "UnitCube",
              "material": "PrototypeGreen"
            }
          }
        ]
      },
      {
        "type": "scene.setTransform",
        "targetName": "Codex Review Smoke Cube",
        "transform": {
          "position": [-2.0, 0.5, 0.0],
          "scale": [1.0, 1.0, 1.0]
        }
      },
      {
        "type": "validate.scene"
      },
      {
        "type": "project.save"
      }
    ]
  }
})";

        AgentOrchestratorResult result;
        result.backend = AgentBackend::CodexCli;
        result.ok = true;
        result.exitCode = 0;
        result.hasNormalizedResult = true;
        result.normalizedResult = orchestrator_.NormalizeProviderOutput(AgentBackend::CodexCli, validBatch, gateway_);
        result.assistantMessage = "Codex CLI normalized result: proposed_command_batch";

        const bool hadGatewayBefore = hasLastGatewayResult_;
        const size_t proposedBefore = proposedActions_.size();
        AgentOrchestratorResult reviewResult =
            ApplyAgentResultToUi(std::move(result), "create review-only smoke cube", false);
        Entity* cube = state_.FindEntityByName("Codex Review Smoke Cube");
        const bool proposedStored = proposedActions_.size() == proposedBefore + 1 && !proposedActions_.empty() &&
                                    proposedActions_.back().canApprove &&
                                    !proposedActions_.back().applied &&
                                    proposedActions_.back().hasCommandBatch;
        if (!reviewResult.ok || cube != nullptr || hasLastGatewayResult_ != hadGatewayBefore || !proposedStored) {
            agentAutoApplyCodexCommandBatches_ = originalAutoApply;
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-command-batch-review-when-auto-apply-disabled failed: disabled auto-apply did not leave the command batch pending review.");
            return false;
        }
        if (!reviewResult.hasNormalizedResult || !reviewResult.normalizedResult.canApprove ||
            reviewResult.normalizedResult.applied) {
            agentAutoApplyCodexCommandBatches_ = originalAutoApply;
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-command-batch-review-when-auto-apply-disabled failed: normalized result did not remain approvable.");
            return false;
        }
        agentAutoApplyCodexCommandBatches_ = originalAutoApply;
        state_.AddActivity("smoke.provider-health.codex-command-batch-review-when-auto-apply-disabled", "Passed",
                           "Validated Codex command batch stayed in Proposed Actions when auto-apply was disabled.");
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-all-probes-fail") {
        if (codex->available || (codex->status != "Not found" && codex->status != "Launch failed" &&
                                 codex->status != "WindowsApps alias inaccessible" && codex->status != "Timed out" &&
                                 codex->status != "Login required" && codex->status != "Auth check timed out")) {
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-all-probes-fail failed: expected unavailable status, got " +
                                             codex->status + " | " + codex->detail);
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-all-probes-fail", "Passed", codex->status + " | " + codex->detail);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-gateway-fallback") {
        AgentOrchestratorResult result =
            orchestrator_.SubmitPrompt(AgentBackend::CodexCli, "create a starter scene", state_, gateway_,
                                       hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
        if (result.usedFallback || result.hasGatewayResult || result.ok) {
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-gateway-fallback failed: provider failure should not mutate through Local Tool Gateway.");
            return false;
        }
        const std::string failureReason = result.diagnostics.empty() ? std::string{} : result.diagnostics.front();
        if (failureReason.find("Codex CLI") == std::string::npos ||
            (failureReason.find("path=") == std::string::npos && failureReason.find("No usable Codex CLI") == std::string::npos)) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-gateway-fallback failed: failure did not include the real Codex detail.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-gateway-fallback", "Passed", failureReason);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-run-chat-response") {
        if (codex->status != "Connected" || !codex->available) {
            std::fprintf(stderr, "Provider health smoke codex-run-chat-response failed: Codex was not connected: %s | %s\n",
                         codex->status.c_str(), codex->detail.c_str());
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-run-chat-response failed: Codex was not connected: " +
                                             codex->status + " | " + codex->detail);
            return false;
        }
        AgentOrchestratorResult result =
            orchestrator_.SubmitPrompt(AgentBackend::CodexCli,
                                       "Reply in plain text with one short sentence about the current project context. Do not propose actions.",
                                       state_, gateway_,
                                       hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
        if (result.usedFallback || !result.hasNormalizedResult ||
            result.normalizedResult.type != ProviderResultType::ChatResponse || result.assistantMessage.empty()) {
            std::fprintf(stderr,
                         "Provider health smoke codex-run-chat-response failed: usedFallback=%s hasNormalized=%s type=%s assistantChars=%zu ok=%s exit=%d diagnostics=%s stdoutChars=%zu stderrChars=%zu\n",
                         result.usedFallback ? "true" : "false",
                         result.hasNormalizedResult ? "true" : "false",
                         result.hasNormalizedResult ? ProviderResultNormalizer::TypeId(result.normalizedResult.type) : "none",
                         result.assistantMessage.size(),
                         result.ok ? "true" : "false",
                         result.exitCode,
                         result.diagnostics.empty() ? "" : result.diagnostics.front().c_str(),
                         result.stdoutText.size(),
                         result.stderrText.size());
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-run-chat-response failed: Codex did not return a normalized chat response.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-run-chat-response", "Passed", result.assistantMessage);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-broad-chat-response") {
        if (codex->status != "Connected" || !codex->available) {
            std::fprintf(stderr, "Provider health smoke codex-broad-chat-response failed: Codex was not connected: %s | %s\n",
                         codex->status.c_str(), codex->detail.c_str());
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-broad-chat-response failed: Codex was not connected: " +
                                             codex->status + " | " + codex->detail);
            return false;
        }

        const std::string broadPrompt = "Start implementing features to the game engine.";
        if (ShouldAutoGenerateImplementationBrief(AgentBackend::CodexCli, broadPrompt)) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-broad-chat-response failed: broad prompt still auto-generates an implementation brief.");
            return false;
        }

        AgentOrchestratorResult result =
            orchestrator_.SubmitPrompt(AgentBackend::CodexCli, broadPrompt, state_, gateway_,
                                       hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
        if (result.usedFallback || result.hasGatewayResult || !result.hasNormalizedResult ||
            result.normalizedResult.type != ProviderResultType::ChatResponse || result.assistantMessage.empty()) {
            std::fprintf(stderr,
                         "Provider health smoke codex-broad-chat-response failed: usedFallback=%s hasGateway=%s hasNormalized=%s type=%s assistantChars=%zu ok=%s exit=%d diagnostics=%s stdoutChars=%zu stderrChars=%zu\n",
                         result.usedFallback ? "true" : "false",
                         result.hasGatewayResult ? "true" : "false",
                         result.hasNormalizedResult ? "true" : "false",
                         result.hasNormalizedResult ? ProviderResultNormalizer::TypeId(result.normalizedResult.type) : "none",
                         result.assistantMessage.size(),
                         result.ok ? "true" : "false",
                         result.exitCode,
                         result.diagnostics.empty() ? "" : result.diagnostics.front().c_str(),
                         result.stdoutText.size(),
                         result.stderrText.size());
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-broad-chat-response failed: broad prompt did not produce a real Codex chat response.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-broad-chat-response", "Passed", result.assistantMessage);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-ready-chat-response") {
        if (codex->status != "Connected" || !codex->available) {
            std::fprintf(stderr, "Provider health smoke codex-ready-chat-response failed: Codex was not connected: %s | %s\n",
                         codex->status.c_str(), codex->detail.c_str());
            state_.AddLog(LogLevel::Error, "Provider health smoke codex-ready-chat-response failed: Codex was not connected: " +
                                             codex->status + " | " + codex->detail);
            return false;
        }

        const std::string readyPrompt = "are you ready to build";
        if (ShouldAutoGenerateImplementationBrief(AgentBackend::CodexCli, readyPrompt)) {
            std::fprintf(stderr,
                         "Provider health smoke codex-ready-chat-response failed: readiness question still auto-generates an implementation brief.\n");
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-ready-chat-response failed: readiness question still auto-generates an implementation brief.");
            return false;
        }

        AgentOrchestratorResult result =
            orchestrator_.SubmitPrompt(AgentBackend::CodexCli, readyPrompt, state_, gateway_,
                                       hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
        if (result.usedFallback || result.hasGatewayResult || !result.hasNormalizedResult ||
            result.normalizedResult.type != ProviderResultType::ChatResponse || result.assistantMessage.empty()) {
            std::fprintf(stderr,
                         "Provider health smoke codex-ready-chat-response failed: usedFallback=%s hasGateway=%s hasNormalized=%s type=%s assistantChars=%zu ok=%s exit=%d diagnostics=%s stdoutChars=%zu stderrChars=%zu\n",
                         result.usedFallback ? "true" : "false",
                         result.hasGatewayResult ? "true" : "false",
                         result.hasNormalizedResult ? "true" : "false",
                         result.hasNormalizedResult ? ProviderResultNormalizer::TypeId(result.normalizedResult.type) : "none",
                         result.assistantMessage.size(),
                         result.ok ? "true" : "false",
                         result.exitCode,
                         result.diagnostics.empty() ? "" : result.diagnostics.front().c_str(),
                         result.stdoutText.size(),
                         result.stderrText.size());
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke codex-ready-chat-response failed: readiness prompt did not produce a real Codex chat response.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.codex-ready-chat-response", "Passed", result.assistantMessage);
        return true;
    }
    if (options_.smokeTestProviderHealth == "codex-launch-failed") {
        return expectStatus("Launch failed", options_.smokeTestProviderHealth);
    }
    if (options_.smokeTestProviderHealth == "openai-missing-key") {
        const ProviderHealth* openai = orchestrator_.FindProvider(AgentBackend::OpenAIApi);
        if (openai == nullptr) {
            state_.AddLog(LogLevel::Error, "Provider health smoke openai-missing-key failed: OpenAI API provider row was missing.");
            return false;
        }
        if (openai->available || openai->status != "Missing API key") {
            state_.AddLog(LogLevel::Error, "Provider health smoke openai-missing-key failed: expected Missing API key, got " +
                                             openai->status + " | " + openai->detail);
            return false;
        }
        state_.AddActivity("smoke.provider-health.openai-missing-key", "Passed", openai->detail);
        return true;
    }
    if (options_.smokeTestProviderHealth == "openai-gateway-fallback") {
        AgentOrchestratorResult result =
            orchestrator_.SubmitPrompt(AgentBackend::OpenAIApi, "create a starter scene", state_, gateway_,
                                       hasLastGatewayResult_ ? &lastGatewayResult_.batch : nullptr);
        if (result.usedFallback || result.hasGatewayResult || result.ok) {
            state_.AddLog(LogLevel::Error, "Provider health smoke openai-gateway-fallback failed: provider failure should not mutate through Local Tool Gateway.");
            return false;
        }
        const std::string failureReason = result.diagnostics.empty() ? std::string{} : result.diagnostics.front();
        if (failureReason.find("OpenAI API") == std::string::npos ||
            failureReason.find("OPENAI_API_KEY") == std::string::npos) {
            state_.AddLog(LogLevel::Error,
                          "Provider health smoke openai-gateway-fallback failed: failure did not include OPENAI_API_KEY detail.");
            return false;
        }
        state_.AddActivity("smoke.provider-health.openai-gateway-fallback", "Passed", failureReason);
        return true;
    }

    state_.AddLog(LogLevel::Error, "Unknown provider health smoke scenario: " + options_.smokeTestProviderHealth);
    return false;
}

void EditorApp::StoreProviderResult(const AgentOrchestratorResult& result) {
    if (!result.hasNormalizedResult) {
        return;
    }

    if (result.normalizedResult.type != ProviderResultType::ProposedCommandBatch &&
        result.normalizedResult.type != ProviderResultType::ProposedFileChange) {
        return;
    }
    if (result.normalizedResult.type == ProviderResultType::ProposedCommandBatch &&
        (result.normalizedResult.applied || result.normalizedResult.approved || !result.normalizedResult.canApprove)) {
        return;
    }

    proposedActions_.push_back(result.normalizedResult);
    if (proposedActions_.size() > 16) {
        proposedActions_.erase(proposedActions_.begin());
    }
}

void EditorApp::AddProviderOutcomeSystemMessage(const AgentOrchestratorResult& result) {
    if (!result.hasNormalizedResult) {
        if (result.hasGatewayResult) {
            state_.AddChat(ChatSender::System, "Local Tool Gateway applied a deterministic command batch.");
        }
        return;
    }

    const NormalizedProviderResult& normalized = result.normalizedResult;
    if (normalized.type == ProviderResultType::ProposedCommandBatch && normalized.applied) {
        state_.AddChat(ChatSender::System, "Codex command batch validated and applied directly.");
    } else if (normalized.type == ProviderResultType::ProposedCommandBatch && normalized.canApprove) {
        state_.AddChat(ChatSender::System, "Provider proposed a command batch. Review Proposed Actions before applying it.");
    } else if (normalized.type == ProviderResultType::ProposedFileChange && normalized.canApprove) {
        state_.AddChat(ChatSender::System, "Provider proposed a file change. Review the diff/content preview before applying it.");
    } else if (normalized.type == ProviderResultType::ProposedFileChange) {
        state_.AddChat(ChatSender::System, "Provider proposed a file change, but it is not ready to apply.");
    } else if (normalized.type == ProviderResultType::ChatResponse) {
        return;
    } else if (normalized.type == ProviderResultType::Diagnostic) {
        state_.AddChat(ChatSender::System, "Provider returned a diagnostic. No actions were proposed.");
    } else if (normalized.type == ProviderResultType::ProviderError) {
        state_.AddChat(ChatSender::System, "Provider output was rejected: " + normalized.message);
    }
}

std::string EditorApp::BuildFileChangePreview(const ProposedFileChange& fileChange) const {
    std::ostringstream stream;
    if (!fileChange.diff.empty()) {
        stream << fileChange.diff;
    } else if (!fileChange.content.empty()) {
        stream << "Full content preview for " << fileChange.path << ":\n";
        stream << fileChange.content;
    } else {
        stream << "No diff or content was provided.";
    }

    std::string preview = stream.str();
    constexpr size_t kMaxPreviewChars = 8000;
    if (preview.size() > kMaxPreviewChars) {
        preview.resize(kMaxPreviewChars);
        preview += "\n...[truncated]";
    }
    return preview;
}

bool EditorApp::ApplyProposedFileChange(size_t index) {
    if (!EnsureEditModeForAction("Apply proposed file change")) {
        return false;
    }

    if (index >= proposedActions_.size()) {
        return false;
    }

    NormalizedProviderResult& action = proposedActions_[index];
    if (!action.canApprove || !action.hasFileChange || action.applied || action.rejected) {
        return false;
    }

    ProposedFileChange& fileChange = action.fileChange;
    if (TrimWhitespace(fileChange.content).empty()) {
        const std::string diagnostic =
            "proposed_file_change apply failed: diff preview only; full content is required for apply.";
        action.diagnostics.push_back(diagnostic);
        state_.AddLog(LogLevel::Error, diagnostic);
        state_.AddActivity("provider.file_change", "Failed", diagnostic);
        state_.AddChat(ChatSender::System, diagnostic);
        return false;
    }

    try {
        std::error_code filesystemError;
        const std::filesystem::path workspaceRoot = std::filesystem::weakly_canonical(std::filesystem::current_path(),
                                                                                     filesystemError);
        if (filesystemError) {
            const std::string diagnostic = "proposed_file_change apply failed: could not resolve workspace root: " +
                                           filesystemError.message();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            return false;
        }

        std::filesystem::path requestedPath = fileChange.path;
        std::filesystem::path targetPath =
            requestedPath.is_absolute() ? requestedPath : (workspaceRoot / requestedPath);
        targetPath = targetPath.lexically_normal();

        if (!IsPathInsideOrSame(workspaceRoot, targetPath.parent_path())) {
            const std::string diagnostic =
                "proposed_file_change apply failed: target is outside the workspace: " + targetPath.string();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            state_.AddActivity("provider.file_change", "Blocked", diagnostic);
            return false;
        }

        const bool existed = std::filesystem::exists(targetPath, filesystemError) && !filesystemError;
        if (existed && !std::filesystem::is_regular_file(targetPath, filesystemError)) {
            const std::string diagnostic =
                "proposed_file_change apply failed: target is not a regular file: " + targetPath.string();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            return false;
        }

        std::string previousContent;
        if (existed) {
            std::ifstream input(targetPath, std::ios::binary);
            if (!input) {
                const std::string diagnostic =
                    "proposed_file_change apply failed: could not read previous file: " + targetPath.string();
                action.diagnostics.push_back(diagnostic);
                state_.AddLog(LogLevel::Error, diagnostic);
                return false;
            }
            std::ostringstream buffer;
            buffer << input.rdbuf();
            previousContent = buffer.str();
        }

        std::filesystem::create_directories(targetPath.parent_path(), filesystemError);
        if (filesystemError) {
            const std::string diagnostic = "proposed_file_change apply failed: could not create parent folder: " +
                                           filesystemError.message();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            return false;
        }

        std::ofstream output(targetPath, std::ios::binary | std::ios::trunc);
        if (!output) {
            const std::string diagnostic =
                "proposed_file_change apply failed: could not open target for write: " + targetPath.string();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            return false;
        }
        output << fileChange.content;
        if (!output.good()) {
            const std::string diagnostic =
                "proposed_file_change apply failed: write failed for target: " + targetPath.string();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            return false;
        }

        fileChange.previousContent = std::move(previousContent);
        fileChange.previousContentCaptured = true;
        fileChange.previousFileExisted = existed;
        fileChange.appliedPath = targetPath.string();
        if (fileChange.sessionId.empty()) {
            fileChange.sessionId = "provider-file-change-" + CurrentTimestampUtc();
        }
        action.approved = true;
        action.applied = true;
        action.canApprove = false;
        action.requiresApproval = false;

        const std::filesystem::path logPath = AgentMemoryDirectoryPath() / "provider_file_changes.jsonl";
        std::filesystem::create_directories(logPath.parent_path());
        json entry{
            {"timestamp_utc", CurrentTimestampUtc()},
            {"event", "applied"},
            {"session_id", fileChange.sessionId},
            {"path", fileChange.path},
            {"absolute_path", targetPath.string()},
            {"change_type", fileChange.changeType},
            {"summary", fileChange.summary},
            {"previous_file_existed", existed},
            {"previous_hash", existed ? HashTextForLog(fileChange.previousContent) : std::string{}},
            {"new_hash", HashTextForLog(fileChange.content)},
            {"content_char_count", fileChange.content.size()},
            {"has_diff_preview", !fileChange.diff.empty()},
        };
        std::ofstream logOutput(logPath, std::ios::app | std::ios::binary);
        logOutput << entry.dump() << '\n';

        state_.RefreshProjectTree();
        state_.AddActivity("provider.file_change", "Applied", targetPath.string());
        state_.AddChat(ChatSender::System, "Applied provider file change: " + targetPath.string());
        return true;
    } catch (const std::exception& exception) {
        const std::string diagnostic = std::string("proposed_file_change apply failed: ") + exception.what();
        action.diagnostics.push_back(diagnostic);
        state_.AddLog(LogLevel::Error, diagnostic);
        state_.AddActivity("provider.file_change", "Failed", diagnostic);
        return false;
    }
}

bool EditorApp::RevertProposedFileChange(size_t index) {
    if (!EnsureEditModeForAction("Revert proposed file change")) {
        return false;
    }

    if (index >= proposedActions_.size()) {
        return false;
    }

    NormalizedProviderResult& action = proposedActions_[index];
    if (!action.hasFileChange || !action.applied || action.fileChange.appliedPath.empty() ||
        !action.fileChange.previousContentCaptured) {
        return false;
    }

    ProposedFileChange& fileChange = action.fileChange;
    try {
        std::error_code filesystemError;
        const std::filesystem::path workspaceRoot = std::filesystem::weakly_canonical(std::filesystem::current_path(),
                                                                                     filesystemError);
        const std::filesystem::path targetPath = std::filesystem::path(fileChange.appliedPath).lexically_normal();
        if (filesystemError || !IsPathInsideOrSame(workspaceRoot, targetPath.parent_path())) {
            const std::string diagnostic =
                "proposed_file_change revert failed: target is outside the workspace: " + targetPath.string();
            action.diagnostics.push_back(diagnostic);
            state_.AddLog(LogLevel::Error, diagnostic);
            return false;
        }

        if (fileChange.previousFileExisted) {
            std::filesystem::create_directories(targetPath.parent_path(), filesystemError);
            std::ofstream output(targetPath, std::ios::binary | std::ios::trunc);
            if (!output) {
                const std::string diagnostic =
                    "proposed_file_change revert failed: could not restore target: " + targetPath.string();
                action.diagnostics.push_back(diagnostic);
                state_.AddLog(LogLevel::Error, diagnostic);
                return false;
            }
            output << fileChange.previousContent;
        } else {
            std::filesystem::remove(targetPath, filesystemError);
            if (filesystemError) {
                const std::string diagnostic = "proposed_file_change revert failed: could not delete created file: " +
                                               filesystemError.message();
                action.diagnostics.push_back(diagnostic);
                state_.AddLog(LogLevel::Error, diagnostic);
                return false;
            }
        }

        const std::filesystem::path logPath = AgentMemoryDirectoryPath() / "provider_file_changes.jsonl";
        std::filesystem::create_directories(logPath.parent_path());
        json entry{
            {"timestamp_utc", CurrentTimestampUtc()},
            {"event", "reverted"},
            {"session_id", fileChange.sessionId},
            {"path", fileChange.path},
            {"absolute_path", targetPath.string()},
            {"restored_previous_file", fileChange.previousFileExisted},
            {"restored_hash", fileChange.previousFileExisted ? HashTextForLog(fileChange.previousContent) : std::string{}},
        };
        std::ofstream logOutput(logPath, std::ios::app | std::ios::binary);
        logOutput << entry.dump() << '\n';

        action.applied = false;
        action.approved = false;
        action.canApprove = true;
        action.requiresApproval = true;
        state_.RefreshProjectTree();
        state_.AddActivity("provider.file_change", "Reverted", targetPath.string());
        state_.AddChat(ChatSender::System, "Reverted provider file change: " + targetPath.string());
        return true;
    } catch (const std::exception& exception) {
        const std::string diagnostic = std::string("proposed_file_change revert failed: ") + exception.what();
        action.diagnostics.push_back(diagnostic);
        state_.AddLog(LogLevel::Error, diagnostic);
        return false;
    }
}

void EditorApp::ApproveProposedAction(size_t index) {
    if (!EnsureEditModeForAction("Approve proposed action")) {
        return;
    }

    if (index >= proposedActions_.size()) {
        return;
    }

    NormalizedProviderResult& action = proposedActions_[index];
    if (action.type == ProviderResultType::ProposedFileChange) {
        ApplyProposedFileChange(index);
        return;
    }

    if (!action.canApprove || !action.hasCommandBatch || action.applied || action.rejected) {
        return;
    }

    ToolGatewayResult applyResult =
        gateway_.ApplyApprovedCommandBatch(action.commandBatch, state_, "user_approved_provider_command_batch");
    lastGatewayResult_ = applyResult;
    hasLastGatewayResult_ = true;
    action.commandBatch = applyResult.batch;
    action.approved = true;
    action.applied = applyResult.batch.applied && applyResult.batch.ok;
    action.canApprove = false;

    state_.AddChat(ChatSender::System, action.applied ? "Approved provider command batch was applied."
                                                      : "Approved provider command batch failed during application.");
    RefreshPathInputs();
}

void EditorApp::RejectProposedAction(size_t index) {
    if (index >= proposedActions_.size()) {
        return;
    }

    NormalizedProviderResult& action = proposedActions_[index];
    action.rejected = true;
    action.canApprove = false;
    state_.AddActivity("proposed action", "Rejected", action.title);
    state_.AddChat(ChatSender::System, "Rejected proposed action: " + action.title);
}

void EditorApp::OpenCodexLoginFromUi() {
    const ProviderHealth* codex = orchestrator_.FindProvider(AgentBackend::CodexCli);
    if (!CanLaunchCodexLogin(codex)) {
        const std::string status = codex == nullptr ? "Not found" : codex->status;
        const std::string detail =
            codex == nullptr ? "Codex provider row was missing." :
            codex->detail.empty() ? "Set AI_NATIVE_CODEX_PATH or install Codex before logging in."
                                  : codex->detail;
        state_.AddActivity("Codex login", status, detail);
        state_.AddLog(LogLevel::Warning, "Codex login could not be launched: " + detail);
        RequestProviderHealthRefresh("Codex login requested a fresh provider check");
        return;
    }

    selectedBackend_ = AgentBackend::CodexCli;
    std::string launchDetail;
    if (OpenInteractiveCodexLoginTerminal(codex, std::filesystem::current_path(), &launchDetail)) {
        state_.AddActivity("Codex login", "Opened", launchDetail);
        state_.AddChat(ChatSender::System,
                       "Opened Codex login in a separate terminal. After login completes, use Refresh Codex.");
        agentSurfaceStatus_ = "Opened Codex login. Refresh Codex after authentication completes.";
        return;
    }

    state_.AddActivity("Codex login", "Launch failed", launchDetail);
    state_.AddLog(LogLevel::Error, "Failed to open Codex login terminal: " + launchDetail);
}

void EditorApp::UseOpenAIApiInstead() {
    selectedBackend_ = AgentBackend::OpenAIApi;
    const ProviderHealth* openai = orchestrator_.FindProvider(AgentBackend::OpenAIApi);
    const std::string status = openai == nullptr ? "Unknown" : openai->status;
    const std::string detail = openai == nullptr ? EnvironmentStatusText("OPENAI_API_KEY") : openai->detail;
    state_.AddActivity("Backend selected", status, "OpenAI API | " + detail);
    state_.AddChat(ChatSender::System,
                   "Selected OpenAI API backend. " + EnvironmentStatusText("OPENAI_API_KEY") +
                       ". API keys are read from the environment only and are not stored in project files.");
    RequestProviderHealthRefresh("OpenAI API backend selected");
}

void EditorApp::ApplyCodexPathFromUi() {
    std::string path = codexPathInput_.data();
    path.erase(path.begin(), std::find_if(path.begin(), path.end(), [](unsigned char ch) {
                   return !std::isspace(ch);
               }));
    path.erase(std::find_if(path.rbegin(), path.rend(), [](unsigned char ch) {
                   return !std::isspace(ch);
               }).base(),
               path.end());

    if (!SetProcessEnvironmentValue("AI_NATIVE_CODEX_PATH", path)) {
        state_.AddLog(LogLevel::Error, "Failed to set AI_NATIVE_CODEX_PATH in the current editor process.");
        return;
    }

    selectedBackend_ = AgentBackend::CodexCli;
    state_.AddActivity("Codex setup", "Updated",
                       path.empty() ? "Cleared AI_NATIVE_CODEX_PATH for this editor process."
                                    : "Set AI_NATIVE_CODEX_PATH for this editor process: " + path);
    RequestProviderHealthRefresh("Codex path changed");
    showCodexPathInput_ = false;
}

void EditorApp::RefreshPathInputs() {
    CopyStringToBuffer(projectRootInput_, state_.ProjectRootPathString());
    CopyStringToBuffer(projectFileInput_, state_.ProjectFilePathString());
    CopyStringToBuffer(scenePathInput_, state_.SceneFilePathString());
    CopyStringToBuffer(gameSavePathInput_, state_.GameSaveRootPathString());
    RefreshBuildSettingsInputs();
}

void EditorApp::RefreshBuildSettingsInputs() {
    const ProjectBuildSettings& settings = state_.BuildSettings();
    CopyStringToBuffer(buildOutputDirectoryInput_, settings.outputDirectory);
    CopyStringToBuffer(buildExecutableNameInput_, settings.executableName);
    CopyStringToBuffer(multiplayerBindAddressInput_, settings.multiplayer.bindAddress);
    const std::vector<std::string> targetPlatforms{"Windows", "Linux", "macOS"};
    const auto targetIt =
        std::find(targetPlatforms.begin(), targetPlatforms.end(), NormalizeBuildTargetPlatformName(settings.targetPlatform));
    buildTargetPlatformIndex_ =
        targetIt == targetPlatforms.end() ? 0 : static_cast<int>(std::distance(targetPlatforms.begin(), targetIt));
    buildConfigurationIndex_ = settings.configuration == "Release" ? 1 : 0;
    buildDevelopmentBuild_ = settings.developmentBuild;
    buildCopyProjectFiles_ = settings.copyProjectFiles;
    buildRunPlayerSmokeAfterBuild_ = settings.runPlayerSmokeAfterBuild;
    multiplayerEnabled_ = settings.multiplayer.enabled;
    multiplayerPort_ = settings.multiplayer.port;
    multiplayerMaxPlayers_ = settings.multiplayer.maxPlayers;

    const std::vector<std::string> topologies{"Single Player", "Host Client", "Client Server", "Dedicated Server"};
    const auto topologyIt = std::find(topologies.begin(), topologies.end(), settings.multiplayer.topology);
    multiplayerTopologyIndex_ =
        topologyIt == topologies.end() ? 0 : static_cast<int>(std::distance(topologies.begin(), topologyIt));

    const std::vector<std::string> transports{"Local Loopback", "UDP", "WebSocket"};
    const auto transportIt = std::find(transports.begin(), transports.end(), settings.multiplayer.transport);
    multiplayerTransportIndex_ =
        transportIt == transports.end() ? 0 : static_cast<int>(std::distance(transports.begin(), transportIt));
}

void EditorApp::ApplyBuildSettingsFromUi() {
    ProjectBuildSettings settings = state_.BuildSettings();
    const char* targetPlatforms[] = {"Windows", "Linux", "macOS"};
    const char* configurations[] = {"Debug", "Release"};
    const char* topologies[] = {"Single Player", "Host Client", "Client Server", "Dedicated Server"};
    const char* transports[] = {"Local Loopback", "UDP", "WebSocket"};
    buildTargetPlatformIndex_ =
        std::clamp(buildTargetPlatformIndex_, 0, static_cast<int>(IM_ARRAYSIZE(targetPlatforms)) - 1);
    buildConfigurationIndex_ = std::clamp(buildConfigurationIndex_, 0, static_cast<int>(IM_ARRAYSIZE(configurations)) - 1);
    multiplayerTopologyIndex_ = std::clamp(multiplayerTopologyIndex_, 0, static_cast<int>(IM_ARRAYSIZE(topologies)) - 1);
    multiplayerTransportIndex_ = std::clamp(multiplayerTransportIndex_, 0, static_cast<int>(IM_ARRAYSIZE(transports)) - 1);

    settings.targetPlatform = targetPlatforms[buildTargetPlatformIndex_];
    settings.architecture = "x64";
    settings.configuration = configurations[buildConfigurationIndex_];
    settings.outputDirectory = TrimWhitespace(buildOutputDirectoryInput_.data());
    settings.executableName = TrimWhitespace(buildExecutableNameInput_.data());
    settings.developmentBuild = buildDevelopmentBuild_;
    settings.copyProjectFiles = buildCopyProjectFiles_;
    settings.runPlayerSmokeAfterBuild = buildRunPlayerSmokeAfterBuild_;
    if (settings.scenes.empty()) {
        std::error_code error;
        const std::filesystem::path relativeScene =
            std::filesystem::relative(state_.SceneFilePathString(), state_.ProjectRootPathString(), error);
        settings.scenes = {error ? state_.SceneFilePathString() : relativeScene.generic_string()};
    }
    settings.multiplayer.enabled = multiplayerEnabled_;
    settings.multiplayer.topology = topologies[multiplayerTopologyIndex_];
    settings.multiplayer.transport = transports[multiplayerTransportIndex_];
    settings.multiplayer.bindAddress = TrimWhitespace(multiplayerBindAddressInput_.data());
    settings.multiplayer.port = multiplayerPort_;
    settings.multiplayer.maxPlayers = multiplayerMaxPlayers_;
    state_.SetBuildSettings(std::move(settings));

    std::string error;
    if (state_.SaveProject(&error)) {
        lastBuildStatus_ = "Build settings saved to " + state_.ProjectFilePathString();
        state_.AddActivity("build.settings", "Saved", state_.ProjectFilePathString());
    } else {
        lastBuildStatus_ = "Build settings save failed: " + error;
        state_.AddLog(LogLevel::Error, lastBuildStatus_);
    }
    RefreshBuildSettingsInputs();
}

std::filesystem::path EditorApp::PlayerExecutablePathForCurrentBuild() const {
    const ProjectBuildSettings& settings = state_.BuildSettings();
    const std::filesystem::path currentExecutable = CurrentExecutablePath();
    const std::filesystem::path currentDirectory = currentExecutable.parent_path();
    const std::string targetPlatform = NormalizeBuildTargetPlatformName(settings.targetPlatform);
    const std::string configurationSuffix = settings.configuration == "Release" ? "release" : "debug";
    std::vector<std::filesystem::path> candidates;
    if (targetPlatform == "Windows") {
        const std::filesystem::path preferredPreset =
            settings.configuration == "Release" ? "windows-ninja-release" : "windows-ninja-debug";
        candidates = {
            currentDirectory / "ai_native_player.exe",
            std::filesystem::current_path() / "build" / preferredPreset / "ai_native_player.exe",
            std::filesystem::current_path() / "build" / "windows-ninja-debug" / "ai_native_player.exe",
            std::filesystem::current_path() / "build" / "windows-ninja-release" / "ai_native_player.exe",
        };
    } else if (targetPlatform == "Linux") {
        const std::filesystem::path preferredPreset = "linux-ninja-" + configurationSuffix;
        candidates = {
            currentDirectory / "ai_native_player",
            std::filesystem::current_path() / "build" / preferredPreset / "ai_native_player",
            std::filesystem::current_path() / "build" / "linux-ninja-debug" / "ai_native_player",
            std::filesystem::current_path() / "build" / "linux-ninja-release" / "ai_native_player",
        };
    } else {
        const std::filesystem::path preferredPreset = "macos-ninja-" + configurationSuffix;
        candidates = {
            currentDirectory / "ai_native_player",
            std::filesystem::current_path() / "build" / preferredPreset / "ai_native_player",
            std::filesystem::current_path() / "build" / "macos-ninja-debug" / "ai_native_player",
            std::filesystem::current_path() / "build" / "macos-ninja-release" / "ai_native_player",
        };
    }
    for (const std::filesystem::path& candidate : candidates) {
        if (std::filesystem::exists(candidate)) {
            return candidate;
        }
    }
    return candidates.empty() ? std::filesystem::path{} : candidates.front();
}

bool EditorApp::PackageProjectFromUi() {
    if (!EnsureEditModeForAction("Package player build")) {
        return false;
    }

    ApplyBuildSettingsFromUi();
    ProjectBuildReport report;
    std::string error;
    const std::filesystem::path playerExecutable = PlayerExecutablePathForCurrentBuild();
    if (!state_.PackagePlayerBuild(playerExecutable, &report, &error)) {
        lastBuildStatus_ = "Package failed: " + error;
        state_.AddLog(LogLevel::Error, lastBuildStatus_);
        return false;
    }

    lastBuildOutputPath_ = report.outputDirectory.string();
    lastBuildStatus_ = "Packaged " + report.targetPlatform + " " + report.executablePath.string() +
                       " | files=" + std::to_string(report.copiedFileCount) +
                       " | manifest=" + report.manifestPath.string();
    if (!report.runtimeSmokeStatus.empty()) {
        lastBuildStatus_ += " | smoke=" + report.runtimeSmokeStatus;
    }
    state_.AddActivity("build.packagePlayer", "Complete", lastBuildStatus_);
    RefreshPathInputs();
    return true;
}

bool EditorApp::PackageAllTargetsFromUi() {
    if (!EnsureEditModeForAction("Package all player builds")) {
        return false;
    }

    ApplyBuildSettingsFromUi();
    const ProjectBuildSettings originalSettings = state_.BuildSettings();
    const std::vector<std::string> targetPlatforms{"Windows", "Linux", "macOS"};
    bool anyPackaged = false;
    std::vector<std::string> summaries;

    for (const std::string& targetPlatform : targetPlatforms) {
        ProjectBuildSettings settings = originalSettings;
        settings.targetPlatform = targetPlatform;
        if (settings.outputDirectory.empty() || IsKnownDefaultBuildOutputDirectory(settings.outputDirectory)) {
            settings.outputDirectory = DefaultBuildOutputDirectoryForTarget(targetPlatform);
        }
        state_.SetBuildSettings(settings);
        RefreshBuildSettingsInputs();

        ProjectBuildReport report;
        std::string error;
        const std::filesystem::path playerExecutable = PlayerExecutablePathForCurrentBuild();
        if (state_.PackagePlayerBuild(playerExecutable, &report, &error)) {
            anyPackaged = true;
            lastBuildOutputPath_ = report.outputDirectory.string();
            summaries.push_back(targetPlatform + ": packaged " + report.executablePath.string());
            state_.AddActivity("build.packagePlayer", "Complete", targetPlatform + " " + report.executablePath.string());
        } else {
            summaries.push_back(targetPlatform + ": unavailable - " + error);
            state_.AddActivity("build.packagePlayer", "Unavailable", targetPlatform + " " + error);
        }
    }

    state_.SetBuildSettings(originalSettings);
    std::string saveError;
    state_.SaveProject(&saveError);
    RefreshBuildSettingsInputs();
    lastBuildStatus_ = "Package all targets: " + JoinStrings(summaries, " | ");
    if (!saveError.empty()) {
        lastBuildStatus_ += " | restore save failed: " + saveError;
        state_.AddLog(LogLevel::Error, lastBuildStatus_);
    } else {
        state_.AddLog(anyPackaged ? LogLevel::Info : LogLevel::Warning, lastBuildStatus_);
    }
    return anyPackaged;
}

bool EditorApp::BrowseBuildOutputFolderFromUi() {
    std::filesystem::path initialPath = TrimWhitespace(buildOutputDirectoryInput_.data());
    if (initialPath.empty()) {
        initialPath = state_.BuildOutputDirectoryPathString();
    } else if (!initialPath.is_absolute()) {
        initialPath = std::filesystem::path(state_.ProjectRootPathString()) / initialPath;
    }

    std::filesystem::path selectedPath;
    std::string error;
    if (PickFolderWithDialog("Select player build output folder", initialPath, &selectedPath, &error)) {
        CopyStringToBuffer(buildOutputDirectoryInput_, selectedPath.string());
        state_.AddActivity("build.output", "Selected", selectedPath.string());
        return true;
    }
    if (!error.empty()) {
        state_.AddLog(LogLevel::Warning, "Build output folder picker failed: " + error);
    }
    return false;
}

void EditorApp::NewProjectFromUi() {
    if (!EnsureEditModeForAction("New project")) {
        return;
    }

    std::string error;
    std::filesystem::path projectPath = projectRootInput_.data();
    std::filesystem::path projectRoot = state_.DefaultProjectRootPath();
    if (!projectPath.empty()) {
        projectRoot = projectPath.has_extension() ? projectPath.parent_path() : projectPath;
    }
    if (projectRoot.empty()) {
        projectRoot = state_.DefaultProjectRootPath();
    }

    if (state_.NewProject(projectRoot, &error)) {
        projectExplorerSelectedPath_.clear();
        state_.AddLog(LogLevel::Info, "Created new project at " + state_.ProjectRootPathString() + ".");
    } else {
        state_.AddLog(LogLevel::Error, "New project failed: " + error);
    }
    RefreshPathInputs();
}

