void EditorApp::SaveProjectAsFromUi() {
    if (!EnsureEditModeForAction("Save project as")) {
        return;
    }

    std::filesystem::path selectedPath;
    std::string error;
    std::filesystem::path initialPath = projectRootInput_.data();
    if (initialPath.empty()) {
        initialPath = state_.ProjectRootPathString();
    }

    if (!PickFolderWithDialog("Save AI Native project as folder", initialPath, &selectedPath, &error)) {
        if (!error.empty()) {
            state_.AddLog(LogLevel::Warning, "Project Save As picker failed: " + error);
        }
        return;
    }

    if (state_.SaveProjectAs(selectedPath, &error)) {
        projectExplorerSelectedPath_.clear();
        state_.AddActivity("project.saveAs", "Complete", state_.ProjectRootPathString());
    } else {
        state_.AddLog(LogLevel::Error, "Project Save As failed: " + error);
    }
    RefreshPathInputs();
}

