void EditorApp::SaveSceneAsWithDialogFromUi() {
    if (!EnsureEditModeForAction("Save scene as")) {
        return;
    }

    std::filesystem::path selectedPath;
    std::string error;
    const std::filesystem::path currentScene = state_.SceneFilePathString();
    const std::filesystem::path initialPath = currentScene.empty() ? std::filesystem::path(scenePathInput_.data())
                                                                   : currentScene;
    const std::string defaultName = initialPath.filename().empty() ? "Prototype.scene.json"
                                                                   : initialPath.filename().string();
    if (!PickSaveFileWithDialog("Save scene as", initialPath, defaultName.c_str(), &selectedPath, &error)) {
        if (!error.empty()) {
            state_.AddLog(LogLevel::Warning, "Scene Save As picker failed: " + error);
        }
        return;
    }

    selectedPath = NormalizeSceneSavePath(selectedPath);
    CopyStringToBuffer(scenePathInput_, selectedPath.string());
    SaveSceneAsFromUi();
}

